window.ORACLE_CARDS = [
  /* ———————— CERCUL PĂMÂNTULUI ———————— */
  {el:'earth',kw:{ro:'Rădăcina',en:'The Root',pt:'A Raiz'},t:{ro:'Nimic înalt nu crește fără rădăcini adânci. Coboară înainte să urci.',en:'Nothing tall grows without deep roots. Descend before you rise.',pt:'Nada de alto cresce sem raízes fundas. Desce antes de subir.'},inv:{ro:'Așază-te. Simte-ți greutatea.',en:'Sit. Feel your own weight.',pt:'Senta-te. Sente o teu próprio peso.'}},
  {el:'earth',kw:{ro:'Răbdarea',en:'Patience',pt:'A Paciência'},t:{ro:'Piatra nu se grăbește să devină munte. Ce e temeinic se face încet.',en:'The stone does not rush to become a mountain. What is lasting is made slowly.',pt:'A pedra não se apressa a ser montanha. O que é duradouro faz-se devagar.'},inv:{ro:'Nu forța azi ce se coace mâine.',en:'Don’t force today what ripens tomorrow.',pt:'Não forces hoje o que amadurece amanhã.'}},
  {el:'earth',kw:{ro:'Trupul',en:'The Body',pt:'O Corpo'},t:{ro:'Sufletul locuiește undeva anume. Cinstește casa în care stai.',en:'The soul dwells somewhere. Honor the house you live in.',pt:'A alma mora nalgum lugar. Honra a casa onde habitas.'},inv:{ro:'Mulțumește azi trupului tău.',en:'Thank your body today.',pt:'Agradece hoje ao teu corpo.'}},
  {el:'earth',kw:{ro:'Disciplina',en:'Discipline',pt:'A Disciplina'},t:{ro:'Libertatea nu e lipsa formei, ci forma stăpânită.',en:'Freedom is not the absence of form, but form mastered.',pt:'A liberdade não é a ausência de forma, mas a forma dominada.'},inv:{ro:'Alege un singur lucru și ține-te de el.',en:'Choose one thing and keep to it.',pt:'Escolhe uma coisa e mantém-te nela.'}},
  {el:'earth',kw:{ro:'Smerenia',en:'Humility',pt:'A Humildade'},t:{ro:'Spicul plin se pleacă și nu e frânt de vânt.',en:'The full ear of wheat bends and is not broken by the wind.',pt:'A espiga cheia inclina-se e não é quebrada pelo vento.'},inv:{ro:'Recunoaște azi un lucru pe care nu-l știi.',en:'Admit one thing you do not know today.',pt:'Admite hoje uma coisa que não sabes.'}},
  {el:'earth',kw:{ro:'Temelia',en:'The Foundation',pt:'O Alicerce'},t:{ro:'Zidește pe ce nu se clatină. Restul e nisip frumos.',en:'Build on what does not shift. The rest is beautiful sand.',pt:'Constrói sobre o que não se move. O resto é bela areia.'},inv:{ro:'Ce rămâne când pierzi totul? Acolo zidește.',en:'What remains when all is lost? Build there.',pt:'O que fica quando perdes tudo? Constrói aí.'}},

  /* ———————— CERCUL APEI ———————— */
  {el:'water',kw:{ro:'Curgerea',en:'The Flow',pt:'A Corrente'},t:{ro:'Apa nu se luptă cu piatra; o ocolește și ajunge la mare.',en:'Water does not fight the stone; it goes around and reaches the sea.',pt:'A água não luta com a pedra; contorna-a e chega ao mar.'},inv:{ro:'Unde te lupți degeaba? Curge pe lângă.',en:'Where do you struggle in vain? Flow past it.',pt:'Onde lutas em vão? Passa ao lado.'}},
  {el:'water',kw:{ro:'Golirea',en:'Emptying',pt:'O Esvaziar'},t:{ro:'Doar cupa goală poate fi umplută. Fă loc.',en:'Only the empty cup can be filled. Make room.',pt:'Só a taça vazia se pode encher. Abre espaço.'},inv:{ro:'Lasă azi ceva să plece.',en:'Let something leave today.',pt:'Deixa hoje algo partir.'}},
  {el:'water',kw:{ro:'Forma',en:'The Form',pt:'A Forma'},t:{ro:'Apa ia forma vasului, dar rămâne apă. Adaptează-te fără să te pierzi.',en:'Water takes the vessel’s shape yet stays water. Adapt without losing yourself.',pt:'A água toma a forma do vaso mas continua água. Adapta-te sem te perderes.'},inv:{ro:'Îndoaie-te, nu te rupe.',en:'Bend, do not break.',pt:'Dobra-te, não te quebres.'}},
  {el:'water',kw:{ro:'Blândețea',en:'Gentleness',pt:'A Doçura'},t:{ro:'Ce e moale învinge ce e tare. Picătura sapă stânca.',en:'The soft overcomes the hard. The drop carves the rock.',pt:'O macio vence o duro. A gota talha a rocha.'},inv:{ro:'Fii blând azi, mai ales cu tine.',en:'Be gentle today, above all with yourself.',pt:'Sê doce hoje, sobretudo contigo.'}},
  {el:'water',kw:{ro:'Adâncul',en:'The Deep',pt:'O Fundo'},t:{ro:'La suprafață e furtună; în adânc, tăcere. Coboară.',en:'On the surface, storm; in the deep, silence. Descend.',pt:'À superfície, tempestade; no fundo, silêncio. Desce.'},inv:{ro:'Sub emoție, ce e liniștit?',en:'Beneath the emotion, what is still?',pt:'Sob a emoção, o que está quieto?'}},
  {el:'water',kw:{ro:'Oglinda',en:'The Mirror',pt:'O Espelho'},t:{ro:'Apa liniștită oglindește cerul; mintea liniștită, adevărul.',en:'Still water mirrors the sky; a still mind, the truth.',pt:'A água quieta espelha o céu; a mente quieta, a verdade.'},inv:{ro:'Liniștește-te ca să vezi limpede.',en:'Grow still, to see clearly.',pt:'Aquieta-te, para ver com clareza.'}},

  /* ———————— CERCUL FOCULUI ———————— */
  {el:'fire',kw:{ro:'Scânteia',en:'The Spark',pt:'A Faísca'},t:{ro:'Tot ce arde a pornit dintr-o scânteie. Nu o disprețui pe a ta.',en:'All that blazes began as a spark. Do not despise yours.',pt:'Tudo o que arde começou numa faísca. Não desprezes a tua.'},inv:{ro:'Ce mic pas aprinzi azi?',en:'What small step will you light today?',pt:'Que pequeno passo acendes hoje?'}},
  {el:'fire',kw:{ro:'Arderea',en:'The Burning',pt:'A Queima'},t:{ro:'Focul nu distruge aurul; îi arde zgura. Lasă-te curățat.',en:'Fire does not destroy gold; it burns away the dross. Let yourself be purified.',pt:'O fogo não destrói o ouro; queima-lhe a escória. Deixa-te purificar.'},inv:{ro:'Ce trebuie să lași să ardă?',en:'What must you let burn?',pt:'O que tens de deixar arder?'}},
  {el:'fire',kw:{ro:'Curajul',en:'Courage',pt:'A Coragem'},t:{ro:'Curajul nu e lipsa fricii, ci mersul înainte cu ea de mână.',en:'Courage is not the absence of fear, but walking on with it by the hand.',pt:'A coragem não é a ausência de medo, mas caminhar com ele pela mão.'},inv:{ro:'Fă azi lucrul de care ți-e teamă.',en:'Do the thing you fear today.',pt:'Faz hoje aquilo que temes.'}},
  {el:'fire',kw:{ro:'Voința',en:'The Will',pt:'A Vontade'},t:{ro:'Un scop clar arde prin o mie de scuze.',en:'A clear aim burns through a thousand excuses.',pt:'Um objetivo claro queima mil desculpas.'},inv:{ro:'Ce vrei cu adevărat? Spune-o.',en:'What do you truly want? Say it.',pt:'O que queres de verdade? Di-lo.'}},
  {el:'fire',kw:{ro:'Lumina',en:'The Light',pt:'A Luz'},t:{ro:'O singură lumânare risipește o beznă veche de o mie de ani.',en:'A single candle scatters a darkness a thousand years old.',pt:'Uma só vela dispersa uma escuridão de mil anos.'},inv:{ro:'Aprinde, nu blestema întunericul.',en:'Kindle a light; do not curse the dark.',pt:'Acende uma luz; não amaldiçoes o escuro.'}},
  {el:'fire',kw:{ro:'Pasiunea',en:'Passion',pt:'A Paixão'},t:{ro:'Fă din ceea ce iubești rug, nu cenușă.',en:'Make of what you love a fire, not ashes.',pt:'Faz do que amas fogo, não cinzas.'},inv:{ro:'Ce te aprinde? Mergi spre asta.',en:'What sets you alight? Move toward it.',pt:'O que te acende? Caminha para isso.'}},

  /* ———————— CERCUL VÂNTULUI ———————— */
  {el:'wind',kw:{ro:'Suflarea',en:'The Breath',pt:'O Sopro'},t:{ro:'Între inspir și expir încape toată viața. Ești la o suflare de pace.',en:'Between in-breath and out-breath fits a whole life. You are one breath from peace.',pt:'Entre inspirar e expirar cabe uma vida inteira. Estás a um sopro da paz.'},inv:{ro:'Respiră o dată, adânc, acum.',en:'Take one deep breath, now.',pt:'Respira fundo uma vez, agora.'}},
  {el:'wind',kw:{ro:'Gândul',en:'The Thought',pt:'O Pensamento'},t:{ro:'Nu ești gândurile tale; ești cerul prin care trec norii.',en:'You are not your thoughts; you are the sky the clouds pass through.',pt:'Não és os teus pensamentos; és o céu por onde passam as nuvens.'},inv:{ro:'Privește un gând fără să-l crezi.',en:'Watch a thought without believing it.',pt:'Observa um pensamento sem acreditar nele.'}},
  {el:'wind',kw:{ro:'Libertatea',en:'Freedom',pt:'A Liberdade'},t:{ro:'Nimeni nu-ți poate lua felul în care întâmpini ce ți se dă.',en:'No one can take the way you meet what you are given.',pt:'Ninguém te pode tirar o modo como recebes o que te é dado.'},inv:{ro:'Alege azi răspunsul, nu reacția.',en:'Choose the response, not the reaction.',pt:'Escolhe a resposta, não a reação.'}},
  {el:'wind',kw:{ro:'Schimbarea',en:'Change',pt:'A Mudança'},t:{ro:'Vântul nu poate fi ținut în pumn. Nici clipa. Dă drumul.',en:'The wind cannot be held in a fist. Nor the moment. Let go.',pt:'O vento não se segura no punho. Nem o instante. Larga.'},inv:{ro:'De ce te agăți, deși a trecut?',en:'What do you clutch, though it has passed?',pt:'O que agarras, embora já tenha passado?'}},
  {el:'wind',kw:{ro:'Cuvântul',en:'The Word',pt:'A Palavra'},t:{ro:'Un cuvânt poate zidi sau surpa o lume. Cântărește-l.',en:'A word can build or topple a world. Weigh it.',pt:'Uma palavra pode erguer ou derrubar um mundo. Pesa-a.'},inv:{ro:'Spune azi un cuvânt care zidește.',en:'Speak a word that builds today.',pt:'Diz hoje uma palavra que constrói.'}},
  {el:'wind',kw:{ro:'Tăcerea',en:'Silence',pt:'O Silêncio'},t:{ro:'În pauza dintre cuvinte locuiește înțelesul.',en:'In the pause between words, meaning dwells.',pt:'Na pausa entre as palavras mora o sentido.'},inv:{ro:'Taci azi o clipă mai mult.',en:'Stay silent a moment longer today.',pt:'Fica hoje calado um instante a mais.'}},

  /* ———————— CERCUL VIDULUI ———————— */
  {el:'voidx',kw:{ro:'Golul',en:'The Void',pt:'O Vazio'},t:{ro:'Din gol se naște totul. Nu-l umple de frică.',en:'From emptiness, all is born. Do not fill it out of fear.',pt:'Do vazio nasce tudo. Não o enchas por medo.'},inv:{ro:'Stai o clipă fără să faci nimic.',en:'Sit a moment doing nothing.',pt:'Fica um instante sem fazer nada.'}},
  {el:'voidx',kw:{ro:'Misterul',en:'The Mystery',pt:'O Mistério'},t:{ro:'Ce e mai adânc nu se explică; se trăiește.',en:'What is deepest is not explained; it is lived.',pt:'O que é mais fundo não se explica; vive-se.'},inv:{ro:'Lasă azi o întrebare fără răspuns.',en:'Leave one question unanswered today.',pt:'Deixa hoje uma pergunta sem resposta.'}},
  {el:'voidx',kw:{ro:'Unitatea',en:'Oneness',pt:'A Unidade'},t:{ro:'Valul se crede singur până își amintește că e mare.',en:'The wave thinks itself alone until it remembers it is the sea.',pt:'A onda julga-se só até se lembrar de que é mar.'},inv:{ro:'Ce te desparte cu adevărat de tot?',en:'What truly separates you from all?',pt:'O que te separa verdadeiramente de tudo?'}},
  {el:'voidx',kw:{ro:'Prezența',en:'Presence',pt:'A Presença'},t:{ro:'Veșnicia nu e timp lung; e adâncimea lui acum.',en:'Eternity is not long time; it is the depth of now.',pt:'A eternidade não é tempo longo; é a profundidade do agora.'},inv:{ro:'Fii de față. Aici. Acum.',en:'Be present. Here. Now.',pt:'Está presente. Aqui. Agora.'}},
  {el:'voidx',kw:{ro:'Tăcerea Cerului',en:'Heaven’s Silence',pt:'O Silêncio do Céu'},t:{ro:'Uneori tăcerea Cerului e cea mai deplină vorbire.',en:'Sometimes Heaven’s silence is the fullest speech.',pt:'Às vezes o silêncio do Céu é a fala mais plena.'},inv:{ro:'Ascultă azi liniștea.',en:'Listen to the silence today.',pt:'Escuta hoje o silêncio.'}},
  {el:'voidx',kw:{ro:'Lumina neapusă',en:'Unfading Light',pt:'A Luz que Não Se Apaga'},t:{ro:'Sub toate e o lumină care nu se stinge. Ești făcut din ea.',en:'Beneath all is a light that never goes out. You are made of it.',pt:'Sob tudo há uma luz que nunca se apaga. És feito dela.'},inv:{ro:'Ce în tine nu s-a stins niciodată?',en:'What in you has never been extinguished?',pt:'O que em ti nunca se apagou?'}},

  /* ———————— CELE TREI CHEI ———————— */
  {el:'key',kw:{ro:'Atenția',en:'Attention',pt:'A Atenção'},t:{ro:'Atenția e cea mai rară formă de iubire. Ce privești, prinde viață.',en:'Attention is the rarest form of love. What you behold comes alive.',pt:'A atenção é a forma mais rara de amor. O que contemplas ganha vida.'},inv:{ro:'Dăruiește cuiva atenția ta întreagă.',en:'Give someone your whole attention.',pt:'Dá a alguém a tua atenção inteira.'}},
  {el:'key',kw:{ro:'Respirația',en:'The Breath',pt:'A Respiração'},t:{ro:'Suflarea e puntea dintre trup și duh. Traversează-o des.',en:'Breath is the bridge between body and spirit. Cross it often.',pt:'A respiração é a ponte entre o corpo e o espírito. Atravessa-a amiúde.'},inv:{ro:'Respiră ca și cum ar fi prima oară.',en:'Breathe as if for the first time.',pt:'Respira como se fosse a primeira vez.'}},
  {el:'key',kw:{ro:'Prezența',en:'Presence',pt:'A Presença'},t:{ro:'Nu ai unde ajunge. Ești deja aici. Sosește.',en:'There is nowhere to arrive. You are already here. Arrive.',pt:'Não há para onde chegar. Já estás aqui. Chega.'},inv:{ro:'Oprește-te din alergat. Ai ajuns.',en:'Stop running. You have arrived.',pt:'Pára de correr. Já chegaste.'}},

  /* ———————— CERCUL INIMII — inteligența emoțională ———————— */
  {el:'heart',kw:{ro:'Simțirea',en:'The Feeling',pt:'A Sensação'},t:{ro:'Ce simți nu e o poruncă; e o veste. Citește scrisoarea, nu o înghiți.',en:'What you feel is not a command; it is news. Read the letter, do not swallow it.',pt:'O que sentes não é uma ordem; é uma notícia. Lê a carta, não a engulas.'},inv:{ro:'Numește emoția înainte să acționezi din ea.',en:'Name the emotion before you act from it.',pt:'Nomeia a emoção antes de agires a partir dela.'}},
  {el:'heart',kw:{ro:'Numirea',en:'The Naming',pt:'A Nomeação'},t:{ro:'O emoție numită e pe jumătate îmblânzită. Ce nu numești te conduce din umbră.',en:'A named emotion is half-tamed. What you do not name rules you from the shadows.',pt:'Uma emoção nomeada está meio domada. O que não nomeias governa-te das sombras.'},inv:{ro:'Spune-i pe nume: „asta e frică", „asta e dor".',en:'Call it by name: “this is fear,” “this is longing.”',pt:'Chama-lhe pelo nome: «isto é medo», «isto é saudade».'}},
  {el:'heart',kw:{ro:'Valul',en:'The Wave',pt:'A Onda'},t:{ro:'Nicio emoție nu e veșnică. Vine, crește, se sparge, trece. Tu rămâi țărmul.',en:'No emotion is forever. It comes, swells, breaks, passes. You remain the shore.',pt:'Nenhuma emoção é para sempre. Vem, cresce, rebenta, passa. Tu ficas a margem.'},inv:{ro:'Lasă valul de acum să treacă fără să te lupți cu el.',en:'Let this wave pass without fighting it.',pt:'Deixa esta onda passar sem lutares com ela.'}},
  {el:'heart',kw:{ro:'Granița',en:'The Boundary',pt:'A Fronteira'},t:{ro:'Un „nu" spus întreg hrănește mai mult decât un „da" spus pe jumătate.',en:'A whole “no” nourishes more than a half-hearted “yes.”',pt:'Um «não» inteiro nutre mais do que um «sim» pela metade.'},inv:{ro:'Unde spui „da" doar de frică? Spune azi altfel.',en:'Where do you say yes only from fear? Say otherwise today.',pt:'Onde dizes sim só por medo? Diz hoje de outro modo.'}},
  {el:'heart',kw:{ro:'Furia',en:'Anger',pt:'A Raiva'},t:{ro:'Furia e un paznic cu inima bună: arată unde a fost călcată o graniță. Ascult-o, nu o dezlănțui.',en:'Anger is a warm-hearted guard: it shows where a line was crossed. Hear it; do not unleash it.',pt:'A raiva é um guarda de bom coração: mostra onde uma linha foi cruzada. Escuta-a; não a desencadeies.'},inv:{ro:'Ce graniță apără furia ta de azi?',en:'What boundary does today’s anger defend?',pt:'Que fronteira defende a tua raiva de hoje?'}},
  {el:'heart',kw:{ro:'Frica',en:'Fear',pt:'O Medo'},t:{ro:'Frica îți arată ce prețuiești. Nimeni nu tremură pentru ce nu-i pasă.',en:'Fear shows you what you treasure. No one trembles for what they do not care about.',pt:'O medo mostra-te o que tesouras. Ninguém treme pelo que não lhe importa.'},inv:{ro:'Sub frica ta, ce comoară se ascunde?',en:'Beneath your fear, what treasure hides?',pt:'Sob o teu medo, que tesouro se esconde?'}},
  {el:'heart',kw:{ro:'Rușinea',en:'Shame',pt:'A Vergonha'},t:{ro:'Rușinea moare când e spusă cu voce blândă cuiva care ascultă cu drag.',en:'Shame dies when spoken gently to someone who listens with love.',pt:'A vergonha morre quando dita com doçura a quem escuta com amor.'},inv:{ro:'Spune azi cuiva de încredere un lucru greu de spus.',en:'Tell a trusted soul one hard thing today.',pt:'Conta hoje a uma alma de confiança uma coisa difícil.'}},
  {el:'heart',kw:{ro:'Tristețea',en:'Sadness',pt:'A Tristeza'},t:{ro:'Tristețea e iubirea care nu mai are unde se duce. Las-o să curgă; își face singură albia.',en:'Sadness is love with nowhere left to go. Let it flow; it carves its own bed.',pt:'A tristeza é amor sem para onde ir. Deixa-a correr; ela abre o seu próprio leito.'},inv:{ro:'Plângi dacă vine plânsul. E și el o limpezire.',en:'Cry if tears come. They too are a clearing.',pt:'Chora se as lágrimas vierem. Também elas são uma clareira.'}},
  {el:'heart',kw:{ro:'Bucuria',en:'Joy',pt:'A Alegria'},t:{ro:'Bucuria nu așteaptă zile mari. Stă în lucruri mici, gata să fie văzută.',en:'Joy does not wait for great days. It sits in small things, waiting to be seen.',pt:'A alegria não espera os grandes dias. Mora nas coisas pequenas, à espera de ser vista.'},inv:{ro:'Prinde azi trei bucurii mărunte în zbor.',en:'Catch three small joys in flight today.',pt:'Apanha hoje três pequenas alegrias em voo.'}},
  {el:'heart',kw:{ro:'Recunoștința',en:'Gratitude',pt:'A Gratidão'},t:{ro:'Recunoștința nu schimbă ce ai; schimbă ochiul care privește. Și atunci ai mai mult.',en:'Gratitude does not change what you have; it changes the eye that sees. And then you have more.',pt:'A gratidão não muda o que tens; muda o olho que vê. E então tens mais.'},inv:{ro:'Mulțumește azi pentru un lucru pe care-l crezi „normal".',en:'Give thanks today for something you call “normal.”',pt:'Agradece hoje por algo a que chamas «normal».'}},
  {el:'heart',kw:{ro:'Iertarea',en:'Forgiveness',pt:'O Perdão'},t:{ro:'Iertarea nu-l dezleagă pe celălalt de ce-a făcut; te dezleagă pe tine de a-l căra.',en:'Forgiveness does not excuse the other; it frees you from carrying them.',pt:'O perdão não desculpa o outro; liberta-te de o carregar.'},inv:{ro:'Pe cine cari de prea mult timp? Lasă-l jos.',en:'Whom have you carried too long? Set them down.',pt:'Quem carregas há tempo demais? Pousa-o.'}},
  {el:'heart',kw:{ro:'Iertarea de sine',en:'Self-Forgiveness',pt:'O Perdão a Si'},t:{ro:'Ai făcut ce-ai știut, cu cât ai avut. Când ai știut mai mult, ai făcut mai bine.',en:'You did what you knew, with what you had. When you knew more, you did better.',pt:'Fizeste o que sabias, com o que tinhas. Quando soubeste mais, fizeste melhor.'},inv:{ro:'Iartă-i omului care ai fost o greșeală veche.',en:'Forgive the person you were one old mistake.',pt:'Perdoa à pessoa que foste um erro antigo.'}},
  {el:'heart',kw:{ro:'Blândețea cu sine',en:'Self-Kindness',pt:'A Doçura Consigo'},t:{ro:'Vorbește-ți cum i-ai vorbi unui copil obosit: ferm, cald și fără dispreț.',en:'Speak to yourself as to a tired child: firmly, warmly, without contempt.',pt:'Fala contigo como com uma criança cansada: com firmeza, calor e sem desprezo.'},inv:{ro:'Ce ți-ai spus azi? Ai spune-o unui prieten?',en:'What did you tell yourself today? Would you say it to a friend?',pt:'O que disseste a ti hoje? Di-lo-ias a um amigo?'}},
  {el:'heart',kw:{ro:'Corpul care știe',en:'The Knowing Body',pt:'O Corpo que Sabe'},t:{ro:'Umerii, stomacul, respirația: corpul vorbește înaintea gândului. Ascultă-l primul.',en:'Shoulders, stomach, breath: the body speaks before the thought. Listen to it first.',pt:'Ombros, estômago, respiração: o corpo fala antes do pensamento. Escuta-o primeiro.'},inv:{ro:'Unde se strânge corpul tău chiar acum? Respiră acolo.',en:'Where does your body tighten right now? Breathe there.',pt:'Onde se aperta o teu corpo agora? Respira aí.'}},
  {el:'heart',kw:{ro:'Ascultarea',en:'Listening',pt:'A Escuta'},t:{ro:'A asculta nu e a aștepta să-ți vină rândul. E a face loc întreg celuilalt.',en:'Listening is not waiting for your turn. It is making full room for the other.',pt:'Escutar não é esperar a tua vez. É abrir espaço inteiro ao outro.'},inv:{ro:'Ascultă azi pe cineva până la capăt, fără să pregătești răspunsul.',en:'Hear someone out today without rehearsing your reply.',pt:'Escuta hoje alguém até ao fim sem ensaiar a resposta.'}},
  {el:'heart',kw:{ro:'Nevoia',en:'The Need',pt:'A Necessidade'},t:{ro:'Sub fiecare emoție stă o nevoie care cere pâine. Hrănește nevoia, nu doar vuietul ei.',en:'Beneath every emotion sits a need asking for bread. Feed the need, not only its roar.',pt:'Sob cada emoção há uma necessidade a pedir pão. Alimenta a necessidade, não só o seu bramido.'},inv:{ro:'Ce nevoie strigă prin emoția ta de azi?',en:'What need cries through today’s emotion?',pt:'Que necessidade grita através da emoção de hoje?'}},
  {el:'heart',kw:{ro:'Cererea',en:'The Asking',pt:'O Pedido'},t:{ro:'A cere nu e slăbiciune; e curajul de a-ți lua nevoia în serios.',en:'Asking is not weakness; it is the courage to take your need seriously.',pt:'Pedir não é fraqueza; é a coragem de levar a sério a tua necessidade.'},inv:{ro:'Cere azi, simplu și direct, un lucru de care ai nevoie.',en:'Ask today, simply and directly, for one thing you need.',pt:'Pede hoje, com simplicidade e franqueza, uma coisa de que precisas.'}},
  {el:'heart',kw:{ro:'Refuzul blând',en:'The Gentle No',pt:'A Recusa Doce'},t:{ro:'Poți refuza cererea fără să refuzi omul. „Nu pot" și „te văd" încap în aceeași frază.',en:'You can refuse the request without refusing the person. “I can’t” and “I see you” fit in one sentence.',pt:'Podes recusar o pedido sem recusar a pessoa. «Não posso» e «vejo-te» cabem na mesma frase.'},inv:{ro:'Spune azi un „nu" cald, fără vinovăție.',en:'Say one warm “no” today, without guilt.',pt:'Diz hoje um «não» caloroso, sem culpa.'}},
  {el:'heart',kw:{ro:'Apropierea',en:'Closeness',pt:'A Proximidade'},t:{ro:'Apropierea se face din o mie de gesturi mici, nu dintr-un singur gest mare.',en:'Closeness is made of a thousand small gestures, not one grand one.',pt:'A proximidade faz-se de mil pequenos gestos, não de um grande.'},inv:{ro:'Fă azi un gest mic pentru un om drag, fără motiv.',en:'Make one small gesture for a dear one today, for no reason.',pt:'Faz hoje um pequeno gesto por alguém querido, sem motivo.'}},
  {el:'heart',kw:{ro:'Singurătatea bună',en:'Good Solitude',pt:'A Boa Solidão'},t:{ro:'E o singurătate care golește și una care umple. A doua se alege; prima se suferă.',en:'There is a loneliness that empties and a solitude that fills. The second is chosen; the first is suffered.',pt:'Há uma solidão que esvazia e uma que enche. A segunda escolhe-se; a primeira sofre-se.'},inv:{ro:'Alege azi o oră doar cu tine, cu bună știință.',en:'Choose one deliberate hour with yourself today.',pt:'Escolhe hoje uma hora deliberada só contigo.'}},
  {el:'heart',kw:{ro:'Invidia-semnal',en:'Envy the Signal',pt:'A Inveja-Sinal'},t:{ro:'Invidia e o hartă întoarsă: îți arată, cu vârful în jos, ce îți dorești cu adevărat.',en:'Envy is an upside-down map: it points, tip down, to what you truly want.',pt:'A inveja é um mapa invertido: aponta, de ponta para baixo, ao que verdadeiramente queres.'},inv:{ro:'Ce îți arată invidia de azi despre dorul tău?',en:'What does today’s envy show about your longing?',pt:'O que mostra a inveja de hoje sobre o teu desejo?'}},
  {el:'heart',kw:{ro:'Comparația',en:'Comparison',pt:'A Comparação'},t:{ro:'Compari interiorul tău cu exteriorul altuia. Nu e o măsurătoare; e o rană.',en:'You compare your inside with another’s outside. That is not measurement; it is a wound.',pt:'Comparas o teu interior com o exterior do outro. Isso não é medida; é ferida.'},inv:{ro:'Măsoară-te azi doar cu tine, cel de ieri.',en:'Measure yourself only against your yesterday.',pt:'Mede-te só com o teu ontem.'}},
  {el:'heart',kw:{ro:'Răbdarea cu sine',en:'Patience with Yourself',pt:'A Paciência Consigo'},t:{ro:'Nu te vindeci la comandă. Inima are anotimpurile ei; nu grăbi primăvara.',en:'You do not heal on command. The heart has its seasons; do not rush the spring.',pt:'Não te curas por ordem. O coração tem as suas estações; não apresses a primavera.'},inv:{ro:'Unde te grăbești cu tine? Mai dă-ți timp.',en:'Where do you rush yourself? Grant more time.',pt:'Onde te apressas contigo? Dá-te mais tempo.'}},
  {el:'heart',kw:{ro:'Copilul dinăuntru',en:'The Inner Child',pt:'A Criança Interior'},t:{ro:'În tine locuiește încă un copil care a vrut doar să fie văzut. Privește-l tu primul.',en:'Within you still lives a child who only wanted to be seen. Be the first to see them.',pt:'Dentro de ti vive ainda uma criança que só quis ser vista. Sê o primeiro a vê-la.'},inv:{ro:'Ce i-ar prinde bine azi copilului care ai fost?',en:'What would do the child you were good today?',pt:'O que faria bem hoje à criança que foste?'}},
  {el:'heart',kw:{ro:'Rana',en:'The Wound',pt:'A Ferida'},t:{ro:'Ce doare arată unde e de lucrat, nu cine ești. Rana e loc, nu nume.',en:'What hurts shows where the work is, not who you are. A wound is a place, not a name.',pt:'O que dói mostra onde está o trabalho, não quem és. A ferida é um lugar, não um nome.'},inv:{ro:'Nu-ți mai spune pe numele rănii tale.',en:'Stop calling yourself by your wound’s name.',pt:'Deixa de te chamar pelo nome da tua ferida.'}},
  {el:'heart',kw:{ro:'Vindecarea',en:'Healing',pt:'A Cura'},t:{ro:'Vindecarea nu șterge urma; o face să nu mai doară la atingere.',en:'Healing does not erase the mark; it makes it stop hurting to the touch.',pt:'A cura não apaga a marca; faz que deixe de doer ao toque.'},inv:{ro:'Ce urmă veche te doare tot mai puțin? Observ-o cu blândețe.',en:'What old mark hurts less and less? Notice it kindly.',pt:'Que marca antiga te dói cada vez menos? Repara nela com doçura.'}},
  {el:'heart',kw:{ro:'Încrederea',en:'Trust',pt:'A Confiança'},t:{ro:'Încrederea se zidește din promisiuni mici, ținute. Începe cu cele față de tine.',en:'Trust is built of small promises kept. Begin with the ones to yourself.',pt:'A confiança faz-se de pequenas promessas cumpridas. Começa pelas que fazes a ti.'},inv:{ro:'Ține azi o promisiune mică făcută ție.',en:'Keep one small promise to yourself today.',pt:'Cumpre hoje uma pequena promessa a ti mesmo.'}},
  {el:'heart',kw:{ro:'Vulnerabilitatea',en:'Vulnerability',pt:'A Vulnerabilidade'},t:{ro:'A te arăta întreg, cu tot cu fisuri, e cea mai tare formă de curaj.',en:'To show yourself whole, cracks and all, is the strongest form of courage.',pt:'Mostrar-te inteiro, com fissuras e tudo, é a forma mais forte de coragem.'},inv:{ro:'Arată azi cuiva o bucată nefardată din tine.',en:'Show someone an unpolished piece of you today.',pt:'Mostra hoje a alguém um pedaço não polido de ti.'}},
  {el:'heart',kw:{ro:'Empatia',en:'Empathy',pt:'A Empatia'},t:{ro:'Fiecare om duce o luptă pe care n-o vezi. Poartă-te ca și cum ai ști asta.',en:'Everyone carries a battle you cannot see. Act as if you knew this.',pt:'Cada pessoa carrega uma batalha que não vês. Age como se o soubesses.'},inv:{ro:'Judecă azi mai puțin un om; întreabă-te ce duce.',en:'Judge someone less today; wonder what they carry.',pt:'Julga menos alguém hoje; imagina o que ele carrega.'}},
  {el:'heart',kw:{ro:'Oglinda celuilalt',en:'The Other’s Mirror',pt:'O Espelho do Outro'},t:{ro:'Ce te scoate din sărite la altul e adesea o veste despre tine. Deschide plicul.',en:'What maddens you in another is often news about you. Open the envelope.',pt:'O que te enfurece no outro é muitas vezes notícia sobre ti. Abre o envelope.'},inv:{ro:'Cine te-a iritat azi? Ce oglindește în tine?',en:'Who irritated you today? What do they mirror in you?',pt:'Quem te irritou hoje? O que espelha em ti?'}},
  {el:'heart',kw:{ro:'Cuvântul cald',en:'The Warm Word',pt:'A Palavra Calorosa'},t:{ro:'Un cuvânt bun spus la timp poate ține un om pe linia de plutire o zi întreagă.',en:'A kind word at the right time can keep a person afloat all day.',pt:'Uma palavra boa na hora certa pode manter alguém à tona o dia inteiro.'},inv:{ro:'Spune azi cuiva, cu voce tare, un lucru bun despre el.',en:'Tell someone one good thing about them today, out loud.',pt:'Diz hoje a alguém, em voz alta, uma coisa boa sobre ele.'}},
  {el:'heart',kw:{ro:'Odihna',en:'Rest',pt:'O Descanso'},t:{ro:'Odihna nu e răsplata de după muncă; e pământul din care crește munca bună.',en:'Rest is not the reward after work; it is the soil good work grows from.',pt:'O descanso não é a recompensa depois do trabalho; é a terra de onde nasce o bom trabalho.'},inv:{ro:'Pune azi odihna în plan, nu la rămășițe.',en:'Schedule rest today; do not leave it the scraps.',pt:'Agenda hoje o descanso; não lhe deixes as sobras.'}},
  {el:'heart',kw:{ro:'Inima deschisă',en:'The Open Heart',pt:'O Coração Aberto'},t:{ro:'Inima închisă nu mai doare, dar nici nu mai cântă. Alege cântecul, cu risc cu tot.',en:'A closed heart no longer aches, but it no longer sings. Choose the song, risk included.',pt:'Um coração fechado já não dói, mas já não canta. Escolhe a canção, com risco e tudo.'},inv:{ro:'Unde te-ai închis de frică? Întredeschide azi ușa.',en:'Where did fear close you? Open the door a crack today.',pt:'Onde o medo te fechou? Abre hoje a porta uma frincha.'}},

  /* ———————— CERCUL PUTERII — puterea lăuntrică divină ———————— */
  {el:'power',kw:{ro:'Scânteia divină',en:'The Divine Spark',pt:'A Faísca Divina'},t:{ro:'În tine arde o scânteie care nu e de la tine — dar e a ta s-o păzești și s-o crești.',en:'In you burns a spark not of your making — yet yours to guard and grow.',pt:'Em ti arde uma faísca que não é tua — mas é tua para guardar e fazer crescer.'},inv:{ro:'Fă azi un lucru vrednic de scânteia din tine.',en:'Do one thing today worthy of the spark within.',pt:'Faz hoje uma coisa digna da faísca que há em ti.'}},
  {el:'power',kw:{ro:'Împărăția dinăuntru',en:'The Kingdom Within',pt:'O Reino Interior'},t:{ro:'Ce cauți pe dinafară locuiește pe dinăuntru. Împărăția începe sub propriile coaste.',en:'What you seek outside dwells inside. The kingdom begins beneath your own ribs.',pt:'O que procuras fora mora dentro. O reino começa debaixo das tuas costelas.'},inv:{ro:'Caută azi înăuntru ce cereai de la lume.',en:'Seek within today what you demanded of the world.',pt:'Procura hoje dentro o que exigias ao mundo.'}},
  {el:'power',kw:{ro:'Chipul',en:'The Image',pt:'A Imagem'},t:{ro:'Porți în tine un chip mai adânc decât oglinda. Trăiește la înălțimea lui.',en:'You carry an image deeper than the mirror. Live up to it.',pt:'Carregas uma imagem mais funda do que o espelho. Vive à sua altura.'},inv:{ro:'Poartă-te azi ca cel care ești de fapt.',en:'Act today as who you truly are.',pt:'Age hoje como quem és de verdade.'}},
  {el:'power',kw:{ro:'Creatorul din tine',en:'The Creator in You',pt:'O Criador em Ti'},t:{ro:'Nu ești doar val purtat de mare; ești și mână care cârmește. Creezi, chiar și când uiți.',en:'You are not only a wave carried by the sea; you are also a steering hand. You create, even when you forget.',pt:'Não és só onda levada pelo mar; és também mão que leme. Crias, mesmo quando esqueces.'},inv:{ro:'Ce creezi azi, cu voie sau fără? Alege cu voie.',en:'What are you creating today, willingly or not? Choose willingly.',pt:'O que crias hoje, de propósito ou não? Escolhe de propósito.'}},
  {el:'power',kw:{ro:'Alegerea',en:'The Choice',pt:'A Escolha'},t:{ro:'Puterea ta stă întreagă într-un singur loc: clipa alegerii. Acolo ești rege.',en:'Your power stands whole in one place: the moment of choice. There, you are sovereign.',pt:'O teu poder está inteiro num só lugar: o momento da escolha. Aí, és soberano.'},inv:{ro:'Fă azi o alegere conștientă, nu din inerție.',en:'Make one conscious choice today, not one of inertia.',pt:'Faz hoje uma escolha consciente, não por inércia.'}},
  {el:'power',kw:{ro:'Rostirea',en:'The Utterance',pt:'A Enunciação'},t:{ro:'Cuvintele tale sunt semințe cu putere. Nu semăna ce nu vrei să culegi.',en:'Your words are seeds with power. Do not sow what you would not reap.',pt:'As tuas palavras são sementes com poder. Não semeies o que não colherias.'},inv:{ro:'Rostește azi doar ce vrei să crească.',en:'Speak today only what you want to grow.',pt:'Diz hoje só o que queres que cresça.'}},
  {el:'power',kw:{ro:'Lumina din tine',en:'The Light in You',pt:'A Luz em Ti'},t:{ro:'Nu ți s-a dat lumina ca s-o ții sub obroc. Cuiva îi e întuneric exact unde tu vezi.',en:'The light was not given you to hide under a basket. Someone is in the dark exactly where you can see.',pt:'A luz não te foi dada para a esconderes debaixo do alqueire. Alguém está no escuro exatamente onde tu vês.'},inv:{ro:'Luminează azi drumul cuiva cu ce știi.',en:'Light someone’s path today with what you know.',pt:'Ilumina hoje o caminho de alguém com o que sabes.'}},
  {el:'power',kw:{ro:'Izvorul',en:'The Spring',pt:'A Nascente'},t:{ro:'Puterea ta nu e un butoi care se golește; e un izvor care curge cât îl lași.',en:'Your power is not a barrel that empties; it is a spring that flows as long as you let it.',pt:'O teu poder não é um barril que se esvazia; é uma nascente que corre enquanto a deixares.'},inv:{ro:'Ce astupă izvorul tău? Dă piatra la o parte.',en:'What blocks your spring? Roll the stone away.',pt:'O que tapa a tua nascente? Rola a pedra para longe.'}},
  {el:'power',kw:{ro:'Muntele dinăuntru',en:'The Inner Mountain',pt:'A Montanha Interior'},t:{ro:'Furtunile trec peste munte; muntele rămâne. În tine e un loc care nu se clatină.',en:'Storms pass over the mountain; the mountain remains. In you there is a place that does not shake.',pt:'As tempestades passam sobre a montanha; a montanha permanece. Em ti há um lugar que não estremece.'},inv:{ro:'Coboară azi o clipă în locul tău neclintit.',en:'Descend for a moment into your unshaken place.',pt:'Desce um momento ao teu lugar inabalável.'}},
  {el:'power',kw:{ro:'Învierea dimineții',en:'The Morning Rising',pt:'A Ressurreição da Manhã'},t:{ro:'Fiecare dimineață ți se dă o viață mică, întreagă. Ieri a murit aseară.',en:'Each morning you are given a small, whole life. Yesterday died last night.',pt:'Cada manhã recebes uma vida pequena e inteira. Ontem morreu esta noite.'},inv:{ro:'Începe azi ca și cum abia te-ai născut priceput.',en:'Begin today as if newly born, yet wise.',pt:'Começa hoje como recém-nascido, mas sábio.'}},
  {el:'power',kw:{ro:'Aripile',en:'The Wings',pt:'As Asas'},t:{ro:'Nu-ți cere nimeni să zbori fără aripi; doar să nu le mai ții strânse de frică.',en:'No one asks you to fly without wings; only to stop folding them out of fear.',pt:'Ninguém te pede que voes sem asas; só que deixes de as dobrar por medo.'},inv:{ro:'Întinde azi aripile un deget mai mult.',en:'Stretch your wings one finger further today.',pt:'Estende hoje as asas um dedo mais.'}},
  {el:'power',kw:{ro:'Coroana',en:'The Crown',pt:'A Coroa'},t:{ro:'Demnitatea nu ți-o dă lumea și nu ți-o poate lua. E coroana pe care o porți pe dinăuntru.',en:'Dignity is not given by the world, nor can it be taken. It is the crown worn on the inside.',pt:'A dignidade não a dá o mundo nem a pode tirar. É a coroa que se usa por dentro.'},inv:{ro:'Stai azi drept, orice s-ar întâmpla. Porți coroană.',en:'Stand tall today, whatever comes. You wear a crown.',pt:'Fica hoje de cabeça erguida, venha o que vier. Usas coroa.'}},
  {el:'power',kw:{ro:'Focul sacru',en:'The Sacred Fire',pt:'O Fogo Sagrado'},t:{ro:'Entuziasmul e foc sfânt: zeul mic dinăuntru care spune „da" vieții. Hrănește-l.',en:'Enthusiasm is holy fire: the small god within that says yes to life. Feed it.',pt:'O entusiasmo é fogo sagrado: o pequeno deus interior que diz sim à vida. Alimenta-o.'},inv:{ro:'Fă azi lucrul care îți aprinde „da"-ul.',en:'Do the thing that kindles your yes today.',pt:'Faz hoje aquilo que acende o teu sim.'}},
  {el:'power',kw:{ro:'Nemărginirea',en:'The Boundless',pt:'O Ilimitado'},t:{ro:'Marginile tale de azi sunt amintiri, nu ziduri. Cele mai multe se mută când pășești.',en:'Today’s limits are memories, not walls. Most of them move when you step.',pt:'Os limites de hoje são memórias, não muros. A maioria move-se quando dás um passo.'},inv:{ro:'Pășește azi un pas dincolo de „nu pot".',en:'Step once past “I can’t” today.',pt:'Dá hoje um passo para lá do «não consigo».'}},
  {el:'power',kw:{ro:'Amintirea',en:'The Remembering',pt:'A Lembrança'},t:{ro:'Nu înveți să fii puternic; îți amintești că ești. Uitarea a fost singura slăbiciune.',en:'You do not learn to be strong; you remember you are. Forgetting was the only weakness.',pt:'Não aprendes a ser forte; lembras-te de que és. O esquecimento foi a única fraqueza.'},inv:{ro:'Amintește-ți o clipă în care ai fost mai mult decât credeai.',en:'Recall a moment you were more than you believed.',pt:'Recorda um momento em que foste mais do que acreditavas.'}},
  {el:'power',kw:{ro:'Trezirea',en:'The Awakening',pt:'O Despertar'},t:{ro:'A te trezi nu e o dată în viață; e în fiecare clipă în care alegi să fii de față.',en:'Awakening is not once in a lifetime; it is every moment you choose to be present.',pt:'Despertar não é uma vez na vida; é cada instante em que escolhes estar presente.'},inv:{ro:'Trezește-te azi de trei ori: dimineața, la prânz, seara.',en:'Wake three times today: morning, noon, evening.',pt:'Desperta três vezes hoje: de manhã, ao meio-dia, à noite.'}},
  {el:'power',kw:{ro:'Visul care visează',en:'The Dream that Dreams',pt:'O Sonho que Sonha'},t:{ro:'Nu doar tu porți visul; și visul te poartă pe tine. Lasă-te dus unde vrea să crească.',en:'You do not only carry the dream; the dream carries you. Let it take you where it wants to grow.',pt:'Não és só tu que levas o sonho; o sonho leva-te a ti. Deixa-te levar para onde ele quer crescer.'},inv:{ro:'Ce vis nu-ți dă pace? Fă-i azi un pas.',en:'What dream will not leave you alone? Give it one step today.',pt:'Que sonho não te deixa em paz? Dá-lhe hoje um passo.'}},
  {el:'power',kw:{ro:'Puterea blândă',en:'The Gentle Power',pt:'O Poder Suave'},t:{ro:'Puterea adevărată nu strigă. Ca soarele, își face lucrarea fără să se certe cu norii.',en:'True power does not shout. Like the sun, it does its work without quarreling with clouds.',pt:'O verdadeiro poder não grita. Como o sol, faz a sua obra sem discutir com as nuvens.'},inv:{ro:'Fii azi puternic în liniște, nu în gălăgie.',en:'Be strong in silence today, not in noise.',pt:'Sê forte hoje em silêncio, não em barulho.'}},
  {el:'power',kw:{ro:'Stăpânul casei',en:'Master of the House',pt:'O Dono da Casa'},t:{ro:'Gândurile sunt oaspeți; unii mint, unii fură. Tu ești stăpânul care alege cine rămâne.',en:'Thoughts are guests; some lie, some steal. You are the master who chooses who stays.',pt:'Os pensamentos são hóspedes; uns mentem, outros roubam. Tu és o dono que escolhe quem fica.'},inv:{ro:'Cine ți-a intrat azi în casă nepoftit? Condu-l la ușă.',en:'Who entered uninvited today? Walk them to the door.',pt:'Quem entrou sem convite hoje? Acompanha-o à porta.'}},
  {el:'power',kw:{ro:'Cheia porții',en:'The Gate Key',pt:'A Chave do Portão'},t:{ro:'Nimeni nu-ți poate deschide dinăuntru în locul tău. Dar nici încuia nu-ți poate.',en:'No one can open you from within on your behalf. But neither can they lock you.',pt:'Ninguém te pode abrir por dentro em teu lugar. Mas também não te pode trancar.'},inv:{ro:'Ce ușă lăuntrică ții încuiată din obișnuință?',en:'What inner door do you keep locked from habit?',pt:'Que porta interior manténs trancada por hábito?'}},
  {el:'power',kw:{ro:'Moștenirea',en:'The Inheritance',pt:'A Herança'},t:{ro:'Ești moștenitorul tuturor celor care nu s-au dat bătuți înaintea ta. Averea e în sânge.',en:'You are heir to all who did not give up before you. The fortune runs in the blood.',pt:'És herdeiro de todos os que não desistiram antes de ti. A fortuna corre no sangue.'},inv:{ro:'Fă azi cinste unui înaintaș care a răzbit.',en:'Honor one forebear today who endured.',pt:'Honra hoje um antepassado que resistiu.'}},
  {el:'power',kw:{ro:'Semințele de lumină',en:'Seeds of Light',pt:'As Sementes de Luz'},t:{ro:'Fiecare gest bun e o sămânță de lumină pusă în pământul lumii. Nu toate răsar azi. Toate răsar.',en:'Every good deed is a seed of light set in the world’s soil. Not all sprout today. All sprout.',pt:'Cada boa ação é uma semente de luz posta na terra do mundo. Nem todas brotam hoje. Todas brotam.'},inv:{ro:'Seamănă azi o lumină pe care n-o vei vedea răsărind.',en:'Sow one light today you will not see rise.',pt:'Semeia hoje uma luz que não verás nascer.'}},
  {el:'power',kw:{ro:'Rugăciunea faptei',en:'The Prayer of Deeds',pt:'A Oração dos Atos'},t:{ro:'Sunt rugăciuni spuse cu buzele și rugăciuni spuse cu mâinile. A doua se aude mai departe.',en:'Some prayers are said with lips, some with hands. The second carries farther.',pt:'Há orações ditas com os lábios e orações ditas com as mãos. As segundas vão mais longe.'},inv:{ro:'Roagă-te azi printr-o faptă bună tăcută.',en:'Pray today through one silent good deed.',pt:'Reza hoje através de uma boa ação silenciosa.'}},
  {el:'power',kw:{ro:'Minunea măruntă',en:'The Small Miracle',pt:'O Pequeno Milagre'},t:{ro:'Aștepți minunea mare și calci zilnic pe cele mici: răsăritul, pâinea, omul de lângă tine.',en:'You await the great miracle and daily step over the small ones: sunrise, bread, the person beside you.',pt:'Esperas o grande milagre e todos os dias passas por cima dos pequenos: o nascer do sol, o pão, a pessoa ao teu lado.'},inv:{ro:'Numără azi trei minuni pe lângă care treceai.',en:'Count three miracles you used to pass by.',pt:'Conta três milagres por que costumavas passar.'}},
  {el:'power',kw:{ro:'Îndrăzneala',en:'The Daring',pt:'A Ousadia'},t:{ro:'Cerul nu se supără pe cei care îndrăznesc. Se întristează pentru cei care nu-și încearcă aripile.',en:'Heaven is not angry with those who dare. It grieves for those who never try their wings.',pt:'O Céu não se zanga com quem ousa. Entristece-se por quem nunca experimenta as asas.'},inv:{ro:'Îndrăznește azi lucrul amânat de o lună.',en:'Dare today the thing postponed for a month.',pt:'Ousa hoje aquilo que adias há um mês.'}},
  {el:'power',kw:{ro:'Verticala',en:'The Vertical',pt:'A Vertical'},t:{ro:'Omul e singura făptură care leagă pământul de cer stând drept. Ține linia.',en:'The human being alone joins earth to heaven by standing upright. Hold the line.',pt:'Só o ser humano une a terra ao céu ficando de pé. Mantém a linha.'},inv:{ro:'Îndreaptă-ți spatele și gândul deodată.',en:'Straighten your back and your thought at once.',pt:'Endireita ao mesmo tempo as costas e o pensamento.'}},
  {el:'power',kw:{ro:'Rădăcina cerească',en:'The Heavenly Root',pt:'A Raiz Celeste'},t:{ro:'Copacul crește din pământ; omul crește și din cer. Nu-ți tăia rădăcina de sus.',en:'A tree grows from the earth; a person grows also from heaven. Do not cut your upper root.',pt:'A árvore cresce da terra; a pessoa cresce também do céu. Não cortes a tua raiz de cima.'},inv:{ro:'Hrănește azi rădăcina de sus: o clipă de rugă sau tăcere.',en:'Feed the upper root today: a moment of prayer or silence.',pt:'Alimenta hoje a raiz de cima: um momento de oração ou silêncio.'}},
  {el:'power',kw:{ro:'Numele adevărat',en:'The True Name',pt:'O Nome Verdadeiro'},t:{ro:'Nu ești poreclele pe care ți le-a pus frica: „slab", „târziu", „prea puțin". Ai un nume mai vechi.',en:'You are not the nicknames fear gave you: “weak,” “late,” “not enough.” You bear an older name.',pt:'Não és as alcunhas que o medo te deu: «fraco», «tarde», «pouco». Tens um nome mais antigo.'},inv:{ro:'Ce poreclă a fricii lepezi azi?',en:'Which of fear’s nicknames do you shed today?',pt:'Que alcunha do medo largas hoje?'}},
  {el:'power',kw:{ro:'Templul',en:'The Temple',pt:'O Templo'},t:{ro:'Unde stai tu e loc sfânt, dacă tu îl sfințești cu felul în care trăiești în el.',en:'Where you stand is holy ground, if you hallow it by how you live there.',pt:'Onde estás é chão sagrado, se o santificares pelo modo como ali vives.'},inv:{ro:'Fă azi din locul tău de muncă un loc curat.',en:'Make your workplace clean ground today.',pt:'Faz hoje do teu local de trabalho um chão limpo.'}},
  {el:'power',kw:{ro:'Slujirea',en:'The Serving',pt:'O Servir'},t:{ro:'Puterea care se slujește doar pe sine se stinge. Cea care slujește crește slujind.',en:'Power that serves only itself burns out. Power that serves grows by serving.',pt:'O poder que só se serve a si esgota-se. O poder que serve cresce servindo.'},inv:{ro:'Pune azi puterea ta la lucru pentru altcineva.',en:'Put your strength to work for someone else today.',pt:'Põe hoje a tua força ao serviço de outro.'}},
  {el:'power',kw:{ro:'Pacea armelor',en:'The Peace of Arms',pt:'A Paz das Armas'},t:{ro:'Cea mai grea biruință e cea în care nu mai ai nevoie de dușman.',en:'The hardest victory is the one where you no longer need an enemy.',pt:'A vitória mais difícil é aquela em que já não precisas de inimigo.'},inv:{ro:'Cu cine te mai războiești în gând? Încheie azi pacea.',en:'Whom do you still fight in your mind? Make peace today.',pt:'Com quem ainda lutas na tua mente? Faz hoje as pazes.'}},
  {el:'power',kw:{ro:'Întregul',en:'The Whole',pt:'O Todo'},t:{ro:'Nu ești o bucată ruptă din ceva; ești un întreg mic în care se oglindește întregul mare.',en:'You are not a torn-off piece; you are a small whole mirroring the great one.',pt:'Não és um pedaço arrancado; és um pequeno todo que espelha o grande.'},inv:{ro:'Trăiește azi ca un întreg, nu ca o lipsă.',en:'Live today as a whole, not as a lack.',pt:'Vive hoje como um todo, não como uma falta.'}},
  {el:'power',kw:{ro:'Binecuvântarea',en:'The Blessing',pt:'A Bênção'},t:{ro:'A binecuvânta înseamnă a vedea binele înainte să se arate — și a-l chema pe nume.',en:'To bless is to see the good before it appears — and to call it by name.',pt:'Abençoar é ver o bem antes de aparecer — e chamá-lo pelo nome.'},inv:{ro:'Binecuvântează azi în gând trei oameni, în taină.',en:'Silently bless three people today.',pt:'Abençoa hoje três pessoas em silêncio.'}},

  /* ———————— CERCUL MINȚII — puterea gândului ———————— */
  {el:'mind',kw:{ro:'Gândul-sămânță',en:'The Seed-Thought',pt:'O Pensamento-Semente'},t:{ro:'Un gând ținut în minte e o sămânță pusă în pământ. Alege ce semeni, căci va răsări.',en:'A thought held in mind is a seed set in soil. Choose your sowing, for it will sprout.',pt:'Um pensamento guardado na mente é uma semente posta na terra. Escolhe o que semeias, pois brotará.'},inv:{ro:'Ce gând ai udat azi fără să vrei?',en:'What thought did you water today without meaning to?',pt:'Que pensamento regaste hoje sem querer?'}},
  {el:'mind',kw:{ro:'Grădinarul',en:'The Gardener',pt:'O Jardineiro'},t:{ro:'Nu poți opri păsările gândului să zboare; poți să nu le lași să-și facă cuib.',en:'You cannot stop the birds of thought from flying; you can keep them from nesting.',pt:'Não podes impedir os pássaros do pensamento de voar; podes impedi-los de fazer ninho.'},inv:{ro:'Ce gând negru a dat azi să-și facă cuib? Alungă-l blând.',en:'Which dark thought tried to nest today? Shoo it gently.',pt:'Que pensamento sombrio quis fazer ninho hoje? Enxota-o com doçura.'}},
  {el:'mind',kw:{ro:'Atenția-apă',en:'Attention the Water',pt:'A Atenção-Água'},t:{ro:'Unde curge atenția, acolo crește viața. Grădina ta e ce privești zilnic.',en:'Where attention flows, life grows. Your garden is what you behold daily.',pt:'Onde a atenção corre, a vida cresce. O teu jardim é aquilo que contemplas todos os dias.'},inv:{ro:'Spre ce ți-a curs azi atenția? Mută albia.',en:'Where did your attention flow today? Move the riverbed.',pt:'Para onde correu a tua atenção hoje? Muda o leito.'}},
  {el:'mind',kw:{ro:'Imaginația',en:'Imagination',pt:'A Imaginação'},t:{ro:'Tot ce a zidit omul a fost întâi o vedenie. Imaginația e mâna dreaptă a viitorului.',en:'All that humanity built was first a vision. Imagination is the future’s right hand.',pt:'Tudo o que a humanidade construiu foi primeiro uma visão. A imaginação é a mão direita do futuro.'},inv:{ro:'Închide ochii și vezi limpede ziua ta bună. Apoi f-o.',en:'Close your eyes and see your good day clearly. Then make it.',pt:'Fecha os olhos e vê com clareza o teu bom dia. Depois fá-lo.'}},
  {el:'mind',kw:{ro:'Intenția',en:'The Intention',pt:'A Intenção'},t:{ro:'Ziua fără intenție e o barcă fără cârmă: plutește, dar nu călătorește.',en:'A day without intention is a boat without a rudder: it floats but does not travel.',pt:'Um dia sem intenção é um barco sem leme: flutua mas não viaja.'},inv:{ro:'Pune-i zilei de azi o singură intenție clară.',en:'Give today one clear intention.',pt:'Dá a hoje uma intenção clara.'}},
  {el:'mind',kw:{ro:'Veghea',en:'The Watch',pt:'A Vigília'},t:{ro:'Stai în poarta minții ca un paznic bun: întreabă fiecare gând ce caută.',en:'Stand at the mind’s gate like a good watchman: ask every thought its business.',pt:'Fica ao portão da mente como um bom guarda: pergunta a cada pensamento ao que vem.'},inv:{ro:'Prinde azi un gând chiar când intră. Doar privește-l.',en:'Catch one thought at the gate today. Just watch it.',pt:'Apanha hoje um pensamento ao portão. Só observa-o.'}},
  {el:'mind',kw:{ro:'Repetarea',en:'Repetition',pt:'A Repetição'},t:{ro:'Gândul repetat devine cărare; cărarea, drum; drumul, soartă. Bate cărări bune.',en:'A repeated thought becomes a trail; the trail a road; the road a fate. Tread good trails.',pt:'Um pensamento repetido torna-se trilho; o trilho, estrada; a estrada, destino. Pisa bons trilhos.'},inv:{ro:'Ce îți spui cel mai des? Ascultă-te o zi.',en:'What do you tell yourself most often? Listen for a day.',pt:'O que dizes a ti mais vezes? Escuta-te por um dia.'}},
  {el:'mind',kw:{ro:'Vorbirea de sine',en:'Self-Talk',pt:'A Fala Consigo'},t:{ro:'Nimeni nu-ți vorbește mai mult decât tine însuți. Fă din vocea aceea un prieten.',en:'No one speaks to you more than you do. Make that voice a friend.',pt:'Ninguém fala contigo mais do que tu. Faz dessa voz uma amiga.'},inv:{ro:'Schimbă azi un „nu pot" în „încă nu pot".',en:'Turn one “I can’t” into “I can’t yet” today.',pt:'Transforma hoje um «não consigo» em «ainda não consigo».'}},
  {el:'mind',kw:{ro:'Îndoiala',en:'Doubt',pt:'A Dúvida'},t:{ro:'Îndoiala e vamă bună la intrare și otravă la masă. Verifică, apoi hotărăște-te.',en:'Doubt is a good customs post, a poison at the table. Verify, then decide.',pt:'A dúvida é boa alfândega e veneno à mesa. Verifica, depois decide.'},inv:{ro:'Unde te tot îndoiești în loc să hotărăști?',en:'Where do you keep doubting instead of deciding?',pt:'Onde continuas a duvidar em vez de decidir?'}},
  {el:'mind',kw:{ro:'Credința minții',en:'The Mind’s Faith',pt:'A Fé da Mente'},t:{ro:'Mintea care crede că se poate găsește o cale; cea care nu crede găsește o scuză.',en:'The mind that believes it can finds a way; the one that doesn’t finds an excuse.',pt:'A mente que crê que consegue encontra um caminho; a que não crê encontra uma desculpa.'},inv:{ro:'Poartă azi gândul „se poate" ca pe o cheie.',en:'Carry “it can be done” like a key today.',pt:'Leva hoje o «é possível» como uma chave.'}},
  {el:'mind',kw:{ro:'Limpezimea',en:'Clarity',pt:'A Clareza'},t:{ro:'Apa se limpezește stând, nu agitând-o. La fel mintea.',en:'Water clears by settling, not by stirring. So does the mind.',pt:'A água clareia assentando, não agitando. Assim a mente.'},inv:{ro:'Înainte de hotărâre, dă-ți cinci minute de liniște.',en:'Before the decision, take five minutes of stillness.',pt:'Antes da decisão, tira cinco minutos de quietude.'}},
  {el:'mind',kw:{ro:'Fereastra',en:'The Window',pt:'A Janela'},t:{ro:'Nu vezi lumea; vezi lumea prin geamul tău. Șterge geamul înainte să judeci priveliștea.',en:'You do not see the world; you see it through your window. Clean the glass before judging the view.',pt:'Não vês o mundo; vê-lo pela tua janela. Limpa o vidro antes de julgares a vista.'},inv:{ro:'Ce presupunere îți murdărește azi geamul?',en:'What assumption smudges your glass today?',pt:'Que suposição suja hoje o teu vidro?'}},
  {el:'mind',kw:{ro:'Norul',en:'The Cloud',pt:'A Nuvem'},t:{ro:'Gândul greu pare cer întreg, dar e doar nor. În spatele lui, seninul n-a plecat nicăieri.',en:'A heavy thought seems the whole sky, but it is only a cloud. Behind it, the blue has not left.',pt:'Um pensamento pesado parece o céu inteiro, mas é só uma nuvem. Por trás dela, o azul não partiu.'},inv:{ro:'Numește norul de azi și amintește-ți cerul.',en:'Name today’s cloud and remember the sky.',pt:'Nomeia a nuvem de hoje e lembra-te do céu.'}},
  {el:'mind',kw:{ro:'Întrebarea bună',en:'The Good Question',pt:'A Boa Pergunta'},t:{ro:'O întrebare bună deschide mai multe uși decât o sută de răspunsuri grăbite.',en:'One good question opens more doors than a hundred hasty answers.',pt:'Uma boa pergunta abre mais portas do que cem respostas apressadas.'},inv:{ro:'Schimbă azi „de ce mie?" în „ce pot face cu asta?".',en:'Trade “why me?” for “what can I do with this?” today.',pt:'Troca hoje o «porquê eu?» pelo «o que posso fazer com isto?».'}},
  {el:'mind',kw:{ro:'Povestea',en:'The Story',pt:'A História'},t:{ro:'Între fapt și durere stă povestea pe care ți-o spui. Faptul e dat; povestea e a ta.',en:'Between the fact and the pain stands the story you tell. The fact is given; the story is yours.',pt:'Entre o facto e a dor está a história que contas. O facto é dado; a história é tua.'},inv:{ro:'Ce poveste îți spui despre necazul de azi? Mai spune una.',en:'What story do you tell about today’s trouble? Tell another.',pt:'Que história contas sobre o problema de hoje? Conta outra.'}},
  {el:'mind',kw:{ro:'Rescrierea',en:'The Rewriting',pt:'A Reescrita'},t:{ro:'Trecutul nu se schimbă, dar înțelesul lui e mereu în lucru. Tu ții condeiul.',en:'The past does not change, but its meaning is forever in the making. You hold the pen.',pt:'O passado não muda, mas o seu sentido está sempre a fazer-se. A caneta é tua.'},inv:{ro:'Găsește azi un dar ascuns într-o veche înfrângere.',en:'Find a hidden gift in an old defeat today.',pt:'Encontra hoje um dom escondido numa derrota antiga.'}},
  {el:'mind',kw:{ro:'Judecata',en:'Judgment',pt:'O Julgamento'},t:{ro:'Judecata pripită e o foarfecă: taie puntea înainte s-o treci.',en:'Hasty judgment is a pair of scissors: it cuts the bridge before you cross.',pt:'O julgamento apressado é uma tesoura: corta a ponte antes de a atravessares.'},inv:{ro:'Amână azi o judecată cu o singură zi.',en:'Postpone one judgment by a single day.',pt:'Adia um julgamento por um único dia.'}},
  {el:'mind',kw:{ro:'Prezumția bună',en:'The Kind Assumption',pt:'A Boa Suposição'},t:{ro:'Când nu știi de ce a făcut-o, alege explicația care te lasă bun și pe tine, și pe el.',en:'When you don’t know why they did it, choose the explanation that keeps you both good.',pt:'Quando não sabes porque o fez, escolhe a explicação que vos mantém bons aos dois.'},inv:{ro:'Dă azi cuiva o explicație mai blândă decât prima.',en:'Grant someone a kinder explanation than your first.',pt:'Concede a alguém uma explicação mais bondosa do que a primeira.'}},
  {el:'mind',kw:{ro:'Mintea începătorului',en:'Beginner’s Mind',pt:'A Mente do Principiante'},t:{ro:'Cel care știe deja nu mai încape nimic nou. Golește-ți paharul din când în când.',en:'The one who already knows has no room for the new. Empty your cup now and then.',pt:'Quem já sabe não tem lugar para o novo. Esvazia a tua taça de vez em quando.'},inv:{ro:'Privește azi un lucru știut ca și cum l-ai vedea întâi.',en:'Look at something familiar as if for the first time.',pt:'Olha para algo conhecido como se fosse a primeira vez.'}},
  {el:'mind',kw:{ro:'Uitarea bună',en:'Good Forgetting',pt:'O Bom Esquecimento'},t:{ro:'Sunt lucruri care se țin minte și lucruri care se țin rană. Pe cele din urmă, lasă-le uitării.',en:'Some things are kept as memory, some as wound. Leave the latter to forgetting.',pt:'Umas coisas guardam-se como memória, outras como ferida. Deixa estas ao esquecimento.'},inv:{ro:'Ce jignire veche mai reciți? N-o mai învăța pe de rost.',en:'What old insult do you still recite? Stop memorizing it.',pt:'Que ofensa antiga ainda recitas? Deixa de a decorar.'}},
  {el:'mind',kw:{ro:'Amintirea aleasă',en:'The Chosen Memory',pt:'A Memória Escolhida'},t:{ro:'Memoria e un muzeu: tu alegi ce expui în sala mare și ce cobori în arhivă.',en:'Memory is a museum: you choose what hangs in the great hall and what goes to the archive.',pt:'A memória é um museu: escolhes o que fica na sala grande e o que vai para o arquivo.'},inv:{ro:'Expune azi în minte o amintire care te întărește.',en:'Hang one strengthening memory in the great hall today.',pt:'Pendura hoje na sala grande uma memória que te fortalece.'}},
  {el:'mind',kw:{ro:'Concentrarea',en:'Focus',pt:'A Concentração'},t:{ro:'Soarele împrăștiat încălzește; adunat în lentilă, aprinde. Adună-ți razele.',en:'Scattered sunlight warms; gathered in a lens, it ignites. Gather your rays.',pt:'A luz espalhada aquece; reunida numa lente, incendeia. Reúne os teus raios.'},inv:{ro:'Un singur lucru, o oră, fără nimic altceva.',en:'One thing, one hour, nothing else.',pt:'Uma coisa, uma hora, nada mais.'}},
  {el:'mind',kw:{ro:'Risipirea',en:'The Scattering',pt:'A Dispersão'},t:{ro:'Cine e peste tot nu e nicăieri. Fărâmele de atenție nu se mai fac pâine.',en:'Whoever is everywhere is nowhere. Crumbs of attention never become bread again.',pt:'Quem está em todo o lado não está em lado nenhum. Migalhas de atenção nunca voltam a ser pão.'},inv:{ro:'Închide azi trei uși care te tot cheamă.',en:'Close three calling doors today.',pt:'Fecha hoje três portas que te chamam.'}},
  {el:'mind',kw:{ro:'Tăcerea minții',en:'The Mind’s Silence',pt:'O Silêncio da Mente'},t:{ro:'Și mintea are nevoie de somnul ei de veghe: clipe fără nicio treabă de gândit.',en:'The mind too needs its waking sleep: moments with nothing to think about.',pt:'Também a mente precisa do seu sono desperto: momentos sem nada em que pensar.'},inv:{ro:'Dă-i minții cinci minute fără nicio sarcină.',en:'Give the mind five minutes with no task.',pt:'Dá à mente cinco minutos sem tarefa.'}},
  {el:'mind',kw:{ro:'Visarea cu rost',en:'Purposeful Dreaming',pt:'O Sonhar com Propósito'},t:{ro:'Visarea fără faptă e abur; fapta fără visare e osteneală oarbă. Împreună sunt drum.',en:'Dreaming without deed is vapor; deed without dreaming is blind toil. Together they are a road.',pt:'Sonhar sem obra é vapor; obra sem sonho é labuta cega. Juntos são um caminho.'},inv:{ro:'Visează azi zece minute, apoi fă primul pas mic.',en:'Dream ten minutes today, then take the first small step.',pt:'Sonha dez minutos hoje, depois dá o primeiro pequeno passo.'}},
  {el:'mind',kw:{ro:'Planul',en:'The Plan',pt:'O Plano'},t:{ro:'Planul nu ghicește viitorul; îți dă doar unde să pui piciorul când vine altul.',en:'A plan does not foretell the future; it only gives your foot a place when another future comes.',pt:'Um plano não adivinha o futuro; só dá ao teu pé um lugar quando vem outro futuro.'},inv:{ro:'Fă-ți un plan simplu și ține-l cu mână moale.',en:'Make a simple plan and hold it with a soft hand.',pt:'Faz um plano simples e segura-o com mão leve.'}},
  {el:'mind',kw:{ro:'Măsura',en:'The Measure',pt:'A Medida'},t:{ro:'Nu tot ce se numără contează și nu tot ce contează se numără. Vezi cu ce cântar trăiești.',en:'Not all that counts is counted, and not all that is counted counts. Mind the scale you live by.',pt:'Nem tudo o que conta se conta, e nem tudo o que se conta conta. Atenção à balança por que vives.'},inv:{ro:'Ce măsori zilnic? Măsoară azi și binele făcut.',en:'What do you measure daily? Measure the good done, too.',pt:'O que medes todos os dias? Mede também o bem feito.'}},
  {el:'mind',kw:{ro:'Discernământul',en:'Discernment',pt:'O Discernimento'},t:{ro:'Nu orice glas dinăuntru e al tău; unele sunt doar frici bătrâne cu voce groasă.',en:'Not every inner voice is yours; some are just old fears with deep voices.',pt:'Nem toda a voz interior é tua; algumas são só medos antigos de voz grossa.'},inv:{ro:'Ce voce te sfătuiește azi? A ta sau a fricii?',en:'Which voice counsels you today? Yours or fear’s?',pt:'Que voz te aconselha hoje? A tua ou a do medo?'}},
  {el:'mind',kw:{ro:'Mirarea',en:'Wonder',pt:'O Espanto'},t:{ro:'Mirarea e mintea care a rămas tânără. Cine nu se mai miră a îmbătrânit pe dinăuntru.',en:'Wonder is the mind that stayed young. Who no longer wonders has aged within.',pt:'O espanto é a mente que ficou jovem. Quem já não se espanta envelheceu por dentro.'},inv:{ro:'Miră-te azi de un lucru „obișnuit".',en:'Wonder at one “ordinary” thing today.',pt:'Espanta-te hoje com uma coisa «vulgar».'}},
  {el:'mind',kw:{ro:'Învățarea',en:'Learning',pt:'A Aprendizagem'},t:{ro:'Fiecare om îți e dascăl la ceva. Ziua în care n-ai învățat nimic n-a fost întreagă.',en:'Every person can teach you something. A day without learning was not whole.',pt:'Cada pessoa te pode ensinar algo. Um dia sem aprender não foi inteiro.'},inv:{ro:'Învață azi ceva de la un om neașteptat.',en:'Learn something today from an unexpected teacher.',pt:'Aprende hoje algo com um mestre inesperado.'}},
  {el:'mind',kw:{ro:'Gândul-punte',en:'The Bridge-Thought',pt:'O Pensamento-Ponte'},t:{ro:'Nu poți sări din groapă în vârf de munte; poți gândi întâi un gând puțin mai bun.',en:'You cannot leap from the pit to the peak; you can first think one slightly better thought.',pt:'Não podes saltar do fosso ao cume; podes primeiro pensar um pensamento um pouco melhor.'},inv:{ro:'Urcă azi un singur gând mai sus.',en:'Climb one thought higher today.',pt:'Sobe hoje um pensamento mais alto.'}},
  {el:'mind',kw:{ro:'Ordinea dinăuntru',en:'The Inner Order',pt:'A Ordem Interior'},t:{ro:'Rânduiește-ți întâi mintea, apoi masa de lucru. A doua ține cât prima.',en:'Order your mind first, then your desk. The second lasts as long as the first.',pt:'Arruma primeiro a mente, depois a secretária. A segunda dura o que durar a primeira.'},inv:{ro:'Fă azi curat într-un colț de gând.',en:'Tidy one corner of thought today.',pt:'Arruma hoje um canto do pensamento.'}},
  {el:'mind',kw:{ro:'Mintea-lună',en:'The Moon-Mind',pt:'A Mente-Lua'},t:{ro:'Mintea nu are lumina ei; strălucește cu ce-i dai s-o oglindească. Dă-i lucruri de soare.',en:'The mind has no light of its own; it shines with what you give it to mirror. Feed it sunlit things.',pt:'A mente não tem luz própria; brilha com o que lhe dás a espelhar. Alimenta-a de coisas cheias de sol.'},inv:{ro:'Ce citește, ascultă și privește azi mintea ta?',en:'What does your mind read, hear and watch today?',pt:'O que lê, ouve e vê hoje a tua mente?'}},

  /* ———————— CERCUL DRUMULUI — viața de zi cu zi ———————— */
  {el:'path',kw:{ro:'Începutul mic',en:'The Small Beginning',pt:'O Pequeno Começo'},t:{ro:'Drumul de o mie de zile începe cu un pas atât de mic încât nu-l poți rata.',en:'The thousand-day road begins with a step so small you cannot miss it.',pt:'A estrada de mil dias começa com um passo tão pequeno que não o podes falhar.'},inv:{ro:'Fă azi versiunea de două minute a marelui plan.',en:'Do the two-minute version of the great plan today.',pt:'Faz hoje a versão de dois minutos do grande plano.'}},
  {el:'path',kw:{ro:'Pragul',en:'The Threshold',pt:'O Limiar'},t:{ro:'Cel mai greu pas e cel din prag. După el, drumul te duce el pe tine.',en:'The hardest step is the one across the threshold. After it, the road carries you.',pt:'O passo mais difícil é o do limiar. Depois dele, a estrada leva-te.'},inv:{ro:'Treci azi pragul lucrului amânat.',en:'Cross the threshold of the postponed thing today.',pt:'Atravessa hoje o limiar da coisa adiada.'}},
  {el:'path',kw:{ro:'Pasul',en:'The Step',pt:'O Passo'},t:{ro:'Nu trebuie să vezi tot drumul; ajunge să vezi următorul pas. Restul se arată mergând.',en:'You need not see the whole road; the next step is enough. The rest reveals itself in walking.',pt:'Não precisas de ver a estrada inteira; o próximo passo basta. O resto revela-se caminhando.'},inv:{ro:'Care e următorul pas? Doar pe el fă-l.',en:'What is the next step? Take only that one.',pt:'Qual é o próximo passo? Dá só esse.'}},
  {el:'path',kw:{ro:'Ritmul',en:'The Rhythm',pt:'O Ritmo'},t:{ro:'Nu cel iute ajunge departe, ci cel care nu se oprește. Găsește-ți pasul de drum lung.',en:'Not the swift go far, but those who do not stop. Find your long-road pace.',pt:'Não são os velozes que vão longe, mas os que não param. Encontra o teu passo de longa estrada.'},inv:{ro:'Încetinește azi cât să poți merge mâine.',en:'Slow down today enough to walk tomorrow.',pt:'Abranda hoje o suficiente para caminhares amanhã.'}},
  {el:'path',kw:{ro:'Obiceiul',en:'The Habit',pt:'O Hábito'},t:{ro:'Ești ceea ce repeți. Obiceiul e ruga pe care o faci zilnic fără să știi.',en:'You are what you repeat. Habit is the prayer you say daily without knowing.',pt:'És o que repetes. O hábito é a oração que dizes todos os dias sem saber.'},inv:{ro:'Ce obicei mic te zidește? Ține-l și azi.',en:'Which small habit builds you? Keep it today too.',pt:'Que pequeno hábito te constrói? Mantém-no também hoje.'}},
  {el:'path',kw:{ro:'Lanțul',en:'The Chain',pt:'A Corrente'},t:{ro:'Nu rupe lanțul zilelor bune pentru o zi proastă. O verigă slabă nu strică lanțul ținut.',en:'Do not break the chain of good days for one bad day. A weak link does not ruin a held chain.',pt:'Não quebres a corrente dos bons dias por um dia mau. Um elo fraco não estraga uma corrente segurada.'},inv:{ro:'Reia azi veriga, oricât de mică.',en:'Resume the link today, however small.',pt:'Retoma hoje o elo, por pequeno que seja.'}},
  {el:'path',kw:{ro:'Căderea',en:'The Fall',pt:'A Queda'},t:{ro:'Căderea face parte din mers. Întreabă orice copil care a învățat să umble.',en:'Falling is part of walking. Ask any child who ever learned.',pt:'Cair faz parte do caminhar. Pergunta a qualquer criança que alguma vez aprendeu.'},inv:{ro:'Unde ai căzut de curând? Spune-i „exercițiu".',en:'Where did you fall lately? Call it practice.',pt:'Onde caíste há pouco? Chama-lhe treino.'}},
  {el:'path',kw:{ro:'Ridicarea',en:'The Rising',pt:'O Erguer-se'},t:{ro:'Nu numărul căderilor te definește, ci al ridicărilor. Fii mereu cu una în plus.',en:'Not the falls define you, but the risings. Stay one ahead.',pt:'Não são as quedas que te definem, mas os erguimentos. Fica sempre um à frente.'},inv:{ro:'Ridică-te azi din descurajarea de ieri.',en:'Rise today from yesterday’s discouragement.',pt:'Ergue-te hoje do desânimo de ontem.'}},
  {el:'path',kw:{ro:'Ocolul',en:'The Detour',pt:'O Desvio'},t:{ro:'Unele ocoluri sunt drumul. Ce pare rătăcire se dovedește, din deal, scurtătură.',en:'Some detours are the road. What seems like straying proves, from the hill, a shortcut.',pt:'Alguns desvios são a estrada. O que parece extravio revela-se, da colina, atalho.'},inv:{ro:'Ce ocol de-al tău a fost de fapt drum bun?',en:'Which of your detours was in fact good road?',pt:'Qual dos teus desvios foi, afinal, boa estrada?'}},
  {el:'path',kw:{ro:'Popasul',en:'The Rest-Stop',pt:'A Paragem'},t:{ro:'Și drumeții buni stau jos. Popasul nu e părăsirea drumului; e grija față de picioare.',en:'Good travelers also sit. A rest-stop is not leaving the road; it is care for the feet.',pt:'Os bons viajantes também se sentam. Uma paragem não é deixar a estrada; é cuidar dos pés.'},inv:{ro:'Pune azi un popas adevărat în mijlocul zilei.',en:'Set one true rest in the middle of the day.',pt:'Marca uma paragem verdadeira a meio do dia.'}},
  {el:'path',kw:{ro:'Merindea',en:'The Provisions',pt:'As Provisões'},t:{ro:'Nu pleca la drum lung cu traista goală: somn, pâine, oameni dragi, rugă. Astea țin foamea de drum.',en:'Do not start a long road with an empty satchel: sleep, bread, dear people, prayer. These keep road-hunger away.',pt:'Não comeces uma longa estrada com o alforge vazio: sono, pão, gente querida, oração. Isto afasta a fome do caminho.'},inv:{ro:'Ce lipsește azi din traista ta? Pune-l înapoi.',en:'What is missing from your satchel? Put it back.',pt:'O que falta no teu alforge? Repõe-no.'}},
  {el:'path',kw:{ro:'Tovarășul',en:'The Companion',pt:'O Companheiro'},t:{ro:'Drumul lung se măsoară în tovarăși, nu în kilometri. Alege cu cine mergi.',en:'A long road is measured in companions, not kilometers. Choose whom you walk with.',pt:'Uma longa estrada mede-se em companheiros, não em quilómetros. Escolhe com quem caminhas.'},inv:{ro:'Mulțumește azi unui tovarăș de drum.',en:'Thank one road-companion today.',pt:'Agradece hoje a um companheiro de estrada.'}},
  {el:'path',kw:{ro:'Harta',en:'The Map',pt:'O Mapa'},t:{ro:'Harta nu e drumul. La un moment dat trebuie să lași hârtia și să calci pământul.',en:'The map is not the road. At some point you must put down the paper and tread the ground.',pt:'O mapa não é a estrada. A certa altura tens de pousar o papel e pisar o chão.'},inv:{ro:'Destul plan. Fă azi kilometrul întâi.',en:'Enough planning. Walk the first kilometer today.',pt:'Chega de planear. Anda hoje o primeiro quilómetro.'}},
  {el:'path',kw:{ro:'Busola',en:'The Compass',pt:'A Bússola'},t:{ro:'Când te rătăcești, nu-ți trebuie toată harta; îți trebuie nordul. Al tău care e?',en:'When lost, you do not need the whole map; you need north. What is yours?',pt:'Quando te perdes, não precisas do mapa inteiro; precisas do norte. Qual é o teu?'},inv:{ro:'Numește-ți nordul într-o singură propoziție.',en:'Name your north in a single sentence.',pt:'Nomeia o teu norte numa única frase.'}},
  {el:'path',kw:{ro:'Răscrucea',en:'The Crossroads',pt:'A Encruzilhada'},t:{ro:'La răscruce nu alege drumul cel mai neted, ci pe cel care duce unde vrei să ajungi.',en:'At the crossroads choose not the smoothest road, but the one going where you mean to arrive.',pt:'Na encruzilhada escolhe não a estrada mais lisa, mas a que vai para onde queres chegar.'},inv:{ro:'Ce alegere comodă te duce unde nu vrei?',en:'Which comfortable choice leads where you don’t want to go?',pt:'Que escolha cómoda te leva para onde não queres ir?'}},
  {el:'path',kw:{ro:'Întoarcerea',en:'The Turning Back',pt:'O Regresso'},t:{ro:'A te întoarce de pe drumul greșit nu e înfrângere; e cel mai iute mers înainte.',en:'Turning back from the wrong road is not defeat; it is the fastest way forward.',pt:'Voltar atrás na estrada errada não é derrota; é o modo mais rápido de avançar.'},inv:{ro:'De pe ce drum știi că trebuie să te întorci?',en:'From which road do you know you must turn back?',pt:'De que estrada sabes que deves voltar?'}},
  {el:'path',kw:{ro:'Urcușul',en:'The Climb',pt:'A Subida'},t:{ro:'Pe urcuș gâfâie toți, chiar și cei care par că zboară. Gâfâitul nu e semn rău; e semn de pantă.',en:'On the climb everyone pants, even those who seem to fly. Panting is not a bad sign; it is a sign of slope.',pt:'Na subida todos arquejam, até os que parecem voar. Arquejar não é mau sinal; é sinal de encosta.'},inv:{ro:'Ți-e greu? Poate doar urci. Mai fă un pas.',en:'Is it hard? Perhaps you are simply climbing. One more step.',pt:'Está difícil? Talvez estejas só a subir. Mais um passo.'}},
  {el:'path',kw:{ro:'Coborâșul',en:'The Descent',pt:'A Descida'},t:{ro:'Și coborâșul cere pricepere: să lași înălțimea fără să-ți pierzi înălțimea dinăuntru.',en:'Descending too takes skill: leaving the height without losing the height within.',pt:'Também descer exige perícia: deixar a altura sem perder a altura de dentro.'},inv:{ro:'Încheie frumos ce se încheie. Coboară cu demnitate.',en:'End well what is ending. Descend with dignity.',pt:'Termina bem o que acaba. Desce com dignidade.'}},
  {el:'path',kw:{ro:'Povara lăsată',en:'The Burden Set Down',pt:'O Fardo Pousado'},t:{ro:'Din când în când, desfă bocceaua: jumătate din ce cari nu mai e al drumului de azi.',en:'Now and then, open the bundle: half of what you carry no longer belongs to today’s road.',pt:'De vez em quando, abre a trouxa: metade do que carregas já não é da estrada de hoje.'},inv:{ro:'Lasă azi jos o grijă care nu mai e a ta.',en:'Set down one worry that is no longer yours.',pt:'Pousa uma preocupação que já não é tua.'}},
  {el:'path',kw:{ro:'Sandalele',en:'The Sandals',pt:'As Sandálias'},t:{ro:'Nu poți acoperi lumea cu piele, dar poți purta sandale. Nu schimba lumea; încalță-te.',en:'You cannot cover the world in leather, but you can wear sandals. Do not change the world; put on shoes.',pt:'Não podes cobrir o mundo de couro, mas podes calçar sandálias. Não mudes o mundo; calça-te.'},inv:{ro:'Ce poți schimba la tine în loc să ceri lumii?',en:'What can you change in yourself instead of demanding of the world?',pt:'O que podes mudar em ti em vez de exigir ao mundo?'}},
  {el:'path',kw:{ro:'Drumul de seară',en:'The Evening Road',pt:'A Estrada da Noite'},t:{ro:'Seara, drumul se povestește. Ziua nepovestită se pierde de două ori.',en:'In the evening, the road is retold. An untold day is lost twice.',pt:'À noite, a estrada reconta-se. Um dia não contado perde-se duas vezes.'},inv:{ro:'Povestește-ți seara ziua în trei rânduri.',en:'Tell yourself the day in three lines tonight.',pt:'Conta a ti mesmo o dia em três linhas esta noite.'}},
  {el:'path',kw:{ro:'Zorii',en:'The Dawn',pt:'A Aurora'},t:{ro:'Cine își câștigă dimineața și-a câștigat jumătate de zi. Zorii sunt aur nefurat încă.',en:'Who wins the morning wins half the day. Dawn is gold not yet stolen.',pt:'Quem ganha a manhã ganha meio dia. A aurora é ouro ainda não roubado.'},inv:{ro:'Dă-i dimineții de mâine primul sfert de oră.',en:'Give tomorrow’s dawn its first quarter hour.',pt:'Dá à aurora de amanhã o seu primeiro quarto de hora.'}},
  {el:'path',kw:{ro:'Ceasul bun',en:'The Good Hour',pt:'A Boa Hora'},t:{ro:'Nu toate orele sunt la fel. Află-ți ceasul bun și pune-i în brațe lucrul cel mai de preț.',en:'Not all hours are equal. Find your good hour and place your most precious work in its arms.',pt:'Nem todas as horas são iguais. Encontra a tua boa hora e põe-lhe nos braços o teu trabalho mais precioso.'},inv:{ro:'La ce oră ești cel mai viu? Păzește-o.',en:'At what hour are you most alive? Guard it.',pt:'A que hora estás mais vivo? Guarda-a.'}},
  {el:'path',kw:{ro:'Rânduiala',en:'The Order of Days',pt:'A Ordem dos Dias'},t:{ro:'Rânduiala nu e închisoare; e albia care face din zilele împrăștiate un râu.',en:'Order is not a prison; it is the riverbed that turns scattered days into a river.',pt:'A ordem não é prisão; é o leito que faz dos dias dispersos um rio.'},inv:{ro:'Pune azi o singură rânduială nouă, mică.',en:'Set one small new order today.',pt:'Estabelece hoje uma pequena ordem nova.'}},
  {el:'path',kw:{ro:'Munca-rugă',en:'Work as Prayer',pt:'O Trabalho-Oração'},t:{ro:'Lucrul făcut cu grijă întreagă e o formă de rugăciune pe care o înțeleg toate cerurile.',en:'Work done with whole care is a prayer all heavens understand.',pt:'O trabalho feito com cuidado inteiro é uma oração que todos os céus entendem.'},inv:{ro:'Fă azi un lucru atât de bine încât să semene a mulțumire.',en:'Do one thing so well today it resembles thanksgiving.',pt:'Faz hoje uma coisa tão bem que pareça ação de graças.'}},
  {el:'path',kw:{ro:'Lucrul întreg',en:'The Whole Work',pt:'A Obra Inteira'},t:{ro:'Zece lucruri pe sfert nu fac unul întreg. Termină ce ai început; abia atunci s-a făcut.',en:'Ten quarter-done things do not make one whole. Finish what you began; only then is it made.',pt:'Dez coisas feitas a um quarto não fazem uma inteira. Termina o que começaste; só então está feito.'},inv:{ro:'Du azi la capăt un lucru început demult.',en:'Carry one long-started thing to its end today.',pt:'Leva hoje ao fim uma coisa começada há muito.'}},
  {el:'path',kw:{ro:'Grija zilei',en:'The Day’s Care',pt:'O Cuidado do Dia'},t:{ro:'Fiecare zi are grijile ei; nu împrumuta și de la cele care n-au venit.',en:'Each day has its cares; do not borrow from those not yet arrived.',pt:'Cada dia tem os seus cuidados; não peças emprestado aos que ainda não chegaram.'},inv:{ro:'Rămâi azi doar cu grijile lui azi.',en:'Keep only today’s cares today.',pt:'Fica hoje só com os cuidados de hoje.'}},
  {el:'path',kw:{ro:'Semănatul',en:'The Sowing',pt:'A Sementeira'},t:{ro:'Nu judeca ziua după recoltă, ci după semințele puse. Recolta vine la vremea ei.',en:'Judge the day not by the harvest but by the seeds sown. The harvest comes in its season.',pt:'Julga o dia não pela colheita mas pelas sementes lançadas. A colheita vem na sua estação.'},inv:{ro:'Ce sămânță ai pus azi? Ajunge una.',en:'What seed did you sow today? One is enough.',pt:'Que semente semeaste hoje? Uma basta.'}},
  {el:'path',kw:{ro:'Roadele',en:'The Fruits',pt:'Os Frutos'},t:{ro:'Pomul se cunoaște după roade, nu după foșnet. Și omul la fel.',en:'The tree is known by its fruit, not by its rustling. So is a person.',pt:'A árvore conhece-se pelo fruto, não pelo restolhar. Assim a pessoa.'},inv:{ro:'Mai puțin foșnet azi; o roadă mică în plus.',en:'Less rustling today; one small fruit more.',pt:'Menos restolhar hoje; um pequeno fruto a mais.'}},
  {el:'path',kw:{ro:'Iarna',en:'The Winter',pt:'O Inverno'},t:{ro:'Sunt anotimpuri în care nimic nu pare să crească. Sub zăpadă, rădăcinile lucrează.',en:'There are seasons when nothing seems to grow. Beneath the snow, the roots are working.',pt:'Há estações em que nada parece crescer. Debaixo da neve, as raízes trabalham.'},inv:{ro:'Ești în iarnă? Lucrează la rădăcini.',en:'Are you in winter? Work on the roots.',pt:'Estás no inverno? Trabalha nas raízes.'}},
  {el:'path',kw:{ro:'Primăvara',en:'The Spring',pt:'A Primavera'},t:{ro:'Primăvara nu se grăbește și nu întârzie. Tot ce ai îngrijit pe frig va da în floare.',en:'Spring neither hurries nor delays. All you tended in the cold will blossom.',pt:'A primavera não se apressa nem se atrasa. Tudo o que cuidaste no frio florescerá.'},inv:{ro:'Ce înmugurește deja în viața ta? Vezi-l.',en:'What is already budding in your life? See it.',pt:'O que já rebenta na tua vida? Vê-o.'}},
  {el:'path',kw:{ro:'Pelerinul',en:'The Pilgrim',pt:'O Peregrino'},t:{ro:'Pelerinul nu călătorește ca să ajungă departe, ci ca să ajungă adânc.',en:'The pilgrim travels not to arrive far, but to arrive deep.',pt:'O peregrino viaja não para chegar longe, mas para chegar fundo.'},inv:{ro:'Fă din drumul banal de azi un mic pelerinaj.',en:'Turn today’s ordinary route into a small pilgrimage.',pt:'Torna o trajeto banal de hoje numa pequena peregrinação.'}},
  {el:'path',kw:{ro:'Acasă',en:'Home',pt:'Em Casa'},t:{ro:'Toate drumurile bune duc, până la urmă, spre același loc: omul împăcat care ajungi să fii.',en:'All good roads lead, in the end, to the same place: the reconciled person you become.',pt:'Todas as boas estradas levam, no fim, ao mesmo lugar: a pessoa reconciliada em que te tornas.'},inv:{ro:'Un pas mai aproape de tine: acesta e drumul.',en:'One step closer to yourself: that is the road.',pt:'Um passo mais perto de ti: essa é a estrada.'}},

  /* ———————— CERCUL TIMPULUI ———————— */
  {el:'time',kw:{ro:'Clipa',en:'The Moment',pt:'O Instante'},t:{ro:'Ai o singură avere care nu se poate fura decât cu voia ta: clipa de față.',en:'You own one treasure that can be stolen only with your consent: this moment.',pt:'Tens um único tesouro que só pode ser roubado com o teu consentimento: este instante.'},inv:{ro:'Fii întreg aici, un minut întreg.',en:'Be wholly here, for one whole minute.',pt:'Está inteiro aqui, por um minuto inteiro.'}},
  {el:'time',kw:{ro:'Ceasul',en:'The Hour',pt:'A Hora'},t:{ro:'Ora nu se întoarce, dar nici nu se pierde dacă ai locuit-o. Timpul locuit devine viață.',en:'The hour does not return, yet it is not lost if you dwelt in it. Inhabited time becomes life.',pt:'A hora não volta, mas não se perde se a habitaste. O tempo habitado torna-se vida.'},inv:{ro:'Locuiește ora aceasta; n-o traversa în fugă.',en:'Dwell in this hour; do not sprint through it.',pt:'Habita esta hora; não a atravesses a correr.'}},
  {el:'time',kw:{ro:'Graba',en:'Haste',pt:'A Pressa'},t:{ro:'Graba fură de două ori: îți ia și lucrul bine făcut, și bucuria de a-l face.',en:'Haste steals twice: it takes both the work well done and the joy of doing it.',pt:'A pressa rouba duas vezes: leva o trabalho bem feito e a alegria de o fazer.'},inv:{ro:'Fă azi un lucru cu jumătate din viteză și de două ori mai prezent.',en:'Do one thing at half speed and twice the presence.',pt:'Faz uma coisa a metade da velocidade e com o dobro da presença.'}},
  {el:'time',kw:{ro:'Așteptarea',en:'The Waiting',pt:'A Espera'},t:{ro:'Așteptarea nu e timp mort decât dacă o omori tu. Poate fi rugă, poate fi respiro.',en:'Waiting is dead time only if you kill it. It can be prayer; it can be breath.',pt:'A espera só é tempo morto se tu a matares. Pode ser oração; pode ser respiração.'},inv:{ro:'La prima coadă de azi, respiră în loc să fierbi.',en:'In today’s first queue, breathe instead of boiling.',pt:'Na primeira fila de hoje, respira em vez de ferver.'}},
  {el:'time',kw:{ro:'Amânarea',en:'Postponement',pt:'O Adiamento'},t:{ro:'„Mâine" e țara în care se îngroapă cele mai frumoase vieți netrăite.',en:'“Tomorrow” is the land where the most beautiful unlived lives are buried.',pt:'«Amanhã» é a terra onde se enterram as mais belas vidas não vividas.'},inv:{ro:'Ce tot muți pe mâine? Adu-i azi primul sfert de oră.',en:'What do you keep moving to tomorrow? Give it today’s first quarter hour.',pt:'O que adias sempre? Dá-lhe hoje o primeiro quarto de hora.'}},
  {el:'time',kw:{ro:'Trecutul',en:'The Past',pt:'O Passado'},t:{ro:'Trecutul e un dascăl bun și un stăpân rău. Ia-i lecția, nu-i da cheile casei.',en:'The past is a good teacher and a bad master. Take its lesson; do not hand it the keys.',pt:'O passado é bom professor e mau senhor. Recebe a lição; não lhe entregues as chaves.'},inv:{ro:'Ce lecție ai primit deja? Restul biletului e de aruncat.',en:'What lesson have you already received? The rest of the note can go.',pt:'Que lição já recebeste? O resto do bilhete pode ir.'}},
  {el:'time',kw:{ro:'Viitorul',en:'The Future',pt:'O Futuro'},t:{ro:'Viitorul nu se așteaptă; se seamănă. Ce faci azi e viitor în stare de sămânță.',en:'The future is not awaited; it is sown. What you do today is the future in seed form.',pt:'O futuro não se espera; semeia-se. O que fazes hoje é futuro em forma de semente.'},inv:{ro:'Seamănă azi un lucru pentru cel care vei fi peste un an.',en:'Sow one thing today for who you will be in a year.',pt:'Semeia hoje algo para quem serás daqui a um ano.'}},
  {el:'time',kw:{ro:'Clepsidra',en:'The Hourglass',pt:'A Ampulheta'},t:{ro:'Nu poți opri nisipul, dar poți alege ce faci cât curge. Asta e toată deosebirea.',en:'You cannot stop the sand, but you can choose what you do while it runs. That is the whole difference.',pt:'Não podes parar a areia, mas podes escolher o que fazes enquanto corre. Essa é toda a diferença.'},inv:{ro:'Dacă ziua ar fi pe sfârșite, ce-ai face întâi? Fă-l acum.',en:'If the day were ending, what would you do first? Do it now.',pt:'Se o dia estivesse a acabar, o que farias primeiro? Fá-lo agora.'}},
  {el:'time',kw:{ro:'Vremea potrivită',en:'The Ripe Time',pt:'O Tempo Certo'},t:{ro:'Sunt lucruri care nu se pot grăbi și nu se pot întârzia: au ceasul lor. Înțelept e cine îl simte.',en:'Some things can be neither hurried nor delayed: they keep their own hour. Wise is the one who senses it.',pt:'Há coisas que não se apressam nem se atrasam: têm a sua hora. Sábio é quem a sente.'},inv:{ro:'Ce așteaptă în viața ta vremea potrivită? Nu-l smulge verde.',en:'What in your life awaits its ripe time? Do not pick it green.',pt:'O que na tua vida espera o tempo certo? Não o colhas verde.'}},
  {el:'time',kw:{ro:'Răgazul',en:'The Pause',pt:'A Pausa'},t:{ro:'Muzica se naște din note și din pauze. Viața la fel. Fără răgaz, totul e zgomot.',en:'Music is born of notes and rests. So is life. Without pause, all is noise.',pt:'A música nasce de notas e pausas. A vida também. Sem pausa, tudo é ruído.'},inv:{ro:'Pune azi o pauză adevărată între două treburi.',en:'Set one true rest between two tasks today.',pt:'Coloca hoje uma pausa verdadeira entre duas tarefas.'}},
  {el:'time',kw:{ro:'Anotimpul',en:'The Season',pt:'A Estação'},t:{ro:'Nu cere verii roadele toamnei. Nici ție nu-ți cere, în anotimpul semănatului, secerișul.',en:'Do not ask summer for autumn’s fruit. Nor demand harvest of yourself in sowing season.',pt:'Não peças ao verão os frutos do outono. Nem exijas de ti a colheita na estação da sementeira.'},inv:{ro:'În ce anotimp lăuntric ești? Poartă-te pe măsură.',en:'Which inner season are you in? Act accordingly.',pt:'Em que estação interior estás? Age em conformidade.'}},
  {el:'time',kw:{ro:'Ritmul zilelor',en:'The Rhythm of Days',pt:'O Ritmo dos Dias'},t:{ro:'Zilele bune nu se nimeresc; se compun. Dimineața e cheia în care se cântă restul.',en:'Good days are not stumbled upon; they are composed. Morning is the key the rest is played in.',pt:'Os dias bons não se encontram por acaso; compõem-se. A manhã é o tom em que o resto se toca.'},inv:{ro:'Compune-ți mâine prima oră ca pe o strofă bună.',en:'Compose tomorrow’s first hour like a good stanza.',pt:'Compõe a primeira hora de amanhã como uma boa estrofe.'}},
  {el:'time',kw:{ro:'Amintirea',en:'Memory',pt:'A Memória'},t:{ro:'Amintirea e singurul loc unde timpul se lasă îmblânzit. Umple-o cu zile care merită păstrate.',en:'Memory is the one place where time lets itself be tamed. Fill it with days worth keeping.',pt:'A memória é o único lugar onde o tempo se deixa domar. Enche-a de dias dignos de guardar.'},inv:{ro:'Fă azi ceva ce vei vrea să-ți amintești.',en:'Do something today you will want to remember.',pt:'Faz hoje algo de que queiras lembrar-te.'}},
  {el:'time',kw:{ro:'Uitarea',en:'Forgetting',pt:'O Esquecimento'},t:{ro:'Timpul șterge ce nu se mai folosește. Ajută-l: nu mai deschide zilnic rana veche.',en:'Time erases what is no longer used. Help it: stop opening the old wound daily.',pt:'O tempo apaga o que já não se usa. Ajuda-o: deixa de abrir a ferida antiga todos os dias.'},inv:{ro:'Ce amintire hrănești degeaba? Las-o azi nehrănită.',en:'What memory do you feed in vain? Leave it unfed today.',pt:'Que memória alimentas em vão? Deixa-a hoje sem alimento.'}},
  {el:'time',kw:{ro:'Începutul târziu',en:'The Late Beginning',pt:'O Começo Tardio'},t:{ro:'Cel mai bun moment a fost demult; al doilea cel mai bun e acum. Târziul care începe bate devremele care visează.',en:'The best moment was long ago; the second best is now. A late start beats an early dream.',pt:'O melhor momento foi há muito; o segundo melhor é agora. Um começo tardio vence um sonho madrugador.'},inv:{ro:'La ce e „prea târziu"? Începe oricum.',en:'What is it “too late” for? Begin anyway.',pt:'Para quê é «tarde demais»? Começa mesmo assim.'}},
  {el:'time',kw:{ro:'Zestrea zilei',en:'The Day’s Dowry',pt:'O Dote do Dia'},t:{ro:'Fiecare zi vine cu zestrea ei: douăzeci și patru de ore neatinse. Nimeni nu primește mai mult.',en:'Each day arrives with its dowry: twenty-four untouched hours. No one receives more.',pt:'Cada dia chega com o seu dote: vinte e quatro horas intactas. Ninguém recebe mais.'},inv:{ro:'Cheltuiește azi o oră ca un om bogat: pe ce iubești.',en:'Spend one hour today like a rich man: on what you love.',pt:'Gasta hoje uma hora como um homem rico: no que amas.'}},
  {el:'time',kw:{ro:'Furul mărunt',en:'The Small Thief',pt:'O Pequeno Ladrão'},t:{ro:'Nu orele mari ți se fură, ci minutele mici — câte unul, pe nesimțite, cu zâmbet.',en:'It is not the great hours that are stolen, but the small minutes — one by one, unnoticed, smiling.',pt:'Não são as grandes horas que te roubam, mas os pequenos minutos — um a um, sem dar por isso, a sorrir.'},inv:{ro:'Prinde azi un fur mărunt: ce îți ciugulește minutele?',en:'Catch one small thief today: what pecks at your minutes?',pt:'Apanha hoje um pequeno ladrão: o que belisca os teus minutos?'}},
  {el:'time',kw:{ro:'Ora nimănui',en:'No One’s Hour',pt:'A Hora de Ninguém'},t:{ro:'Există în zi o oră pe care n-o cere nimeni. Cine o găsește și-o păzește are o viață în plus.',en:'There is an hour in the day that no one claims. Who finds and guards it gains an extra life.',pt:'Há no dia uma hora que ninguém reclama. Quem a encontra e a guarda ganha uma vida extra.'},inv:{ro:'Găsește-ți ora nimănui și pune-i numele tău.',en:'Find no one’s hour and give it your name.',pt:'Encontra a hora de ninguém e dá-lhe o teu nome.'}},
  {el:'time',kw:{ro:'Timpul dăruit',en:'Given Time',pt:'O Tempo Doado'},t:{ro:'Timpul dat cuiva drag nu se scade din viață; se adună la ea, în alt registru.',en:'Time given to a dear one is not subtracted from life; it is added to it, in another ledger.',pt:'O tempo dado a alguém querido não se subtrai à vida; soma-se a ela, noutro registo.'},inv:{ro:'Dăruiește azi cuiva o jumătate de oră fără telefon.',en:'Gift someone half an hour without a phone today.',pt:'Oferece hoje a alguém meia hora sem telemóvel.'}},
  {el:'time',kw:{ro:'Bătrânul din tine',en:'The Elder in You',pt:'O Ancião em Ti'},t:{ro:'Într-o zi, un om bătrân va locui în trupul tău. Tot ce faci azi e scrisoare către el.',en:'One day an old person will live in your body. All you do today is a letter to them.',pt:'Um dia, um velho habitará o teu corpo. Tudo o que fazes hoje é uma carta para ele.'},inv:{ro:'Scrie-i azi o veste bună: un obicei care îl va ține.',en:'Send them good news today: a habit that will hold them.',pt:'Envia-lhe hoje uma boa notícia: um hábito que o sustente.'}},
  {el:'time',kw:{ro:'Copilul din urmă',en:'The Child Behind',pt:'A Criança de Antes'},t:{ro:'Copilul care ai fost n-a plecat; ți-a dat doar mâna mai departe. Nu-l face de rușine, fă-l mândru.',en:'The child you were has not left; they only passed you the hand. Do not shame them; make them proud.',pt:'A criança que foste não partiu; apenas te passou a mão. Não a envergonhes; deixa-a orgulhosa.'},inv:{ro:'Fă azi un lucru care l-ar bucura pe cel de la șapte ani.',en:'Do one thing today that would delight your seven-year-old self.',pt:'Faz hoje algo que alegraria o teu eu de sete anos.'}},
  {el:'time',kw:{ro:'Neatârnarea de ceas',en:'Freedom from the Clock',pt:'A Liberdade do Relógio'},t:{ro:'Ceasul măsoară timpul; nu-l stăpânește. Stăpânirea e a celui care alege ce încape în oră.',en:'The clock measures time; it does not rule it. Rule belongs to the one who chooses what fills the hour.',pt:'O relógio mede o tempo; não o governa. O governo é de quem escolhe o que cabe na hora.'},inv:{ro:'O oră fără ceas azi: lasă lucrul să-și ia timpul lui.',en:'One clockless hour today: let the work take its own time.',pt:'Uma hora sem relógio hoje: deixa o trabalho tomar o seu tempo.'}},
  {el:'time',kw:{ro:'Rândul lucrurilor',en:'The Order of Things',pt:'A Ordem das Coisas'},t:{ro:'Nu poți face totul azi, dar poți face lucrul cel dintâi. Rândul bun face timpul larg.',en:'You cannot do everything today, but you can do the first thing. Right order makes time wide.',pt:'Não podes fazer tudo hoje, mas podes fazer a primeira coisa. A boa ordem alarga o tempo.'},inv:{ro:'Care e lucrul cel dintâi? Restul să aștepte la rând.',en:'What is the first thing? Let the rest wait in line.',pt:'Qual é a primeira coisa? Que o resto espere na fila.'}},
  {el:'time',kw:{ro:'Clipa dintre',en:'The Between-Moment',pt:'O Entre-Instante'},t:{ro:'Între ce s-a terminat și ce începe e o clipă goală. Acolo se odihnește sufletul. N-o umple.',en:'Between what ended and what begins lies an empty moment. There the soul rests. Do not fill it.',pt:'Entre o que acabou e o que começa há um instante vazio. Ali descansa a alma. Não o enchas.'},inv:{ro:'Între două treburi, azi: trei respirații, nimic altceva.',en:'Between two tasks today: three breaths, nothing else.',pt:'Entre duas tarefas hoje: três respirações, nada mais.'}},
  {el:'time',kw:{ro:'Veșnicia mică',en:'The Small Eternity',pt:'A Pequena Eternidade'},t:{ro:'Sunt clipe care nu se mai termină de frumoase. Veșnicia își face uneori casă într-o secundă.',en:'Some moments never end, so beautiful they are. Eternity sometimes makes its home in a second.',pt:'Há instantes que não acabam de tão belos. A eternidade às vezes faz casa num segundo.'},inv:{ro:'Când clipa se face mare azi, nu te uita la ceas.',en:'When the moment grows vast today, do not check the clock.',pt:'Quando o instante se fizer grande hoje, não olhes o relógio.'}},
  {el:'time',kw:{ro:'Datoria zilei',en:'The Day’s Debt',pt:'A Dívida do Dia'},t:{ro:'Ziua nu-ți cere să termini lumea; îți cere doar partea ei de lucru. Plătește-i porția și dormi.',en:'The day does not ask you to finish the world; only its share of the work. Pay its portion and sleep.',pt:'O dia não te pede para acabar o mundo; só a sua parte do trabalho. Paga a porção dele e dorme.'},inv:{ro:'Hotărăște ce înseamnă „destul pe azi" — și oprește-te acolo.',en:'Decide what “enough for today” means — and stop there.',pt:'Decide o que significa «suficiente por hoje» — e para aí.'}},
  {el:'time',kw:{ro:'Timpul celuilalt',en:'The Other’s Time',pt:'O Tempo do Outro'},t:{ro:'Fiecare om curge în alt ritm. A-l grăbi pe celălalt e a-i călca albia.',en:'Each person flows at their own pace. To hurry another is to trample their riverbed.',pt:'Cada pessoa corre ao seu ritmo. Apressar o outro é pisar o seu leito.'},inv:{ro:'Lasă azi pe cineva să termine în ritmul lui.',en:'Let someone finish at their own pace today.',pt:'Deixa hoje alguém terminar ao seu próprio ritmo.'}},
  {el:'time',kw:{ro:'Ceasul rău',en:'The Bad Hour',pt:'A Hora Má'},t:{ro:'Și ceasul rău trece — asta e singura lui bunătate. Nu lua hotărâri veșnice în ore trecătoare.',en:'The bad hour passes too — that is its one kindness. Do not make eternal decisions in passing hours.',pt:'A hora má também passa — é a sua única bondade. Não tomes decisões eternas em horas passageiras.'},inv:{ro:'În ceasul greu, amână hotărârile mari pe mâine.',en:'In the hard hour, postpone big decisions until tomorrow.',pt:'Na hora difícil, adia as grandes decisões para amanhã.'}},
  {el:'time',kw:{ro:'Filele albe',en:'The Blank Pages',pt:'As Páginas em Branco'},t:{ro:'Oricâte pagini ai mâzgălit, restul caietului e alb. Viața se judecă și după filele care vin.',en:'However many pages you have blotted, the rest of the notebook is blank. Life is judged also by the pages to come.',pt:'Por mais páginas que tenhas borrado, o resto do caderno está em branco. A vida julga-se também pelas páginas que vêm.'},inv:{ro:'Scrie azi o filă pe care s-o recitești cu drag.',en:'Write a page today you will reread with fondness.',pt:'Escreve hoje uma página que releias com carinho.'}},
  {el:'time',kw:{ro:'Pomul bătrân',en:'The Old Tree',pt:'A Árvore Velha'},t:{ro:'Cel mai bun moment să sădești un pom a fost acum douăzeci de ani. Al doilea: astăzi, la prânz.',en:'The best time to plant a tree was twenty years ago. The second best: today, at noon.',pt:'O melhor momento para plantar uma árvore foi há vinte anos. O segundo melhor: hoje, ao meio-dia.'},inv:{ro:'Sădește azi pomul amânat: cont, curs, scrisoare, sămânță.',en:'Plant the postponed tree today: an account, a course, a letter, a seed.',pt:'Planta hoje a árvore adiada: uma conta, um curso, uma carta, uma semente.'}},
  {el:'time',kw:{ro:'Ceasul de ceas',en:'Hour by Hour',pt:'Hora a Hora'},t:{ro:'Nu trebuie să duci ziua întreagă în spate; du doar ceasul acesta. Ziua se duce singură, ceas de ceas.',en:'You need not carry the whole day; carry only this hour. The day carries itself, hour by hour.',pt:'Não precisas de carregar o dia inteiro; carrega só esta hora. O dia leva-se sozinho, hora a hora.'},inv:{ro:'Îngustează grija la ceasul de față. Atât.',en:'Narrow the worry to this hour. That is all.',pt:'Estreita a preocupação a esta hora. Só isso.'}},
  {el:'time',kw:{ro:'Sărbătoarea',en:'The Feast',pt:'A Festa'},t:{ro:'Fără sărbătoare, timpul e o linie dreaptă care obosește. Pune-i noduri de bucurie.',en:'Without feast days, time is a straight line that tires. Tie knots of joy into it.',pt:'Sem festa, o tempo é uma linha reta que cansa. Ata-lhe nós de alegria.'},inv:{ro:'Fă din seara asta o mică sărbătoare, fără motiv.',en:'Make this evening a small feast, for no reason.',pt:'Faz desta noite uma pequena festa, sem motivo.'}},
  {el:'time',kw:{ro:'Astăzi',en:'Today',pt:'Hoje'},t:{ro:'„Astăzi" e singurul cuvânt din calendar care există cu adevărat. Restul sunt povești.',en:'“Today” is the only word in the calendar that truly exists. The rest are stories.',pt:'«Hoje» é a única palavra do calendário que existe de verdade. O resto são histórias.'},inv:{ro:'Trăiește azi ca pe ziua care este — singura.',en:'Live today as the day it is — the only one.',pt:'Vive hoje como o dia que é — o único.'}},

  /* ———————— CERCUL IUBIRII ———————— */
  {el:'love',kw:{ro:'Iubirea-verb',en:'Love the Verb',pt:'O Amor-Verbo'},t:{ro:'Iubirea nu e ce simți când e ușor; e ce faci când e greu. Substantivul visează, verbul zidește.',en:'Love is not what you feel when it is easy; it is what you do when it is hard. The noun dreams; the verb builds.',pt:'O amor não é o que sentes quando é fácil; é o que fazes quando é difícil. O substantivo sonha; o verbo constrói.'},inv:{ro:'Iubește azi cu o faptă, nu cu o declarație.',en:'Love with a deed today, not a declaration.',pt:'Ama hoje com um ato, não com uma declaração.'}},
  {el:'love',kw:{ro:'Privirea',en:'The Gaze',pt:'O Olhar'},t:{ro:'A iubi pe cineva e a-l privi cum nu-l mai privește nimeni: întreg, fără grabă, fără listă de greșeli.',en:'To love someone is to see them as no one else does: whole, unhurried, without a list of faults.',pt:'Amar alguém é vê-lo como mais ninguém o vê: inteiro, sem pressa, sem lista de defeitos.'},inv:{ro:'Privește azi un om drag zece secunde mai mult.',en:'Look at a dear one ten seconds longer today.',pt:'Olha hoje alguém querido dez segundos a mais.'}},
  {el:'love',kw:{ro:'Gestul mic',en:'The Small Gesture',pt:'O Pequeno Gesto'},t:{ro:'Iubirile mari mor rar din lovituri mari; mor din gesturi mici nefăcute, zi după zi.',en:'Great loves rarely die of great blows; they die of small gestures left undone, day after day.',pt:'Os grandes amores raramente morrem de grandes golpes; morrem de pequenos gestos por fazer, dia após dia.'},inv:{ro:'Ceaiul, biletul, întrebarea: fă azi gestul mic.',en:'The tea, the note, the question: make the small gesture today.',pt:'O chá, o bilhete, a pergunta: faz hoje o pequeno gesto.'}},
  {el:'love',kw:{ro:'Ascultarea de dor',en:'Listening with Longing',pt:'A Escuta Amorosa'},t:{ro:'Cel mai frumos dar pentru un om care vorbește: să nu te grăbești nicăieri cât timp vorbește.',en:'The finest gift for someone speaking: to be in no hurry anywhere while they speak.',pt:'O mais belo presente para quem fala: não teres pressa de nada enquanto fala.'},inv:{ro:'Ascultă azi un om drag ca pe o muzică, nu ca pe o listă.',en:'Listen to a dear one today as to music, not a list.',pt:'Escuta hoje alguém querido como música, não como lista.'}},
  {el:'love',kw:{ro:'Spațiul dintre',en:'The Space Between',pt:'O Espaço Entre'},t:{ro:'Doi copaci prea apropiați se usucă unul pe altul. Iubirea bună lasă loc de soare între rădăcini.',en:'Two trees too close dry each other out. Good love leaves sunlight between the roots.',pt:'Duas árvores demasiado juntas secam-se uma à outra. O bom amor deixa sol entre as raízes.'},inv:{ro:'Dă-i azi celui drag o oră a lui, fără să i-o numeri.',en:'Give your dear one an hour of their own today, uncounted.',pt:'Dá hoje ao teu querido uma hora só dele, sem a contares.'}},
  {el:'love',kw:{ro:'Rădăcină și aripă',en:'Root and Wing',pt:'Raiz e Asa'},t:{ro:'Iubirea adevărată dă două daruri deodată: rădăcină ca să nu te pierzi, aripă ca să nu te oprești.',en:'True love gives two gifts at once: a root so you are not lost, a wing so you are not stopped.',pt:'O amor verdadeiro dá dois presentes ao mesmo tempo: raiz para não te perderes, asa para não parares.'},inv:{ro:'Fii azi și rădăcină, și aripă pentru cineva.',en:'Be both root and wing for someone today.',pt:'Sê hoje raiz e asa para alguém.'}},
  {el:'love',kw:{ro:'Iertarea în doi',en:'Forgiving Together',pt:'O Perdão a Dois'},t:{ro:'În orice iubire lungă se strâng vini mărunte ca praful. Iertarea e măturatul de seară.',en:'In any long love, small faults gather like dust. Forgiveness is the evening sweeping.',pt:'Em qualquer amor longo, juntam-se culpas miúdas como pó. O perdão é a varredura da noite.'},inv:{ro:'Mătură azi un praf vechi: iartă un fleac nespus.',en:'Sweep an old dust today: forgive an unspoken trifle.',pt:'Varre hoje um pó antigo: perdoa uma ninharia calada.'}},
  {el:'love',kw:{ro:'Cuvântul dulce',en:'The Sweet Word',pt:'A Palavra Doce'},t:{ro:'Nu presupune că omul drag știe. Spune-i. Iubirea nespusă hrănește doar pe cel care tace.',en:'Do not assume your dear one knows. Tell them. Unspoken love feeds only the silent one.',pt:'Não presumas que quem amas sabe. Diz-lho. O amor calado alimenta só quem se cala.'},inv:{ro:'Spune azi, cu gura, ce crezi că „se știe".',en:'Say aloud today what you think “is known.”',pt:'Diz hoje, em voz alta, o que achas que «já se sabe».'}},
  {el:'love',kw:{ro:'Iubirea de sine',en:'Self-Love',pt:'O Amor-Próprio'},t:{ro:'Nu poți turna dintr-un ulcior gol. Iubirea de sine nu e trufie; e umplerea ulciorului.',en:'You cannot pour from an empty jug. Self-love is not vanity; it is the filling of the jug.',pt:'Não podes servir de um jarro vazio. O amor-próprio não é vaidade; é encher o jarro.'},inv:{ro:'Fă azi pentru tine ce ai face pentru un om iubit.',en:'Do for yourself today what you would do for a loved one.',pt:'Faz hoje por ti o que farias por alguém amado.'}},
  {el:'love',kw:{ro:'Prietenia',en:'Friendship',pt:'A Amizade'},t:{ro:'Prietenul nu e cel care îți ține partea; e cel care îți ține candela când ție ți se stinge.',en:'A friend is not the one who takes your side; it is the one who holds your candle when yours goes out.',pt:'O amigo não é quem toma o teu partido; é quem segura a tua vela quando ela se apaga.'},inv:{ro:'Aprinde azi candela unui prieten obosit.',en:'Light a tired friend’s candle today.',pt:'Acende hoje a vela de um amigo cansado.'}},
  {el:'love',kw:{ro:'Familia',en:'The Family',pt:'A Família'},t:{ro:'Familia e grădina în care nu alegi semințele, dar alegi cum le uzi. Multe flori iartă grădinarul.',en:'Family is the garden where you do not choose the seeds, but you choose the watering. Many flowers forgive the gardener.',pt:'A família é o jardim onde não escolhes as sementes, mas escolhes a rega. Muitas flores perdoam o jardineiro.'},inv:{ro:'Udă azi o legătură de sânge cu un telefon.',en:'Water a blood-bond with a phone call today.',pt:'Rega hoje um laço de sangue com um telefonema.'}},
  {el:'love',kw:{ro:'Străinul',en:'The Stranger',pt:'O Estrangeiro'},t:{ro:'Bunătatea față de străin e iubirea în forma ei cea mai curată: nu așteaptă nimic înapoi.',en:'Kindness to a stranger is love in its purest form: it expects nothing back.',pt:'A bondade para com o estrangeiro é o amor na sua forma mais pura: não espera nada em troca.'},inv:{ro:'Fă azi un bine unui om pe care nu-l vei revedea.',en:'Do good today to someone you will never see again.',pt:'Faz hoje um bem a alguém que nunca mais verás.'}},
  {el:'love',kw:{ro:'Vrăjmașul',en:'The Adversary',pt:'O Adversário'},t:{ro:'Cine te-a rănit poartă și el o rană pe care n-o vezi. Nu-l scuza; doar nu-i mai bea otrava.',en:'The one who hurt you carries a wound you cannot see. Do not excuse them; just stop drinking their poison.',pt:'Quem te feriu também carrega uma ferida que não vês. Não o desculpes; apenas deixa de beber o seu veneno.'},inv:{ro:'Lasă azi jos paharul cu otravă: un gând de pică.',en:'Set down the poison cup today: one grudge.',pt:'Pousa hoje o copo de veneno: um rancor.'}},
  {el:'love',kw:{ro:'Tandrețea',en:'Tenderness',pt:'A Ternura'},t:{ro:'Lumea e plină de oameni tari. Rar și de preț e omul care a rămas moale fără să fie slab.',en:'The world is full of hard people. Rare and precious is the one who stayed soft without being weak.',pt:'O mundo está cheio de gente dura. Raro e precioso é quem ficou macio sem ser fraco.'},inv:{ro:'Fii azi tandru într-o situație în care puteai fi tăios.',en:'Be tender today where you could have been sharp.',pt:'Sê terno hoje onde podias ter sido cortante.'}},
  {el:'love',kw:{ro:'Statornicia',en:'Steadfastness',pt:'A Constância'},t:{ro:'Oricine iubește pe vreme bună. Iubirea se cunoaște pe furtună, când e mai ușor să pleci și rămâi.',en:'Anyone loves in fair weather. Love is known in the storm, when leaving is easier and you stay.',pt:'Qualquer um ama com bom tempo. O amor conhece-se na tempestade, quando partir é mais fácil e ficas.'},inv:{ro:'Rămâi azi lângă cineva într-un moment incomod.',en:'Stay beside someone through an uncomfortable moment today.',pt:'Fica hoje ao lado de alguém num momento incómodo.'}},
  {el:'love',kw:{ro:'Darul',en:'The Gift',pt:'O Dom'},t:{ro:'Darul adevărat nu e lucrul, ci bucata de viață pusă în el: timpul, gândul, alegerea.',en:'The true gift is not the object, but the piece of life placed in it: the time, the thought, the choosing.',pt:'O verdadeiro presente não é o objeto, mas o pedaço de vida posto nele: o tempo, o pensamento, a escolha.'},inv:{ro:'Dăruiește azi ceva ce nu se cumpără.',en:'Give something today that cannot be bought.',pt:'Oferece hoje algo que não se compra.'}},
  {el:'love',kw:{ro:'Primirea',en:'Receiving',pt:'O Receber'},t:{ro:'A ști să primești e jumătatea uitată a iubirii. Cine refuză darul refuză și mâna care l-a întins.',en:'Knowing how to receive is love’s forgotten half. Who refuses the gift refuses the hand that offered it.',pt:'Saber receber é a metade esquecida do amor. Quem recusa o presente recusa a mão que o estendeu.'},inv:{ro:'Primește azi un ajutor fără să te scuzi.',en:'Accept help today without apologizing.',pt:'Aceita hoje uma ajuda sem te desculpares.'}},
  {el:'love',kw:{ro:'Cheia blândă',en:'The Gentle Key',pt:'A Chave Suave'},t:{ro:'Inima celuilalt nu se descuie cu argumente. Se descuie cu siguranța că nu va fi rănită.',en:'Another’s heart is not unlocked with arguments. It opens to the certainty it will not be hurt.',pt:'O coração do outro não se abre com argumentos. Abre-se com a certeza de que não será ferido.'},inv:{ro:'Fă azi din tine un loc sigur pentru cineva.',en:'Make yourself a safe place for someone today.',pt:'Faz de ti hoje um lugar seguro para alguém.'}},
  {el:'love',kw:{ro:'Oglinda dragă',en:'The Loving Mirror',pt:'O Espelho Amado'},t:{ro:'Cei dragi ne oglindesc ce nu vedem singuri. Iubirea ascultă și oglinda care nu-i place.',en:'Our dear ones mirror what we cannot see alone. Love listens even to the mirror it dislikes.',pt:'Os que amamos espelham o que não vemos sozinhos. O amor escuta até o espelho de que não gosta.'},inv:{ro:'Primește azi o observație de la un om drag fără scut.',en:'Receive one remark from a loved one today without a shield.',pt:'Recebe hoje um reparo de alguém querido sem escudo.'}},
  {el:'love',kw:{ro:'Limba celuilalt',en:'The Other’s Language',pt:'A Língua do Outro'},t:{ro:'Unii iubesc cu vorbe, alții cu fapte, alții cu timp. Învață limba în care iubește omul tău.',en:'Some love with words, some with deeds, some with time. Learn the language your person loves in.',pt:'Uns amam com palavras, outros com atos, outros com tempo. Aprende a língua em que a tua pessoa ama.'},inv:{ro:'Spune azi „te iubesc" pe limba lui, nu pe a ta.',en:'Say “I love you” today in their language, not yours.',pt:'Diz hoje «amo-te» na língua dele, não na tua.'}},
  {el:'love',kw:{ro:'Rana din iubire',en:'The Wound of Love',pt:'A Ferida do Amor'},t:{ro:'Doare doar unde ai iubit. Rana e chitanța iubirii: scumpă, dar dovadă că a fost adevărată.',en:'It only hurts where you loved. The wound is love’s receipt: costly, but proof it was real.',pt:'Só dói onde amaste. A ferida é o recibo do amor: cara, mas prova de que foi verdadeiro.'},inv:{ro:'Mulțumește azi și pentru iubirea care a durut.',en:'Give thanks today even for the love that hurt.',pt:'Agradece hoje até o amor que doeu.'}},
  {el:'love',kw:{ro:'Iubirea lucrului',en:'Loving the Work',pt:'O Amor ao Ofício'},t:{ro:'Poți iubi și un meșteșug, o grădină, o pagină. Tot iubire e: atenție lungă, dăruită zilnic.',en:'You can love a craft, a garden, a page. It is love all the same: long attention, given daily.',pt:'Podes amar um ofício, um jardim, uma página. É amor na mesma: atenção longa, dada diariamente.'},inv:{ro:'Lucrează azi o oră cu dragoste, nu doar cu pricepere.',en:'Work one hour with love today, not skill alone.',pt:'Trabalha hoje uma hora com amor, não só com perícia.'}},
  {el:'love',kw:{ro:'Casa deschisă',en:'The Open House',pt:'A Casa Aberta'},t:{ro:'O masă întinsă face mai multă apropiere decât o mie de mesaje. Ospitalitatea e iubire cu miros de pâine.',en:'A laid table makes more closeness than a thousand messages. Hospitality is love that smells of bread.',pt:'Uma mesa posta cria mais proximidade do que mil mensagens. A hospitalidade é amor com cheiro a pão.'},inv:{ro:'Cheamă pe cineva la masa ta săptămâna asta.',en:'Invite someone to your table this week.',pt:'Convida alguém para a tua mesa esta semana.'}},
  {el:'love',kw:{ro:'Mângâierea',en:'The Consolation',pt:'O Consolo'},t:{ro:'Nu repara omul care plânge. Stai cu el. Umărul tăcut leagă mai bine decât sfatul grăbit.',en:'Do not fix the one who weeps. Stay with them. A silent shoulder binds better than hurried advice.',pt:'Não consertes quem chora. Fica com ele. Um ombro calado une melhor do que um conselho apressado.'},inv:{ro:'Azi, dacă cineva plânge, oferă prezență, nu soluții.',en:'Today, if someone weeps, offer presence, not solutions.',pt:'Hoje, se alguém chorar, oferece presença, não soluções.'}},
  {el:'love',kw:{ro:'Bucuria pentru altul',en:'Joy for Another',pt:'A Alegria pelo Outro'},t:{ro:'Să te bucuri curat de izbânda altuia e o iubire rară — mai rară decât mila și mai frumoasă.',en:'To rejoice cleanly at another’s success is a rare love — rarer than pity, and more beautiful.',pt:'Alegrar-se limpamente com a vitória do outro é um amor raro — mais raro que a pena e mais belo.'},inv:{ro:'Bucură-te azi din inimă de reușita cuiva.',en:'Rejoice wholeheartedly in someone’s success today.',pt:'Alegra-te hoje de coração com o sucesso de alguém.'}},
  {el:'love',kw:{ro:'Hotarul iubirii',en:'Love’s Border',pt:'A Fronteira do Amor'},t:{ro:'Iubirea fără hotar se face jertfă fără rost. Iubește-l pe celălalt fără să te ștergi pe tine.',en:'Love without borders becomes pointless sacrifice. Love the other without erasing yourself.',pt:'O amor sem fronteira torna-se sacrifício sem sentido. Ama o outro sem te apagares a ti.'},inv:{ro:'Unde te ștergi ca să fii iubit? Rescrie-te azi.',en:'Where do you erase yourself to be loved? Rewrite yourself today.',pt:'Onde te apagas para ser amado? Reescreve-te hoje.'}},
  {el:'love',kw:{ro:'Despărțirea bună',en:'The Good Parting',pt:'A Boa Despedida'},t:{ro:'Unele iubiri se termină. Felul în care le închei rămâne în tine pentru totdeauna. Închide ușile blând.',en:'Some loves end. The way you end them stays in you forever. Close doors gently.',pt:'Alguns amores acabam. A forma como os terminas fica em ti para sempre. Fecha as portas com suavidade.'},inv:{ro:'Ce ușă ai trântit cândva? Deschide-o azi, doar cât să spui „pace".',en:'What door did you slam once? Open it today just enough to say “peace.”',pt:'Que porta bateste um dia? Abre-a hoje só o bastante para dizer «paz».'}},
  {el:'love',kw:{ro:'Recunoștința pentru cel de lângă',en:'Gratitude for the One Beside',pt:'A Gratidão por Quem Está ao Lado'},t:{ro:'Pe cei mai buni oameni ai noștri îi vedem cel mai puțin: sunt mereu aici, ca aerul.',en:'We see our best people least: they are always here, like air.',pt:'Vemos menos as nossas melhores pessoas: estão sempre aqui, como o ar.'},inv:{ro:'Vezi-l azi pe cel care e „mereu aici". Spune-i.',en:'See the one who is “always here” today. Tell them.',pt:'Vê hoje quem está «sempre aqui». Diz-lho.'}},
  {el:'love',kw:{ro:'Sămânța de pace',en:'The Seed of Peace',pt:'A Semente da Paz'},t:{ro:'Fiecare ceartă neîncepută e o grădină păstrată. Nu orice adevăr trebuie spus la mânie.',en:'Every quarrel not started is a garden preserved. Not every truth must be spoken in anger.',pt:'Cada briga não começada é um jardim preservado. Nem toda a verdade deve ser dita com raiva.'},inv:{ro:'Înghite azi o replică ascuțită. Grădina rămâne.',en:'Swallow one sharp reply today. The garden remains.',pt:'Engole hoje uma resposta afiada. O jardim permanece.'}},
  {el:'love',kw:{ro:'Iubirea lumii',en:'Love of the World',pt:'O Amor ao Mundo'},t:{ro:'Poți iubi lumea întreagă doar pe bucăți: strada ta, teiul tău, vecinul tău. Începe cu bucata ta.',en:'You can love the whole world only in pieces: your street, your linden, your neighbor. Begin with your piece.',pt:'Só podes amar o mundo inteiro aos pedaços: a tua rua, a tua tília, o teu vizinho. Começa pelo teu pedaço.'},inv:{ro:'Fă azi mai frumoasă bucata ta de lume.',en:'Make your piece of the world more beautiful today.',pt:'Torna hoje mais belo o teu pedaço de mundo.'}},
  {el:'love',kw:{ro:'Izvorul nesecat',en:'The Unfailing Spring',pt:'A Fonte Inesgotável'},t:{ro:'Iubirea e singura avere care crește împărțind-o. Cu cât dai mai multă, cu atât ai mai multă.',en:'Love is the only wealth that grows by being shared. The more you give, the more you have.',pt:'O amor é a única riqueza que cresce ao ser partilhada. Quanto mais dás, mais tens.'},inv:{ro:'Dă azi iubire fără socoteală, măcar o dată.',en:'Give love without accounting today, at least once.',pt:'Dá hoje amor sem contas, ao menos uma vez.'}},
  {el:'love',kw:{ro:'Începutul iubirii',en:'Love’s Beginning',pt:'O Começo do Amor'},t:{ro:'Iubirea nu se găsește gata făcută; se face. În fiecare zi, puțin, ca pâinea.',en:'Love is not found ready-made; it is made. A little every day, like bread.',pt:'O amor não se encontra pronto; faz-se. Um pouco todos os dias, como o pão.'},inv:{ro:'Frământă azi aluatul: un gest de iubire lucrată.',en:'Knead the dough today: one act of worked love.',pt:'Amassa hoje a massa: um gesto de amor trabalhado.'}},
  {el:'love',kw:{ro:'Inima largă',en:'The Wide Heart',pt:'O Coração Largo'},t:{ro:'Inima nu se umple ca un pahar; se lărgește ca un cer. E loc în ea pentru tot ce iubești.',en:'The heart does not fill like a glass; it widens like a sky. There is room in it for all you love.',pt:'O coração não se enche como um copo; alarga-se como um céu. Nele cabe tudo o que amas.'},inv:{ro:'Mai fă azi loc în inimă pentru încă un om.',en:'Make room in your heart for one more person today.',pt:'Faz hoje lugar no coração para mais uma pessoa.'}},

  /* ———————— CERCUL CURAJULUI ———————— */
  {el:'brave',kw:{ro:'Primul pas tremurat',en:'The Trembling First Step',pt:'O Primeiro Passo Trémulo'},t:{ro:'Curajul nu așteaptă să nu-i mai tremure genunchii. Merge cu ei tremurând.',en:'Courage does not wait for its knees to stop shaking. It walks with them shaking.',pt:'A coragem não espera que os joelhos parem de tremer. Caminha com eles a tremer.'},inv:{ro:'Fă azi pasul, cu tremur cu tot.',en:'Take the step today, tremble and all.',pt:'Dá hoje o passo, com tremor e tudo.'}},
  {el:'brave',kw:{ro:'Frica-tovarăș',en:'Fear the Companion',pt:'O Medo Companheiro'},t:{ro:'Frica nu e dușmanul drumului; e tovarășul lui gălăgios. Lasă-l să vorbească; tu condu.',en:'Fear is not the road’s enemy; it is its noisy companion. Let it talk; you drive.',pt:'O medo não é o inimigo do caminho; é o seu companheiro barulhento. Deixa-o falar; tu conduzes.'},inv:{ro:'Ia frica de mână azi și mergeți amândoi înainte.',en:'Take fear by the hand today and walk on together.',pt:'Dá hoje a mão ao medo e caminhem juntos.'}},
  {el:'brave',kw:{ro:'Adevărul rostit',en:'The Spoken Truth',pt:'A Verdade Dita'},t:{ro:'Un adevăr spus cu blândețe cântărește cât o mie de tăceri diplomatice.',en:'One truth spoken gently outweighs a thousand diplomatic silences.',pt:'Uma verdade dita com doçura pesa mais do que mil silêncios diplomáticos.'},inv:{ro:'Spune azi blând un adevăr pe care îl tot ocolești.',en:'Speak gently today a truth you keep avoiding.',pt:'Diz hoje com doçura uma verdade que evitas.'}},
  {el:'brave',kw:{ro:'Cererea de ajutor',en:'Asking for Help',pt:'O Pedido de Ajuda'},t:{ro:'A cere ajutor nu e a te da bătut; e a lupta mai departe cu două brațe în plus.',en:'Asking for help is not surrender; it is fighting on with two extra arms.',pt:'Pedir ajuda não é render-se; é continuar a lutar com dois braços a mais.'},inv:{ro:'Cere azi ajutorul pe care îl amâni de o săptămână.',en:'Ask today for the help you have postponed a week.',pt:'Pede hoje a ajuda que adias há uma semana.'}},
  {el:'brave',kw:{ro:'Nu-ul vertical',en:'The Upright No',pt:'O Não Vertical'},t:{ro:'Cel mai scurt act de curaj are două litere. Spus drept, îți dă înapoi zile întregi de viață.',en:'The shortest act of courage has two letters. Said upright, it returns whole days of life to you.',pt:'O mais curto ato de coragem tem três letras. Dito de pé, devolve-te dias inteiros de vida.'},inv:{ro:'Spune azi un „nu" pe care îl datorezi de mult.',en:'Say today the no you have long owed.',pt:'Diz hoje o «não» que deves há muito.'}},
  {el:'brave',kw:{ro:'Da-ul cu inima bătând',en:'The Yes with a Beating Heart',pt:'O Sim de Coração aos Saltos'},t:{ro:'Unele „da"-uri se spun cu inima bubuind. Acelea deschid ușile care contează.',en:'Some yeses are said with a pounding heart. Those open the doors that matter.',pt:'Alguns «sins» dizem-se com o coração aos saltos. Esses abrem as portas que importam.'},inv:{ro:'Ce „da" îți bate inima? Spune-l azi.',en:'Which yes makes your heart pound? Say it today.',pt:'Que «sim» te faz bater o coração? Di-lo hoje.'}},
  {el:'brave',kw:{ro:'Începutul din nou',en:'Beginning Again',pt:'O Recomeço'},t:{ro:'A începe din nou nu șterge ce a fost; pune ce a fost la lucru. Ruina veche e carieră de piatră.',en:'Beginning again does not erase what was; it puts it to work. The old ruin is a quarry.',pt:'Recomeçar não apaga o que foi; põe-no a trabalhar. A ruína antiga é pedreira.'},inv:{ro:'Zidește azi cu o piatră din vechea ruină.',en:'Build today with one stone from the old ruin.',pt:'Constrói hoje com uma pedra da ruína antiga.'}},
  {el:'brave',kw:{ro:'Riscul măsurat',en:'The Measured Risk',pt:'O Risco Medido'},t:{ro:'Cine nu riscă nimic riscă totul: o viață întreagă neîncepută.',en:'Who risks nothing risks everything: a whole life never begun.',pt:'Quem nada arrisca arrisca tudo: uma vida inteira por começar.'},inv:{ro:'Asumă azi un risc mic cu folos mare.',en:'Take one small risk with a large reward today.',pt:'Assume hoje um pequeno risco de grande fruto.'}},
  {el:'brave',kw:{ro:'Statul singur',en:'Standing Alone',pt:'Estar Só de Pé'},t:{ro:'Uneori curajul e să rămâi singurul care nu aplaudă. Mulțimea trece; coloana ta rămâne.',en:'Sometimes courage is remaining the only one not applauding. The crowd passes; your spine remains.',pt:'Às vezes a coragem é ficar o único que não aplaude. A multidão passa; a tua coluna fica.'},inv:{ro:'Unde taci doar ca să nu ieși din rând?',en:'Where do you stay silent just to stay in line?',pt:'Onde te calas só para não sair da fila?'}},
  {el:'brave',kw:{ro:'Lupta aleasă',en:'The Chosen Battle',pt:'A Batalha Escolhida'},t:{ro:'Nu orice front merită sângele tău. Curajul înțelept își alege bătălia; restul le lasă vântului.',en:'Not every front deserves your blood. Wise courage picks its battle; the rest it leaves to the wind.',pt:'Nem toda a frente merece o teu sangue. A coragem sábia escolhe a sua batalha; o resto deixa ao vento.'},inv:{ro:'Din trei lupte de azi, alege una. Restul, vântului.',en:'Of today’s three fights, choose one. The rest, to the wind.',pt:'De três lutas de hoje, escolhe uma. O resto, ao vento.'}},
  {el:'brave',kw:{ro:'Retragerea înțeleaptă',en:'The Wise Retreat',pt:'A Retirada Sábia'},t:{ro:'A te retrage la timp nu e fugă; e păstrarea puterilor pentru lupta care e a ta.',en:'Retreating in time is not flight; it is keeping your strength for the fight that is yours.',pt:'Retirar-se a tempo não é fuga; é guardar forças para a luta que é tua.'},inv:{ro:'Din ce bătălie străină te retragi azi?',en:'From which foreign battle do you withdraw today?',pt:'De que batalha alheia te retiras hoje?'}},
  {el:'brave',kw:{ro:'Obrazul gol',en:'The Bare Face',pt:'O Rosto Nu'},t:{ro:'Să te arăți fără mască cere mai mult curaj decât orice armură. Și câștigă mai mult.',en:'Showing yourself unmasked takes more courage than any armor. And wins more.',pt:'Mostrares-te sem máscara exige mais coragem do que qualquer armadura. E ganha mais.'},inv:{ro:'Scoate azi masca într-o discuție care contează.',en:'Remove the mask today in one conversation that matters.',pt:'Tira hoje a máscara numa conversa que importa.'}},
  {el:'brave',kw:{ro:'Greșeala mărturisită',en:'The Confessed Mistake',pt:'O Erro Confessado'},t:{ro:'„Am greșit" — două vorbe care dor un minut și vindecă ani.',en:'“I was wrong” — three words that hurt a minute and heal for years.',pt:'«Errei» — uma palavra que dói um minuto e cura anos.'},inv:{ro:'Mărturisește azi o greșeală fără „dar".',en:'Confess one mistake today without a “but.”',pt:'Confessa hoje um erro sem «mas».'}},
  {el:'brave',kw:{ro:'Întrebarea cu voce tare',en:'The Question Aloud',pt:'A Pergunta em Voz Alta'},t:{ro:'În fiecare sală e cineva care nu înțelege și tace. Cel care întreabă îi eliberează pe toți.',en:'In every room someone does not understand and stays silent. The one who asks frees them all.',pt:'Em cada sala há alguém que não entende e se cala. Quem pergunta liberta todos.'},inv:{ro:'Pune azi întrebarea „proastă". E cea mai bună.',en:'Ask the “dumb” question today. It is the best one.',pt:'Faz hoje a pergunta «parva». É a melhor.'}},
  {el:'brave',kw:{ro:'Pielea nouă',en:'The New Skin',pt:'A Pele Nova'},t:{ro:'Șarpele care nu-și leapădă pielea moare în ea. Schimbarea doare exact cât trebuie.',en:'The snake that will not shed its skin dies inside it. Change hurts exactly as much as it must.',pt:'A serpente que não muda de pele morre dentro dela. A mudança dói exatamente o necessário.'},inv:{ro:'Ce piele veche te strânge? Începe lepădarea.',en:'What old skin binds you? Begin the shedding.',pt:'Que pele velha te aperta? Começa a muda.'}},
  {el:'brave',kw:{ro:'Scena',en:'The Stage',pt:'O Palco'},t:{ro:'Tracul e semn că îți pasă. Urcă pe scenă cu el; publicul iartă tremurul, nu absența.',en:'Stage fright means you care. Go up with it; the audience forgives trembling, not absence.',pt:'O nervosismo é sinal de que te importas. Sobe com ele; o público perdoa o tremor, não a ausência.'},inv:{ro:'Arată-te azi acolo unde îți vine să te ascunzi.',en:'Show up today exactly where you wish to hide.',pt:'Aparece hoje exatamente onde te apetece esconder.'}},
  {el:'brave',kw:{ro:'Apărarea celui slab',en:'Defending the Weak',pt:'A Defesa do Fraco'},t:{ro:'Curajul cel mai curat nu se apără pe sine; apără pe cel care nu se poate apăra.',en:'The purest courage does not defend itself; it defends the one who cannot.',pt:'A coragem mais pura não se defende a si; defende quem não pode defender-se.'},inv:{ro:'Ia azi partea cuiva absent din discuție.',en:'Take the side of someone absent from the room today.',pt:'Toma hoje o partido de alguém ausente da sala.'}},
  {el:'brave',kw:{ro:'Frica de bucurie',en:'The Fear of Joy',pt:'O Medo da Alegria'},t:{ro:'Unii se tem de bucurie ca de o datorie care va veni la plată. Bucură-te fără să aștepți factura.',en:'Some fear joy like a debt that will come due. Rejoice without expecting the bill.',pt:'Alguns temem a alegria como uma dívida que vencerá. Alegra-te sem esperar a fatura.'},inv:{ro:'Primește azi o bucurie fără „să vedem cât ține".',en:'Receive one joy today without “let’s see how long it lasts.”',pt:'Recebe hoje uma alegria sem «vamos ver quanto dura».'}},
  {el:'brave',kw:{ro:'Hotarul apărat',en:'The Defended Border',pt:'A Fronteira Defendida'},t:{ro:'Cine nu-și apără hotarul își mută casa în curtea altuia. Curajul păzește poarta fără să urască.',en:'Who does not defend their border ends up living in another’s yard. Courage guards the gate without hatred.',pt:'Quem não defende a sua fronteira acaba a morar no quintal alheio. A coragem guarda o portão sem ódio.'},inv:{ro:'Păzește azi o graniță călcată des, cu calm.',en:'Guard one often-crossed boundary today, calmly.',pt:'Guarda hoje, com calma, uma fronteira muitas vezes pisada.'}},
  {el:'brave',kw:{ro:'Visul mărturisit',en:'The Confessed Dream',pt:'O Sonho Confessado'},t:{ro:'Spune-ți visul cu voce tare și va începe să existe. Ținut în piept, rămâne oftat.',en:'Say your dream aloud and it begins to exist. Kept in the chest, it stays a sigh.',pt:'Diz o teu sonho em voz alta e ele começa a existir. Guardado no peito, fica suspiro.'},inv:{ro:'Mărturisește azi visul unui om de încredere.',en:'Confess the dream to one trusted person today.',pt:'Confessa hoje o sonho a uma pessoa de confiança.'}},
  {el:'brave',kw:{ro:'Răbdarea vitează',en:'Brave Patience',pt:'A Paciência Valente'},t:{ro:'E un curaj și în a rămâne: în a duce ziua grea până la capăt fără să faci rău nimănui.',en:'There is courage in staying too: in carrying the hard day to its end without harming anyone.',pt:'Também há coragem em ficar: em levar o dia difícil até ao fim sem ferir ninguém.'},inv:{ro:'Azi, dacă nu poți străluci, măcar nu răni. E destul.',en:'Today, if you cannot shine, at least do not wound. It is enough.',pt:'Hoje, se não podes brilhar, ao menos não firas. É suficiente.'}},
  {el:'brave',kw:{ro:'Săritura',en:'The Leap',pt:'O Salto'},t:{ro:'Puntea se arată uneori abia după săritură. Nu toate garanțiile vin înainte.',en:'Sometimes the bridge appears only after the leap. Not all guarantees come first.',pt:'Às vezes a ponte só aparece depois do salto. Nem todas as garantias vêm antes.'},inv:{ro:'Ce săritură amâni în așteptarea garanției?',en:'What leap do you delay awaiting a guarantee?',pt:'Que salto adias à espera de garantia?'}},
  {el:'brave',kw:{ro:'Rana arătată',en:'The Shown Wound',pt:'A Ferida Mostrada'},t:{ro:'Rana ascunsă coace; rana arătată medicului potrivit se închide. Alege-ți bine medicii.',en:'A hidden wound festers; a wound shown to the right healer closes. Choose your healers well.',pt:'A ferida escondida infeta; a ferida mostrada ao curador certo fecha. Escolhe bem os teus curadores.'},inv:{ro:'Arată azi rana omului care știe să o țină.',en:'Show the wound today to one who can hold it.',pt:'Mostra hoje a ferida a quem sabe segurá-la.'}},
  {el:'brave',kw:{ro:'Curajul de a fi mic',en:'The Courage to Be Small',pt:'A Coragem de Ser Pequeno'},t:{ro:'Să accepți că ești începător, mic, pe drum — acesta e curajul din care cresc toate celelalte.',en:'To accept being a beginner, small, on the way — this is the courage all others grow from.',pt:'Aceitar ser principiante, pequeno, a caminho — esta é a coragem de que crescem todas as outras.'},inv:{ro:'Fii azi, undeva, cel care învață. Cu plăcere.',en:'Be the learner somewhere today. Gladly.',pt:'Sê hoje, nalgum lugar, o aprendiz. Com gosto.'}},
  {el:'brave',kw:{ro:'Glasul dintâi',en:'The First Voice',pt:'A Primeira Voz'},t:{ro:'Cineva trebuie să spună primul „mie nu-mi pare în regulă". De obicei, toți așteptau.',en:'Someone must be first to say “this does not seem right to me.” Usually, everyone was waiting.',pt:'Alguém tem de ser o primeiro a dizer «isto não me parece bem». Normalmente, todos esperavam.'},inv:{ro:'Fii azi glasul dintâi într-o chestiune mică.',en:'Be the first voice in one small matter today.',pt:'Sê hoje a primeira voz numa questão pequena.'}},
  {el:'brave',kw:{ro:'Ochii în ochi',en:'Eye to Eye',pt:'Olhos nos Olhos'},t:{ro:'Conversația grea, față în față, e poarta pe care intră tot restul vieții tale mai bune.',en:'The hard conversation, face to face, is the gate through which the rest of your better life enters.',pt:'A conversa difícil, cara a cara, é a porta por onde entra o resto da tua vida melhor.'},inv:{ro:'Programează azi discuția pe care o eviți.',en:'Schedule today the talk you avoid.',pt:'Marca hoje a conversa que evitas.'}},
  {el:'brave',kw:{ro:'Puterea lacrimii',en:'The Strength of Tears',pt:'A Força da Lágrima'},t:{ro:'Bărbații și femeile cu adevărat tari nu se rușinează de lacrimă. Se rușinează de împietrire.',en:'Truly strong people are not ashamed of tears. They are ashamed of turning to stone.',pt:'As pessoas verdadeiramente fortes não se envergonham da lágrima. Envergonham-se de virar pedra.'},inv:{ro:'Dacă vine lacrima azi, dă-i drumul cu demnitate.',en:'If tears come today, let them fall with dignity.',pt:'Se a lágrima vier hoje, deixa-a cair com dignidade.'}},
  {el:'brave',kw:{ro:'Zidul și poarta',en:'The Wall and the Gate',pt:'O Muro e a Porta'},t:{ro:'Orice zid are o poartă pentru cel care o caută mai mult decât se plânge de zid.',en:'Every wall has a gate for the one who seeks it more than they complain about the wall.',pt:'Todo o muro tem uma porta para quem a procura mais do que se queixa do muro.'},inv:{ro:'La zidul de azi, caută poarta zece minute înainte să oftezi.',en:'At today’s wall, search for the gate ten minutes before sighing.',pt:'No muro de hoje, procura a porta dez minutos antes de suspirar.'}},
  {el:'brave',kw:{ro:'Numele fricii',en:'Fear’s Name',pt:'O Nome do Medo'},t:{ro:'Frica fără nume e uriașă; numită exact, are dimensiunile ei reale — de obicei mici.',en:'Nameless fear is gigantic; named precisely, it takes its true size — usually small.',pt:'O medo sem nome é gigante; nomeado com precisão, toma o seu tamanho real — geralmente pequeno.'},inv:{ro:'Scrie frica de azi într-o singură propoziție exactă.',en:'Write today’s fear in one exact sentence.',pt:'Escreve o medo de hoje numa única frase exata.'}},
  {el:'brave',kw:{ro:'Steagul mic',en:'The Small Flag',pt:'A Pequena Bandeira'},t:{ro:'Nu trebuie să cucerești muntele azi; e destul să înfigi steagul pe prima movilă.',en:'You need not conquer the mountain today; planting the flag on the first mound is enough.',pt:'Não precisas de conquistar a montanha hoje; basta cravar a bandeira no primeiro morro.'},inv:{ro:'Câștigă azi o victorie de buzunar. Numeşte-o victorie.',en:'Win a pocket victory today. Call it a victory.',pt:'Ganha hoje uma vitória de bolso. Chama-lhe vitória.'}},
  {el:'brave',kw:{ro:'Cuvântul ținut',en:'The Kept Word',pt:'A Palavra Mantida'},t:{ro:'Curajos e și cel care își ține cuvântul când s-a scumpit ținerea lui.',en:'Brave too is the one who keeps their word when keeping it has grown costly.',pt:'Corajoso é também quem mantém a palavra quando mantê-la ficou caro.'},inv:{ro:'Ține azi o promisiune devenită incomodă.',en:'Keep one promise today that became inconvenient.',pt:'Mantém hoje uma promessa que se tornou incómoda.'}},
  {el:'brave',kw:{ro:'Inima în palmă',en:'The Heart in the Palm',pt:'O Coração na Palma'},t:{ro:'Să iubești primul, să saluți primul, să ierți primul: trei viteji care nu fac zgomot.',en:'To love first, greet first, forgive first: three braveries that make no noise.',pt:'Amar primeiro, cumprimentar primeiro, perdoar primeiro: três coragens que não fazem barulho.'},inv:{ro:'Fii azi primul: la salut, la iertare sau la drag.',en:'Be first today: in greeting, forgiving, or loving.',pt:'Sê hoje o primeiro: a cumprimentar, a perdoar ou a amar.'}},
  {el:'brave',kw:{ro:'Curajul liniștit',en:'The Quiet Courage',pt:'A Coragem Tranquila'},t:{ro:'Cel mai des, curajul nu urlă. E vocea mică de seară: „mâine încerc din nou".',en:'Most often, courage does not roar. It is the small evening voice: “tomorrow I try again.”',pt:'Na maioria das vezes, a coragem não ruge. É a pequena voz da noite: «amanhã tento outra vez».'},inv:{ro:'Spune-ți-o diseară, orice-a fost azi: „mâine încerc din nou".',en:'Say it tonight, whatever today was: “tomorrow I try again.”',pt:'Di-lo esta noite, seja como for o dia: «amanhã tento outra vez».'}},

  /* ———————— CERCUL NOPȚII ———————— */
  {el:'night',kw:{ro:'Somnul',en:'Sleep',pt:'O Sono'},t:{ro:'Somnul nu e timp pierdut; e atelierul în care noaptea îți repară ziua.',en:'Sleep is not lost time; it is the workshop where night repairs your day.',pt:'O sono não é tempo perdido; é a oficina onde a noite repara o teu dia.'},inv:{ro:'Culcă-te azi cu o jumătate de oră mai devreme, ca un dar.',en:'Go to bed half an hour earlier today, as a gift.',pt:'Deita-te hoje meia hora mais cedo, como um presente.'}},
  {el:'night',kw:{ro:'Visul',en:'The Dream',pt:'O Sonho'},t:{ro:'Noaptea, mintea îți vorbește în imagini ce nu îndrăznește ziua în cuvinte.',en:'At night the mind tells you in images what it dares not say by day in words.',pt:'À noite, a mente diz-te em imagens o que de dia não ousa dizer em palavras.'},inv:{ro:'Dimineață, înainte de telefon, întreabă-te ce ai visat.',en:'In the morning, before the phone, ask what you dreamed.',pt:'De manhã, antes do telemóvel, pergunta-te o que sonhaste.'}},
  {el:'night',kw:{ro:'Întunericul-învățător',en:'Darkness the Teacher',pt:'A Escuridão Mestra'},t:{ro:'În plină lumină nu se văd stelele. Unele adevăruri au nevoie de întuneric ca să se arate.',en:'In full light the stars cannot be seen. Some truths need darkness to appear.',pt:'Em plena luz não se veem as estrelas. Algumas verdades precisam de escuridão para aparecer.'},inv:{ro:'Ce a scos la iveală o perioadă întunecată a ta?',en:'What did one of your dark seasons reveal?',pt:'O que revelou uma das tuas estações escuras?'}},
  {el:'night',kw:{ro:'Steaua',en:'The Star',pt:'A Estrela'},t:{ro:'Cu cât noaptea e mai adâncă, cu atât steaua se vede mai bine. Ține minte asta în nopțile tale.',en:'The deeper the night, the clearer the star. Remember this in your own nights.',pt:'Quanto mais funda a noite, mais clara a estrela. Lembra-o nas tuas noites.'},inv:{ro:'În greul de azi, caută punctul care încă luminează.',en:'In today’s weight, find the point that still shines.',pt:'No peso de hoje, encontra o ponto que ainda brilha.'}},
  {el:'night',kw:{ro:'Luna',en:'The Moon',pt:'A Lua'},t:{ro:'Luna nu se rușinează că lumina ei e primită. Nici tu: primim toți lumina de undeva.',en:'The moon is not ashamed its light is received. Nor should you be: we all receive light from somewhere.',pt:'A lua não se envergonha de a sua luz ser recebida. Nem tu: todos recebemos luz de algum lugar.'},inv:{ro:'Numește-ți azi un soare: cine te luminează?',en:'Name one of your suns today: who lights you?',pt:'Nomeia hoje um dos teus sóis: quem te ilumina?'}},
  {el:'night',kw:{ro:'Veghea',en:'The Vigil',pt:'A Vigília'},t:{ro:'Sunt nopți în care nu se doarme: la căpătâi, la gânduri, la rugă. Veghea e și ea o lucrare.',en:'There are nights without sleep: at bedsides, with thoughts, in prayer. The vigil too is a work.',pt:'Há noites em que não se dorme: à cabeceira, com pensamentos, em oração. A vigília também é obra.'},inv:{ro:'Dacă nu poți dormi, nu te lupta: veghează frumos.',en:'If you cannot sleep, do not fight: keep a beautiful vigil.',pt:'Se não consegues dormir, não lutes: vela com beleza.'}},
  {el:'night',kw:{ro:'Ora fără martori',en:'The Hour Without Witnesses',pt:'A Hora Sem Testemunhas'},t:{ro:'Cine ești când nu te vede nimeni — acela ești. Noaptea știe adevărul acesta.',en:'Who you are when no one sees — that is who you are. The night knows this truth.',pt:'Quem és quando ninguém vê — esse és tu. A noite conhece essa verdade.'},inv:{ro:'Fă azi, nevăzut, un lucru de care ai fi mândru văzut.',en:'Do unseen today what would make you proud if seen.',pt:'Faz hoje, sem seres visto, algo de que te orgulharias visto.'}},
  {el:'night',kw:{ro:'Gândurile de la miezul nopții',en:'Midnight Thoughts',pt:'Os Pensamentos da Meia-Noite'},t:{ro:'La miezul nopții toate par mai grave. Nu semna nimic în instanța aceea; judecata e trucată.',en:'At midnight everything seems graver. Sign nothing in that courtroom; the trial is rigged.',pt:'À meia-noite tudo parece mais grave. Não assines nada nesse tribunal; o julgamento é viciado.'},inv:{ro:'Gândul negru de noapte: reia-l mâine la lumină.',en:'The night’s dark thought: retry it tomorrow in daylight.',pt:'O pensamento negro da noite: julga-o amanhã à luz do dia.'}},
  {el:'night',kw:{ro:'Seara bună',en:'The Good Evening',pt:'A Boa Noite'},t:{ro:'Ziua se încheie cum i-o închei. Un sfert de oră blând seara spală opt ore aspre.',en:'The day ends the way you end it. A gentle quarter hour at night washes eight rough ones.',pt:'O dia acaba como o acabas. Um quarto de hora suave à noite lava oito horas ásperas.'},inv:{ro:'Fă-ți diseară un mic ritual de încheiere: ceai, pagină, liniște.',en:'Make a small closing ritual tonight: tea, a page, quiet.',pt:'Faz esta noite um pequeno ritual de fecho: chá, uma página, silêncio.'}},
  {el:'night',kw:{ro:'Lepădarea zilei',en:'Shedding the Day',pt:'O Despir do Dia'},t:{ro:'Nu duce ziua în pat. Hainele ei — grijile, replicile, lista — se lasă la ușă, cu pantofii.',en:'Do not take the day to bed. Its clothes — worries, retorts, lists — stay at the door, with the shoes.',pt:'Não leves o dia para a cama. As roupas dele — preocupações, respostas, listas — ficam à porta, com os sapatos.'},inv:{ro:'Scrie pe hârtie ce rămâne pe mâine. Apoi lasă-l acolo.',en:'Write down what waits for tomorrow. Then leave it there.',pt:'Escreve o que fica para amanhã. Depois deixa-o lá.'}},
  {el:'night',kw:{ro:'Rugăciunea de seară',en:'The Evening Prayer',pt:'A Oração da Noite'},t:{ro:'Seara, pune ziua în mâini mai mari decât ale tale. Somnul vine mai ușor la cel care a predat tura.',en:'At night, place the day in hands larger than yours. Sleep comes easier to the one who has handed over the watch.',pt:'À noite, põe o dia em mãos maiores que as tuas. O sono vem mais fácil a quem entregou o turno.'},inv:{ro:'Încheie ziua cu trei mulțumiri, ca trei lumânări.',en:'Close the day with three thanks, like three candles.',pt:'Fecha o dia com três agradecimentos, como três velas.'}},
  {el:'night',kw:{ro:'Odihna fără vină',en:'Rest Without Guilt',pt:'O Descanso Sem Culpa'},t:{ro:'Nu trebuie să meriți odihna; o meriți fiind viu. Și pământul stă o iarnă întreagă.',en:'You need not earn rest; being alive earns it. Even the earth lies fallow a whole winter.',pt:'Não precisas de merecer o descanso; estar vivo já o merece. Até a terra descansa um inverno inteiro.'},inv:{ro:'Odihnește-te azi fără să te scuzi nimănui.',en:'Rest today without apologizing to anyone.',pt:'Descansa hoje sem pedir desculpa a ninguém.'}},
  {el:'night',kw:{ro:'Cortina',en:'The Curtain',pt:'A Cortina'},t:{ro:'Orice zi e o piesă; are nevoie de cortină. Fără sfârșituri, nu există începuturi.',en:'Every day is a play; it needs its curtain. Without endings there are no beginnings.',pt:'Cada dia é uma peça; precisa da sua cortina. Sem fins não há começos.'},inv:{ro:'Trage azi cortina la ora hotărâtă, nu când cazi.',en:'Draw the curtain at the chosen hour, not when you collapse.',pt:'Corre a cortina à hora marcada, não quando caíres.'}},
  {el:'night',kw:{ro:'Cerul înstelat',en:'The Starry Sky',pt:'O Céu Estrelado'},t:{ro:'Privește cerul nopții zece minute și problemele tale își recapătă dimensiunile: mici, ale unui om iubit de un univers mare.',en:'Watch the night sky ten minutes and your troubles regain their size: small, belonging to someone held by a vast universe.',pt:'Olha o céu noturno dez minutos e os teus problemas retomam o tamanho: pequenos, de alguém amparado por um universo vasto.'},inv:{ro:'Ieși diseară sub cer. Doar privește.',en:'Step out under the sky tonight. Just look.',pt:'Sai esta noite para debaixo do céu. Só olha.'}},
  {el:'night',kw:{ro:'Frica de întuneric',en:'Fear of the Dark',pt:'O Medo do Escuro'},t:{ro:'Nu întunericul te sperie, ci ce pui tu în el. Golul se umple cu ce aduci de acasă.',en:'It is not the dark that frightens you, but what you place in it. The void fills with what you bring from home.',pt:'Não é o escuro que te assusta, mas o que pões nele. O vazio enche-se com o que trazes de casa.'},inv:{ro:'Intră azi calm într-un „întuneric": o necunoscută mică.',en:'Enter one small “dark” calmly today: a little unknown.',pt:'Entra hoje com calma num pequeno «escuro»: uma incógnita.'}},
  {el:'night',kw:{ro:'Cântecul de leagăn',en:'The Lullaby',pt:'A Canção de Embalar'},t:{ro:'Adormi cum adorm copiii iubiți: cu cineva care îți spune, fie și în gând, „ești în siguranță".',en:'Fall asleep as loved children do: with someone saying, even in thought, “you are safe.”',pt:'Adormece como as crianças amadas: com alguém a dizer, nem que seja em pensamento, «estás em segurança».'},inv:{ro:'Spune-ți diseară, la culcare: „am făcut destul; sunt în siguranță".',en:'Tell yourself at bedtime: “I did enough; I am safe.”',pt:'Diz a ti mesmo ao deitar: «fiz o suficiente; estou seguro».'}},
  {el:'night',kw:{ro:'Miezul iernii',en:'Midwinter',pt:'O Coração do Inverno'},t:{ro:'În miezul cel mai adânc al iernii, ziua începe deja să crească. Așa și în nopțile vieții.',en:'In the deepest midwinter, the days have already begun to grow. So it is in life’s nights.',pt:'No mais fundo do inverno, os dias já começaram a crescer. Assim é nas noites da vida.'},inv:{ro:'În cel mai greu punct, amintește-ți: creșterea a început.',en:'At the hardest point, remember: the growing has begun.',pt:'No ponto mais difícil, lembra: o crescimento já começou.'}},
  {el:'night',kw:{ro:'Paznicul de noapte',en:'The Night Watchman',pt:'O Guarda-Noturno'},t:{ro:'Cineva veghează întotdeauna: un far, o mamă, o stea, un Dumnezeu. Nimeni nu doarme nepăzit.',en:'Someone is always keeping watch: a lighthouse, a mother, a star, a God. No one sleeps unguarded.',pt:'Alguém vela sempre: um farol, uma mãe, uma estrela, um Deus. Ninguém dorme sem guarda.'},inv:{ro:'Adormi diseară cu gândul la cine veghează pentru tine.',en:'Fall asleep tonight thinking of who keeps watch for you.',pt:'Adormece esta noite a pensar em quem vela por ti.'}},
  {el:'night',kw:{ro:'Visul de peste zi',en:'The Waking Dream',pt:'O Sonho Acordado'},t:{ro:'Reveria nu e lene; e mintea care respiră. Din plimbările ei fără țintă se întoarce cu comori.',en:'Daydreaming is not laziness; it is the mind breathing. From its aimless walks it returns with treasure.',pt:'O devaneio não é preguiça; é a mente a respirar. Dos seus passeios sem rumo volta com tesouros.'},inv:{ro:'Lasă-ți azi mintea zece minute în plimbare liberă.',en:'Let the mind wander freely ten minutes today.',pt:'Deixa hoje a mente vaguear livre dez minutos.'}},
  {el:'night',kw:{ro:'Umbra',en:'The Shadow',pt:'A Sombra'},t:{ro:'Umbra ta e dovada că stai în lumină. Nu fugi de ea; întoarce-te doar cu fața spre soare.',en:'Your shadow is proof you stand in light. Do not flee it; simply turn your face to the sun.',pt:'A tua sombra é prova de que estás na luz. Não fujas dela; volta apenas o rosto para o sol.'},inv:{ro:'Recunoaște azi o umbră a ta fără să te sperii de ea.',en:'Acknowledge one of your shadows today without fright.',pt:'Reconhece hoje uma sombra tua sem susto.'}},
  {el:'night',kw:{ro:'Tăcerea nopții',en:'The Night’s Silence',pt:'O Silêncio da Noite'},t:{ro:'Noaptea, lumea își coboară vocea. Coboar-o și tu: ultimele gânduri să fie șoapte bune.',en:'At night the world lowers its voice. Lower yours too: let the last thoughts be kind whispers.',pt:'À noite o mundo baixa a voz. Baixa a tua também: que os últimos pensamentos sejam sussurros bons.'},inv:{ro:'Fără ecrane în ultima jumătate de oră. Doar șoapte.',en:'No screens in the last half hour. Only whispers.',pt:'Sem ecrãs na última meia hora. Só sussurros.'}},
  {el:'night',kw:{ro:'Roua',en:'The Dew',pt:'O Orvalho'},t:{ro:'Noaptea lasă rouă: mici daruri limpezi pentru cine se trezește devreme. Nimic nu se pierde peste noapte.',en:'Night leaves dew: small clear gifts for the early riser. Nothing is lost overnight.',pt:'A noite deixa orvalho: pequenos dons límpidos para quem acorda cedo. Nada se perde durante a noite.'},inv:{ro:'Trezește-te mâine cât să prinzi liniștea dinaintea lumii.',en:'Wake tomorrow in time to catch the hush before the world.',pt:'Acorda amanhã a tempo de apanhar a calma antes do mundo.'}},
  {el:'night',kw:{ro:'Podul de vise',en:'The Bridge of Dreams',pt:'A Ponte dos Sonhos'},t:{ro:'Seara pune întrebarea, dimineața aduce răspunsul. Somnul e podul dintre ele.',en:'Evening asks the question; morning brings the answer. Sleep is the bridge between them.',pt:'A noite faz a pergunta; a manhã traz a resposta. O sono é a ponte entre elas.'},inv:{ro:'Pune-i somnului o întrebare la culcare. Ascultă dimineața.',en:'Give sleep a question at bedtime. Listen in the morning.',pt:'Dá ao sono uma pergunta ao deitar. Escuta de manhã.'}},
  {el:'night',kw:{ro:'Lumina din fereastră',en:'The Window Light',pt:'A Luz da Janela'},t:{ro:'O fereastră luminată în noapte înseamnă mereu același lucru: ești așteptat undeva.',en:'A lit window in the night always means the same thing: somewhere, you are expected.',pt:'Uma janela acesa na noite significa sempre o mesmo: em algum lugar, és esperado.'},inv:{ro:'Fii azi fereastra luminată pentru cineva.',en:'Be the lit window for someone today.',pt:'Sê hoje a janela acesa para alguém.'}},
  {el:'night',kw:{ro:'Ceasul dintre zile',en:'The Hour Between Days',pt:'A Hora Entre os Dias'},t:{ro:'Miezul nopții e o graniță blândă: o zi și-a iertat greșelile, alta nu le-a făcut încă.',en:'Midnight is a gentle border: one day has forgiven its faults, the other has not yet made any.',pt:'A meia-noite é uma fronteira suave: um dia já perdoou os erros, o outro ainda não os cometeu.'},inv:{ro:'La miezul nopții, dacă ești treaz, iartă ziua întreagă.',en:'At midnight, if awake, forgive the whole day.',pt:'À meia-noite, se estiveres acordado, perdoa o dia inteiro.'}},
  {el:'night',kw:{ro:'Greierii',en:'The Crickets',pt:'Os Grilos'},t:{ro:'Noaptea are orchestra ei măruntă care cântă pentru nimeni și pentru toți. Gratuitatea e și ea o lecție.',en:'Night has its small orchestra playing for no one and for all. Gratuitousness too is a lesson.',pt:'A noite tem a sua pequena orquestra que toca para ninguém e para todos. A gratuitidade também é lição.'},inv:{ro:'Fă azi un lucru frumos care nu folosește la nimic.',en:'Do one beautiful useless thing today.',pt:'Faz hoje uma coisa bela que não serve para nada.'}},
  {el:'night',kw:{ro:'Oboseala cinstită',en:'Honest Tiredness',pt:'O Cansaço Honesto'},t:{ro:'E o oboseală rea, a risipei, și una dulce, a lucrului cu rost. Doar a doua se odihnește complet.',en:'There is a bad tiredness, of waste, and a sweet one, of meaningful work. Only the second rests fully.',pt:'Há um cansaço mau, do desperdício, e um doce, do trabalho com sentido. Só o segundo descansa por completo.'},inv:{ro:'Obosește azi pe lucruri care merită oboseala.',en:'Tire yourself today on things worth the tiring.',pt:'Cansa-te hoje com coisas que merecem o cansaço.'}},
  {el:'night',kw:{ro:'Patul făcut',en:'The Made Bed',pt:'A Cama Feita'},t:{ro:'Seara îi mulțumești dimineții care ți-a făcut patul. Fă-i și tu dimineții de mâine un bine de cu seară.',en:'At night you thank the morning that made your bed. Do tomorrow’s morning a kindness tonight.',pt:'À noite agradeces à manhã que te fez a cama. Faz também esta noite um bem à manhã de amanhã.'},inv:{ro:'Pregătește de cu seară un lucru pentru mâine.',en:'Prepare one thing tonight for tomorrow.',pt:'Prepara esta noite uma coisa para amanhã.'}},
  {el:'night',kw:{ro:'Somnul pământului',en:'The Earth’s Sleep',pt:'O Sono da Terra'},t:{ro:'Sămânța nu se plânge că e îngropată. Știe că întunericul acesta e început, nu sfârșit.',en:'The seed does not complain of being buried. It knows this darkness is a beginning, not an end.',pt:'A semente não se queixa de estar enterrada. Sabe que esta escuridão é começo, não fim.'},inv:{ro:'Ești îngropat în ceva? Poate ești, de fapt, plantat.',en:'Buried in something? Perhaps you are, in fact, planted.',pt:'Enterrado em algo? Talvez estejas, na verdade, plantado.'}},
  {el:'night',kw:{ro:'Farul',en:'The Lighthouse',pt:'O Farol'},t:{ro:'Farul nu aleargă după corăbii. Stă și luminează; cine caută țărmul îl găsește.',en:'The lighthouse does not chase ships. It stands and shines; whoever seeks the shore finds it.',pt:'O farol não corre atrás dos navios. Fica e ilumina; quem procura a costa encontra-o.'},inv:{ro:'Nu convinge azi pe nimeni. Doar luminează constant.',en:'Convince no one today. Just shine steadily.',pt:'Não convenças ninguém hoje. Apenas brilha constante.'}},
  {el:'night',kw:{ro:'Zorii',en:'The Dawn',pt:'A Aurora'},t:{ro:'Nicio noapte din istoria lumii nu a învins vreo dimineață. Statistica asta e de partea ta.',en:'No night in the history of the world has ever defeated a morning. That statistic is on your side.',pt:'Nenhuma noite na história do mundo venceu uma manhã. Essa estatística está do teu lado.'},inv:{ro:'În noaptea grea, repetă: dimineața are scor perfect.',en:'In the hard night, repeat: morning has a perfect record.',pt:'Na noite difícil, repete: a manhã tem um registo perfeito.'}},
  {el:'night',kw:{ro:'Cheia de sub pernă',en:'The Key Under the Pillow',pt:'A Chave Debaixo da Almofada'},t:{ro:'Adormi cu o întrebare bună sub pernă și te trezești cu o ușă întredeschisă.',en:'Sleep with a good question under the pillow and wake with a door ajar.',pt:'Dorme com uma boa pergunta debaixo da almofada e acorda com uma porta entreaberta.'},inv:{ro:'Alege întrebarea de sub pernă pentru la noapte.',en:'Choose tonight’s under-pillow question.',pt:'Escolhe a pergunta desta noite para debaixo da almofada.'}},
  {el:'night',kw:{ro:'Noapte bună',en:'Good Night',pt:'Boa Noite'},t:{ro:'„Noapte bună" e o binecuvântare mică pe care o dăm zilnic fără să știm ce dăm: pace, pază, mâine.',en:'“Good night” is a small blessing we give daily without knowing what we give: peace, guard, tomorrow.',pt:'«Boa noite» é uma pequena bênção que damos todos os dias sem saber o que damos: paz, guarda, amanhã.'},inv:{ro:'Spune diseară „noapte bună" ca pe o binecuvântare adevărată.',en:'Say “good night” tonight as a true blessing.',pt:'Diz esta noite «boa noite» como uma bênção verdadeira.'}},

  /* ———————— CERCUL MUNCII ———————— */
  {el:'work',kw:{ro:'Meșteșugul',en:'The Craft',pt:'O Ofício'},t:{ro:'Meșteșugul e rugăciunea mâinilor: același gest, repetat cu grijă, până devine binecuvântare.',en:'Craft is the prayer of the hands: the same gesture, repeated with care, until it becomes blessing.',pt:'O ofício é a oração das mãos: o mesmo gesto, repetido com cuidado, até se tornar bênção.'},inv:{ro:'Fă azi un gest de lucru ca și cum l-ai semna.',en:'Make one working gesture today as if signing it.',pt:'Faz hoje um gesto de trabalho como se o assinasses.'}},
  {el:'work',kw:{ro:'Uneltele',en:'The Tools',pt:'As Ferramentas'},t:{ro:'Spune-mi cum îți ții uneltele și îți spun cum îți ții gândurile. Rânduiala de pe masă începe în minte.',en:'Show me how you keep your tools and I will tell you how you keep your thoughts. The order on the bench begins in the mind.',pt:'Mostra-me como guardas as tuas ferramentas e digo-te como guardas os teus pensamentos. A ordem da bancada começa na mente.'},inv:{ro:'Curăță-ți azi uneltele — și pe cele din calculator.',en:'Clean your tools today — the digital ones too.',pt:'Limpa hoje as tuas ferramentas — também as digitais.'}},
  {el:'work',kw:{ro:'Ucenicia',en:'Apprenticeship',pt:'A Aprendizagem'},t:{ro:'Nimeni nu s-a născut meșter. Fiecare mână sigură de azi a fost cândva o mână care tremura.',en:'No one was born a master. Every steady hand today was once a trembling one.',pt:'Ninguém nasceu mestre. Toda a mão firme de hoje foi um dia uma mão que tremia.'},inv:{ro:'Fii azi ucenic la ceva, fără rușine.',en:'Be an apprentice at something today, without shame.',pt:'Sê hoje aprendiz de algo, sem vergonha.'}},
  {el:'work',kw:{ro:'Lucrul de azi',en:'Today’s Work',pt:'O Trabalho de Hoje'},t:{ro:'Nu ești chemat să termini toată lucrarea; nici nu ești liber să o părăsești. Fă-ți partea de azi.',en:'You are not called to finish all the work; nor are you free to abandon it. Do today’s share.',pt:'Não és chamado a terminar toda a obra; nem és livre de a abandonar. Faz a parte de hoje.'},inv:{ro:'Care e partea ta de azi? F-o și fii împăcat.',en:'What is today’s share? Do it and be at peace.',pt:'Qual é a tua parte de hoje? Fá-la e fica em paz.'}},
  {el:'work',kw:{ro:'Șlefuirea',en:'The Polishing',pt:'O Polimento'},t:{ro:'Diferența dintre bun și minunat e un strat subțire de răbdare pe care mulți nu-l mai aplică.',en:'The difference between good and wonderful is a thin coat of patience most people no longer apply.',pt:'A diferença entre bom e maravilhoso é uma fina camada de paciência que muitos já não aplicam.'},inv:{ro:'Dă azi lucrului tău încă o trecere de șlefuit.',en:'Give your work one more polishing pass today.',pt:'Dá hoje ao teu trabalho mais uma demão de polimento.'}},
  {el:'work',kw:{ro:'Lucrul nevăzut',en:'The Unseen Work',pt:'O Trabalho Invisível'},t:{ro:'Temelia nu se vede și ține casa. Fă bine și partea pe care n-o va lăuda nimeni.',en:'The foundation is unseen and holds the house. Do well the part no one will praise.',pt:'O alicerce não se vê e sustém a casa. Faz bem também a parte que ninguém louvará.'},inv:{ro:'Fă azi impecabil un lucru pe care nu-l vede nimeni.',en:'Do one invisible thing impeccably today.',pt:'Faz hoje impecavelmente algo que ninguém vê.'}},
  {el:'work',kw:{ro:'Semnătura',en:'The Signature',pt:'A Assinatura'},t:{ro:'Tot ce iese din mâinile tale îți poartă numele, fie că îl scrii, fie că nu.',en:'Everything that leaves your hands bears your name, whether you write it or not.',pt:'Tudo o que sai das tuas mãos leva o teu nome, quer o escrevas quer não.'},inv:{ro:'Întreabă-te la fiecare livrare: „aș semna asta?"',en:'Ask at every delivery: “would I sign this?”',pt:'Pergunta em cada entrega: «assinaria isto?»'}},
  {el:'work',kw:{ro:'Pauza lucrătorului',en:'The Worker’s Rest',pt:'A Pausa do Trabalhador'},t:{ro:'Coasa neascuțită muncește dublu și taie jumătate. Oprirea pentru ascuțit e tot muncă.',en:'A dull scythe works double and cuts half. Stopping to sharpen is work too.',pt:'A foice romba trabalha o dobro e corta metade. Parar para afiar também é trabalho.'},inv:{ro:'Ascute-te azi: o pauză, o plimbare, un pahar de apă.',en:'Sharpen yourself today: a pause, a walk, a glass of water.',pt:'Afia-te hoje: uma pausa, uma caminhada, um copo de água.'}},
  {el:'work',kw:{ro:'Lucrul împreună',en:'Working Together',pt:'O Trabalho em Conjunto'},t:{ro:'Singur mergi mai repede; împreună ajungi mai departe. Alege după lungimea drumului.',en:'Alone you go faster; together you go farther. Choose by the length of the road.',pt:'Sozinho vais mais depressa; juntos vão mais longe. Escolhe pela extensão do caminho.'},inv:{ro:'Cere sau oferă azi un umăr la o treabă comună.',en:'Ask for or lend a shoulder to a shared task today.',pt:'Pede ou oferece hoje um ombro numa tarefa comum.'}},
  {el:'work',kw:{ro:'Prețul cinstit',en:'The Honest Price',pt:'O Preço Justo'},t:{ro:'Cine își vinde lucrul pe nimic spune lumii că nimicul e prețul lui. Cinstește-ți osteneala.',en:'Who sells their work for nothing tells the world that nothing is its price. Honor your labor.',pt:'Quem vende o seu trabalho por nada diz ao mundo que nada é o seu preço. Honra o teu esforço.'},inv:{ro:'Spune azi un preț drept fără să-ți ceri iertare.',en:'Name a fair price today without apologizing.',pt:'Diz hoje um preço justo sem pedir desculpa.'}},
  {el:'work',kw:{ro:'Atelierul',en:'The Workshop',pt:'A Oficina'},t:{ro:'Locul unde lucrezi îți lucrează și el ție. Fă din colțul tău de muncă un loc care te ridică.',en:'The place where you work also works on you. Make your corner a place that lifts you.',pt:'O lugar onde trabalhas também trabalha em ti. Faz do teu canto um lugar que te eleva.'},inv:{ro:'Adaugă azi atelierului tău un lucru frumos.',en:'Add one beautiful thing to your workshop today.',pt:'Acrescenta hoje uma coisa bela à tua oficina.'}},
  {el:'work',kw:{ro:'Repetiția',en:'The Repetition',pt:'A Repetição'},t:{ro:'A mia oară nu seamănă cu prima decât pe dinafară. Înăuntru, mâna a devenit știință.',en:'The thousandth time resembles the first only from outside. Within, the hand has become knowledge.',pt:'A milésima vez só se parece com a primeira por fora. Por dentro, a mão tornou-se saber.'},inv:{ro:'Repetă azi cu drag ce ai mai făcut de o mie de ori.',en:'Repeat with love today what you have done a thousand times.',pt:'Repete hoje com amor o que já fizeste mil vezes.'}},
  {el:'work',kw:{ro:'Refacerea',en:'The Redoing',pt:'O Refazer'},t:{ro:'A reface un lucru prost făcut doare o zi; a-l lăsa așa doare de fiecare dată când îl vezi.',en:'Redoing a botched work hurts for a day; leaving it hurts every time you see it.',pt:'Refazer um trabalho malfeito dói um dia; deixá-lo assim dói cada vez que o vês.'},inv:{ro:'Refă azi lucrul care te înțeapă de câte ori treci pe lângă el.',en:'Redo today the thing that stings each time you pass it.',pt:'Refaz hoje aquilo que te espicaça cada vez que passas.'}},
  {el:'work',kw:{ro:'Primul ceas',en:'The First Hour',pt:'A Primeira Hora'},t:{ro:'Prima oră de lucru e lutul moale al zilei: ce pui în ea se întărește până seara.',en:'The first hour of work is the day’s soft clay: what you shape in it hardens by evening.',pt:'A primeira hora de trabalho é o barro macio do dia: o que moldas nela endurece até à noite.'},inv:{ro:'Pune mâine în primul ceas lucrul cel mai de preț.',en:'Place your most precious task in tomorrow’s first hour.',pt:'Põe amanhã na primeira hora o trabalho mais precioso.'}},
  {el:'work',kw:{ro:'Ultima privire',en:'The Last Look',pt:'O Último Olhar'},t:{ro:'Meșterul bun se mai întoarce o dată din prag. Ultima privire prinde ce au scăpat toate celelalte.',en:'The good craftsman turns back once from the doorway. The last look catches what all the others missed.',pt:'O bom artesão volta-se uma vez à porta. O último olhar apanha o que todos os outros deixaram escapar.'},inv:{ro:'Înainte de a preda, mai dă azi o ultimă privire.',en:'Before you hand it over, take one last look today.',pt:'Antes de entregar, dá hoje um último olhar.'}},
  {el:'work',kw:{ro:'Mândria curată',en:'Clean Pride',pt:'O Orgulho Limpo'},t:{ro:'E o mândrie care umflă pieptul și una care îndreaptă spatele. A doua e voie s-o porți.',en:'There is a pride that puffs the chest and one that straightens the back. The second you may wear.',pt:'Há um orgulho que incha o peito e um que endireita as costas. O segundo podes usá-lo.'},inv:{ro:'Bucură-te azi curat de un lucru bine făcut de tine.',en:'Take clean joy today in something you made well.',pt:'Alegra-te hoje limpamente com algo que fizeste bem.'}},
  {el:'work',kw:{ro:'Slujirea prin lucru',en:'Service Through Work',pt:'O Serviço pelo Trabalho'},t:{ro:'La capătul oricărei munci adevărate stă un om ajutat. Dacă nu-l vezi, caută-l: el dă rostul.',en:'At the end of any true work stands a person helped. If you cannot see them, look: they give the meaning.',pt:'No fim de todo o trabalho verdadeiro está uma pessoa ajudada. Se não a vês, procura: é ela que dá o sentido.'},inv:{ro:'Numește omul pe care îl ajută munca ta de azi.',en:'Name the person your work helps today.',pt:'Nomeia a pessoa que o teu trabalho ajuda hoje.'}},
  {el:'work',kw:{ro:'Banul cinstit',en:'Honest Money',pt:'O Dinheiro Honesto'},t:{ro:'Banul cinstit doarme liniștit. Cel necinstit ține trează toată casa.',en:'Honest money sleeps soundly. Dishonest money keeps the whole house awake.',pt:'O dinheiro honesto dorme tranquilo. O desonesto mantém a casa toda acordada.'},inv:{ro:'Câștigă azi doar ce poți povesti cu fruntea sus.',en:'Earn today only what you can recount with your head high.',pt:'Ganha hoje apenas o que possas contar de cabeça erguida.'}},
  {el:'work',kw:{ro:'Lucrul care te alege',en:'The Work that Chooses You',pt:'O Trabalho que Te Escolhe'},t:{ro:'Există un lucru pe care îl faci uitând de ceas. Acolo îți vorbește chemarea, încet.',en:'There is a work you do forgetting the clock. There your calling speaks, softly.',pt:'Há um trabalho que fazes esquecendo o relógio. Ali fala a tua vocação, baixinho.'},inv:{ro:'La ce uiți de timp? Dă-i mai mult loc în viață.',en:'Where do you lose track of time? Give it more room in your life.',pt:'Onde perdes a noção do tempo? Dá-lhe mais lugar na vida.'}},
  {el:'work',kw:{ro:'Începutul stângaci',en:'The Clumsy Start',pt:'O Começo Desajeitado'},t:{ro:'Orice lucru bun a fost întâi făcut prost de cineva care n-a renunțat. Prostul început e început.',en:'Every good work was first done badly by someone who did not quit. A poor start is still a start.',pt:'Toda a boa obra foi primeiro malfeita por alguém que não desistiu. Um mau começo ainda é começo.'},inv:{ro:'Fă azi prost, dar fă. Mâine faci mai bine.',en:'Do it badly today, but do it. Tomorrow you do better.',pt:'Faz hoje mal, mas faz. Amanhã fazes melhor.'}},
  {el:'work',kw:{ro:'Măsura lucrului',en:'The Work’s Measure',pt:'A Medida do Trabalho'},t:{ro:'Nu orele puse contează, ci viața pusă în ore. O oră întreagă bate o zi împrăștiată.',en:'Not the hours put in, but the life put into the hours. One whole hour beats a scattered day.',pt:'Não contam as horas postas, mas a vida posta nas horas. Uma hora inteira vence um dia disperso.'},inv:{ro:'Dă azi o oră fără nicio fereastră deschisă în plus.',en:'Give one hour today with no extra window open.',pt:'Dá hoje uma hora sem nenhuma janela extra aberta.'}},
  {el:'work',kw:{ro:'Roata carului',en:'The Cartwheel',pt:'A Roda do Carro'},t:{ro:'Roata care scârțâie cere untdelemn, nu discursuri. Problemele de lucru se ung, nu se plâng.',en:'The creaking wheel needs oil, not speeches. Work problems are to be oiled, not lamented.',pt:'A roda que chia pede óleo, não discursos. Os problemas do trabalho untam-se, não se lamentam.'},inv:{ro:'Unge azi roata care scârțâie de o săptămână.',en:'Oil today the wheel that has creaked for a week.',pt:'Unta hoje a roda que chia há uma semana.'}},
  {el:'work',kw:{ro:'Ochiul stăpânului',en:'The Master’s Eye',pt:'O Olho do Dono'},t:{ro:'Nimeni nu-ți va păzi lucrarea cum o păzești tu. Fii ochiul bun al treburilor tale.',en:'No one will watch over your work as you do. Be the good eye of your own affairs.',pt:'Ninguém guardará a tua obra como tu. Sê o bom olho dos teus assuntos.'},inv:{ro:'Verifică azi personal lucrul cel mai important.',en:'Check your most important work personally today.',pt:'Verifica hoje pessoalmente o trabalho mais importante.'}},
  {el:'work',kw:{ro:'Grădina meseriei',en:'The Garden of the Trade',pt:'O Jardim da Profissão'},t:{ro:'Meseria neîngrijită se sălbăticește ca o grădină. Învață ceva nou în ea în fiecare lună.',en:'An untended trade grows wild like a garden. Learn something new in it every month.',pt:'Uma profissão descuidada torna-se brava como um jardim. Aprende nela algo novo todos os meses.'},inv:{ro:'Plantează azi în meseria ta o sămânță nouă: o tehnică, o unealtă.',en:'Plant a new seed in your trade today: a technique, a tool.',pt:'Planta hoje na tua profissão uma semente nova: uma técnica, uma ferramenta.'}},
  {el:'work',kw:{ro:'Truda dulce',en:'Sweet Toil',pt:'A Fadiga Doce'},t:{ro:'Pâinea muncită are alt gust — îl știe orice om care a asudat pentru ceva al lui.',en:'Earned bread tastes different — anyone who has sweated for something of their own knows it.',pt:'O pão suado sabe diferente — sabe-o quem já suou por algo seu.'},inv:{ro:'Câștigă-ți azi un lucru mic prin trudă directă.',en:'Earn one small thing today by direct toil.',pt:'Ganha hoje uma coisa pequena por esforço direto.'}},
  {el:'work',kw:{ro:'Cuvântul dat în lucru',en:'The Word Given in Work',pt:'A Palavra Dada no Trabalho'},t:{ro:'Termenul promis e o punte pe care celălalt a început deja să calce. Nu o rupe sub el.',en:'A promised deadline is a bridge the other has already begun to cross. Do not break it under them.',pt:'Um prazo prometido é uma ponte que o outro já começou a atravessar. Não a quebres debaixo dele.'},inv:{ro:'Dacă nu mai poți ține un termen, spune azi, nu în ultima zi.',en:'If a deadline is slipping, say so today, not on the last day.',pt:'Se um prazo escapa, di-lo hoje, não no último dia.'}},
  {el:'work',kw:{ro:'Lucrul mărunt',en:'The Small Task',pt:'A Tarefa Miúda'},t:{ro:'Cine e credincios în lucrul mărunt i se încredințează lucrul mare. Ordinea asta nu se sare.',en:'Who is faithful in small tasks is entrusted with great ones. That order is not skipped.',pt:'Quem é fiel nas tarefas pequenas recebe as grandes. Essa ordem não se salta.'},inv:{ro:'Fă azi perfect cel mai mărunt lucru din listă.',en:'Do today’s smallest task perfectly.',pt:'Faz hoje na perfeição a tarefa mais miúda da lista.'}},
  {el:'work',kw:{ro:'Foaia albă',en:'The Blank Sheet',pt:'A Folha em Branco'},t:{ro:'Foaia albă nu e dușman; e câmp nearat. Primul rând e brazda; restul vine după plug.',en:'The blank sheet is no enemy; it is an unplowed field. The first line is the furrow; the rest follows the plow.',pt:'A folha em branco não é inimiga; é campo por lavrar. A primeira linha é o sulco; o resto segue o arado.'},inv:{ro:'Sparge azi o foaie albă cu un prim rând imperfect.',en:'Break a blank sheet today with an imperfect first line.',pt:'Quebra hoje uma folha em branco com uma primeira linha imperfeita.'}},
  {el:'work',kw:{ro:'Sfârșitul zilei de lucru',en:'The Workday’s End',pt:'O Fim do Dia de Trabalho'},t:{ro:'Închide lucrul cum închizi o poartă: cu zgomotul limpede al zăvorului. Altfel te urmează acasă.',en:'Close the work as you close a gate: with the clear sound of the latch. Otherwise it follows you home.',pt:'Fecha o trabalho como fechas um portão: com o som nítido do ferrolho. Senão, segue-te para casa.'},inv:{ro:'Pune azi un mic ritual de închidere: lista pe mâine, masa curată.',en:'Set a small closing ritual today: tomorrow’s list, a clean desk.',pt:'Cria hoje um pequeno ritual de fecho: a lista de amanhã, a mesa limpa.'}},
  {el:'work',kw:{ro:'Lauda ucenicului',en:'Praising the Apprentice',pt:'O Elogio ao Aprendiz'},t:{ro:'O vorbă bună spusă la timp unui începător poate hotărî un drum întreg de om.',en:'A kind word said in time to a beginner can decide a person’s whole road.',pt:'Uma boa palavra dita a tempo a um principiante pode decidir todo o caminho de uma pessoa.'},inv:{ro:'Laudă azi, precis și sincer, lucrul unui începător.',en:'Praise a beginner’s work today, precisely and sincerely.',pt:'Elogia hoje, com precisão e sinceridade, o trabalho de um principiante.'}},
  {el:'work',kw:{ro:'Piatra din capul unghiului',en:'The Cornerstone',pt:'A Pedra Angular'},t:{ro:'Uneori piatra aruncată de toți se dovedește cea care ține zidirea. Nu disprețui ideile modeste.',en:'Sometimes the stone everyone rejected proves to be the one that holds the building. Do not despise modest ideas.',pt:'Às vezes a pedra que todos rejeitaram revela-se a que sustém o edifício. Não desprezes as ideias modestas.'},inv:{ro:'Reia azi o idee „proastă" și mai privește-o o dată.',en:'Revisit one “bad” idea today and look again.',pt:'Retoma hoje uma ideia «má» e olha outra vez.'}},
  {el:'work',kw:{ro:'Secerișul altora',en:'Others’ Harvest',pt:'A Colheita dos Outros'},t:{ro:'Culegem zilnic din livezi sădite de oameni pe care nu i-am cunoscut. Sădește și tu pentru necunoscuți.',en:'We daily pick from orchards planted by people we never met. Plant for strangers too.',pt:'Colhemos todos os dias de pomares plantados por gente que nunca conhecemos. Planta também para desconhecidos.'},inv:{ro:'Lasă azi în lucrul tău ceva bun pentru cine vine după.',en:'Leave something good in your work today for who comes after.',pt:'Deixa hoje no teu trabalho algo bom para quem vier depois.'}},
  {el:'work',kw:{ro:'Odihna meritată',en:'The Earned Rest',pt:'O Descanso Merecido'},t:{ro:'Și lucrul bun știe să se oprească. A șaptea zi nu e lene; e încununare.',en:'Good work also knows how to stop. The seventh day is not laziness; it is a crowning.',pt:'O bom trabalho também sabe parar. O sétimo dia não é preguiça; é coroação.'},inv:{ro:'Pune-ți în calendar ziua a șaptea — și apăr-o.',en:'Put the seventh day in your calendar — and defend it.',pt:'Marca no calendário o sétimo dia — e defende-o.'}},

  /* ———————— CERCUL CORPULUI ———————— */
  {el:'body',kw:{ro:'Casa trupului',en:'The Body’s House',pt:'A Casa do Corpo'},t:{ro:'Trupul e singura casă pe care o primești pentru tot drumul. Locuiește-o cu recunoștință.',en:'The body is the only house you receive for the whole road. Dwell in it with gratitude.',pt:'O corpo é a única casa que recebes para todo o caminho. Habita-a com gratidão.'},inv:{ro:'Mulțumește-i azi trupului pentru un lucru anume.',en:'Thank your body today for one particular thing.',pt:'Agradece hoje ao corpo por uma coisa concreta.'}},
  {el:'body',kw:{ro:'Durerea-mesager',en:'Pain the Messenger',pt:'A Dor Mensageira'},t:{ro:'Durerea nu e pedeapsă; e poștaș. Nu împușca mesagerul înainte să-i citești scrisoarea.',en:'Pain is not punishment; it is a postman. Do not shoot the messenger before reading the letter.',pt:'A dor não é castigo; é carteiro. Não mates o mensageiro antes de ler a carta.'},inv:{ro:'Ce îți spune o durere mică pe care o tot amuțești?',en:'What is a small pain you keep silencing trying to say?',pt:'O que tenta dizer uma pequena dor que andas a calar?'}},
  {el:'body',kw:{ro:'Mersul',en:'Walking',pt:'O Caminhar'},t:{ro:'Multe noduri ale minții se dezleagă din mers. Picioarele sunt și ele un fel de gândire.',en:'Many knots of the mind untie themselves while walking. The legs too are a kind of thinking.',pt:'Muitos nós da mente desatam-se a caminhar. As pernas também são uma forma de pensar.'},inv:{ro:'Plimbă azi o problemă jumătate de oră.',en:'Walk a problem for half an hour today.',pt:'Passeia hoje um problema durante meia hora.'}},
  {el:'body',kw:{ro:'Apa',en:'Water',pt:'A Água'},t:{ro:'Ești făcut mai ales din apă. Multe „stări proaste" sunt doar sete cu nume pompos.',en:'You are made mostly of water. Many “bad moods” are just thirst with a fancy name.',pt:'És feito sobretudo de água. Muitos «maus estados» são só sede com nome pomposo.'},inv:{ro:'Bea un pahar de apă acum, înainte de orice concluzie.',en:'Drink a glass of water now, before any conclusion.',pt:'Bebe um copo de água agora, antes de qualquer conclusão.'}},
  {el:'body',kw:{ro:'Hrana',en:'The Food',pt:'O Alimento'},t:{ro:'Devii, încet, ce mănânci și ce privești. Amândouă sunt hrană; alege-le cu aceeași grijă.',en:'You slowly become what you eat and what you watch. Both are food; choose them with equal care.',pt:'Tornas-te, devagar, o que comes e o que vês. Ambos são alimento; escolhe-os com o mesmo cuidado.'},inv:{ro:'Pune azi pe masă — și pe ecran — o hrană curată.',en:'Put clean food on the table today — and on the screen.',pt:'Põe hoje comida limpa na mesa — e no ecrã.'}},
  {el:'body',kw:{ro:'Foamea și sațiul',en:'Hunger and Fullness',pt:'A Fome e a Saciedade'},t:{ro:'Oprește-te când mai încape puțin. Măsura la masă e o filozofie întreagă, mestecată.',en:'Stop while a little room remains. Measure at the table is a whole philosophy, chewed.',pt:'Para enquanto ainda cabe um pouco. A medida à mesa é uma filosofia inteira, mastigada.'},inv:{ro:'La o masă de azi, oprește-te la „aproape plin".',en:'At one meal today, stop at “almost full.”',pt:'Numa refeição de hoje, para no «quase cheio».'}},
  {el:'body',kw:{ro:'Spatele drept',en:'The Straight Back',pt:'As Costas Direitas'},t:{ro:'Ține-ți spatele drept și inima prinde curaj de la el. Trupul îi predă sufletului lecții mute.',en:'Hold your back straight and the heart takes courage from it. The body teaches the soul silent lessons.',pt:'Mantém as costas direitas e o coração ganha coragem com elas. O corpo dá à alma lições mudas.'},inv:{ro:'De trei ori azi: umerii jos, coloana sus, o respirație.',en:'Three times today: shoulders down, spine tall, one breath.',pt:'Três vezes hoje: ombros para baixo, coluna erguida, uma respiração.'}},
  {el:'body',kw:{ro:'Mâinile',en:'The Hands',pt:'As Mãos'},t:{ro:'Mâinile tale au mângâiat, au muncit, au dus. Privește-le: sunt biografia ta scrisă în piele.',en:'Your hands have caressed, worked, carried. Look at them: your biography written in skin.',pt:'As tuas mãos acariciaram, trabalharam, carregaram. Olha para elas: a tua biografia escrita na pele.'},inv:{ro:'Fă azi cu mâinile un lucru bun și concret.',en:'Do one good concrete thing with your hands today.',pt:'Faz hoje com as mãos uma coisa boa e concreta.'}},
  {el:'body',kw:{ro:'Ochii',en:'The Eyes',pt:'Os Olhos'},t:{ro:'Ochii obosesc nu de câte văd, ci de câte nu-i lași să închidă. Dă-le și lor orizont, nu doar ecran.',en:'Eyes tire not from how much they see, but from how little you let them close. Give them horizon, not only screen.',pt:'Os olhos cansam-se não do que veem, mas do quanto não os deixas fechar. Dá-lhes horizonte, não só ecrã.'},inv:{ro:'La fiecare oră, 20 de secunde de privit departe.',en:'Every hour, twenty seconds of looking far away.',pt:'A cada hora, vinte segundos a olhar para longe.'}},
  {el:'body',kw:{ro:'Inima-tobă',en:'The Drum-Heart',pt:'O Coração-Tambor'},t:{ro:'O tobă bate în tine de dinainte să te naști, fără să-i ceri. Măcar din când în când, ascult-o cu mulțumire.',en:'A drum has beaten in you since before your birth, unasked. At least now and then, listen with thanks.',pt:'Um tambor bate em ti desde antes de nasceres, sem lho pedires. Ao menos de vez em quando, escuta-o com gratidão.'},inv:{ro:'Pune mâna pe inimă un minut. Doar ascultă.',en:'Place a hand on your heart for a minute. Just listen.',pt:'Põe a mão no coração um minuto. Só escuta.'}},
  {el:'body',kw:{ro:'Plămânii',en:'The Lungs',pt:'Os Pulmões'},t:{ro:'Respirația e singura funcție și involuntară, și la poruncă. E mânerul cu care apuci starea ta.',en:'Breath is the only function both automatic and at command. It is the handle by which you grasp your state.',pt:'A respiração é a única função automática e ao comando. É a pega com que agarras o teu estado.'},inv:{ro:'Patru respirații lente când urcă graba, azi.',en:'Four slow breaths when haste rises today.',pt:'Quatro respirações lentas quando a pressa subir, hoje.'}},
  {el:'body',kw:{ro:'Oglinda blândă',en:'The Kind Mirror',pt:'O Espelho Bondoso'},t:{ro:'Trupul aude tot ce spui despre el. Vorbește-i în oglindă cum i-ai vorbi unui prieten drag.',en:'The body hears everything you say about it. Speak to it in the mirror as to a dear friend.',pt:'O corpo ouve tudo o que dizes sobre ele. Fala-lhe ao espelho como a um amigo querido.'},inv:{ro:'Azi, în oglindă: un cuvânt bun în loc de inventarul lipsurilor.',en:'Today, in the mirror: one kind word instead of the inventory of flaws.',pt:'Hoje, ao espelho: uma palavra boa em vez do inventário de defeitos.'}},
  {el:'body',kw:{ro:'Vârsta trupului',en:'The Body’s Age',pt:'A Idade do Corpo'},t:{ro:'Trupul nu îmbătrânește împotriva ta; îmbătrânește purtându-te. Ridurile sunt kilometrajul iubirii lui.',en:'The body does not age against you; it ages carrying you. Wrinkles are the mileage of its love.',pt:'O corpo não envelhece contra ti; envelhece a carregar-te. As rugas são a quilometragem do seu amor.'},inv:{ro:'Privește azi un semn al vârstei cu recunoștință, nu cu ciudă.',en:'Look at one sign of age today with gratitude, not resentment.',pt:'Olha hoje um sinal da idade com gratidão, não com mágoa.'}},
  {el:'body',kw:{ro:'Boala-învățător',en:'Illness the Teacher',pt:'A Doença Mestra'},t:{ro:'Boala oprește trupul ca să audă sufletul. Întreab-o ce lecție aduce, chiar dacă o refuzi ca soartă.',en:'Illness stops the body so the soul may be heard. Ask what lesson it brings, even as you refuse it as fate.',pt:'A doença pára o corpo para que a alma seja ouvida. Pergunta que lição traz, mesmo recusando-a como destino.'},inv:{ro:'Ce ți-a arătat ultima boală despre viața ta de dinainte?',en:'What did your last illness show about your life before it?',pt:'O que te mostrou a última doença sobre a tua vida anterior?'}},
  {el:'body',kw:{ro:'Vindecarea',en:'The Healing',pt:'A Cura'},t:{ro:'Medicul leagă rana; trupul o închide. În tine lucrează zi și noapte un spital tăcut. Ajută-l.',en:'The doctor binds the wound; the body closes it. Within you a silent hospital works day and night. Help it.',pt:'O médico liga a ferida; o corpo fecha-a. Em ti trabalha dia e noite um hospital silencioso. Ajuda-o.'},inv:{ro:'Dă-i azi spitalului tău tăcut: somn, apă, liniște.',en:'Give your silent hospital today: sleep, water, calm.',pt:'Dá hoje ao teu hospital silencioso: sono, água, calma.'}},
  {el:'body',kw:{ro:'Atingerea',en:'The Touch',pt:'O Toque'},t:{ro:'O îmbrățișare de șase secunde spune ce nu încape în șase mii de cuvinte.',en:'A six-second embrace says what six thousand words cannot hold.',pt:'Um abraço de seis segundos diz o que não cabe em seis mil palavras.'},inv:{ro:'Îmbrățișează azi pe cineva drag fără grabă.',en:'Hug someone dear today without hurry.',pt:'Abraça hoje alguém querido sem pressa.'}},
  {el:'body',kw:{ro:'Vocea',en:'The Voice',pt:'A Voz'},t:{ro:'Vocea ta e un instrument pe care nu-l mai are nimeni. Cântă-i cuiva măcar vorbind frumos.',en:'Your voice is an instrument no one else owns. Play it for someone, if only by speaking kindly.',pt:'A tua voz é um instrumento que mais ninguém tem. Toca-a para alguém, nem que seja falando com bondade.'},inv:{ro:'Coboară azi tonul într-o discuție care urcă.',en:'Lower your tone today in a rising argument.',pt:'Baixa hoje o tom numa discussão que sobe.'}},
  {el:'body',kw:{ro:'Pielea',en:'The Skin',pt:'A Pele'},t:{ro:'Pielea e granița unde te termini tu și începe lumea. Soarele, vântul și apa o țin vie; dă-i-le.',en:'The skin is the border where you end and the world begins. Sun, wind and water keep it alive; give them to it.',pt:'A pele é a fronteira onde acabas tu e começa o mundo. Sol, vento e água mantêm-na viva; dá-lhos.'},inv:{ro:'Scoate azi pielea la aer: zece minute afară.',en:'Give your skin air today: ten minutes outside.',pt:'Dá hoje ar à pele: dez minutos lá fora.'}},
  {el:'body',kw:{ro:'Trupul dimineții',en:'The Morning Body',pt:'O Corpo da Manhã'},t:{ro:'Cum îți trezești trupul, așa îți pornești ziua: smuls — zi smulsă; întins ca o pisică — zi suplă.',en:'As you wake the body, so the day begins: yanked — a yanked day; stretched like a cat — a supple day.',pt:'Como acordas o corpo, assim começa o dia: arrancado — dia arrancado; espreguiçado como um gato — dia ágil.'},inv:{ro:'Mâine: un minut de întins înainte de primul pas.',en:'Tomorrow: one minute of stretching before the first step.',pt:'Amanhã: um minuto de alongamento antes do primeiro passo.'}},
  {el:'body',kw:{ro:'Osteneala bună',en:'The Good Fatigue',pt:'O Cansaço Bom'},t:{ro:'Trupul obosit de mișcare doarme ca un copil; cel obosit de griji doarme ca un datornic.',en:'A body tired from movement sleeps like a child; one tired from worry sleeps like a debtor.',pt:'Um corpo cansado de movimento dorme como criança; um cansado de preocupações dorme como devedor.'},inv:{ro:'Obosește-ți azi trupul cu mișcare, măcar 20 de minute.',en:'Tire your body with movement today, at least twenty minutes.',pt:'Cansa hoje o corpo com movimento, pelo menos vinte minutos.'}},
  {el:'body',kw:{ro:'Genunchii',en:'The Knees',pt:'Os Joelhos'},t:{ro:'Genunchii știu două lucruri mari: să te urce muntele și să te plece în rugă. Amândouă te înalță.',en:'Knees know two great things: to climb you up the mountain and to bend you in prayer. Both raise you.',pt:'Os joelhos sabem duas coisas grandes: subir-te a montanha e dobrar-te em oração. Ambas te elevam.'},inv:{ro:'Folosește azi genunchii într-unul din cele două feluri.',en:'Use your knees in one of the two ways today.',pt:'Usa hoje os joelhos de uma das duas maneiras.'}},
  {el:'body',kw:{ro:'Urechea',en:'The Ear',pt:'O Ouvido'},t:{ro:'Urechea nu are pleoape: aude tot, mereu. Alege-i cu grijă hrana — vorbe, muzici, oameni.',en:'The ear has no eyelids: it hears everything, always. Choose its food with care — words, music, people.',pt:'O ouvido não tem pálpebras: ouve tudo, sempre. Escolhe com cuidado o seu alimento — palavras, músicas, pessoas.'},inv:{ro:'Hrănește-ți azi urechile cu ceva care te ridică.',en:'Feed your ears today with something that lifts you.',pt:'Alimenta hoje os ouvidos com algo que te eleva.'}},
  {el:'body',kw:{ro:'Zâmbetul',en:'The Smile',pt:'O Sorriso'},t:{ro:'Zâmbetul e singura gimnastică ce lucrează simultan fața ta și ziua altuia.',en:'The smile is the only exercise that works your face and another’s day at once.',pt:'O sorriso é a única ginástica que trabalha ao mesmo tempo o teu rosto e o dia de outro.'},inv:{ro:'Dăruiește azi trei zâmbete întregi, cu ochi cu tot.',en:'Give three whole smiles today, eyes included.',pt:'Oferece hoje três sorrisos inteiros, com os olhos incluídos.'}},
  {el:'body',kw:{ro:'Postul',en:'The Fast',pt:'O Jejum'},t:{ro:'Din când în când, spune „nu" poftei ca să audă și ea cine e stăpânul casei.',en:'Now and then say no to craving, so it too hears who is master of the house.',pt:'De vez em quando diz «não» ao apetite, para que também ele ouça quem manda em casa.'},inv:{ro:'Postește azi de un singur lucru mărunt, ales de tine.',en:'Fast today from one small thing of your choosing.',pt:'Jejua hoje de uma só coisa pequena, à tua escolha.'}},
  {el:'body',kw:{ro:'Ținuta',en:'The Bearing',pt:'O Porte'},t:{ro:'Îmbracă-te ca pentru ziua pe care o vrei, nu ca pentru cea de care te temi.',en:'Dress for the day you want, not the one you fear.',pt:'Veste-te para o dia que queres, não para o que temes.'},inv:{ro:'Alege azi o ținută care îți ridică umerii.',en:'Choose clothes today that lift your shoulders.',pt:'Escolhe hoje uma roupa que te levante os ombros.'}},
  {el:'body',kw:{ro:'Casa curată',en:'The Clean House',pt:'A Casa Limpa'},t:{ro:'Trupul se spală zilnic; și casa lui lăuntrică cere apă: sudoare, lacrimi, respirații adânci.',en:'The body is washed daily; its inner house also asks for water: sweat, tears, deep breaths.',pt:'O corpo lava-se todos os dias; a sua casa interior também pede água: suor, lágrimas, respirações fundas.'},inv:{ro:'Alege azi o „apă" lăuntrică: sport, plâns bun sau respirat adânc.',en:'Choose one inner “water” today: sport, a good cry, or deep breathing.',pt:'Escolhe hoje uma «água» interior: desporto, um bom choro ou respiração funda.'}},
  {el:'body',kw:{ro:'Pragul de sus',en:'The Upper Threshold',pt:'O Limiar de Cima'},t:{ro:'Trupul poate mai mult decât crede mintea și mai puțin decât cere mândria. Ascultă-l pe el, nu pe ele.',en:'The body can do more than the mind believes and less than pride demands. Listen to it, not to them.',pt:'O corpo pode mais do que a mente crê e menos do que o orgulho exige. Escuta-o a ele, não a elas.'},inv:{ro:'Azi, la efort: nici lene, nici forțare. Ascultare.',en:'Today, in effort: neither sloth nor strain. Listening.',pt:'Hoje, no esforço: nem preguiça nem forçar. Escuta.'}},
  {el:'body',kw:{ro:'Bătrânețea trupului',en:'The Body’s Old Age',pt:'A Velhice do Corpo'},t:{ro:'Ce faci azi cu trupul e scrisoarea pe care i-o trimiți bătrâneții tale. Scrie-i vești bune.',en:'What you do with your body today is the letter you send your old age. Send good news.',pt:'O que fazes hoje com o corpo é a carta que envias à tua velhice. Manda boas notícias.'},inv:{ro:'Fă azi pentru trup un lucru pe care ți-l va mulțumi peste 30 de ani.',en:'Do one thing for your body today it will thank you for in thirty years.',pt:'Faz hoje pelo corpo algo que ele te agradecerá daqui a trinta anos.'}},
  {el:'body',kw:{ro:'Aerul',en:'The Air',pt:'O Ar'},t:{ro:'Trăiești din împrumut de aer, clipă de clipă, fără contract. Universul îți face zilnic acest credit.',en:'You live on borrowed air, moment by moment, no contract. The universe extends you this credit daily.',pt:'Vives de ar emprestado, instante a instante, sem contrato. O universo dá-te este crédito todos os dias.'},inv:{ro:'Ieși azi să respiri aer adevărat, nu doar aer de cameră.',en:'Step out today to breathe real air, not only room air.',pt:'Sai hoje para respirar ar verdadeiro, não só ar de sala.'}},
  {el:'body',kw:{ro:'Graiul trupului',en:'The Body’s Speech',pt:'A Fala do Corpo'},t:{ro:'Trupul vorbește întruna: pumnii strânși, maxilarul încleștat, umerii urcați. Învață-i limba: e despre tine.',en:'The body speaks constantly: clenched fists, tight jaw, raised shoulders. Learn its language: it is about you.',pt:'O corpo fala sem parar: punhos cerrados, maxilar tenso, ombros subidos. Aprende a sua língua: fala de ti.'},inv:{ro:'De trei ori azi, întreabă-te: „ce spune trupul meu acum?"',en:'Three times today ask: “what is my body saying now?”',pt:'Três vezes hoje pergunta: «o que diz o meu corpo agora?»'}},
  {el:'body',kw:{ro:'Odihna ochilor',en:'The Rest of the Eyes',pt:'O Descanso dos Olhos'},t:{ro:'Închide ochii un minut în plină zi: e cea mai scurtă călătorie spre tine.',en:'Close your eyes one minute in broad daylight: the shortest journey back to yourself.',pt:'Fecha os olhos um minuto em pleno dia: a viagem mais curta de volta a ti.'},inv:{ro:'Un minut de ochi închiși, acum sau la prânz.',en:'One minute, eyes closed, now or at noon.',pt:'Um minuto de olhos fechados, agora ou ao meio-dia.'}},
  {el:'body',kw:{ro:'Râsul',en:'Laughter',pt:'O Riso'},t:{ro:'Râsul din tot trupul scutură praful de pe suflet. E gimnastica bucuriei — și nu cere echipament.',en:'A whole-body laugh shakes the dust off the soul. It is the gymnastics of joy — and needs no equipment.',pt:'Um riso de corpo inteiro sacode o pó da alma. É a ginástica da alegria — e não pede equipamento.'},inv:{ro:'Râzi azi o dată cu toată ființa, fără jumătăți.',en:'Laugh once today with your whole being, no halves.',pt:'Ri hoje uma vez com todo o teu ser, sem metades.'}},
  {el:'body',kw:{ro:'Templul viu',en:'The Living Temple',pt:'O Templo Vivo'},t:{ro:'Nu ai un trup; ești, și prin trup, un loc sfânt care umblă. Poartă-te ca atare cu tine și cu ceilalți.',en:'You do not merely have a body; through it, you are a walking holy place. Treat yourself and others accordingly.',pt:'Não tens apenas um corpo; és, também por ele, um lugar sagrado que caminha. Trata-te — e aos outros — como tal.'},inv:{ro:'Cinstește azi templul: al tău și al celui de lângă tine.',en:'Honor the temple today: yours and your neighbor’s.',pt:'Honra hoje o templo: o teu e o do teu próximo.'}},

  /* ———————— CERCUL NATURII ———————— */
  {el:'nature',kw:{ro:'Copacul',en:'The Tree',pt:'A Árvore'},t:{ro:'Copacul crește în două direcții deodată: spre cer și spre adânc. Doar așa ține furtunile.',en:'The tree grows in two directions at once: toward the sky and toward the deep. Only thus does it hold in storms.',pt:'A árvore cresce em duas direções ao mesmo tempo: para o céu e para o fundo. Só assim aguenta as tempestades.'},inv:{ro:'Crește azi în ambele: un pas în sus, unul în adânc.',en:'Grow both ways today: one step upward, one inward.',pt:'Cresce hoje nas duas: um passo para cima, um para dentro.'}},
  {el:'nature',kw:{ro:'Râul',en:'The River',pt:'O Rio'},t:{ro:'Râul nu se ceartă cu malurile; le mulțumește că îl fac râu. Marginile tale te adună, nu te închid.',en:'The river does not quarrel with its banks; it thanks them for making it a river. Your limits gather you; they do not cage you.',pt:'O rio não discute com as margens; agradece-lhes por fazerem dele um rio. Os teus limites reúnem-te; não te prendem.'},inv:{ro:'Mulțumește azi unei „margini" care te ține adunat.',en:'Thank one “bank” today that keeps you gathered.',pt:'Agradece hoje a uma «margem» que te mantém reunido.'}},
  {el:'nature',kw:{ro:'Muntele',en:'The Mountain',pt:'A Montanha'},t:{ro:'Muntele nu se grăbește să fie cucerit și nu se mândrește când e. El doar stă — și stând, învață.',en:'The mountain does not hurry to be conquered, nor boast when it is. It simply stands — and standing, it teaches.',pt:'A montanha não se apressa a ser conquistada nem se gaba quando o é. Apenas está — e estando, ensina.'},inv:{ro:'Stai azi neclintit într-o singură privință.',en:'Stand unmoved today in one single matter.',pt:'Fica hoje inabalável numa única questão.'}},
  {el:'nature',kw:{ro:'Iarba',en:'The Grass',pt:'A Erva'},t:{ro:'Iarba călcată se ridică a doua zi. Nu prin tărie, ci prin faptul că nu știe să se dea bătută.',en:'Trodden grass rises the next day. Not by strength, but by not knowing how to give up.',pt:'A erva pisada levanta-se no dia seguinte. Não pela força, mas por não saber desistir.'},inv:{ro:'Ridică-te azi, simplu, fără discurs, ca iarba.',en:'Rise today, simply, without a speech, like grass.',pt:'Levanta-te hoje, simplesmente, sem discurso, como a erva.'}},
  {el:'nature',kw:{ro:'Sămânța',en:'The Seed',pt:'A Semente'},t:{ro:'Într-o sămânță doarme o pădure. În gestul tău mic de azi, cine știe ce dorm.',en:'In one seed sleeps a forest. In your small gesture today, who knows what sleeps.',pt:'Numa semente dorme uma floresta. No teu pequeno gesto de hoje, quem sabe o que dorme.'},inv:{ro:'Fă gestul mic; lasă pădurea în seama timpului.',en:'Make the small gesture; leave the forest to time.',pt:'Faz o gesto pequeno; deixa a floresta ao tempo.'}},
  {el:'nature',kw:{ro:'Furtuna',en:'The Storm',pt:'A Tempestade'},t:{ro:'Furtuna rupe ce e uscat și înmoaie ce e viu. Când vine, întreabă-te: ce era uscat în mine?',en:'The storm breaks what is dry and softens what is alive. When it comes, ask: what in me was dry?',pt:'A tempestade quebra o que está seco e amolece o que está vivo. Quando vier, pergunta: o que estava seco em mim?'},inv:{ro:'După furtuna de curând, ce a curățat de fapt?',en:'After your recent storm, what did it actually clear?',pt:'Depois da tua tempestade recente, o que limpou de facto?'}},
  {el:'nature',kw:{ro:'Soarele',en:'The Sun',pt:'O Sol'},t:{ro:'Soarele răsare și peste cei care l-au înjurat aseară. Învață de la el meseria de a lumina fără condiții.',en:'The sun rises even over those who cursed it last night. Learn from it the craft of shining without conditions.',pt:'O sol nasce até sobre os que ontem o amaldiçoaram. Aprende com ele o ofício de brilhar sem condições.'},inv:{ro:'Luminează azi și pe cineva care nu „merită".',en:'Shine today even on someone who does not “deserve” it.',pt:'Ilumina hoje até alguém que não «merece».'}},
  {el:'nature',kw:{ro:'Ploaia',en:'The Rain',pt:'A Chuva'},t:{ro:'Ploaia nu întreabă grădina dacă e pregătită. Vine — și grădina se descurcă înflorind.',en:'The rain does not ask the garden if it is ready. It comes — and the garden copes by blooming.',pt:'A chuva não pergunta ao jardim se está pronto. Vem — e o jardim resolve florindo.'},inv:{ro:'La neprevăzutul de azi, răspunde ca grădina: crescând.',en:'Answer today’s unforeseen like the garden: by growing.',pt:'Responde ao imprevisto de hoje como o jardim: crescendo.'}},
  {el:'nature',kw:{ro:'Vântul prin frunze',en:'Wind Through Leaves',pt:'O Vento nas Folhas'},t:{ro:'Frunza nu se luptă cu vântul; dansează cu el și rămâne pe ram. Rigiditatea rupe, suplețea ține.',en:'The leaf does not fight the wind; it dances with it and stays on the branch. Rigidity breaks; suppleness holds.',pt:'A folha não luta com o vento; dança com ele e fica no ramo. A rigidez quebra; a flexibilidade segura.'},inv:{ro:'Unde te-ai înțepenit? Dansează azi puțin cu vântul.',en:'Where have you stiffened? Dance a little with the wind today.',pt:'Onde ficaste rígido? Dança hoje um pouco com o vento.'}},
  {el:'nature',kw:{ro:'Păsările',en:'The Birds',pt:'Os Pássaros'},t:{ro:'Pasărea cântă înainte să știe dacă va găsi hrană azi. Cântecul dinaintea siguranței — asta e credința.',en:'The bird sings before knowing whether it will find food today. Song before certainty — that is faith.',pt:'O pássaro canta antes de saber se hoje achará alimento. O canto antes da certeza — isso é fé.'},inv:{ro:'Începe ziua cu „cântecul", nu cu grija.',en:'Begin the day with the song, not the worry.',pt:'Começa o dia com o canto, não com a preocupação.'}},
  {el:'nature',kw:{ro:'Furnica',en:'The Ant',pt:'A Formiga'},t:{ro:'Furnica nu ține discursuri despre hărnicie. Cară. Grămada crește din drumuri mici, nu din planuri mari.',en:'The ant gives no speeches on diligence. It carries. The heap grows from small trips, not grand plans.',pt:'A formiga não faz discursos sobre diligência. Carrega. O monte cresce de pequenas viagens, não de grandes planos.'},inv:{ro:'Astăzi: mai puține vorbe despre plan, un drum mic în plus.',en:'Today: fewer words about the plan, one more small trip.',pt:'Hoje: menos palavras sobre o plano, mais uma pequena viagem.'}},
  {el:'nature',kw:{ro:'Albina',en:'The Bee',pt:'A Abelha'},t:{ro:'Albina ia din floare fără să o sărăcească și lasă în urmă rod. Fii un astfel de oaspete în viețile altora.',en:'The bee takes from the flower without impoverishing it and leaves fruit behind. Be such a guest in others’ lives.',pt:'A abelha tira da flor sem a empobrecer e deixa fruto atrás. Sê um hóspede assim na vida dos outros.'},inv:{ro:'Din orice întâlnire de azi, lasă omul mai bogat, nu mai gol.',en:'Leave everyone you meet today richer, not emptier.',pt:'Deixa hoje cada pessoa que encontrares mais rica, não mais vazia.'}},
  {el:'nature',kw:{ro:'Pădurea',en:'The Forest',pt:'A Floresta'},t:{ro:'Pădurea e un singur trup cu mii de trunchiuri: sub pământ, rădăcinile își dau de veste și își împart hrana.',en:'The forest is one body with a thousand trunks: underground, the roots send word and share food.',pt:'A floresta é um só corpo com mil troncos: debaixo da terra, as raízes avisam-se e partilham alimento.'},inv:{ro:'Trimite azi „hrană prin rădăcini": un ajutor nevăzut cuiva din rețeaua ta.',en:'Send “food through the roots” today: unseen help to someone in your grove.',pt:'Envia hoje «alimento pelas raízes»: uma ajuda invisível a alguém do teu bosque.'}},
  {el:'nature',kw:{ro:'Marea',en:'The Sea',pt:'O Mar'},t:{ro:'Marea primește toate râurile și nu dă pe dinafară. Lărgimea e răspunsul ei la tot ce vine.',en:'The sea receives all rivers and does not overflow. Wideness is its answer to all that comes.',pt:'O mar recebe todos os rios e não transborda. A largueza é a sua resposta a tudo o que chega.'},inv:{ro:'La ce te umple azi, răspunde lărgindu-te, nu revărsându-te.',en:'To what fills you today, answer by widening, not overflowing.',pt:'Ao que te encher hoje, responde alargando-te, não transbordando.'}},
  {el:'nature',kw:{ro:'Pietrele',en:'The Stones',pt:'As Pedras'},t:{ro:'Piatra din drum e piedică pentru grăbit și treaptă pentru cel care urcă. Piatra e aceeași.',en:'The stone in the road is an obstacle to the hurried and a step to the climber. The stone is the same.',pt:'A pedra no caminho é obstáculo para o apressado e degrau para quem sobe. A pedra é a mesma.'},inv:{ro:'Fă azi dintr-o piedică o treaptă, măcar una.',en:'Turn one obstacle into a step today, at least one.',pt:'Transforma hoje um obstáculo em degrau, pelo menos um.'}},
  {el:'nature',kw:{ro:'Zăpada',en:'The Snow',pt:'A Neve'},t:{ro:'Zăpada acoperă totul cu aceeași blândețe: și grădina, și groapa. Învață de la ea iertarea care nu alege.',en:'Snow covers everything with the same gentleness: garden and pit alike. Learn from it the forgiveness that does not pick.',pt:'A neve cobre tudo com a mesma doçura: o jardim e a cova. Aprende com ela o perdão que não escolhe.'},inv:{ro:'Acoperă azi cu blândețe o greșeală — a ta sau a altuia.',en:'Cover one mistake gently today — yours or another’s.',pt:'Cobre hoje com doçura um erro — teu ou de outro.'}},
  {el:'nature',kw:{ro:'Ceața',en:'The Fog',pt:'O Nevoeiro'},t:{ro:'Pe ceață nu se vede departe — dar se vede următorul pas. Atât îți trebuie ca să nu stai pe loc.',en:'In fog you cannot see far — but you can see the next step. That is all you need to keep from standing still.',pt:'No nevoeiro não se vê longe — mas vê-se o próximo passo. É tudo o que precisas para não ficares parado.'},inv:{ro:'În nelămurirea de azi, fă doar pasul care se vede.',en:'In today’s unclarity, take only the step you can see.',pt:'Na incerteza de hoje, dá só o passo que se vê.'}},
  {el:'nature',kw:{ro:'Curcubeul',en:'The Rainbow',pt:'O Arco-Íris'},t:{ro:'Curcubeul cere două lucruri deodată: ploaie și soare. Așa și bucuriile mari: au în ele și lacrimă.',en:'The rainbow requires two things at once: rain and sun. So do great joys: they hold a tear within.',pt:'O arco-íris exige duas coisas ao mesmo tempo: chuva e sol. Assim as grandes alegrias: trazem uma lágrima dentro.'},inv:{ro:'Primește azi o bucurie amestecată fără să o strici cerând-o pură.',en:'Accept a mixed joy today without spoiling it by demanding purity.',pt:'Aceita hoje uma alegria misturada sem a estragares exigindo-a pura.'}},
  {el:'nature',kw:{ro:'Grădina',en:'The Garden',pt:'O Jardim'},t:{ro:'Grădina răspunde exact la ce faci, nu la ce intenționezi. Udată — crește; promisă — se usucă.',en:'The garden answers exactly what you do, not what you intend. Watered — it grows; promised — it withers.',pt:'O jardim responde exatamente ao que fazes, não ao que tencionas. Regado — cresce; prometido — seca.'},inv:{ro:'Udă azi, concret, un lucru pe care doar îl promiteai.',en:'Water concretely today one thing you only kept promising.',pt:'Rega hoje, concretamente, algo que só prometias.'}},
  {el:'nature',kw:{ro:'Pământul reavăn',en:'The Moist Earth',pt:'A Terra Húmida'},t:{ro:'Mâinile băgate în pământ scot afară mai mult decât buruieni: scot și neliniștea din om.',en:'Hands dug into soil pull out more than weeds: they pull the restlessness out of a person.',pt:'As mãos metidas na terra tiram mais do que ervas: tiram também a inquietação da pessoa.'},inv:{ro:'Atinge azi pământul: o plantă, o grădină, un ghiveci.',en:'Touch the earth today: a plant, a garden, a pot.',pt:'Toca hoje na terra: uma planta, um jardim, um vaso.'}},
  {el:'nature',kw:{ro:'Răsăritul',en:'The Sunrise',pt:'O Nascer do Sol'},t:{ro:'Răsăritul se dă gratis în fiecare zi și rămâne nevăzut de aproape toți. Fii dintre cei puțini.',en:'The sunrise is given free each day and goes unseen by nearly all. Be among the few.',pt:'O nascer do sol é dado de graça todos os dias e quase ninguém o vê. Sê dos poucos.'},inv:{ro:'Prinde un răsărit săptămâna asta, cu ochii tăi.',en:'Catch one sunrise this week, with your own eyes.',pt:'Apanha um nascer do sol esta semana, com os teus olhos.'}},
  {el:'nature',kw:{ro:'Apusul',en:'The Sunset',pt:'O Pôr do Sol'},t:{ro:'Soarele știe să plece frumos — de aceea îl iertăm zilnic că ne lasă în întuneric. Învață arta plecărilor.',en:'The sun knows how to leave beautifully — that is why we forgive it daily for leaving us in the dark. Learn the art of departures.',pt:'O sol sabe partir com beleza — por isso lhe perdoamos todos os dias deixar-nos no escuro. Aprende a arte das partidas.'},inv:{ro:'Încheie azi frumos ceva: o zi de lucru, o vizită, o discuție.',en:'End something beautifully today: a workday, a visit, a talk.',pt:'Termina hoje algo com beleza: um dia de trabalho, uma visita, uma conversa.'}},
  {el:'nature',kw:{ro:'Luna plină',en:'The Full Moon',pt:'A Lua Cheia'},t:{ro:'Luna e plină doar câteva nopți pe lună — și nu se rușinează de restul. Ai și tu voie la faze.',en:'The moon is full only a few nights a month — and is not ashamed of the rest. You too are allowed phases.',pt:'A lua só está cheia poucas noites por mês — e não se envergonha das outras. Também tu tens direito a fases.'},inv:{ro:'Ce fază ești azi? Trăiește-o fără să-ți ceri scuze.',en:'Which phase are you today? Live it without apology.',pt:'Em que fase estás hoje? Vive-a sem pedir desculpa.'}},
  {el:'nature',kw:{ro:'Cerul senin',en:'The Clear Sky',pt:'O Céu Limpo'},t:{ro:'Oricâți nori trec, cerul nu se murdărește. Fii cerul, nu vremea.',en:'However many clouds pass, the sky is not stained. Be the sky, not the weather.',pt:'Por mais nuvens que passem, o céu não se mancha. Sê o céu, não o tempo.'},inv:{ro:'Azi, sub orice „vreme", amintește-ți: tu ești cerul.',en:'Today, beneath any “weather,” remember: you are the sky.',pt:'Hoje, sob qualquer «tempo», lembra: tu és o céu.'}},
  {el:'nature',kw:{ro:'Mugurii',en:'The Buds',pt:'Os Rebentos'},t:{ro:'Mugurele nu forțează primăvara; o așteaptă gata făcut. Pregătirea e partea ta; înflorirea vine singură.',en:'The bud does not force the spring; it awaits it fully formed. Preparation is your part; blooming comes on its own.',pt:'O rebento não força a primavera; espera-a já pronto. A preparação é a tua parte; a floração vem sozinha.'},inv:{ro:'Pregătește azi ceva pentru anotimpul care vine.',en:'Prepare something today for the season to come.',pt:'Prepara hoje algo para a estação que vem.'}},
  {el:'nature',kw:{ro:'Frunza care cade',en:'The Falling Leaf',pt:'A Folha que Cai'},t:{ro:'Toamna, copacul nu ține doliu după frunze. Le dă drumul ca să treacă iarna viu. Lepădarea e strategie, nu tragedie.',en:'In autumn the tree does not mourn its leaves. It lets them go to survive the winter. Shedding is strategy, not tragedy.',pt:'No outono, a árvore não faz luto pelas folhas. Larga-as para atravessar viva o inverno. Largar é estratégia, não tragédia.'},inv:{ro:'Ce frunză lași jos ca să treci iarna? Numește-o.',en:'What leaf do you drop to make it through winter? Name it.',pt:'Que folha largas para atravessar o inverno? Nomeia-a.'}},
  {el:'nature',kw:{ro:'Izvorul',en:'The Spring',pt:'A Nascente'},t:{ro:'Izvorul dă apă fără să întrebe cine bea. Dărnicia lui vine din faptul că e legat de ceva mai adânc.',en:'The spring gives water without asking who drinks. Its generosity comes from being joined to something deeper.',pt:'A nascente dá água sem perguntar quem bebe. A sua generosidade vem de estar ligada a algo mais fundo.'},inv:{ro:'Leagă-te azi de adânc: liniște, rugă sau natură — apoi dă mai departe.',en:'Join the deep today: silence, prayer or nature — then give onward.',pt:'Liga-te hoje ao fundo: silêncio, oração ou natureza — depois dá em diante.'}},
  {el:'nature',kw:{ro:'Cuibul',en:'The Nest',pt:'O Ninho'},t:{ro:'Pasărea își face cuibul fir cu fir, fără arhitect. Încrederea că se poate e jumătate din construcție.',en:'The bird builds its nest twig by twig, with no architect. Trust that it can be done is half the building.',pt:'O pássaro faz o ninho fio a fio, sem arquiteto. A confiança de que é possível é metade da construção.'},inv:{ro:'Adaugă azi un fir la cuibul tău: casă, familie, vis.',en:'Add one twig to your nest today: home, family, dream.',pt:'Acrescenta hoje um fio ao teu ninho: casa, família, sonho.'}},
  {el:'nature',kw:{ro:'Anotimpurile',en:'The Seasons',pt:'As Estações'},t:{ro:'Natura nu ține nimic pe loc: tot ce vine, trece; tot ce trece, revine. Ține-te de ritm, nu de clipă.',en:'Nature holds nothing still: all that comes, passes; all that passes, returns. Hold to the rhythm, not the moment.',pt:'A natureza não segura nada no lugar: tudo o que vem, passa; tudo o que passa, volta. Agarra-te ao ritmo, não ao instante.'},inv:{ro:'Ce anotimp se încheie în viața ta? Salută-l pe următorul.',en:'What season is ending in your life? Greet the next one.',pt:'Que estação termina na tua vida? Saúda a próxima.'}},
  {el:'nature',kw:{ro:'Roua dimineții',en:'The Morning Dew',pt:'O Orvalho da Manhã'},t:{ro:'Roua nu cade pe frunza care se scutură întruna. Liniștește-te și darurile mici se vor așeza pe tine.',en:'Dew does not settle on the leaf that keeps shaking. Grow still, and small gifts will settle on you.',pt:'O orvalho não pousa na folha que não pára de se sacudir. Aquieta-te, e os pequenos dons pousarão em ti.'},inv:{ro:'Stai azi nemișcat cinci minute și vezi ce se așază.',en:'Be still five minutes today and see what settles.',pt:'Fica hoje quieto cinco minutos e vê o que pousa.'}},
  {el:'nature',kw:{ro:'Muntele de departe',en:'The Mountain from Afar',pt:'A Montanha ao Longe'},t:{ro:'De aproape, muntele e pietre și osteneală; de departe, e albastru și chemare. Amândouă sunt adevărate.',en:'Up close, the mountain is stones and toil; from afar, blue and calling. Both are true.',pt:'De perto, a montanha é pedras e canseira; de longe, azul e chamamento. Ambas são verdadeiras.'},inv:{ro:'Privește azi de departe muntele pe care urci: de ce ai pornit?',en:'Look from afar today at the mountain you climb: why did you set out?',pt:'Olha hoje de longe a montanha que sobes: porque partiste?'}},
  {el:'nature',kw:{ro:'Pârgul',en:'The Ripening',pt:'O Amadurecer'},t:{ro:'Fructul crud ține de ram cu toată puterea; cel copt se desprinde singur. Nu te rupe; coace-te.',en:'The unripe fruit clings to the branch with all its might; the ripe one lets go by itself. Do not tear away; ripen.',pt:'O fruto verde agarra-se ao ramo com toda a força; o maduro solta-se sozinho. Não te arranques; amadurece.'},inv:{ro:'Unde te forțezi să te desprinzi necopt? Mai coace-te puțin.',en:'Where do you force an unripe letting-go? Ripen a little longer.',pt:'Onde forças um largar verde? Amadurece mais um pouco.'}},
  {el:'nature',kw:{ro:'Cântecul greierului',en:'The Cricket’s Song',pt:'O Canto do Grilo'},t:{ro:'Nimeni nu i-a cerut greierului să cânte. El cântă pentru că din asta e făcut. Tu din ce ești făcut?',en:'No one asked the cricket to sing. It sings because that is what it is made of. What are you made of?',pt:'Ninguém pediu ao grilo que cantasse. Canta porque é disso que é feito. De que és feito tu?'},inv:{ro:'Fă azi, măcar zece minute, lucrul din care ești făcut.',en:'Do, for at least ten minutes today, the thing you are made of.',pt:'Faz hoje, ao menos dez minutos, aquilo de que és feito.'}},

  /* ———————— CERCUL TĂCERII ———————— */
  {el:'silence',kw:{ro:'Tăcerea dintâi',en:'The First Silence',pt:'O Primeiro Silêncio'},t:{ro:'Înainte de orice cuvânt a fost tăcere. Cine o vizitează des vorbește apoi mai adevărat.',en:'Before every word there was silence. Who visits it often speaks more truly afterward.',pt:'Antes de toda a palavra houve silêncio. Quem o visita amiúde fala depois com mais verdade.'},inv:{ro:'Începe azi o discuție importantă cu trei secunde de tăcere.',en:'Begin one important talk today with three seconds of silence.',pt:'Começa hoje uma conversa importante com três segundos de silêncio.'}},
  {el:'silence',kw:{ro:'Pauza din vorbă',en:'The Pause in Speech',pt:'A Pausa na Fala'},t:{ro:'Pauza pusă bine face cuvântul de dinainte s-atârne și pe cel de după să cadă drept.',en:'A well-placed pause makes the word before it linger and the one after fall true.',pt:'Uma pausa bem posta faz a palavra de antes pesar e a de depois cair certa.'},inv:{ro:'Vorbește azi mai rar cu o idee. Lasă pauzele să lucreze.',en:'Speak a touch slower today. Let the pauses work.',pt:'Fala hoje um pouco mais devagar. Deixa as pausas trabalhar.'}},
  {el:'silence',kw:{ro:'Ascultarea adâncă',en:'Deep Listening',pt:'A Escuta Profunda'},t:{ro:'Sub cuvintele omului curge un râu: ce simte, ce speră, ce-l doare. Ascultă râul, nu doar podul.',en:'Beneath a person’s words runs a river: what they feel, hope, and ache. Listen to the river, not just the bridge.',pt:'Sob as palavras de alguém corre um rio: o que sente, espera e dói. Escuta o rio, não só a ponte.'},inv:{ro:'Într-o discuție de azi, ascultă râul de sub cuvinte.',en:'In one talk today, listen to the river beneath the words.',pt:'Numa conversa de hoje, escuta o rio sob as palavras.'}},
  {el:'silence',kw:{ro:'Liniștea din zgomot',en:'Stillness in Noise',pt:'A Calma no Ruído'},t:{ro:'Nu poți amuți lumea, dar poți coborî volumul dinăuntru. Liniștea adevărată e portabilă.',en:'You cannot mute the world, but you can lower the volume within. True stillness is portable.',pt:'Não podes silenciar o mundo, mas podes baixar o volume por dentro. A verdadeira calma é portátil.'},inv:{ro:'În cel mai zgomotos moment al zilei, găsește-ți liniștea de buzunar.',en:'In the loudest moment today, find your pocket stillness.',pt:'No momento mais barulhento de hoje, encontra a tua calma de bolso.'}},
  {el:'silence',kw:{ro:'Cuvântul necheltuit',en:'The Unspent Word',pt:'A Palavra Não Gasta'},t:{ro:'Cuvântul nespus la mânie e o avere pusă deoparte. O găsești mâine, întreagă, cu dobânda păcii.',en:'The word unsaid in anger is wealth set aside. You find it tomorrow, whole, with the interest of peace.',pt:'A palavra não dita na raiva é riqueza posta de lado. Encontra-la amanhã, inteira, com os juros da paz.'},inv:{ro:'Economisește azi o replică. Pune-o la păstrare.',en:'Save one retort today. Put it in keeping.',pt:'Poupa hoje uma resposta. Guarda-a.'}},
  {el:'silence',kw:{ro:'Tăcerea împreună',en:'Silence Together',pt:'O Silêncio a Dois'},t:{ro:'Prietenia adevărată se cunoaște după tăcerea în care e bine. Cu cine poți tăcea, cu acela poți orice.',en:'True friendship is known by the silence that feels good. With whomever you can be silent, you can do anything.',pt:'A amizade verdadeira conhece-se pelo silêncio em que se está bem. Com quem podes calar, podes tudo.'},inv:{ro:'Stai azi cu cineva drag fără să umpleți liniștea.',en:'Sit with someone dear today without filling the quiet.',pt:'Fica hoje com alguém querido sem encher o silêncio.'}},
  {el:'silence',kw:{ro:'Chilia lăuntrică',en:'The Inner Cell',pt:'A Cela Interior'},t:{ro:'Porți în tine o încăpere în care nu intră nimeni fără voia ta. Mobileaz-o frumos: acolo te retragi.',en:'You carry within a room no one enters without your leave. Furnish it well: that is where you retreat.',pt:'Levas em ti um quarto onde ninguém entra sem tua licença. Mobila-o bem: é para lá que te recolhes.'},inv:{ro:'Retrage-te azi trei minute în chilia ta, oriunde ai fi.',en:'Withdraw three minutes into your cell today, wherever you are.',pt:'Recolhe-te hoje três minutos na tua cela, onde estiveres.'}},
  {el:'silence',kw:{ro:'Muțenia rea',en:'The Bad Silence',pt:'O Silêncio Mau'},t:{ro:'E o tăcere care vindecă și una care pedepsește. A doua nu e liniște; e război cu gura închisă.',en:'There is a silence that heals and one that punishes. The second is not quiet; it is war with a closed mouth.',pt:'Há um silêncio que cura e um que castiga. O segundo não é calma; é guerra de boca fechada.'},inv:{ro:'Dacă taci azi ca pedeapsă, mai bine spune blând ce doare.',en:'If you are silent as punishment today, better say gently what hurts.',pt:'Se hoje calas como castigo, melhor dizer com doçura o que dói.'}},
  {el:'silence',kw:{ro:'Tăcerea dinaintea răspunsului',en:'The Silence Before the Answer',pt:'O Silêncio Antes da Resposta'},t:{ro:'Secunda de tăcere dinaintea răspunsului e sita prin care trec doar cuvintele vrednice.',en:'The second of silence before an answer is the sieve through which only worthy words pass.',pt:'O segundo de silêncio antes da resposta é a peneira por onde só passam palavras dignas.'},inv:{ro:'Pune azi sita: o secundă înainte de fiecare răspuns aprins.',en:'Use the sieve today: one second before every heated reply.',pt:'Usa hoje a peneira: um segundo antes de cada resposta acesa.'}},
  {el:'silence',kw:{ro:'Zgomotul lumii',en:'The World’s Noise',pt:'O Ruído do Mundo'},t:{ro:'Lumea strigă fiindcă se teme că n-o auzi. Ce e cu adevărat important vorbește în șoaptă.',en:'The world shouts because it fears you will not hear. What truly matters speaks in a whisper.',pt:'O mundo grita porque teme que não o ouças. O que importa de verdade fala em sussurro.'},inv:{ro:'Coboară azi volumul lumii: mai puține notificări, mai multă șoaptă.',en:'Turn the world down today: fewer notifications, more whisper.',pt:'Baixa hoje o volume do mundo: menos notificações, mais sussurro.'}},
  {el:'silence',kw:{ro:'Postul de cuvinte',en:'The Fast of Words',pt:'O Jejum de Palavras'},t:{ro:'O oră fără vorbe pe zi și vorbele tale de restul zilei încep să cântărească.',en:'One wordless hour a day, and your words for the rest of it begin to carry weight.',pt:'Uma hora sem palavras por dia, e as tuas palavras do resto do dia começam a pesar.'},inv:{ro:'Ține azi o oră de post al vorbelor.',en:'Keep one hour’s fast of words today.',pt:'Guarda hoje uma hora de jejum de palavras.'}},
  {el:'silence',kw:{ro:'Liniștea dimineții',en:'The Morning Quiet',pt:'A Quietude da Manhã'},t:{ro:'Dimineața, înainte ca lumea să se trezească, liniștea e proaspătă ca pâinea caldă. Rupe-ți o bucată.',en:'In the morning, before the world wakes, the quiet is fresh as warm bread. Break off a piece.',pt:'De manhã, antes de o mundo acordar, a quietude é fresca como pão quente. Parte um pedaço.'},inv:{ro:'Mâine, primele zece minute: fără sunete, fără ecran.',en:'Tomorrow, the first ten minutes: no sounds, no screen.',pt:'Amanhã, os primeiros dez minutos: sem sons, sem ecrã.'}},
  {el:'silence',kw:{ro:'Secretul păstrat',en:'The Kept Secret',pt:'O Segredo Guardado'},t:{ro:'Taina încredințată ție e un ou în palma ta. Nu se ține strâns și nu se dă mai departe. Se ține cald.',en:'A secret entrusted to you is an egg in your palm. Not to be squeezed, not to be passed on. To be kept warm.',pt:'Um segredo confiado a ti é um ovo na tua palma. Não se aperta, não se passa adiante. Guarda-se quente.'},inv:{ro:'Păzește azi ce ți s-a încredințat, chiar dacă „e interesant".',en:'Guard today what was entrusted to you, however “interesting.”',pt:'Guarda hoje o que te foi confiado, por mais «interessante» que seja.'}},
  {el:'silence',kw:{ro:'Tăcerea rugăciunii',en:'The Silence of Prayer',pt:'O Silêncio da Oração'},t:{ro:'Cea mai adâncă rugăciune nu cere nimic: stă, pur și simplu, în fața Celui care știe deja.',en:'The deepest prayer asks nothing: it simply stands before the One who already knows.',pt:'A oração mais profunda não pede nada: apenas está diante d’Aquele que já sabe.'},inv:{ro:'Stai azi două minute în fața cerului fără să ceri nimic.',en:'Stand two minutes before heaven today asking nothing.',pt:'Fica hoje dois minutos diante do céu sem pedir nada.'}},
  {el:'silence',kw:{ro:'Cuvântul cântărit',en:'The Weighed Word',pt:'A Palavra Pesada'},t:{ro:'Vameșii vechi cântăreau marfa la poartă. Fii vameșul gurii tale: ce nu are greutate nu trece.',en:'Old customs men weighed goods at the gate. Be the customs man of your mouth: what has no weight does not pass.',pt:'Os antigos alfandegários pesavam a mercadoria à porta. Sê o alfandegário da tua boca: o que não tem peso não passa.'},inv:{ro:'Azi, la fiecare lucru important: merită spus? de mine? acum?',en:'Today, for each big thing: worth saying? by me? now?',pt:'Hoje, para cada coisa importante: vale dizer? por mim? agora?'}},
  {el:'silence',kw:{ro:'Ecoul',en:'The Echo',pt:'O Eco'},t:{ro:'Ce strigi în vale se întoarce la tine întocmai. Lumea e un munte politicos: îți răspunde cu vocea ta.',en:'What you shout into the valley returns to you exactly. The world is a polite mountain: it answers in your voice.',pt:'O que gritas ao vale volta-te tal e qual. O mundo é uma montanha educada: responde com a tua voz.'},inv:{ro:'Trimite azi în vale doar ce vrei să auzi înapoi.',en:'Send into the valley today only what you want echoed back.',pt:'Manda hoje ao vale só o que queres ouvir de volta.'}},
  {el:'silence',kw:{ro:'Odaia goală',en:'The Empty Room',pt:'O Quarto Vazio'},t:{ro:'Odaia goală nu e săracă; e gata. La fel mintea golită seara: pregătită pentru oaspetele de mâine.',en:'The empty room is not poor; it is ready. So is the mind emptied at night: prepared for tomorrow’s guest.',pt:'O quarto vazio não é pobre; está pronto. Assim a mente esvaziada à noite: preparada para o hóspede de amanhã.'},inv:{ro:'Golește-ți diseară mintea pe hârtie. Lasă odaia gata.',en:'Empty your mind onto paper tonight. Leave the room ready.',pt:'Esvazia esta noite a mente para o papel. Deixa o quarto pronto.'}},
  {el:'silence',kw:{ro:'Vorbirea despre alții',en:'Speaking of Others',pt:'O Falar dos Outros'},t:{ro:'Cine îți vorbește de rău pe alții îți ia măsura pentru haina pe care ți-o va croi și ție.',en:'Whoever speaks ill of others to you is taking your measurements for the coat they will cut for you too.',pt:'Quem te fala mal dos outros está a tirar-te as medidas para o casaco que também te há de talhar.'},inv:{ro:'Azi, când începe bârfa, taci frumos sau schimbă apa.',en:'Today, when gossip starts, fall kindly silent or change the water.',pt:'Hoje, quando começar o mexerico, cala com elegância ou muda de águas.'}},
  {el:'silence',kw:{ro:'Muzica liniștii',en:'The Music of Quiet',pt:'A Música da Quietude'},t:{ro:'După un concert mare, sala tace o clipă înainte de aplauze. În clipa aceea locuiește tot concertul.',en:'After a great concert, the hall is silent an instant before the applause. In that instant lives the whole concert.',pt:'Depois de um grande concerto, a sala cala-se um instante antes do aplauso. Nesse instante mora o concerto inteiro.'},inv:{ro:'După ceva frumos azi, nu comenta imediat. Stai în clipă.',en:'After something beautiful today, do not comment at once. Stay in the instant.',pt:'Depois de algo belo hoje, não comentes logo. Fica no instante.'}},
  {el:'silence',kw:{ro:'Graiul faptei',en:'The Speech of Deeds',pt:'A Fala dos Atos'},t:{ro:'Faptele au glasul cel mai tare tocmai pentru că nu spun nimic. Lasă-le pe ele să-ți țină discursurile.',en:'Deeds have the loudest voice precisely because they say nothing. Let them give your speeches.',pt:'Os atos têm a voz mais alta precisamente porque não dizem nada. Deixa-os fazer os teus discursos.'},inv:{ro:'Azi, în loc să explici cine ești, arată o dată.',en:'Today, instead of explaining who you are, show it once.',pt:'Hoje, em vez de explicares quem és, mostra uma vez.'}},
  {el:'silence',kw:{ro:'Urechile împrumutate',en:'The Borrowed Ears',pt:'Os Ouvidos Emprestados'},t:{ro:'Uneori omul nu are nevoie de gura ta, ci doar de urechile tale. Împrumută-i-le fără dobândă.',en:'Sometimes a person needs not your mouth, only your ears. Lend them interest-free.',pt:'Às vezes a pessoa não precisa da tua boca, só dos teus ouvidos. Empresta-lhos sem juros.'},inv:{ro:'Împrumută azi cuiva urechile, un sfert de oră întreg.',en:'Lend someone your ears today, one whole quarter hour.',pt:'Empresta hoje a alguém os ouvidos, um quarto de hora inteiro.'}},
  {el:'silence',kw:{ro:'Tăcerea din bibliotecă',en:'The Library Hush',pt:'O Silêncio da Biblioteca'},t:{ro:'În liniștea dintre rafturi, mii de voci așteaptă cuminți să fie deschise. Liniștea plină e cea mai bogată.',en:'In the hush between shelves, a thousand voices wait quietly to be opened. Full silence is the richest kind.',pt:'No silêncio entre as estantes, mil vozes esperam quietas ser abertas. O silêncio cheio é o mais rico.'},inv:{ro:'Petrece azi un sfert de oră cu o carte, în tăcere deplină.',en:'Spend a quarter hour with a book today, in complete quiet.',pt:'Passa hoje um quarto de hora com um livro, em silêncio total.'}},
  {el:'silence',kw:{ro:'Nespusul dintre doi',en:'The Unsaid Between Two',pt:'O Não Dito Entre Dois'},t:{ro:'În orice casă se strânge nespus, ca praful sub pat. Din când în când, faceți curat vorbind.',en:'In every home the unsaid gathers like dust under the bed. Now and then, clean house by speaking.',pt:'Em toda a casa o não dito junta-se como pó debaixo da cama. De vez em quando, façam limpeza falando.'},inv:{ro:'Scoate azi de sub pat un singur nespus, cu blândețe.',en:'Bring one unsaid thing out from under the bed today, gently.',pt:'Tira hoje de debaixo da cama um só não dito, com doçura.'}},
  {el:'silence',kw:{ro:'Tăcerea de aur',en:'The Golden Silence',pt:'O Silêncio de Ouro'},t:{ro:'Vorba e argint doar când tăcerea din jurul ei e aur. Sărăcia vorbelor multe e că n-au ramă.',en:'Speech is silver only when the silence around it is gold. The poverty of many words is that they have no frame.',pt:'A fala é prata só quando o silêncio à sua volta é ouro. A pobreza das muitas palavras é não terem moldura.'},inv:{ro:'Înrămează azi în tăcere singurul lucru important de spus.',en:'Frame in silence today the one important thing to say.',pt:'Emoldura hoje em silêncio a única coisa importante a dizer.'}},
  {el:'silence',kw:{ro:'Fântâna adâncă',en:'The Deep Well',pt:'O Poço Fundo'},t:{ro:'Fântânile adânci nu se laudă cu apa lor. Cine are adânc vorbește puțin și adapă mult.',en:'Deep wells do not boast of their water. Whoever has depth speaks little and waters much.',pt:'Os poços fundos não se gabam da sua água. Quem tem fundura fala pouco e dá muito de beber.'},inv:{ro:'Adapă azi pe cineva fără să-i ții și o prelegere.',en:'Water someone today without also giving a lecture.',pt:'Dá hoje de beber a alguém sem lhe dares também uma palestra.'}},
  {el:'silence',kw:{ro:'Clopotul',en:'The Bell',pt:'O Sino'},t:{ro:'Clopotul sună o dată și lasă văzduhul să ducă restul. Spune esențialul; lasă tăcerea să-l poarte.',en:'The bell strikes once and lets the air carry the rest. Say the essential; let silence carry it.',pt:'O sino toca uma vez e deixa o ar levar o resto. Diz o essencial; deixa o silêncio levá-lo.'},inv:{ro:'Azi, la lucrul cel mare: o singură frază, apoi taci.',en:'Today, for the big thing: one sentence, then silence.',pt:'Hoje, para a coisa grande: uma frase, depois silêncio.'}},
  {el:'silence',kw:{ro:'Ninsoarea',en:'The Snowfall',pt:'A Nevada'},t:{ro:'Nimic nu tace mai frumos decât ninsoarea. Și totuși schimbă fața întregii lumi până dimineața.',en:'Nothing is silent more beautifully than snowfall. And yet it changes the face of the world by morning.',pt:'Nada silencia mais belamente do que a neve a cair. E contudo muda a face do mundo até de manhã.'},inv:{ro:'Schimbă azi ceva în tăcere, fără anunț. Ca ninsoarea.',en:'Change something in silence today, unannounced. Like snow.',pt:'Muda hoje algo em silêncio, sem anúncio. Como a neve.'}},
  {el:'silence',kw:{ro:'Șoapta potrivită',en:'The Right Whisper',pt:'O Sussurro Certo'},t:{ro:'Copiii adorm la șoaptă, nu la strigăt. Multe uși din om se deschid doar la voce mică.',en:'Children fall asleep to whispers, not shouts. Many doors in a person open only to a soft voice.',pt:'As crianças adormecem ao sussurro, não ao grito. Muitas portas na pessoa só se abrem à voz baixa.'},inv:{ro:'Încearcă azi cu șoapta acolo unde strigătul a dat greș.',en:'Try a whisper today where shouting has failed.',pt:'Tenta hoje o sussurro onde o grito falhou.'}},
  {el:'silence',kw:{ro:'Cartea închisă',en:'The Closed Book',pt:'O Livro Fechado'},t:{ro:'Nu tot ce știi trebuie spus. Fii ca o carte bună: deschisă cui întreabă, închisă cui răsfoiește din plictis.',en:'Not all you know must be told. Be like a good book: open to those who ask, closed to idle browsers.',pt:'Nem tudo o que sabes deve ser dito. Sê como um bom livro: aberto a quem pergunta, fechado a quem folheia por tédio.'},inv:{ro:'Păstrează azi ceva doar pentru cine întreabă cu adevărat.',en:'Keep something today only for those who truly ask.',pt:'Guarda hoje algo só para quem pergunta de verdade.'}},
  {el:'silence',kw:{ro:'Liniștea de după furtună',en:'The Calm After the Storm',pt:'A Calma Depois da Tempestade'},t:{ro:'După ceartă, primul care tace frumos câștigă pentru amândoi.',en:'After a quarrel, the first to fall kindly silent wins for both.',pt:'Depois da discussão, o primeiro a calar com bondade ganha pelos dois.'},inv:{ro:'Fii azi primul care lasă liniștea să intre după o ceartă.',en:'Be the first today to let the calm in after a quarrel.',pt:'Sê hoje o primeiro a deixar entrar a calma depois de uma discussão.'}},
  {el:'silence',kw:{ro:'Ceasul fără limbi',en:'The Clock Without Hands',pt:'O Relógio Sem Ponteiros'},t:{ro:'În tăcerea deplină, timpul își pierde limbile. Rămâne doar prezența — și ea îți ajunge.',en:'In complete silence, the clock loses its hands. Only presence remains — and it is enough.',pt:'No silêncio completo, o relógio perde os ponteiros. Fica só a presença — e ela basta.'},inv:{ro:'Cinci minute azi fără timp: doar tu, aici.',en:'Five minutes today outside time: just you, here.',pt:'Cinco minutos hoje fora do tempo: só tu, aqui.'}},
  {el:'silence',kw:{ro:'Ultimul cuvânt',en:'The Last Word',pt:'A Última Palavra'},t:{ro:'Cine renunță la ultimul cuvânt câștigă ultima pace. Schimbul e mereu în folosul lui.',en:'Who gives up the last word gains the last peace. The trade is always in their favor.',pt:'Quem abre mão da última palavra ganha a última paz. A troca é sempre a seu favor.'},inv:{ro:'Lasă azi cuiva ultimul cuvânt. Ia-ți tu pacea.',en:'Leave someone the last word today. Take the peace.',pt:'Deixa hoje a alguém a última palavra. Fica tu com a paz.'}},
  {el:'silence',kw:{ro:'Tăcerea care binecuvântează',en:'The Silence that Blesses',pt:'O Silêncio que Abençoa'},t:{ro:'Poți binecuvânta și fără cuvinte: o privire bună peste un om e o rugă întreagă.',en:'You can bless without words: a kind gaze over a person is a whole prayer.',pt:'Podes abençoar sem palavras: um olhar bom sobre alguém é uma oração inteira.'},inv:{ro:'Binecuvântează azi din priviri trei oameni, în tăcere.',en:'Bless three people with your gaze today, in silence.',pt:'Abençoa hoje três pessoas com o olhar, em silêncio.'}},

  /* ———————— CERCUL COPILULUI ———————— */
  {el:'child',kw:{ro:'Mirarea dintâi',en:'The First Wonder',pt:'O Primeiro Espanto'},t:{ro:'Copilul vede lumea pentru prima oară în fiecare zi. Ochiul acela nu se pierde; doar se dezvață.',en:'The child sees the world for the first time every day. That eye is not lost; it is only untrained.',pt:'A criança vê o mundo pela primeira vez todos os dias. Esse olhar não se perde; apenas se desaprende.'},inv:{ro:'Privește azi un lucru banal ca la prima vedere.',en:'Look at one ordinary thing today as if first seen.',pt:'Olha hoje uma coisa banal como se fosse a primeira vez.'}},
  {el:'child',kw:{ro:'Întrebarea „de ce"',en:'The Question “Why”',pt:'A Pergunta «Porquê»'},t:{ro:'Copilul întreabă „de ce" până dă de fund. Adultul se oprește la primul răspuns comod.',en:'The child asks “why” until reaching the bottom. The adult stops at the first comfortable answer.',pt:'A criança pergunta «porquê» até chegar ao fundo. O adulto pára na primeira resposta cómoda.'},inv:{ro:'Pune azi trei „de ce" la rând unei singure păreri de-ale tale.',en:'Ask three whys in a row of one of your own opinions today.',pt:'Faz hoje três «porquês» seguidos a uma opinião tua.'}},
  {el:'child',kw:{ro:'Căderea și râsul',en:'Falling and Laughing',pt:'Cair e Rir'},t:{ro:'Copilul cade, râde și încearcă iar. Nicăieri în el nu scrie „sunt un om care cade".',en:'The child falls, laughs, and tries again. Nowhere inside does it say “I am one who falls.”',pt:'A criança cai, ri e tenta de novo. Em nenhum lugar dela está escrito «sou alguém que cai».'},inv:{ro:'La prima greșeală de azi, râzi întâi, judecă-te deloc.',en:'At today’s first mistake, laugh first, judge not at all.',pt:'No primeiro erro de hoje, ri primeiro, não te julgues.'}},
  {el:'child',kw:{ro:'Prima oară',en:'The First Time',pt:'A Primeira Vez'},t:{ro:'Tot ce știi bine a avut o primă oară stângace. Cinstește stângăcia: e mama priceperii.',en:'All you now do well once had a clumsy first time. Honor clumsiness: it is the mother of skill.',pt:'Tudo o que hoje fazes bem teve uma primeira vez desajeitada. Honra o desajeito: é a mãe da perícia.'},inv:{ro:'Fă azi un lucru pentru prima oară, oricât de mic.',en:'Do one thing for the first time today, however small.',pt:'Faz hoje algo pela primeira vez, por pequeno que seja.'}},
  {el:'child',kw:{ro:'Iertarea iute',en:'Quick Forgiveness',pt:'O Perdão Rápido'},t:{ro:'Copiii se ceartă dimineața și se joacă la prânz. Ei știu: jocul e mai mare decât cearta.',en:'Children quarrel in the morning and play by noon. They know: the game is bigger than the quarrel.',pt:'As crianças brigam de manhã e brincam ao meio-dia. Elas sabem: o jogo é maior que a briga.'},inv:{ro:'Scurtează azi o supărare cu o zi întreagă.',en:'Shorten one sulk by a whole day today.',pt:'Encurta hoje um amuo num dia inteiro.'}},
  {el:'child',kw:{ro:'Desculț prin iarbă',en:'Barefoot in Grass',pt:'Descalço na Erva'},t:{ro:'Talpa goală pe pământ e cea mai veche rugăciune a trupului. Copiii o spun fără să știe.',en:'A bare sole on the earth is the body’s oldest prayer. Children say it without knowing.',pt:'A planta do pé nua na terra é a oração mais antiga do corpo. As crianças dizem-na sem saber.'},inv:{ro:'Umblă azi desculț măcar un minut.',en:'Walk barefoot at least one minute today.',pt:'Anda hoje descalço pelo menos um minuto.'}},
  {el:'child',kw:{ro:'Somnul fără griji',en:'Carefree Sleep',pt:'O Sono Sem Cuidados'},t:{ro:'Copilul adoarme la mijlocul propoziției, sigur că lumea îl va aștepta. Lumea chiar așteaptă.',en:'The child falls asleep mid-sentence, certain the world will wait. The world does wait.',pt:'A criança adormece a meio da frase, certa de que o mundo esperará. O mundo espera mesmo.'},inv:{ro:'Adormi diseară fără să termini toate propozițiile zilei.',en:'Fall asleep tonight without finishing all the day’s sentences.',pt:'Adormece esta noite sem acabar todas as frases do dia.'}},
  {el:'child',kw:{ro:'Desenul',en:'The Drawing',pt:'O Desenho'},t:{ro:'Copilul desenează fără să întrebe dacă are talent. Face din bucurie, nu din verdict.',en:'The child draws without asking if it has talent. It creates from joy, not verdict.',pt:'A criança desenha sem perguntar se tem talento. Cria por alegria, não por veredicto.'},inv:{ro:'Creează azi ceva fără să-l judeci deloc.',en:'Create something today without judging it at all.',pt:'Cria hoje algo sem o julgares de todo.'}},
  {el:'child',kw:{ro:'Povestea de seară',en:'The Bedtime Story',pt:'A História de Embalar'},t:{ro:'„A fost odată" deschide o ușă pe care niciun argument n-o poate deschide. Poveștile intră unde teoriile bat degeaba.',en:'“Once upon a time” opens a door no argument can. Stories enter where theories knock in vain.',pt:'«Era uma vez» abre uma porta que nenhum argumento abre. As histórias entram onde as teorias batem em vão.'},inv:{ro:'Spune azi cuiva o poveste în loc de o lecție.',en:'Tell someone a story today instead of a lesson.',pt:'Conta hoje a alguém uma história em vez de uma lição.'}},
  {el:'child',kw:{ro:'„Mai spune o dată"',en:'“Tell It Again”',pt:'«Conta Outra Vez»'},t:{ro:'Copilul cere aceeași poveste de o sută de ori: știe că lucrurile bune nu se epuizează prin repetare.',en:'The child asks for the same story a hundred times: it knows good things are not used up by repeating.',pt:'A criança pede a mesma história cem vezes: sabe que as coisas boas não se gastam ao repetir.'},inv:{ro:'Reia azi cu drag o bucurie „deja știută".',en:'Return gladly today to an “already known” joy.',pt:'Volta hoje com gosto a uma alegria «já conhecida».'}},
  {el:'child',kw:{ro:'Curiozitatea',en:'Curiosity',pt:'A Curiosidade'},t:{ro:'Curiozitatea e foamea sufletului tânăr. Cine o hrănește zilnic nu îmbătrânește pe dinăuntru.',en:'Curiosity is the young soul’s hunger. Who feeds it daily does not grow old within.',pt:'A curiosidade é a fome da alma jovem. Quem a alimenta todos os dias não envelhece por dentro.'},inv:{ro:'Urmează azi o curiozitate fără niciun folos practic.',en:'Follow one useless curiosity today.',pt:'Segue hoje uma curiosidade sem utilidade prática.'}},
  {el:'child',kw:{ro:'Lacrima scurtă',en:'The Short Tear',pt:'A Lágrima Curta'},t:{ro:'Copilul plânge tare și scurt, apoi e gata. Adultul plânge încet și ani întregi. Învață plânsul scurt.',en:'The child cries loudly and briefly, then is done. The adult cries quietly for years. Learn the short cry.',pt:'A criança chora alto e pouco, e pronto. O adulto chora baixinho durante anos. Aprende o choro curto.'},inv:{ro:'Dă azi durerii un ceas întreg — apoi ușa.',en:'Give the hurt one full hour today — then the door.',pt:'Dá hoje à dor uma hora inteira — depois a porta.'}},
  {el:'child',kw:{ro:'Îmbrățișarea fără motiv',en:'The Hug for No Reason',pt:'O Abraço Sem Motivo'},t:{ro:'Copilul te îmbrățișează pentru că exiști. Cea mai curată dragoste nu are „pentru că".',en:'The child hugs you because you exist. The purest love has no “because.”',pt:'A criança abraça-te porque existes. O amor mais puro não tem «porquê».'},inv:{ro:'Îmbrățișează azi pe cineva fără nicio ocazie.',en:'Hug someone today with no occasion at all.',pt:'Abraça hoje alguém sem ocasião nenhuma.'}},
  {el:'child',kw:{ro:'Buzunarul cu comori',en:'The Pocket of Treasures',pt:'O Bolso de Tesouros'},t:{ro:'În buzunarul unui copil: o piatră, un capac, o sfoară — un muzeu al atenției. Bogăția e un fel de a privi.',en:'In a child’s pocket: a stone, a cap, a string — a museum of attention. Wealth is a way of seeing.',pt:'No bolso de uma criança: uma pedra, uma tampa, um fio — um museu da atenção. A riqueza é um modo de ver.'},inv:{ro:'Adună azi o „comoară" măruntă și păstreaz-o pe birou.',en:'Collect one small “treasure” today and keep it on your desk.',pt:'Recolhe hoje um pequeno «tesouro» e guarda-o na secretária.'}},
  {el:'child',kw:{ro:'Acum-ul copilului',en:'The Child’s Now',pt:'O Agora da Criança'},t:{ro:'Copilul nu-și amână bucuria pentru vacanță. Bucuria lui are o singură adresă: acum.',en:'The child does not postpone joy until vacation. Its joy has one address: now.',pt:'A criança não adia a alegria para as férias. A alegria dela tem uma só morada: agora.'},inv:{ro:'Nu amâna azi o bucurie mică posibilă acum.',en:'Do not postpone today a small joy possible now.',pt:'Não adies hoje uma pequena alegria possível agora.'}},
  {el:'child',kw:{ro:'Jocul serios',en:'Serious Play',pt:'O Brincar a Sério'},t:{ro:'Nimeni nu muncește mai serios decât un copil care se joacă. Seriozitatea fără joc obosește; jocul serios zidește.',en:'No one works more seriously than a child at play. Seriousness without play tires; serious play builds.',pt:'Ninguém trabalha mais a sério do que uma criança a brincar. A seriedade sem jogo cansa; o jogo a sério constrói.'},inv:{ro:'Lucrează azi o oră cu seriozitatea jucăușă a copilului.',en:'Work one hour today with a child’s playful seriousness.',pt:'Trabalha hoje uma hora com a seriedade brincalhona da criança.'}},
  {el:'child',kw:{ro:'Ochii de jos',en:'The View from Below',pt:'O Olhar de Baixo'},t:{ro:'De la înălțimea copilului, lumea e uriașă și plină de mistere. Apleacă-te: misterele n-au plecat.',en:'From a child’s height, the world is vast and full of mysteries. Bend down: the mysteries have not left.',pt:'Da altura da criança, o mundo é enorme e cheio de mistérios. Baixa-te: os mistérios não partiram.'},inv:{ro:'Apleacă-te azi la ceva mic: o insectă, o floare, un detaliu.',en:'Bend down to something small today: an insect, a flower, a detail.',pt:'Baixa-te hoje para algo pequeno: um inseto, uma flor, um detalhe.'}},
  {el:'child',kw:{ro:'Încrederea dintâi',en:'The First Trust',pt:'A Primeira Confiança'},t:{ro:'Copilul sare în brațe fără să verifice dacă vor prinde. Cine n-a fost prins învață greu; dar și el poate reînvăța.',en:'The child leaps into arms without checking they will catch. Whoever was dropped learns hard; yet even they can relearn.',pt:'A criança salta para os braços sem verificar se seguram. Quem caiu aprende com custo; mas até esse pode reaprender.'},inv:{ro:'Fă azi un mic salt de încredere într-un om bun.',en:'Take one small leap of trust in a good person today.',pt:'Dá hoje um pequeno salto de confiança numa boa pessoa.'}},
  {el:'child',kw:{ro:'Cutia goală',en:'The Empty Box',pt:'A Caixa Vazia'},t:{ro:'Dai copilului o jucărie scumpă și el se joacă cu cutia. Imaginația face aur din carton.',en:'Give a child an expensive toy and it plays with the box. Imagination makes gold of cardboard.',pt:'Dás a uma criança um brinquedo caro e ela brinca com a caixa. A imaginação faz ouro do cartão.'},inv:{ro:'Fă azi ceva minunat dintr-un nimic aflat la îndemână.',en:'Make something wonderful today from a nothing at hand.',pt:'Faz hoje algo maravilhoso de um nada à mão.'}},
  {el:'child',kw:{ro:'Numele lucrurilor',en:'Naming Things',pt:'O Nome das Coisas'},t:{ro:'Copilul botează tot: norul, băţul, melcul. A numi cu drag e primul fel de a lua în stăpânire lumea — fără să o rănești.',en:'The child names everything: the cloud, the stick, the snail. Naming with love is the first way to own the world — without wounding it.',pt:'A criança batiza tudo: a nuvem, o pau, o caracol. Nomear com carinho é o primeiro modo de possuir o mundo — sem o ferir.'},inv:{ro:'Dă azi un nume blând unei griji — se va îmblânzi.',en:'Give a gentle name to one worry today — it will tame.',pt:'Dá hoje um nome doce a uma preocupação — ela amansará.'}},
  {el:'child',kw:{ro:'Rana pupată',en:'The Kissed Scrape',pt:'O Dodói Beijado'},t:{ro:'Pupatul rănii nu e medicină și totuși vindecă. Jumătate din durerile lumii cer doar să fie văzute cu dragoste.',en:'Kissing the scrape is not medicine, yet it heals. Half the world’s pains only ask to be seen with love.',pt:'Beijar o dodói não é medicina e, contudo, cura. Metade das dores do mundo só pede ser vista com amor.'},inv:{ro:'„Pupă" azi rana cuiva: vezi-o, numește-o, stai lângă ea.',en:'“Kiss” someone’s scrape today: see it, name it, stay by it.',pt:'«Beija» hoje o dodói de alguém: vê-o, nomeia-o, fica ao lado.'}},
  {el:'child',kw:{ro:'Da-ul dintâi',en:'The First Yes',pt:'O Primeiro Sim'},t:{ro:'Copilul spune „da" vieții înainte să-i cunoască prețul. Înțeleptul îl spune din nou, după ce l-a aflat.',en:'The child says yes to life before knowing its price. The wise say it again after learning it.',pt:'A criança diz «sim» à vida antes de saber o preço. O sábio di-lo de novo depois de o conhecer.'},inv:{ro:'Spune azi „da" vieții, cu tot cu prețul știut.',en:'Say yes to life today, known price included.',pt:'Diz hoje «sim» à vida, com o preço já sabido.'}},
  {el:'child',kw:{ro:'Fără ceas',en:'Clockless',pt:'Sem Relógio'},t:{ro:'Copilul nu știe cât e ceasul și tocmai de aceea are timp. Ceasul măsoară; copilul trăiește.',en:'The child does not know the hour and precisely therefore has time. The clock measures; the child lives.',pt:'A criança não sabe as horas e é justamente por isso que tem tempo. O relógio mede; a criança vive.'},inv:{ro:'Petrece azi o jumătate de oră fără să știi cât e ceasul.',en:'Spend half an hour today not knowing the time.',pt:'Passa hoje meia hora sem saber as horas.'}},
  {el:'child',kw:{ro:'Uimirea de ploaie',en:'Rain Amazement',pt:'O Espanto da Chuva'},t:{ro:'Adultul fuge de ploaie; copilul o întâmpină cu palmele deschise. Aceeași ploaie, două vieți.',en:'The adult runs from rain; the child greets it with open palms. Same rain, two lives.',pt:'O adulto foge da chuva; a criança recebe-a de palmas abertas. A mesma chuva, duas vidas.'},inv:{ro:'Întâmpină azi o „ploaie" cu palmele deschise.',en:'Greet one “rain” today with open palms.',pt:'Recebe hoje uma «chuva» de palmas abertas.'}},
  {el:'child',kw:{ro:'Întrebarea din pat',en:'The Bedtime Question',pt:'A Pergunta da Cama'},t:{ro:'Seara, copiii pun întrebările cele mari: de unde vin stelele, unde se duce ziua. Nu adormi fără o întrebare mare.',en:'At night, children ask the big questions: where stars come from, where the day goes. Do not fall asleep without one big question.',pt:'À noite, as crianças fazem as grandes perguntas: de onde vêm as estrelas, para onde vai o dia. Não adormeças sem uma grande pergunta.'},inv:{ro:'Pune-ți diseară o întrebare de copil, mare cât cerul.',en:'Ask yourself a child’s question tonight, big as the sky.',pt:'Faz esta noite uma pergunta de criança, grande como o céu.'}},
  {el:'child',kw:{ro:'Piticul din poveste',en:'The Story’s Helper',pt:'O Ajudante do Conto'},t:{ro:'În povești, cel mic și neluat în seamă salvează împărăția. În viață, la fel: nu disprețui rolurile mici.',en:'In tales, the small and overlooked one saves the kingdom. In life too: do not despise small roles.',pt:'Nos contos, o pequeno e ignorado salva o reino. Na vida também: não desprezes os papéis pequenos.'},inv:{ro:'Joacă azi impecabil un rol mărunt.',en:'Play a small role impeccably today.',pt:'Faz hoje na perfeição um papel pequeno.'}},
  {el:'child',kw:{ro:'Mâna întinsă în sus',en:'The Hand Reaching Up',pt:'A Mão Estendida para Cima'},t:{ro:'Copilul întinde mâna în sus fără rușine: știe că are dreptul la ajutor. Tu când ai uitat asta?',en:'The child reaches up without shame: it knows it has a right to help. When did you forget that?',pt:'A criança estende a mão para cima sem vergonha: sabe que tem direito a ajuda. Quando esqueceste isso?'},inv:{ro:'Întinde azi mâna în sus: cere ajutor simplu, ca un copil.',en:'Reach up today: ask for help simply, like a child.',pt:'Estende hoje a mão para cima: pede ajuda com simplicidade, como uma criança.'}},
  {el:'child',kw:{ro:'Ziua de mâine a copilului',en:'The Child’s Tomorrow',pt:'O Amanhã da Criança'},t:{ro:'Pentru copil, „mâine" e o promisiune, nu o amenințare. Diferența nu e în mâine; e în inimă.',en:'For the child, “tomorrow” is a promise, not a threat. The difference is not in tomorrow; it is in the heart.',pt:'Para a criança, «amanhã» é promessa, não ameaça. A diferença não está no amanhã; está no coração.'},inv:{ro:'Culcă-te azi cu un „abia aștept" pentru mâine.',en:'Go to bed with one “I can’t wait” for tomorrow.',pt:'Deita-te hoje com um «mal posso esperar» para amanhã.'}},
  {el:'child',kw:{ro:'Copilul din ceilalți',en:'The Child in Others',pt:'A Criança nos Outros'},t:{ro:'În omul care țipă la tine a fost cândva un copil care a învățat să țipe ca să fie auzit. Vezi copilul, îmblânzești omul.',en:'Inside the person shouting at you was once a child who learned to shout to be heard. See the child, and you soften the adult.',pt:'Dentro de quem grita contigo houve um dia uma criança que aprendeu a gritar para ser ouvida. Vê a criança e amansas o adulto.'},inv:{ro:'La următorul conflict, caută copilul din celălalt.',en:'In the next conflict, look for the child in the other.',pt:'No próximo conflito, procura a criança no outro.'}},
  {el:'child',kw:{ro:'Cireșele la urechi',en:'Cherries on the Ears',pt:'As Cerejas nas Orelhas'},t:{ro:'Copilul face din cireșe cercei și din vară o împărăție. Sărbătoarea se improvizează din ce e la îndemână.',en:'The child makes earrings of cherries and a kingdom of summer. Celebration is improvised from what is at hand.',pt:'A criança faz brincos de cerejas e um reino do verão. A festa improvisa-se com o que está à mão.'},inv:{ro:'Improvizează azi o sărbătoare de cinci minute.',en:'Improvise a five-minute celebration today.',pt:'Improvisa hoje uma festa de cinco minutos.'}},
  {el:'child',kw:{ro:'A crește',en:'Growing Up',pt:'Crescer'},t:{ro:'A crește nu înseamnă a-l părăsi pe copilul din tine, ci a-l lua de mână și a-i arăta lumea mai departe.',en:'Growing up does not mean abandoning the child in you, but taking their hand and showing them more of the world.',pt:'Crescer não é abandonar a criança em ti, mas dar-lhe a mão e mostrar-lhe mais do mundo.'},inv:{ro:'Ia azi copilul din tine de mână la o plimbare.',en:'Take the child in you by the hand for a walk today.',pt:'Leva hoje a criança em ti pela mão a passear.'}},
  {el:'child',kw:{ro:'Ochii care cred',en:'Believing Eyes',pt:'Os Olhos que Creem'},t:{ro:'Copilul crede ce îi spui despre el. Și adultul crede — doar că vocea care îi spune e acum înăuntru. Vorbește-i frumos.',en:'The child believes what you tell it about itself. So does the adult — only the telling voice is now within. Speak kindly.',pt:'A criança acredita no que lhe dizes sobre ela. O adulto também — só que a voz que diz está agora dentro. Fala com bondade.'},inv:{ro:'Spune-i azi copilului dinăuntru o propoziție bună despre el.',en:'Tell your inner child one good sentence about themselves today.',pt:'Diz hoje à tua criança interior uma frase boa sobre ela.'}},
  {el:'child',kw:{ro:'Binecuvântarea celui mic',en:'The Little One’s Blessing',pt:'A Bênção do Pequeno'},t:{ro:'Unde intră un copil, casa se luminează fără să se aprindă nimic. Fii și tu, pe unde intri, o astfel de lumină.',en:'Where a child enters, the house brightens though nothing is lit. Be such a light wherever you enter.',pt:'Onde entra uma criança, a casa ilumina-se sem se acender nada. Sê também tu essa luz por onde entrares.'},inv:{ro:'Intră azi în fiecare încăpere ca o veste bună.',en:'Enter every room today like good news.',pt:'Entra hoje em cada sala como uma boa notícia.'}},

  /* ———————— CERCUL BĂTRÂNEȚII ———————— */
  {el:'elder',kw:{ro:'Ridurile',en:'The Wrinkles',pt:'As Rugas'},t:{ro:'Ridurile sunt scrisul de mână al vieții pe chipul omului. Cine a râs mult are caligrafia frumoasă.',en:'Wrinkles are life’s handwriting on a face. Whoever laughed much has beautiful calligraphy.',pt:'As rugas são a caligrafia da vida no rosto. Quem riu muito tem uma bela letra.'},inv:{ro:'Scrie azi pe chip un rând de râs adevărat.',en:'Write one line of true laughter on your face today.',pt:'Escreve hoje no rosto uma linha de riso verdadeiro.'}},
  {el:'elder',kw:{ro:'Povestea spusă',en:'The Told Story',pt:'A História Contada'},t:{ro:'Bătrânul care își spune povestea nu trăncănește: își predă comoara. Ascult-o cât mai e cine s-o spună.',en:'The elder telling their story is not rambling: they are handing over treasure. Listen while there is still someone to tell it.',pt:'O velho que conta a sua história não tagarela: entrega o seu tesouro. Escuta enquanto há quem conte.'},inv:{ro:'Cere azi unui om în vârstă o poveste — și ascult-o întreagă.',en:'Ask an elder for a story today — and hear it whole.',pt:'Pede hoje a um idoso uma história — e escuta-a inteira.'}},
  {el:'elder',kw:{ro:'Mâinile bunicii',en:'Grandmother’s Hands',pt:'As Mãos da Avó'},t:{ro:'Mâinile bătrâne care au frământat, au cusut și au mângâiat o viață știu un adevăr: iubirea se face cu mâinile.',en:'Old hands that kneaded, sewed and caressed for a lifetime know one truth: love is made with the hands.',pt:'As mãos velhas que amassaram, coseram e afagaram uma vida sabem uma verdade: o amor faz-se com as mãos.'},inv:{ro:'Fă azi cu mâinile un gest de dragoste concret.',en:'Make one concrete gesture of love with your hands today.',pt:'Faz hoje com as mãos um gesto concreto de amor.'}},
  {el:'elder',kw:{ro:'Răbdarea anilor',en:'The Patience of Years',pt:'A Paciência dos Anos'},t:{ro:'Bătrânii nu se mai grăbesc — nu fiindcă nu mai pot, ci fiindcă au aflat cât de puține lucruri merită graba.',en:'Elders no longer hurry — not because they cannot, but because they learned how few things deserve haste.',pt:'Os velhos já não se apressam — não porque não podem, mas porque aprenderam quão poucas coisas merecem pressa.'},inv:{ro:'Întreabă-te azi la fiecare grabă: ar grăbi-o un om înțelept de 80 de ani?',en:'Ask at every rush today: would a wise eighty-year-old hurry this?',pt:'Pergunta em cada pressa de hoje: um sábio de oitenta anos apressaria isto?'}},
  {el:'elder',kw:{ro:'Lucrurile lăsate',en:'The Things Set Down',pt:'As Coisas Pousadas'},t:{ro:'Bătrânețea bună e o lungă lăsare din mâini: întâi poverile, apoi părerile, la urmă frica. Rămâne esențialul, ușor.',en:'Good old age is a long setting-down: first the burdens, then the opinions, last the fear. What remains is the essential, light.',pt:'A boa velhice é um longo pousar: primeiro os fardos, depois as opiniões, por fim o medo. Fica o essencial, leve.'},inv:{ro:'Lasă azi din mâini o părere veche care doar cântărește.',en:'Set down one old opinion today that only weighs.',pt:'Pousa hoje uma opinião antiga que só pesa.'}},
  {el:'elder',kw:{ro:'Iertarea târzie',en:'The Late Forgiveness',pt:'O Perdão Tardio'},t:{ro:'Nicio iertare nu e prea târzie cât timp mai bate o inimă. Unele se spun și peste morminte — și tot ușurează.',en:'No forgiveness is too late while a heart still beats. Some are spoken even over graves — and still lighten.',pt:'Nenhum perdão é tarde demais enquanto um coração bate. Alguns dizem-se até sobre túmulos — e ainda aliviam.'},inv:{ro:'Nu lăsa pe bătrânețe iertarea posibilă azi.',en:'Do not leave for old age a forgiveness possible today.',pt:'Não deixes para a velhice um perdão possível hoje.'}},
  {el:'elder',kw:{ro:'Grădina bătrânului',en:'The Elder’s Garden',pt:'O Jardim do Velho'},t:{ro:'Bătrânul sădește pomi la umbra cărora nu va sta. Așa arată dragostea care a scăpat de sine.',en:'The elder plants trees in whose shade they will not sit. That is what love freed of self looks like.',pt:'O velho planta árvores a cuja sombra não se sentará. Assim é o amor liberto de si mesmo.'},inv:{ro:'Sădește azi ceva pentru cine vine după tine.',en:'Plant something today for those who come after you.',pt:'Planta hoje algo para quem vem depois de ti.'}},
  {el:'elder',kw:{ro:'Moștenirea vie',en:'The Living Inheritance',pt:'A Herança Viva'},t:{ro:'Averea se împarte la notar; moștenirea adevărată se împarte în timpul vieții: obiceiuri, vorbe, feluri de a iubi.',en:'Property is divided at the notary; the true inheritance is given while alive: habits, sayings, ways of loving.',pt:'Os bens dividem-se no notário; a herança verdadeira dá-se em vida: hábitos, ditos, modos de amar.'},inv:{ro:'Predă azi cuiva o bucată de moștenire vie.',en:'Hand someone a piece of living inheritance today.',pt:'Entrega hoje a alguém um pedaço de herança viva.'}},
  {el:'elder',kw:{ro:'Încetineala bună',en:'The Good Slowness',pt:'A Boa Lentidão'},t:{ro:'Pasul bătrân e lent și tocmai de aceea vede: floarea din gard, salutul vecinului, cerul. Viteza e o formă de orbire.',en:'The old step is slow and precisely therefore it sees: the fence flower, the neighbor’s greeting, the sky. Speed is a form of blindness.',pt:'O passo velho é lento e justamente por isso vê: a flor da cerca, o cumprimento do vizinho, o céu. A velocidade é uma forma de cegueira.'},inv:{ro:'Mergi azi undeva intenționat mai încet — și numără ce vezi.',en:'Walk somewhere deliberately slower today — and count what you see.',pt:'Vai hoje a algum lado deliberadamente mais devagar — e conta o que vês.'}},
  {el:'elder',kw:{ro:'Demnitatea',en:'Dignity',pt:'A Dignidade'},t:{ro:'Trupul poate slăbi; demnitatea nu are vârstă. Se poartă la fel la 20 și la 90: cu spatele sufletului drept.',en:'The body may weaken; dignity has no age. It is worn the same at 20 and 90: with the soul’s back straight.',pt:'O corpo pode enfraquecer; a dignidade não tem idade. Usa-se igual aos 20 e aos 90: com as costas da alma direitas.'},inv:{ro:'Îndreaptă azi spatele sufletului, orice ar fi.',en:'Straighten the soul’s back today, whatever comes.',pt:'Endireita hoje as costas da alma, aconteça o que acontecer.'}},
  {el:'elder',kw:{ro:'Frica de uitare',en:'The Fear of Being Forgotten',pt:'O Medo do Esquecimento'},t:{ro:'Nu vei fi ținut minte pentru ce ai strâns, ci pentru ce ai dat. Uitarea nu are putere asupra binelui făcut.',en:'You will be remembered not for what you gathered, but for what you gave. Forgetting has no power over good done.',pt:'Serás lembrado não pelo que juntaste, mas pelo que deste. O esquecimento não tem poder sobre o bem feito.'},inv:{ro:'Depune azi în „contul de neuitat": un bine dat.',en:'Deposit in the unforgettable account today: one good given.',pt:'Deposita hoje na conta do inesquecível: um bem dado.'}},
  {el:'elder',kw:{ro:'Tinerii care nu ascultă',en:'The Young Who Won’t Listen',pt:'Os Jovens que Não Escutam'},t:{ro:'Nici tu n-ai ascultat, și tot ai ajuns. Lasă-i să greșească-nvățând; rămâi doar farul aprins.',en:'You did not listen either, and still you arrived. Let them learn by erring; just keep the lighthouse lit.',pt:'Tu também não escutaste, e ainda assim chegaste. Deixa-os aprender errando; mantém apenas o farol aceso.'},inv:{ro:'Azi: mai puține sfaturi nechemate, o pildă vie în plus.',en:'Today: fewer unasked advices, one more living example.',pt:'Hoje: menos conselhos não pedidos, mais um exemplo vivo.'}},
  {el:'elder',kw:{ro:'Casa amintirilor',en:'The House of Memories',pt:'A Casa das Memórias'},t:{ro:'La bătrânețe locuiești în două case: cea de zid și cea de amintiri. Zidește-o de pe acum frumoasă pe a doua.',en:'In old age you live in two houses: one of walls and one of memories. Build the second beautifully starting now.',pt:'Na velhice moras em duas casas: a de paredes e a de memórias. Constrói desde já com beleza a segunda.'},inv:{ro:'Pune azi o cameră frumoasă în casa de amintiri.',en:'Add one beautiful room to the memory house today.',pt:'Acrescenta hoje um quarto belo à casa das memórias.'}},
  {el:'elder',kw:{ro:'Ochelarii',en:'The Spectacles',pt:'Os Óculos'},t:{ro:'Ochii bătrâni văd mai slab literele și mai limpede oamenii. E un schimb pe care mulți l-ar face.',en:'Old eyes see letters more dimly and people more clearly. It is a trade many would make.',pt:'Os olhos velhos veem pior as letras e melhor as pessoas. É uma troca que muitos fariam.'},inv:{ro:'Privește azi un om cu „ochii bătrâni": dincolo de detalii.',en:'Look at someone today with “old eyes”: past the details.',pt:'Olha hoje alguém com «olhos velhos»: para lá dos detalhes.'}},
  {el:'elder',kw:{ro:'Bastonul',en:'The Cane',pt:'A Bengala'},t:{ro:'Bastonul nu e înfrângere; e înțelepciunea de a primi sprijin. Cine se sprijină ajunge; cine refuză, cade.',en:'The cane is not defeat; it is the wisdom of accepting support. Who leans, arrives; who refuses, falls.',pt:'A bengala não é derrota; é a sabedoria de aceitar apoio. Quem se apoia chega; quem recusa, cai.'},inv:{ro:'Primește azi un sprijin fără să te rușinezi de el.',en:'Accept one support today without shame.',pt:'Aceita hoje um apoio sem vergonha.'}},
  {el:'elder',kw:{ro:'Rețeta nescrisă',en:'The Unwritten Recipe',pt:'A Receita Não Escrita'},t:{ro:'Gustul copilăriei tale stă într-o rețetă pe care o știe o singură pereche de mâini. Scrie-o cât se mai poate.',en:'The taste of your childhood lives in a recipe known by a single pair of hands. Write it down while you still can.',pt:'O sabor da tua infância vive numa receita que só um par de mãos conhece. Escreve-a enquanto podes.'},inv:{ro:'Salvează săptămâna asta o rețetă sau un meșteșug de familie.',en:'Save one family recipe or craft this week.',pt:'Guarda esta semana uma receita ou um saber de família.'}},
  {el:'elder',kw:{ro:'Anii buni rămași',en:'The Good Years Left',pt:'Os Bons Anos que Restam'},t:{ro:'Nu număra anii care s-au dus; numără-i pe cei în care încă poți iubi, ierta și sădi. Aceia sunt averea.',en:'Do not count the years gone; count those in which you can still love, forgive and plant. Those are the fortune.',pt:'Não contes os anos idos; conta aqueles em que ainda podes amar, perdoar e plantar. Esses são a fortuna.'},inv:{ro:'Fă azi un plan frumos pentru anii buni rămași.',en:'Make one beautiful plan today for the good years left.',pt:'Faz hoje um belo plano para os bons anos que restam.'}},
  {el:'elder',kw:{ro:'Tovarășul de o viață',en:'The Lifelong Companion',pt:'O Companheiro de Uma Vida'},t:{ro:'Doi bătrâni care tac împreună pe o bancă au terminat de mult conversația și au rămas cu esențialul: prezența.',en:'Two elders silent together on a bench finished the conversation long ago and kept the essential: presence.',pt:'Dois velhos calados num banco terminaram a conversa há muito e ficaram com o essencial: a presença.'},inv:{ro:'Stai azi lângă omul tău fără niciun program.',en:'Sit beside your person today with no agenda.',pt:'Senta-te hoje ao lado da tua pessoa sem agenda.'}},
  {el:'elder',kw:{ro:'Lucrul neterminat',en:'The Unfinished Work',pt:'A Obra Inacabada'},t:{ro:'Vei lăsa lucruri neterminate — ca toți. Grija ta să fie doar ca cele începute să fi fost vrednice de început.',en:'You will leave things unfinished — as all do. Care only that what you began was worth beginning.',pt:'Deixarás coisas por acabar — como todos. Cuida apenas que o que começaste valesse a pena começar.'},inv:{ro:'Începe azi doar lucruri vrednice de a rămâne neterminate.',en:'Begin today only things worthy even unfinished.',pt:'Começa hoje só coisas dignas até inacabadas.'}},
  {el:'elder',kw:{ro:'Binecuvântarea nepoților',en:'Blessing the Grandchildren',pt:'A Bênção dos Netos'},t:{ro:'Mâna bătrână pe creștetul tânăr mută nevăzut o avere dintr-o viață în alta. Binecuvântarea e un testament fără hârtie.',en:'The old hand on a young head moves an unseen fortune from one life to another. A blessing is a will without paper.',pt:'A mão velha na cabeça jovem transfere uma fortuna invisível de uma vida para outra. A bênção é um testamento sem papel.'},inv:{ro:'Binecuvântează azi un tânăr, cu mâna sau cu gândul.',en:'Bless a young one today, with hand or thought.',pt:'Abençoa hoje um jovem, com a mão ou o pensamento.'}},
  {el:'elder',kw:{ro:'Toamna omului',en:'The Autumn of a Person',pt:'O Outono da Pessoa'},t:{ro:'Toamna nu se plânge că nu e vară: își arată culorile pe care vara nu le are. Fiecare vârstă are foliajul ei.',en:'Autumn does not lament not being summer: it shows colors summer lacks. Each age has its own foliage.',pt:'O outono não se queixa de não ser verão: mostra cores que o verão não tem. Cada idade tem a sua folhagem.'},inv:{ro:'Arată azi o culoare pe care doar vârsta ta o are.',en:'Show a color today that only your age possesses.',pt:'Mostra hoje uma cor que só a tua idade tem.'}},
  {el:'elder',kw:{ro:'Somnul de după-amiază',en:'The Afternoon Nap',pt:'A Sesta'},t:{ro:'Bătrânii au recucerit somnul de după-amiază pe care copiii îl pierd la școală. Cercul se închide cu un pui de somn.',en:'Elders reconquer the afternoon nap children lose at school. The circle closes with a little sleep.',pt:'Os velhos reconquistam a sesta que as crianças perdem na escola. O círculo fecha-se com um soninho.'},inv:{ro:'Îngăduie-ți azi zece minute de odihnă „nemeritată".',en:'Allow ten minutes of “unearned” rest today.',pt:'Permite-te hoje dez minutos de descanso «não merecido».'}},
  {el:'elder',kw:{ro:'Cei plecați',en:'Those Departed',pt:'Os que Partiram'},t:{ro:'Cu vârsta, ai tot mai mulți oameni dragi „dincolo". Nu-i o sărăcire, ci o punte care se lărgește.',en:'With age, more and more dear ones are “beyond.” It is not impoverishment, but a bridge growing wider.',pt:'Com a idade, tens cada vez mais queridos «do outro lado». Não é empobrecimento, é uma ponte que se alarga.'},inv:{ro:'Pomenește azi cu drag un om plecat: o poveste despre el.',en:'Remember a departed one fondly today: one story about them.',pt:'Recorda hoje com carinho alguém que partiu: uma história dele.'}},
  {el:'elder',kw:{ro:'Simplitatea de pe urmă',en:'The Final Simplicity',pt:'A Simplicidade Final'},t:{ro:'La capătul multor complicații, bătrânul înțelept ajunge la trei lucruri: soarele pe față, pâinea caldă, omul de alături.',en:'At the end of many complications, the wise elder arrives at three things: sun on the face, warm bread, the person beside.',pt:'No fim de muitas complicações, o velho sábio chega a três coisas: o sol no rosto, o pão quente, a pessoa ao lado.'},inv:{ro:'Trăiește azi din cele trei lucruri simple. Restul, bonus.',en:'Live on the three simple things today. The rest is bonus.',pt:'Vive hoje das três coisas simples. O resto é bónus.'}},
  {el:'elder',kw:{ro:'Școala pierderilor',en:'The School of Losses',pt:'A Escola das Perdas'},t:{ro:'Bătrânețea e universitatea pierderilor — și diplomele ei sunt blândețea și recunoștința. Nu toți absolvă; tu poți.',en:'Old age is the university of losses — its diplomas are gentleness and gratitude. Not all graduate; you can.',pt:'A velhice é a universidade das perdas — os seus diplomas são a doçura e a gratidão. Nem todos se formam; tu podes.'},inv:{ro:'Transformă azi o pierdere veche într-o lecție blândă.',en:'Turn one old loss into a gentle lesson today.',pt:'Transforma hoje uma perda antiga numa lição doce.'}},
  {el:'elder',kw:{ro:'Vinul vechi',en:'The Old Wine',pt:'O Vinho Velho'},t:{ro:'Unele lucruri nu se strică cu anii, ci se împlinesc: vinul, prietenia, omul lucrat frumos.',en:'Some things do not spoil with years but come into fullness: wine, friendship, a person well-wrought.',pt:'Algumas coisas não se estragam com os anos, completam-se: o vinho, a amizade, a pessoa bem lavrada.'},inv:{ro:'Ce se împlinește în tine cu anii? Numește un lucru.',en:'What ripens in you with the years? Name one thing.',pt:'O que amadurece em ti com os anos? Nomeia uma coisa.'}},
  {el:'elder',kw:{ro:'Pragul serii',en:'The Evening Threshold',pt:'O Limiar da Tarde'},t:{ro:'Spre seară lumina e mai blândă și umbrele mai lungi — și tocmai atunci fotografiile ies cele mai frumoase. Așa și viața.',en:'Toward evening the light softens and shadows lengthen — and just then photographs come out most beautiful. So does life.',pt:'Ao entardecer a luz amansa e as sombras alongam-se — e é então que as fotografias saem mais belas. Assim a vida.'},inv:{ro:'Caută azi frumusețea specifică orei târzii — a zilei sau a vieții.',en:'Seek today the beauty specific to the late hour — of the day or of life.',pt:'Procura hoje a beleza própria da hora tardia — do dia ou da vida.'}},
  {el:'elder',kw:{ro:'Numele bun',en:'The Good Name',pt:'O Bom Nome'},t:{ro:'La capăt, rămân două averi: oamenii pe care i-ai iubit și numele bun. Amândouă se agonisesc mărunt, zilnic.',en:'At the end, two fortunes remain: the people you loved and a good name. Both are earned in small daily coins.',pt:'No fim, restam duas fortunas: as pessoas que amaste e o bom nome. Ambas se juntam em moedas pequenas, diárias.'},inv:{ro:'Adaugă azi o monedă la numele tău bun.',en:'Add one coin to your good name today.',pt:'Acrescenta hoje uma moeda ao teu bom nome.'}},
  {el:'elder',kw:{ro:'Râsul fără dinți',en:'The Toothless Laugh',pt:'O Riso Sem Dentes'},t:{ro:'Bătrânul care râde cu gura știrbă a câștigat războiul cu vanitatea. Râsul lui e cel mai liber de pe pământ.',en:'The elder laughing with missing teeth has won the war against vanity. Theirs is the freest laugh on earth.',pt:'O velho que ri desdentado venceu a guerra contra a vaidade. O seu riso é o mais livre da terra.'},inv:{ro:'Râzi azi o dată fără să-ți pese deloc cum arăți.',en:'Laugh once today caring nothing for how you look.',pt:'Ri hoje uma vez sem te importares com a aparência.'}},
  {el:'elder',kw:{ro:'Scrisoarea către urmași',en:'The Letter to Descendants',pt:'A Carta aos Vindouros'},t:{ro:'Scrie-le celor de peste 50 de ani ce ai învățat cu preț mare. Hârtia e ieftină; lecțiile au costat o viață.',en:'Write to those fifty years ahead what you learned at great price. Paper is cheap; the lessons cost a life.',pt:'Escreve aos de daqui a cinquenta anos o que aprendeste a alto preço. O papel é barato; as lições custaram uma vida.'},inv:{ro:'Începe azi scrisoarea: primele trei lecții ale tale.',en:'Begin the letter today: your first three lessons.',pt:'Começa hoje a carta: as tuas primeiras três lições.'}},
  {el:'elder',kw:{ro:'Mulțumescul de seară',en:'The Evening Thank-You',pt:'O Obrigado da Noite'},t:{ro:'Bătrânii frumoși au un obicei: mulțumesc serii pentru zi, oricum a fost ziua. Așa se face pacea cu viața, seară de seară.',en:'Beautiful elders keep one habit: thanking the evening for the day, however the day was. Thus peace with life is made, night by night.',pt:'Os velhos belos têm um hábito: agradecer à noite pelo dia, fosse o dia como fosse. Assim se faz a paz com a vida, noite após noite.'},inv:{ro:'Începe diseară obiceiul: „mulțumesc pentru ziua asta".',en:'Start the habit tonight: “thank you for this day.”',pt:'Começa esta noite o hábito: «obrigado por este dia».'}},
  {el:'elder',kw:{ro:'Tinerețea dinăuntru',en:'The Youth Within',pt:'A Juventude de Dentro'},t:{ro:'Trupul ține socoteala anilor; sufletul nu știe să numere. Cine iubește, învață și se miră e tânăr cu acte în regulă.',en:'The body keeps count of years; the soul cannot count. Whoever loves, learns and wonders is young with full papers.',pt:'O corpo conta os anos; a alma não sabe contar. Quem ama, aprende e se espanta é jovem com todos os papéis.'},inv:{ro:'Fă azi cele trei dovezi: iubește, învață, miră-te.',en:'Give the three proofs today: love, learn, wonder.',pt:'Dá hoje as três provas: ama, aprende, espanta-te.'}},

  {el:'elder',kw:{ro:'Cartea vieții recitită',en:'Life’s Book Reread',pt:'O Livro da Vida Relido'},t:{ro:'La bătrânețe recitești cartea vieții și înțelegi capitolele grele: erau cotituri, nu funduri de sac.',en:'In old age you reread the book of your life and understand the hard chapters: they were turns, not dead ends.',pt:'Na velhice relês o livro da vida e compreendes os capítulos difíceis: eram curvas, não becos sem saída.'},inv:{ro:'Recitește azi un „capitol greu": ce cotitură a fost, de fapt?',en:'Reread one “hard chapter” today: what turn was it really?',pt:'Relê hoje um «capítulo difícil»: que curva foi, na verdade?'}},

  /* ———————— CERCUL DARULUI ———————— */
  {el:'gift',kw:{ro:'Darul fără nume',en:'The Nameless Gift',pt:'O Dom Sem Nome'},t:{ro:'Cel mai curat dar nu are etichetă cu numele dăruitorului. Binele anonim e binele în forma lui pură.',en:'The purest gift bears no tag with the giver’s name. Anonymous good is goodness in its pure form.',pt:'O dom mais puro não traz etiqueta com o nome de quem dá. O bem anónimo é o bem na sua forma pura.'},inv:{ro:'Fă azi un bine care nu poate fi urmărit până la tine.',en:'Do one good today that cannot be traced to you.',pt:'Faz hoje um bem que não possa ser rastreado até ti.'}},
  {el:'gift',kw:{ro:'Mâna care dă',en:'The Giving Hand',pt:'A Mão que Dá'},t:{ro:'Mâna care dă rămâne mereu deasupra — nu prin mândrie, ci prin legea nevăzută a dăruirii.',en:'The giving hand always stays above — not by pride, but by the unseen law of giving.',pt:'A mão que dá fica sempre por cima — não por orgulho, mas pela lei invisível do dar.'},inv:{ro:'Fii azi de trei ori mâna care dă.',en:'Be the giving hand three times today.',pt:'Sê hoje três vezes a mão que dá.'}},
  {el:'gift',kw:{ro:'Darul potrivit',en:'The Fitting Gift',pt:'O Dom Certo'},t:{ro:'Darul potrivit nu e cel mai scump, ci cel care spune: „te-am văzut, știu cine ești".',en:'The fitting gift is not the dearest, but the one that says: “I have seen you; I know who you are.”',pt:'O dom certo não é o mais caro, mas o que diz: «vi-te; sei quem és».'},inv:{ro:'Dăruiește azi ceva care dovedește că ai văzut omul.',en:'Give something today that proves you saw the person.',pt:'Oferece hoje algo que prove que viste a pessoa.'}},
  {el:'gift',kw:{ro:'Timpul dăruit',en:'Given Time',pt:'O Tempo Doado'},t:{ro:'Poți face bani la loc; timpul dat cuiva nu se mai întoarce — de aceea e cel mai scump dar de pe pământ.',en:'Money can be remade; time given to someone never returns — that is why it is the dearest gift on earth.',pt:'O dinheiro refaz-se; o tempo dado a alguém não volta — por isso é o dom mais caro da terra.'},inv:{ro:'Dăruiește azi o oră întreagă, fără telefon, unui om.',en:'Gift someone one whole phoneless hour today.',pt:'Oferece hoje a alguém uma hora inteira, sem telemóvel.'}},
  {el:'gift',kw:{ro:'Darul primit frumos',en:'The Gift Well Received',pt:'O Dom Bem Recebido'},t:{ro:'A primi cu bucurie curată e și el un dar făcut dăruitorului. Nu-l văduvi cu „nu trebuia".',en:'To receive with clean joy is itself a gift to the giver. Do not rob them with “you shouldn’t have.”',pt:'Receber com alegria limpa é também um dom para quem dá. Não o roubes com «não era preciso».'},inv:{ro:'Primește azi orice ți se dă cu un „mulțumesc" întreg.',en:'Receive whatever is given today with a whole thank-you.',pt:'Recebe hoje o que te derem com um «obrigado» inteiro.'}},
  {el:'gift',kw:{ro:'Prisosul',en:'The Surplus',pt:'O Excedente'},t:{ro:'Tot ce ai peste nevoie e sămânță care așteaptă pământ. Hambarul plin care nu seamănă putrezește.',en:'All you have beyond need is seed awaiting soil. The full barn that never sows, rots.',pt:'Tudo o que tens além da necessidade é semente à espera de terra. O celeiro cheio que não semeia apodrece.'},inv:{ro:'Găsește azi în prisosul tău o sămânță și seam-o.',en:'Find one seed in your surplus today and sow it.',pt:'Encontra hoje no teu excedente uma semente e semeia-a.'}},
  {el:'gift',kw:{ro:'Cuvântul-cadou',en:'The Word as Present',pt:'A Palavra-Presente'},t:{ro:'O laudă precisă, spusă la timp, se poartă în suflet ani întregi. E darul care nu costă și nu se strică.',en:'Precise praise, given in time, is carried in the soul for years. The gift that costs nothing and never spoils.',pt:'Um elogio preciso, dado a tempo, leva-se na alma anos inteiros. O presente que nada custa e nunca se estraga.'},inv:{ro:'Împachetează azi o laudă precisă și d-o cuiva.',en:'Wrap one precise praise today and hand it over.',pt:'Embrulha hoje um elogio preciso e entrega-o.'}},
  {el:'gift',kw:{ro:'Dăruirea în taină',en:'Giving in Secret',pt:'O Dar em Segredo'},t:{ro:'Binele povestit se plătește pe loc cu admirație; binele tăcut rămâne la dobândă în alt registru.',en:'Good recounted is paid at once in admiration; silent good gathers interest in another ledger.',pt:'O bem contado paga-se logo com admiração; o bem calado rende juros noutro livro.'},inv:{ro:'Fă azi un bine și nu-l povesti nimănui, niciodată.',en:'Do one good today and never tell a soul.',pt:'Faz hoje um bem e nunca o contes a ninguém.'}},
  {el:'gift',kw:{ro:'Darul refuzat',en:'The Refused Gift',pt:'O Dom Recusado'},t:{ro:'Jignirea refuzată rămâne a celui care a adus-o. Nu tot ce ți se întinde trebuie luat în mână.',en:'An insult refused remains with its bringer. Not all that is offered must be taken in hand.',pt:'A ofensa recusada fica com quem a trouxe. Nem tudo o que te estendem deve ser tomado.'},inv:{ro:'Refuză azi elegant un „dar" otrăvit: o bârfă, o pică.',en:'Politely refuse one poisoned “gift” today: a gossip, a grudge.',pt:'Recusa hoje com elegância um «presente» envenenado: um mexerico, um rancor.'}},
  {el:'gift',kw:{ro:'Darurile tale',en:'Your Gifts',pt:'Os Teus Dons'},t:{ro:'Talentul nefolosit e o scrisoare nedeschisă de la Dumnezeu. Nu muri cu scrisorile sigilate.',en:'An unused talent is an unopened letter from God. Do not die with the letters sealed.',pt:'Um talento por usar é uma carta fechada de Deus. Não morras com as cartas seladas.'},inv:{ro:'Deschide azi o „scrisoare": folosește un talent lăsat deoparte.',en:'Open one “letter” today: use a talent set aside.',pt:'Abre hoje uma «carta»: usa um talento posto de lado.'}},
  {el:'gift',kw:{ro:'Paharul cu apă',en:'The Cup of Water',pt:'O Copo de Água'},t:{ro:'Nu disprețui darurile mici: paharul de apă dat la vreme cântărește cât un ospăț dat târziu.',en:'Do not despise small gifts: a cup of water given in time outweighs a feast given late.',pt:'Não desprezes os dons pequenos: o copo de água dado a tempo pesa mais que um banquete tardio.'},inv:{ro:'Dă azi „paharul cu apă" cerut acum, nu ospățul promis.',en:'Give the cup asked for now, not the feast promised later.',pt:'Dá hoje o copo pedido agora, não o banquete prometido.'}},
  {el:'gift',kw:{ro:'Darul iertării',en:'The Gift of Pardon',pt:'O Dom do Perdão'},t:{ro:'Iertarea e singurul dar care se face în două exemplare: unul pentru celălalt, unul pentru tine.',en:'Forgiveness is the only gift made in two copies: one for the other, one for you.',pt:'O perdão é o único dom feito em duas cópias: uma para o outro, uma para ti.'},inv:{ro:'Fă azi darul dublu: iartă o datorie mică.',en:'Make the double gift today: forgive a small debt.',pt:'Faz hoje o dom duplo: perdoa uma pequena dívida.'}},
  {el:'gift',kw:{ro:'Ce nu se cumpără',en:'What Cannot Be Bought',pt:'O que Não Se Compra'},t:{ro:'Cele mai dorite daruri nu au preț: atenția, răbdarea, prezența, încrederea. Tocmai de aceea par rare.',en:'The most wanted gifts have no price: attention, patience, presence, trust. That is exactly why they seem rare.',pt:'Os dons mais desejados não têm preço: atenção, paciência, presença, confiança. Por isso mesmo parecem raros.'},inv:{ro:'Dăruiește azi unul dintre cele patru, din belșug.',en:'Give one of the four abundantly today.',pt:'Oferece hoje um dos quatro, em abundância.'}},
  {el:'gift',kw:{ro:'Dăruitorul vesel',en:'The Cheerful Giver',pt:'O Doador Alegre'},t:{ro:'Darul dat cu fața acră e pe jumătate luat înapoi. Chipul dăruitorului e ambalajul darului.',en:'A gift given with a sour face is half taken back. The giver’s face is the gift’s wrapping.',pt:'O dom dado de cara azeda é meio retirado. O rosto de quem dá é o embrulho do presente.'},inv:{ro:'Orice dai azi, dă cu chip luminos.',en:'Whatever you give today, give with a bright face.',pt:'O que deres hoje, dá com rosto luminoso.'}},
  {el:'gift',kw:{ro:'Darul înapoi la izvor',en:'The Gift Returned to the Spring',pt:'O Dom de Volta à Fonte'},t:{ro:'Mulțumirea e felul apei de a se întoarce la izvor. Nimic nu se pierde când binele e recunoscut.',en:'Gratitude is water’s way of returning to the spring. Nothing is lost when good is acknowledged.',pt:'A gratidão é o modo de a água voltar à fonte. Nada se perde quando o bem é reconhecido.'},inv:{ro:'Întoarce azi apa la izvor: mulțumește unui binefăcător vechi.',en:'Return water to the spring today: thank an old benefactor.',pt:'Devolve hoje a água à fonte: agradece a um antigo benfeitor.'}},
  {el:'gift',kw:{ro:'Zestrea de dimineață',en:'The Morning Endowment',pt:'O Dote da Manhã'},t:{ro:'Fiecare zi primești nemeritat: lumină, aer, încă o șansă. Trăiește ca un om care a primit — nu ca unul căruia i se datorează.',en:'Each day you receive unearned: light, air, another chance. Live as one who has received — not as one who is owed.',pt:'Cada dia recebes sem merecer: luz, ar, mais uma oportunidade. Vive como quem recebeu — não como credor.'},inv:{ro:'Poartă-te azi ca un dăruit, nu ca un creditor.',en:'Carry yourself today as one gifted, not as a creditor.',pt:'Comporta-te hoje como presenteado, não como credor.'}},
  {el:'gift',kw:{ro:'Darul greu',en:'The Heavy Gift',pt:'O Dom Pesado'},t:{ro:'Unele daruri cer curaj: adevărul spus blând, hotarul pus la timp. Dor la desfacere și folosesc o viață.',en:'Some gifts take courage: truth said gently, a boundary set in time. They hurt at unwrapping and serve a lifetime.',pt:'Alguns dons pedem coragem: a verdade dita com doçura, o limite posto a tempo. Doem ao abrir e servem uma vida.'},inv:{ro:'Fă azi cuiva un dar greu, cu toată blândețea.',en:'Give someone a heavy gift today, with all gentleness.',pt:'Dá hoje a alguém um dom pesado, com toda a doçura.'}},
  {el:'gift',kw:{ro:'Coșul împărțit',en:'The Shared Basket',pt:'O Cesto Repartido'},t:{ro:'Pâinea împărțită hrănește de două ori: o dată trupul, o dată legătura dintre oameni.',en:'Bread shared feeds twice: once the body, once the bond between people.',pt:'O pão repartido alimenta duas vezes: uma o corpo, outra o laço entre as pessoas.'},inv:{ro:'Împarte azi din coșul tău, chiar dacă nu e plin.',en:'Share from your basket today, even if not full.',pt:'Reparte hoje do teu cesto, mesmo que não esteja cheio.'}},
  {el:'gift',kw:{ro:'Darul pentru dușman',en:'The Gift for the Adversary',pt:'O Dom para o Adversário'},t:{ro:'Un bine făcut celui care ți-a greșit e cărbune aprins pe vechea ceartă: o arde până la pace.',en:'A kindness to one who wronged you is live coal on the old quarrel: it burns it down to peace.',pt:'Um bem feito a quem te errou é brasa sobre a velha desavença: queima-a até à paz.'},inv:{ro:'Fă azi un mic bine cuiva cu care ești în răceală.',en:'Do a small kindness today to someone you are cold with.',pt:'Faz hoje um pequeno bem a alguém com quem estás de mal.'}},
  {el:'gift',kw:{ro:'Mărinimia',en:'Largesse',pt:'A Largueza'},t:{ro:'Mărinimia nu se măsoară în sume, ci în raport cu punga. Bănuțul văduvei cântărește cât vistieria.',en:'Largesse is measured not in sums but against the purse. The widow’s coin weighs as much as the treasury.',pt:'A largueza não se mede em somas, mas em relação à bolsa. A moedinha da viúva pesa como o tesouro.'},inv:{ro:'Dă azi „mult pentru tine", oricât de puțin ar părea altora.',en:'Give “much for you” today, however little it seems to others.',pt:'Dá hoje «muito para ti», por pouco que pareça aos outros.'}},
  {el:'gift',kw:{ro:'Darul de a fi de față',en:'The Gift of Showing Up',pt:'O Dom de Estar Presente'},t:{ro:'La bucurie vin mulți; la greu vin darurile adevărate: cei care pur și simplu apar.',en:'Many come to joy; to hardship come the true gifts: those who simply show up.',pt:'À alegria vêm muitos; à dificuldade vêm os dons verdadeiros: os que simplesmente aparecem.'},inv:{ro:'Apari azi acolo unde cuiva îi e greu.',en:'Show up today where someone struggles.',pt:'Aparece hoje onde alguém está em dificuldade.'}},
  {el:'gift',kw:{ro:'Regalul de a asculta',en:'The Royal Gift of Listening',pt:'O Dom Real de Escutar'},t:{ro:'Într-o lume care strigă, urechea ta liniștită e un tron oferit celuilalt. Așază-l pe el, o vreme.',en:'In a shouting world, your quiet ear is a throne offered to another. Seat them there awhile.',pt:'Num mundo que grita, o teu ouvido calmo é um trono oferecido ao outro. Senta-o lá um tempo.'},inv:{ro:'Oferă azi tronul: ascultă un om fără să te aperi.',en:'Offer the throne today: hear someone without defending.',pt:'Oferece hoje o trono: escuta alguém sem te defenderes.'}},
  {el:'gift',kw:{ro:'Florile acum',en:'Flowers Now',pt:'As Flores Agora'},t:{ro:'Dă-i omului floarea cât o poate mirosi. Cel mai trist buchet e cel adus prea târziu.',en:'Give the flower while it can be smelled. The saddest bouquet is the one brought too late.',pt:'Dá a flor enquanto pode ser cheirada. O ramo mais triste é o que chega tarde demais.'},inv:{ro:'Nu amâna: du azi „florile" cuiva în viață fiind.',en:'Do not delay: bring someone their “flowers” today, while living.',pt:'Não adies: leva hoje as «flores» a alguém em vida.'}},
  {el:'gift',kw:{ro:'Darul spațiului',en:'The Gift of Room',pt:'O Dom do Espaço'},t:{ro:'Uneori cel mai bun dar e să te dai un pas înapoi: să lași loc celuilalt să crească, să respire, să greșească.',en:'Sometimes the best gift is stepping back: leaving the other room to grow, breathe, and err.',pt:'Às vezes o melhor dom é dar um passo atrás: deixar ao outro espaço para crescer, respirar, errar.'},inv:{ro:'Fă azi cuiva darul spațiului: mai puțin control, mai mult loc.',en:'Give the gift of room today: less control, more space.',pt:'Dá hoje o dom do espaço: menos controlo, mais lugar.'}},
  {el:'gift',kw:{ro:'A doua haină',en:'The Second Coat',pt:'O Segundo Casaco'},t:{ro:'Dulapul care dă pe dinafară și omul care tremură afară sunt o singură problemă cu o singură rezolvare.',en:'The overflowing wardrobe and the person shivering outside are one problem with one solution.',pt:'O armário a transbordar e a pessoa a tremer lá fora são um só problema com uma só solução.'},inv:{ro:'Scoate săptămâna asta „a doua haină" din dulap și d-o.',en:'Take the “second coat” from the wardrobe this week and give it.',pt:'Tira esta semana o «segundo casaco» do armário e dá-o.'}},
  {el:'gift',kw:{ro:'Darul care crește dăruind',en:'The Gift that Grows by Giving',pt:'O Dom que Cresce ao Dar'},t:{ro:'Împarte cunoașterea și ea se înmulțește; ascunde-o și se ofilește în tine.',en:'Share knowledge and it multiplies; hide it and it withers within you.',pt:'Partilha o conhecimento e ele multiplica-se; esconde-o e murcha em ti.'},inv:{ro:'Învață azi pe cineva un lucru pe care îl faci bine.',en:'Teach someone today one thing you do well.',pt:'Ensina hoje a alguém algo que fazes bem.'}},
  {el:'gift',kw:{ro:'Cadoul de la necunoscut',en:'The Stranger’s Gift',pt:'O Presente do Desconhecido'},t:{ro:'Bunătatea unui necunoscut restaurează încrederea în toți oamenii dintr-o singură lovitură. Fii tu lovitura aceea.',en:'A stranger’s kindness restores faith in all people at a single stroke. Be that stroke.',pt:'A bondade de um desconhecido restaura a fé em todas as pessoas de um só golpe. Sê tu esse golpe.'},inv:{ro:'Fii azi bunătatea-surpriză din ziua unui străin.',en:'Be the surprise kindness in a stranger’s day.',pt:'Sê hoje a bondade-surpresa no dia de um estranho.'}},
  {el:'gift',kw:{ro:'Darul greșelii mărturisite',en:'The Gift of the Admitted Error',pt:'O Dom do Erro Confessado'},t:{ro:'Când îți mărturisești greșeala, dăruiești două lucruri: adevărul tău și voia altora de a și-l spune pe al lor.',en:'When you admit your error you give two things: your truth, and others’ permission to speak theirs.',pt:'Quando confessas o teu erro dás duas coisas: a tua verdade e a licença dos outros para dizerem a deles.'},inv:{ro:'Deschide azi drumul: mărturisește primul o greșeală.',en:'Open the road today: admit an error first.',pt:'Abre hoje o caminho: confessa primeiro um erro.'}},
  {el:'gift',kw:{ro:'Puntea de aur',en:'The Golden Bridge',pt:'A Ponte de Ouro'},t:{ro:'Când celălalt vrea să iasă din ceartă, întinde-i o punte de aur, nu un examen. Pacea nu se ia cu note.',en:'When the other wants out of the quarrel, offer a golden bridge, not an exam. Peace is not graded.',pt:'Quando o outro quer sair da briga, estende-lhe uma ponte de ouro, não um exame. A paz não leva nota.'},inv:{ro:'Întinde azi o punte de aur cuiva care vrea pace.',en:'Extend a golden bridge today to one who wants peace.',pt:'Estende hoje uma ponte de ouro a quem quer paz.'}},
  {el:'gift',kw:{ro:'Ultimul dar',en:'The Last Gift',pt:'O Último Dom'},t:{ro:'La sfârșit, tot ce rămâne din noi e ce am apucat să dăm. Restul se împarte; darul rămâne dat.',en:'In the end, all that remains of us is what we managed to give. The rest gets divided; the gift stays given.',pt:'No fim, tudo o que fica de nós é o que chegámos a dar. O resto reparte-se; o dom fica dado.'},inv:{ro:'Mărește-ți azi partea care rămâne: dă ceva de păstrat.',en:'Enlarge your remaining share today: give something keepable.',pt:'Aumenta hoje a tua parte que fica: dá algo para guardar.'}},
  {el:'gift',kw:{ro:'Dania veselă a firii',en:'Nature’s Merry Alms',pt:'A Esmola Alegre da Natureza'},t:{ro:'Pomul dă fructe și celui care aruncă în el cu pietre. Așa arată dărnicia ajunsă la maturitate.',en:'The tree gives fruit even to those who throw stones at it. That is generosity come of age.',pt:'A árvore dá fruto até a quem lhe atira pedras. Assim é a generosidade madura.'},inv:{ro:'Dă azi rod și cuiva care te-a lovit cu o piatră.',en:'Bear fruit today even for one who threw a stone.',pt:'Dá hoje fruto até a quem te atirou uma pedra.'}},
  {el:'gift',kw:{ro:'Binecuvântarea din prag',en:'The Doorstep Blessing',pt:'A Bênção da Soleira'},t:{ro:'Când pleci dintr-o casă sau dintr-o zi, lasă în urmă un cuvânt bun. Binecuvântarea din prag rămâne în odaie.',en:'When leaving a house or a day, leave a kind word behind. The doorstep blessing stays in the room.',pt:'Ao saíres de uma casa ou de um dia, deixa uma palavra boa. A bênção da soleira fica na sala.'},inv:{ro:'Pleacă azi de peste tot lăsând un cuvânt bun în prag.',en:'Leave everywhere today with a kind word at the door.',pt:'Sai hoje de todo o lado deixando uma palavra boa à porta.'}},
  {el:'gift',kw:{ro:'Darul zilei de azi',en:'The Gift of This Day',pt:'O Dom deste Dia'},t:{ro:'I se spune „prezent" pentru că asta este: un dar pus în mâinile tale în fiecare dimineață. Desfă-l cu grijă.',en:'It is called “the present” because that is what it is: a gift placed in your hands each morning. Unwrap it with care.',pt:'Chama-se «presente» porque é isso mesmo: um dom posto nas tuas mãos cada manhã. Abre-o com cuidado.'},inv:{ro:'Desfă ziua de azi ca pe un dar, nu ca pe o corvoadă.',en:'Unwrap today like a gift, not a chore.',pt:'Abre o dia de hoje como um presente, não como um fardo.'}},

  /* ———————— CERCUL CASEI ———————— */
  {el:'home',kw:{ro:'Pragul',en:'The Doorstep',pt:'A Soleira'},t:{ro:'Pragul desparte două lumi: lasă-ți la el noroiul de pe tălpi și pe cel de pe suflet.',en:'The doorstep divides two worlds: leave on it the mud of your soles and of your soul.',pt:'A soleira separa dois mundos: deixa nela a lama das solas e a da alma.'},inv:{ro:'Fă-ți azi un mic ritual de prag: o respirație înainte de a intra acasă.',en:'Make a doorstep ritual today: one breath before entering home.',pt:'Cria hoje um ritual de soleira: uma respiração antes de entrar em casa.'}},
  {el:'home',kw:{ro:'Vatra',en:'The Hearth',pt:'A Lareira'},t:{ro:'Fiecare casă are o vatră — locul unde se adună toți. Azi e adesea un ecran; alege să fie o masă.',en:'Every home has a hearth — where all gather. Today it is often a screen; choose it to be a table.',pt:'Cada casa tem uma lareira — onde todos se juntam. Hoje é muitas vezes um ecrã; escolhe que seja uma mesa.'},inv:{ro:'Adună diseară casa în jurul mesei, nu al ecranului.',en:'Gather the house around the table tonight, not the screen.',pt:'Junta esta noite a casa à volta da mesa, não do ecrã.'}},
  {el:'home',kw:{ro:'Cheile',en:'The Keys',pt:'As Chaves'},t:{ro:'Puțini oameni au cheia casei tale; și mai puțini, pe a inimii. Alege-i pe amândouă cu aceeași grijă.',en:'Few people hold the key to your house; fewer still, to your heart. Choose both with the same care.',pt:'Poucos têm a chave da tua casa; menos ainda, a do coração. Escolhe ambas com o mesmo cuidado.'},inv:{ro:'Gândește-te azi cine are „chei" la tine — și dacă le merită.',en:'Consider today who holds your “keys” — and whether they deserve them.',pt:'Pensa hoje em quem tem as tuas «chaves» — e se as merece.'}},
  {el:'home',kw:{ro:'Curățenia',en:'The Cleaning',pt:'A Limpeza'},t:{ro:'Când nu știi de unde să-ți apuci viața, fă ordine într-un sertar. Casa limpezită limpezește și capul.',en:'When you do not know where to grasp your life, tidy one drawer. A cleared house clears the head.',pt:'Quando não sabes por onde pegar na vida, arruma uma gaveta. A casa arrumada arruma a cabeça.'},inv:{ro:'Fă azi ordine într-un singur sertar. Doar unul.',en:'Tidy one single drawer today. Just one.',pt:'Arruma hoje uma única gaveta. Só uma.'}},
  {el:'home',kw:{ro:'Fereastra',en:'The Window',pt:'A Janela'},t:{ro:'Casa fără ferestre deschise se îmbolnăvește; omul fără ferestre către lume, la fel. Aerisește amândouă.',en:'A house with closed windows sickens; so does a person without windows to the world. Air out both.',pt:'A casa de janelas fechadas adoece; a pessoa sem janelas para o mundo também. Areja ambas.'},inv:{ro:'Deschide azi larg o fereastră a casei și una a minții.',en:'Open wide one window of the house and one of the mind today.',pt:'Abre hoje de par em par uma janela da casa e uma da mente.'}},
  {el:'home',kw:{ro:'Masa întinsă',en:'The Laid Table',pt:'A Mesa Posta'},t:{ro:'Casa se sfințește prin oaspeți. Unde s-a pus un tacâm în plus, acolo a intrat cerul pe ușă.',en:'A home is hallowed by guests. Where one extra plate is set, heaven has walked in the door.',pt:'A casa santifica-se pelos hóspedes. Onde se pôs um talher a mais, o céu entrou pela porta.'},inv:{ro:'Pune săptămâna asta un tacâm în plus la masa ta.',en:'Set one extra place at your table this week.',pt:'Põe esta semana um talher a mais na tua mesa.'}},
  {el:'home',kw:{ro:'Colțul tău',en:'Your Corner',pt:'O Teu Canto'},t:{ro:'Orice suflet are nevoie de un colț al lui: un scaun, o lumină, o priveliște. Acolo te repari zilnic.',en:'Every soul needs a corner of its own: a chair, a light, a view. There you mend daily.',pt:'Toda a alma precisa de um canto seu: uma cadeira, uma luz, uma vista. Ali te reparas todos os dias.'},inv:{ro:'Amenajează-ți azi colțul — sau petrece în el un sfert de oră.',en:'Arrange your corner today — or spend a quarter hour in it.',pt:'Arranja hoje o teu canto — ou passa nele um quarto de hora.'}},
  {el:'home',kw:{ro:'Pereții care ascultă',en:'The Listening Walls',pt:'As Paredes que Escutam'},t:{ro:'Pereții țin minte tonul cu care se vorbește între ei. Casa devine, încet, ce se spune în ea.',en:'Walls remember the tone spoken within them. A house slowly becomes what is said inside it.',pt:'As paredes lembram o tom com que se fala entre elas. A casa torna-se, devagar, o que nela se diz.'},inv:{ro:'Hrănește azi pereții cu vorbe pe care să merite să le țină.',en:'Feed the walls today with words worth keeping.',pt:'Alimenta hoje as paredes com palavras dignas de guardar.'}},
  {el:'home',kw:{ro:'Lucrurile puține',en:'The Few Things',pt:'As Poucas Coisas'},t:{ro:'Fiecare lucru din casă îți cere câte puțin: praf șters, loc, atenție. Păstrează doar ce îți dă mai mult decât cere.',en:'Each thing in the house asks a little of you: dusting, room, attention. Keep only what gives more than it asks.',pt:'Cada coisa na casa pede-te um pouco: pó limpo, lugar, atenção. Guarda só o que dá mais do que pede.'},inv:{ro:'Scoate azi din casă trei lucruri care doar cer.',en:'Remove three things today that only ask.',pt:'Tira hoje de casa três coisas que só pedem.'}},
  {el:'home',kw:{ro:'Casa dinăuntru',en:'The House Within',pt:'A Casa de Dentro'},t:{ro:'Poți schimba multe adrese; într-o singură casă locuiești toată viața: în tine. Renoveaz-o cu prioritate.',en:'You may change many addresses; in one house you live all your life: yourself. Renovate it first.',pt:'Podes mudar de morada muitas vezes; numa só casa vives a vida toda: em ti. Renova-a primeiro.'},inv:{ro:'Fă azi o mică „renovare" înăuntru: un obicei, un gând.',en:'Do one small inner renovation today: a habit, a thought.',pt:'Faz hoje uma pequena renovação interior: um hábito, um pensamento.'}},
  {el:'home',kw:{ro:'Oaspetele',en:'The Guest',pt:'O Hóspede'},t:{ro:'Primește oaspetele ca pe un trimis: unii aduc pâine, alții lecții, unii amândouă. Niciunul nu vine degeaba.',en:'Receive the guest as an envoy: some bring bread, some lessons, some both. None comes for nothing.',pt:'Recebe o hóspede como enviado: uns trazem pão, outros lições, alguns ambos. Nenhum vem em vão.'},inv:{ro:'Primește azi pe cineva ca pe un trimis, nu ca pe o întrerupere.',en:'Receive someone today as an envoy, not an interruption.',pt:'Recebe hoje alguém como enviado, não como interrupção.'}},
  {el:'home',kw:{ro:'Reparatul',en:'The Mending',pt:'O Conserto'},t:{ro:'Robinetul care picură și supărarea care mocnește se repară la fel: azi, cât stricăciunea e mică.',en:'The dripping tap and the smoldering grudge are fixed the same way: today, while the damage is small.',pt:'A torneira que pinga e a mágoa que arde consertam-se igual: hoje, enquanto o estrago é pequeno.'},inv:{ro:'Repară azi un lucru mic din casă — sau dintre voi.',en:'Mend one small thing today — in the house or between you.',pt:'Conserta hoje uma coisa pequena — na casa ou entre vocês.'}},
  {el:'home',kw:{ro:'Lumina aprinsă',en:'The Light Left On',pt:'A Luz Acesa'},t:{ro:'Cineva care îți lasă lumina aprinsă te iubește într-un fel pe care nu-l spune. Citește limbile tăcute ale casei.',en:'Someone leaving the light on for you loves you in an unspoken way. Read the house’s silent languages.',pt:'Quem te deixa a luz acesa ama-te de um modo que não diz. Lê as línguas mudas da casa.'},inv:{ro:'Spune azi cu un gest tăcut „te-am așteptat".',en:'Say “I waited for you” with a silent gesture today.',pt:'Diz hoje com um gesto mudo «esperei por ti».'}},
  {el:'home',kw:{ro:'Rânduiala casei',en:'The House’s Order',pt:'A Ordem da Casa'},t:{ro:'Casa cu rânduială economisește o viață de căutat chei. Fiecare lucru cu locul lui e o grijă mai puțin.',en:'An ordered house saves a lifetime of key-hunting. Each thing in its place is one worry fewer.',pt:'A casa com ordem poupa uma vida à procura de chaves. Cada coisa no seu lugar é uma preocupação a menos.'},inv:{ro:'Dă azi „domiciliu stabil" unui lucru mereu rătăcit.',en:'Give one always-lost item a fixed address today.',pt:'Dá hoje morada fixa a uma coisa sempre perdida.'}},
  {el:'home',kw:{ro:'Casa părintească',en:'The Parental Home',pt:'A Casa dos Pais'},t:{ro:'Oriunde ai ajunge, o casă bătrână îți ține copilăria în păstrare. Viziteaz-o — în lume sau în amintire.',en:'Wherever you arrive, an old house keeps your childhood in trust. Visit it — in the world or in memory.',pt:'Aonde quer que chegues, uma casa velha guarda a tua infância. Visita-a — no mundo ou na memória.'},inv:{ro:'Fă azi o vizită casei părintești, măcar cu gândul.',en:'Visit the parental home today, at least in thought.',pt:'Visita hoje a casa dos pais, ao menos em pensamento.'}},
  {el:'home',kw:{ro:'Vecinul',en:'The Neighbor',pt:'O Vizinho'},t:{ro:'Vecinul bun e o rudă pe care ți-o dă adresa. La cutremur, el ajunge înaintea tuturor rudelor de sânge.',en:'A good neighbor is a relative given by your address. In an earthquake, they arrive before any blood kin.',pt:'O bom vizinho é um parente dado pela morada. No terramoto, chega antes de todos os parentes de sangue.'},inv:{ro:'Investește azi în ruda de adresă: un salut, un mic ajutor.',en:'Invest in the address-relative today: a greeting, small help.',pt:'Investe hoje no parente de morada: um cumprimento, uma pequena ajuda.'}},
  {el:'home',kw:{ro:'Acoperișul',en:'The Roof',pt:'O Telhado'},t:{ro:'Sub același acoperiș, supărările se țin ca fumul: ori le dai drumul pe horn, ori vă afumă pe toți.',en:'Under one roof, resentments behave like smoke: either let them out the chimney or they smoke you all.',pt:'Sob o mesmo teto, as mágoas são como fumo: ou saem pela chaminé, ou defumam todos.'},inv:{ro:'Deschide azi hornul: spune blând o nemulțumire ținută.',en:'Open the chimney today: voice a held grievance gently.',pt:'Abre hoje a chaminé: diz com doçura uma queixa guardada.'}},
  {el:'home',kw:{ro:'Grădina din fața casei',en:'The Front Garden',pt:'O Jardim da Frente'},t:{ro:'Ce crește în fața casei tale e salutul tău zilnic către lume. Chiar și un singur ghiveci spune „aici locuiește grijă".',en:'What grows before your house is your daily greeting to the world. Even one pot says “care lives here.”',pt:'O que cresce diante da tua casa é o teu cumprimento diário ao mundo. Até um só vaso diz «aqui mora cuidado».'},inv:{ro:'Pune sau îngrijește azi „ghiveciul" din fața casei.',en:'Place or tend the front “pot” today.',pt:'Põe ou cuida hoje do «vaso» da frente.'}},
  {el:'home',kw:{ro:'Camera oaspeților lăuntrici',en:'The Inner Guest Room',pt:'O Quarto de Hóspedes Interior'},t:{ro:'Gândurile sunt oaspeți ai casei tale lăuntrice. Unora le faci patul; altora le arăți politicos ușa.',en:'Thoughts are guests of your inner house. For some you make the bed; others you politely show the door.',pt:'Os pensamentos são hóspedes da tua casa interior. A uns fazes a cama; a outros mostras educadamente a porta.'},inv:{ro:'Alege azi conștient: care gând primește pat, care primește ușa?',en:'Choose consciously today: which thought gets the bed, which the door?',pt:'Escolhe hoje com consciência: que pensamento recebe cama, qual recebe porta?'}},
  {el:'home',kw:{ro:'Casa mică',en:'The Small House',pt:'A Casa Pequena'},t:{ro:'O casă mică plină de râs e mai încăpătoare decât un palat plin de tăceri reci.',en:'A small house full of laughter holds more than a palace full of cold silences.',pt:'Uma casa pequena cheia de riso cabe mais do que um palácio de silêncios frios.'},inv:{ro:'Umple azi casa cu un râs — asta o mărește.',en:'Fill the house with one laugh today — that enlarges it.',pt:'Enche hoje a casa com um riso — isso aumenta-a.'}},
  {el:'home',kw:{ro:'Cuibul gol',en:'The Empty Nest',pt:'O Ninho Vazio'},t:{ro:'Când copiii pleacă, nu rămâne gol: rămâne loc. Pentru voi doi, pentru oaspeți, pentru visurile amânate.',en:'When children leave, no void remains: room remains. For you two, for guests, for postponed dreams.',pt:'Quando os filhos partem, não fica vazio: fica lugar. Para vocês dois, para hóspedes, para sonhos adiados.'},inv:{ro:'Umple un „loc rămas" cu ceva demult amânat.',en:'Fill one remaining room with something long postponed.',pt:'Enche um lugar que ficou com algo há muito adiado.'}},
  {el:'home',kw:{ro:'Focul din sobă',en:'The Stove Fire',pt:'O Fogo do Fogão'},t:{ro:'Focul casei cere lemne în fiecare zi — la fel căldura dintre cei care o locuiesc. Nu lăsa jarul pe mâine.',en:'The house fire needs wood daily — so does the warmth between those who live there. Do not leave embers for tomorrow.',pt:'O fogo da casa pede lenha todos os dias — assim o calor entre quem a habita. Não deixes as brasas para amanhã.'},inv:{ro:'Pune azi un lemn pe focul dintre voi: o vorbă, un ceai, o mângâiere.',en:'Lay one log on the fire between you today: a word, a tea, a caress.',pt:'Põe hoje uma acha no fogo entre vocês: uma palavra, um chá, um afago.'}},
  {el:'home',kw:{ro:'Zidul și iedera',en:'The Wall and the Ivy',pt:'O Muro e a Hera'},t:{ro:'Casele vechi țin împreună prin ziduri și prin iederă: ce e tare are nevoie și de ce e viu.',en:'Old houses hold together by walls and by ivy: what is strong also needs what is alive.',pt:'As casas velhas mantêm-se por muros e por hera: o que é forte também precisa do que é vivo.'},inv:{ro:'Pune azi ceva viu lângă ce e doar solid: o plantă, o poză, o floare.',en:'Set something alive beside the merely solid today: a plant, a photo, a flower.',pt:'Põe hoje algo vivo junto ao que é só sólido: uma planta, uma foto, uma flor.'}},
  {el:'home',kw:{ro:'Adresa sufletului',en:'The Soul’s Address',pt:'A Morada da Alma'},t:{ro:'Ești acasă acolo unde poți tăcea fără să fie ciudat. Prin asta se recunoaște adresa sufletului.',en:'You are home where you can be silent without it being strange. That is how the soul’s address is known.',pt:'Estás em casa onde podes calar sem ser estranho. Assim se reconhece a morada da alma.'},inv:{ro:'Cine îți e „acasă"? Petrece azi timp la adresa aceea.',en:'Who is “home” to you? Spend time at that address today.',pt:'Quem é «casa» para ti? Passa hoje tempo nessa morada.'}},
  {el:'home',kw:{ro:'Ordinea de seară',en:'The Evening Tidy-Up',pt:'A Arrumação da Noite'},t:{ro:'Zece minute de ordine seara sunt o scrisoare de dragoste către tine, cel de mâine dimineață.',en:'Ten minutes of evening tidying is a love letter to your tomorrow-morning self.',pt:'Dez minutos de arrumação à noite são uma carta de amor ao teu eu de amanhã de manhã.'},inv:{ro:'Scrie diseară scrisoarea: zece minute de ordine.',en:'Write the letter tonight: ten minutes of order.',pt:'Escreve esta noite a carta: dez minutos de ordem.'}},
  {el:'home',kw:{ro:'Casa deschisă rar',en:'The Rarely Opened Home',pt:'A Casa Raramente Aberta'},t:{ro:'Casa în care nu intră nimeni ani de zile se face muzeu, apoi mormânt. Ține-o vie prin uși care se mai deschid.',en:'A house no one enters for years becomes a museum, then a tomb. Keep it alive with doors that still open.',pt:'A casa onde ninguém entra durante anos vira museu, depois túmulo. Mantém-na viva com portas que ainda se abrem.'},inv:{ro:'Deschide luna asta ușa pentru cineva care n-a mai intrat.',en:'Open the door this month to someone who has not been in.',pt:'Abre este mês a porta a alguém que nunca entrou.'}},
  {el:'home',kw:{ro:'Icoana sau candela',en:'The Icon or the Vigil Light',pt:'O Ícone ou a Lamparina'},t:{ro:'Fiecare casă are nevoie de un punct mai înalt decât grijile: o icoană, o candelă, un verset, o fotografie sfântă ei.',en:'Every home needs one point higher than its worries: an icon, a vigil light, a verse, a photograph sacred to it.',pt:'Cada casa precisa de um ponto mais alto que as preocupações: um ícone, uma lamparina, um versículo, uma fotografia sagrada para ela.'},inv:{ro:'Așază sau îngrijește azi punctul înalt al casei tale.',en:'Place or tend your home’s high point today.',pt:'Coloca ou cuida hoje do ponto alto da tua casa.'}},
  {el:'home',kw:{ro:'Mutatul',en:'The Move',pt:'A Mudança'},t:{ro:'La mutat afli adevărul: din toată casa, îți trebuie trei cutii. Restul era decor pentru o viață pe care o amânai.',en:'Moving reveals the truth: of the whole house, you need three boxes. The rest was scenery for a postponed life.',pt:'Na mudança descobres a verdade: de toda a casa, precisas de três caixas. O resto era cenário de uma vida adiada.'},inv:{ro:'Întreabă-te azi: ce ar intra în cele trei cutii ale tale?',en:'Ask today: what would go in your three boxes?',pt:'Pergunta hoje: o que iria nas tuas três caixas?'}},
  {el:'home',kw:{ro:'Casa de departe',en:'Home from Afar',pt:'A Casa ao Longe'},t:{ro:'De departe, casa nu e ziduri: e un miros, o voce, un fel de lumină după-amiaza. Acestea se pot duce oriunde.',en:'From afar, home is not walls: it is a smell, a voice, a way the light falls in the afternoon. These can travel anywhere.',pt:'De longe, a casa não é paredes: é um cheiro, uma voz, um jeito de luz à tarde. Isso pode viajar para qualquer lugar.'},inv:{ro:'Recreează azi, oriunde ești, un semn mic de „acasă".',en:'Recreate one small sign of home today, wherever you are.',pt:'Recria hoje, onde estiveres, um pequeno sinal de casa.'}},
  {el:'home',kw:{ro:'Temelia nevăzută',en:'The Unseen Foundation',pt:'O Alicerce Invisível'},t:{ro:'Nicio casă nu stă pe ce se vede. Nici familia: stă pe iertări repetate, răbdări tăcute, mici renunțări zilnice.',en:'No house stands on what is visible. Nor does a family: it stands on repeated forgivings, silent patiences, small daily yieldings.',pt:'Nenhuma casa assenta no que se vê. Nem a família: assenta em perdões repetidos, paciências caladas, pequenas cedências diárias.'},inv:{ro:'Toarnă azi în temelie: o iertare sau o renunțare mică.',en:'Pour into the foundation today: one forgiveness or small yielding.',pt:'Deita hoje no alicerce: um perdão ou uma pequena cedência.'}},
  {el:'home',kw:{ro:'Casa-corabie',en:'The House-Ship',pt:'A Casa-Navio'},t:{ro:'Casa e corabia cu care familia trece anii. Nu contează cât e de mare; contează să nu ia apă la încredere.',en:'The home is the ship a family sails the years in. Its size matters little; what matters is that trust takes no water.',pt:'A casa é o navio em que a família atravessa os anos. O tamanho pouco importa; importa que a confiança não meta água.'},inv:{ro:'Astupă azi o mică gaură de încredere din corabia voastră.',en:'Seal one small leak of trust in your ship today.',pt:'Tapa hoje uma pequena fuga de confiança no vosso navio.'}},
  {el:'home',kw:{ro:'Binecuvântarea casei',en:'The Blessing of the House',pt:'A Bênção da Casa'},t:{ro:'Casa în care se mulțumește seara și se iartă înainte de somn e păzită mai bine decât cu orice lacăt.',en:'A house where thanks are given at night and pardons before sleep is guarded better than by any lock.',pt:'A casa onde se agradece à noite e se perdoa antes do sono está mais guardada do que por qualquer cadeado.'},inv:{ro:'Pune diseară cele două lacăte bune: mulțumirea și iertarea.',en:'Set the two good locks tonight: thanks and pardon.',pt:'Põe esta noite os dois bons cadeados: a gratidão e o perdão.'}},

  {el:'home',kw:{ro:'Mirosul casei',en:'The Smell of Home',pt:'O Cheiro de Casa'},t:{ro:'Mirosul casei tale — pâine, lemn, cafea, cei dragi — e o amintire pe care nici uitarea n-o poate lua. Îl porți oriunde.',en:'The smell of your home — bread, wood, coffee, loved ones — is a memory even forgetting cannot take. You carry it anywhere.',pt:'O cheiro da tua casa — pão, madeira, café, os que amas — é uma memória que nem o esquecimento leva. Levá-lo contigo a toda a parte.'},inv:{ro:'Umple azi casa cu un miros bun: pâine, cafea, o floare.',en:'Fill the home with one good smell today: bread, coffee, a flower.',pt:'Enche hoje a casa com um bom cheiro: pão, café, uma flor.'}},

  /* ———————— CERCUL PRIETENIEI ———————— */
  {el:'friend',kw:{ro:'Prietenul-oglindă',en:'The Mirror Friend',pt:'O Amigo-Espelho'},t:{ro:'Prietenul adevărat îți arată și ce nu vrei să vezi — dar ți-o arată ținându-te de mână.',en:'A true friend shows you even what you do not want to see — but shows it holding your hand.',pt:'O amigo verdadeiro mostra-te até o que não queres ver — mas mostra-o segurando a tua mão.'},inv:{ro:'Primește azi o oglindire incomodă de la un prieten, fără scut.',en:'Receive one uncomfortable mirroring from a friend today, shieldless.',pt:'Recebe hoje um reflexo incómodo de um amigo, sem escudo.'}},
  {el:'friend',kw:{ro:'Telefonul fără motiv',en:'The Call for No Reason',pt:'A Chamada Sem Motivo'},t:{ro:'„Mi-am adus aminte de tine" e una dintre cele mai frumoase propoziții din limba oamenilor.',en:'“I was thinking of you” is one of the most beautiful sentences in the human language.',pt:'«Lembrei-me de ti» é uma das frases mais belas da língua humana.'},inv:{ro:'Sun-o azi: spune-i cuiva că ți-ai amintit de el.',en:'Make the call today: tell someone you remembered them.',pt:'Faz hoje a chamada: diz a alguém que te lembraste dele.'}},
  {el:'friend',kw:{ro:'Prietenia veche',en:'The Old Friendship',pt:'A Amizade Antiga'},t:{ro:'Prietenia veche reia vorba de unde a rămas, chiar și după ani. Timpul nu o rupe; doar o pune pe pauză.',en:'Old friendship resumes where it left off, even after years. Time does not break it; it only presses pause.',pt:'A amizade antiga retoma a conversa onde ficou, mesmo após anos. O tempo não a quebra; só a põe em pausa.'},inv:{ro:'Apasă azi „play": scrie unui prieten vechi.',en:'Press play today: write to an old friend.',pt:'Carrega hoje no play: escreve a um velho amigo.'}},
  {el:'friend',kw:{ro:'Umărul',en:'The Shoulder',pt:'O Ombro'},t:{ro:'Uneori prietenia nu are nimic de spus; are doar un umăr de pus la dispoziție. E de ajuns.',en:'Sometimes friendship has nothing to say; it only has a shoulder to offer. It is enough.',pt:'Às vezes a amizade não tem nada a dizer; tem só um ombro a oferecer. É suficiente.'},inv:{ro:'Fii azi umăr, nu sfat.',en:'Be a shoulder today, not advice.',pt:'Sê hoje ombro, não conselho.'}},
  {el:'friend',kw:{ro:'Bucuria nefurată',en:'The Unstolen Joy',pt:'A Alegria Não Roubada'},t:{ro:'Prietenul adevărat se cunoaște la reușita ta: se bucură fără umbră. Invidia nu încape unde e prietenie întreagă.',en:'A true friend is known at your success: they rejoice without shadow. Envy has no room where friendship is whole.',pt:'O amigo verdadeiro conhece-se no teu sucesso: alegra-se sem sombra. A inveja não cabe onde a amizade é inteira.'},inv:{ro:'Bucură-te azi curat de izbânda unui prieten. Spune-i-o.',en:'Rejoice cleanly today at a friend’s win. Tell them.',pt:'Alegra-te hoje limpo com a vitória de um amigo. Diz-lho.'}},
  {el:'friend',kw:{ro:'Apărarea în lipsă',en:'Defense in Absence',pt:'A Defesa na Ausência'},t:{ro:'Prietenul se cunoaște după ce spune despre tine când nu ești de față. Fii tu întâi acest prieten.',en:'A friend is known by what they say of you in your absence. First be that friend yourself.',pt:'O amigo conhece-se pelo que diz de ti na tua ausência. Sê tu primeiro esse amigo.'},inv:{ro:'Apără azi un prieten absent dintr-o discuție.',en:'Defend an absent friend in a conversation today.',pt:'Defende hoje um amigo ausente numa conversa.'}},
  {el:'friend',kw:{ro:'Cearta bună',en:'The Good Quarrel',pt:'A Boa Discussão'},t:{ro:'Prietenia care nu suportă nicio ceartă e sticlă; cea călită de câteva certuri drepte e oțel.',en:'A friendship that bears no quarrel is glass; one tempered by a few honest quarrels is steel.',pt:'A amizade que não suporta nenhuma briga é vidro; a temperada por algumas brigas justas é aço.'},inv:{ro:'Nu ocoli azi o discuție dreaptă cu un om drag.',en:'Do not avoid an honest talk with a dear one today.',pt:'Não evites hoje uma conversa justa com alguém querido.'}},
  {el:'friend',kw:{ro:'Tovărășia tăcută',en:'The Silent Company',pt:'A Companhia Calada'},t:{ro:'A sta împreună fără program și fără vorbe e examenul suprem al prieteniei. Puțini îl trec; aceia rămân.',en:'Being together without plan or words is friendship’s final exam. Few pass; those remain.',pt:'Estar juntos sem plano e sem palavras é o exame final da amizade. Poucos passam; esses ficam.'},inv:{ro:'Dă azi examenul: timp împreună fără program.',en:'Take the exam today: time together with no plan.',pt:'Faz hoje o exame: tempo juntos sem plano.'}},
  {el:'friend',kw:{ro:'Datoria ștearsă',en:'The Erased Debt',pt:'A Dívida Apagada'},t:{ro:'Între prieteni, socoteala exactă strică prietenia exactă. Dă fără condică; primește fără povară.',en:'Between friends, exact accounting spoils exact friendship. Give without ledger; receive without burden.',pt:'Entre amigos, a conta exata estraga a amizade exata. Dá sem livro; recebe sem fardo.'},inv:{ro:'Șterge azi o mică „datorie" ținută în minte.',en:'Erase one small mental “debt” today.',pt:'Apaga hoje uma pequena «dívida» guardada na mente.'}},
  {el:'friend',kw:{ro:'Prietenul incomod',en:'The Inconvenient Friend',pt:'O Amigo Incómodo'},t:{ro:'Ferește-te de prietenii care te aprobă mereu: sunt fie neatenți, fie interesați. Prietenul bun te mai și contrazice.',en:'Beware friends who always approve: they are either inattentive or interested. A good friend also contradicts you.',pt:'Cuidado com amigos que sempre aprovam: ou estão desatentos ou interessados. O bom amigo também te contradiz.'},inv:{ro:'Mulțumește azi unui om care te contrazice cinstit.',en:'Thank someone today who contradicts you honestly.',pt:'Agradece hoje a alguém que te contradiz com honestidade.'}},
  {el:'friend',kw:{ro:'Podul întreținut',en:'The Maintained Bridge',pt:'A Ponte Mantida'},t:{ro:'Prietenia e un pod care se întreține circulând pe el. Podurile nefolosite se surpă în tăcere.',en:'Friendship is a bridge maintained by crossing it. Unused bridges collapse in silence.',pt:'A amizade é uma ponte que se mantém atravessando-a. As pontes sem uso ruem em silêncio.'},inv:{ro:'Treci azi un pod neumblat de mult: un mesaj scurt ajunge.',en:'Cross one long-unused bridge today: a short message will do.',pt:'Atravessa hoje uma ponte há muito parada: uma mensagem curta chega.'}},
  {el:'friend',kw:{ro:'Prietenul de drum scurt',en:'The Short-Road Friend',pt:'O Amigo de Estrada Curta'},t:{ro:'Unii oameni ne sunt dați doar pentru o bucată de drum. Nu-i judeca după lungime; judecă-i după lumină.',en:'Some people are given to us for only a stretch of road. Judge them not by length but by light.',pt:'Algumas pessoas são-nos dadas só para um troço de estrada. Não as julgues pelo comprimento; julga-as pela luz.'},inv:{ro:'Mulțumește în gând unui prieten „de sezon" de altădată.',en:'Silently thank a “seasonal” friend from the past.',pt:'Agradece em pensamento a um amigo «de estação» de outrora.'}},
  {el:'friend',kw:{ro:'Masa prieteniei',en:'The Friendship Table',pt:'A Mesa da Amizade'},t:{ro:'Nicio prietenie n-a slăbit din prea multe mese împreună. Pâinea frântă în doi leagă mai tare decât orice contract.',en:'No friendship ever weakened from too many shared meals. Bread broken together binds tighter than any contract.',pt:'Nenhuma amizade enfraqueceu por refeições a mais em conjunto. O pão partido a dois une mais que qualquer contrato.'},inv:{ro:'Programează săptămâna asta o masă cu un prieten.',en:'Schedule a meal with a friend this week.',pt:'Marca esta semana uma refeição com um amigo.'}},
  {el:'friend',kw:{ro:'Secretul ținut',en:'The Kept Confidence',pt:'A Confidência Guardada'},t:{ro:'Prietenia se zidește din taine ținute și se surpă dintr-una singură scăpată. Fii seif, nu sită.',en:'Friendship is built of confidences kept and collapses from a single one spilled. Be a vault, not a sieve.',pt:'A amizade constrói-se de confidências guardadas e rui por uma só derramada. Sê cofre, não peneira.'},inv:{ro:'Verifică-te azi: ești seif pentru cei care ți se încred?',en:'Check yourself today: are you a vault for those who confide?',pt:'Verifica-te hoje: és cofre para quem confia em ti?'}},
  {el:'friend',kw:{ro:'Prietenul nou',en:'The New Friend',pt:'O Amigo Novo'},t:{ro:'La orice vârstă se mai pot lega prietenii — dar numai de cei care mai lasă ușa întredeschisă.',en:'Friendships can still form at any age — but only for those who keep the door ajar.',pt:'Em qualquer idade ainda se fazem amizades — mas só para quem deixa a porta entreaberta.'},inv:{ro:'Lasă azi ușa întredeschisă: o vorbă în plus cu un om nou.',en:'Leave the door ajar today: one extra word with someone new.',pt:'Deixa hoje a porta entreaberta: uma palavra a mais com alguém novo.'}},
  {el:'friend',kw:{ro:'Rugăciunea pentru prieten',en:'Prayer for a Friend',pt:'A Oração pelo Amigo'},t:{ro:'Cel mai discret fel de a iubi un prieten: să-l pomenești în ruga sau în gândul tău bun, fără să afle vreodată.',en:'The most discreet way to love a friend: to hold them in your prayer or good thought, without their ever knowing.',pt:'O modo mais discreto de amar um amigo: tê-lo na tua oração ou bom pensamento, sem que ele jamais saiba.'},inv:{ro:'Poartă azi un prieten în gândul tău cel bun.',en:'Carry a friend in your good thought today.',pt:'Leva hoje um amigo no teu bom pensamento.'}},
  {el:'friend',kw:{ro:'Hotarul prieteniei',en:'The Friendship Boundary',pt:'O Limite da Amizade'},t:{ro:'Și prietenia are hotare: nu-i cere prietenului să-ți fie și terapeut, și bancă, și program de urgență. Ține-l prieten.',en:'Friendship too has borders: do not ask a friend to be your therapist, bank and emergency line. Keep them a friend.',pt:'A amizade também tem limites: não peças ao amigo que seja terapeuta, banco e linha de emergência. Mantém-no amigo.'},inv:{ro:'Ușurează azi un prieten de un rol care nu e al lui.',en:'Relieve a friend today of a role that is not theirs.',pt:'Alivia hoje um amigo de um papel que não é dele.'}},
  {el:'friend',kw:{ro:'Râsul împreună',en:'Laughing Together',pt:'Rir Juntos'},t:{ro:'Oamenii care au râs mult împreună nu se mai pot dușmăni cu totul: râsul comun e un legământ vesel.',en:'People who have laughed much together can never fully become enemies: shared laughter is a merry covenant.',pt:'Quem riu muito junto nunca se torna inimigo por completo: o riso partilhado é uma aliança alegre.'},inv:{ro:'Reînnoiește azi legământul: un râs bun cu un prieten.',en:'Renew the covenant today: a good laugh with a friend.',pt:'Renova hoje a aliança: uma boa gargalhada com um amigo.'}},
  {el:'friend',kw:{ro:'Vestea dată întâi',en:'The First-Told News',pt:'A Notícia Contada Primeiro'},t:{ro:'Cui îi spui primul vestea bună — acela îți e omul. Prietenia se măsoară în astfel de întâietăți.',en:'Whoever hears your good news first — that is your person. Friendship is measured in such firsts.',pt:'A quem contas primeiro a boa notícia — essa é a tua pessoa. A amizade mede-se nessas primazias.'},inv:{ro:'Dă azi cuiva drag o veste bună, lui întâi.',en:'Give a dear one good news today, them first.',pt:'Dá hoje a alguém querido uma boa notícia, a ele primeiro.'}},
  {el:'friend',kw:{ro:'Iertarea între prieteni',en:'Forgiveness Between Friends',pt:'O Perdão Entre Amigos'},t:{ro:'Prietenia lungă e o salbă de iertări mărunte pe care nimeni nu le-a numărat. Nu începe acum numărătoarea.',en:'A long friendship is a necklace of small pardons no one counted. Do not start counting now.',pt:'A amizade longa é um colar de pequenos perdões que ninguém contou. Não comeces agora a contagem.'},inv:{ro:'Adaugă azi o mărgea la salbă, fără să ții socoteala.',en:'Add one bead to the necklace today, keeping no count.',pt:'Acrescenta hoje uma conta ao colar, sem levar a conta.'}},
  {el:'friend',kw:{ro:'Prietenul care pleacă',en:'The Friend Who Leaves',pt:'O Amigo que Parte'},t:{ro:'Unele prietenii se sting fără vină. Lasă-le să apună frumos, cu recunoștință, nu cu proces.',en:'Some friendships fade without fault. Let them set beautifully, with gratitude, not a trial.',pt:'Algumas amizades apagam-se sem culpa. Deixa-as pôr-se com beleza, com gratidão, não com julgamento.'},inv:{ro:'Închide în pace, azi, o prietenie apusă: fără vinovați.',en:'Close a faded friendship in peace today: no culprits.',pt:'Fecha hoje em paz uma amizade posta: sem culpados.'}},
  {el:'friend',kw:{ro:'A fi tu prietenul',en:'Being the Friend Yourself',pt:'Ser Tu o Amigo'},t:{ro:'Nu întreba unde sunt prietenii adevărați. Întreabă al cui prieten adevărat ești tu. Răspunsul aduce prieteni.',en:'Do not ask where true friends are. Ask whose true friend you are. The answer brings friends.',pt:'Não perguntes onde estão os amigos verdadeiros. Pergunta de quem és tu amigo verdadeiro. A resposta traz amigos.'},inv:{ro:'Fii azi, activ, prietenul pe care ți-l dorești.',en:'Actively be today the friend you wish for.',pt:'Sê hoje, ativamente, o amigo que desejas ter.'}},
  {el:'friend',kw:{ro:'Cufărul cu amintiri comune',en:'The Chest of Shared Memories',pt:'O Baú das Memórias Comuns'},t:{ro:'„Mai știi când…?" e cheia unui cufăr pe care doar voi doi îl puteți deschide. Averea aceea nu se devalorizează.',en:'“Remember when…?” is the key to a chest only you two can open. That wealth never devalues.',pt:'«Lembras-te de quando…?» é a chave de um baú que só vocês dois abrem. Essa riqueza nunca desvaloriza.'},inv:{ro:'Deschide azi cufărul: un „mai știi când" cu un prieten.',en:'Open the chest today: one “remember when” with a friend.',pt:'Abre hoje o baú: um «lembras-te» com um amigo.'}},
  {el:'friend',kw:{ro:'Prietenul din carte',en:'The Friend in the Book',pt:'O Amigo do Livro'},t:{ro:'O carte bună e un prieten răbdător: te așteaptă ani, nu se supără, îți vorbește exact când deschizi.',en:'A good book is a patient friend: it waits years, takes no offense, speaks exactly when you open it.',pt:'Um bom livro é um amigo paciente: espera anos, não se ofende, fala exatamente quando o abres.'},inv:{ro:'Petrece azi un sfert de oră cu un prieten-carte.',en:'Spend a quarter hour with a book-friend today.',pt:'Passa hoje um quarto de hora com um amigo-livro.'}},
  {el:'friend',kw:{ro:'Cuvântul greu la vreme grea',en:'The Strong Word in the Hard Hour',pt:'A Palavra Forte na Hora Difícil'},t:{ro:'În ziua neagră a prietenului, nu-ți căuta cuvintele perfecte. „Sunt aici" le bate pe toate.',en:'On a friend’s black day, do not search for perfect words. “I am here” beats them all.',pt:'No dia negro do amigo, não procures as palavras perfeitas. «Estou aqui» vence todas.'},inv:{ro:'Dacă cineva drag e la greu, trimite azi: „sunt aici".',en:'If someone dear struggles, send today: “I am here.”',pt:'Se alguém querido sofre, envia hoje: «estou aqui».'}},
  {el:'friend',kw:{ro:'Grădina cu oameni',en:'The Garden of People',pt:'O Jardim de Pessoas'},t:{ro:'Prieteniile sunt o grădină: unele plante cer zilnic apă, altele înfloresc și uitate. Cunoaște-ți florile.',en:'Friendships are a garden: some plants need daily water, others bloom even forgotten. Know your flowers.',pt:'As amizades são um jardim: umas plantas pedem água diária, outras florescem mesmo esquecidas. Conhece as tuas flores.'},inv:{ro:'Udă azi planta care cere des; salută-o pe cea răbdătoare.',en:'Water the needy plant today; greet the patient one.',pt:'Rega hoje a planta exigente; saúda a paciente.'}},
  {el:'friend',kw:{ro:'Prietenia cu tine',en:'Friendship with Yourself',pt:'A Amizade Contigo'},t:{ro:'Ești singurul om cu care stai garantat toată viața. Merita-ți-ar propria prietenie? Lucrează la ea.',en:'You are the only person you are guaranteed to live with all your life. Would you earn your own friendship? Work on it.',pt:'És a única pessoa com quem vives garantidamente a vida toda. Merecerias a tua própria amizade? Trabalha nela.'},inv:{ro:'Poartă-te azi cu tine ca un prieten bun: fără trădări mici.',en:'Treat yourself as a good friend today: no small betrayals.',pt:'Trata-te hoje como um bom amigo: sem pequenas traições.'}},
  {el:'friend',kw:{ro:'Musafirul care ridică',en:'The Guest Who Lifts',pt:'O Convidado que Eleva'},t:{ro:'Sunt oameni după care rămâi mai bun și oameni după care rămâi golit. Fii din prima categorie și alege des din ea.',en:'Some people leave you better, some leave you drained. Be of the first kind and choose from it often.',pt:'Há pessoas que te deixam melhor e pessoas que te deixam vazio. Sê da primeira espécie e escolhe muito dela.'},inv:{ro:'După fiecare întâlnire de azi, întreabă-te: am ridicat sau am golit?',en:'After each meeting today ask: did I lift or drain?',pt:'Depois de cada encontro de hoje pergunta: elevei ou esvaziei?'}},
  {el:'friend',kw:{ro:'Distanța care nu desparte',en:'The Distance that Does Not Divide',pt:'A Distância que Não Separa'},t:{ro:'Kilometrii despart trupuri, nu prietenii. Două inimi pe aceeași frecvență nu știu geografie.',en:'Kilometers part bodies, not friendships. Two hearts on the same frequency know no geography.',pt:'Os quilómetros separam corpos, não amizades. Dois corações na mesma frequência não sabem geografia.'},inv:{ro:'Anulează azi un fus orar: scrie prietenului de departe.',en:'Cancel a time zone today: write the faraway friend.',pt:'Anula hoje um fuso horário: escreve ao amigo distante.'}},
  {el:'friend',kw:{ro:'Sfatul cerut',en:'The Asked-For Advice',pt:'O Conselho Pedido'},t:{ro:'Sfatul necerut e critică deghizată; sfatul cerut e dar. Așteaptă întrebarea înainte să dai răspunsul.',en:'Unasked advice is disguised criticism; asked advice is a gift. Wait for the question before giving the answer.',pt:'O conselho não pedido é crítica disfarçada; o pedido é dom. Espera a pergunta antes de dar a resposta.'},inv:{ro:'Ține azi un sfat bun în buzunar până e cerut.',en:'Keep one good advice pocketed today until asked.',pt:'Guarda hoje um bom conselho no bolso até ser pedido.'}},
  {el:'friend',kw:{ro:'Vinul prieteniei',en:'The Wine of Friendship',pt:'O Vinho da Amizade'},t:{ro:'Prietenia nouă e must: dulce și tulbure. Dă-i ani, păstrează-o bine, și devine vinul care încălzește bătrânețile.',en:'New friendship is must: sweet and cloudy. Give it years, keep it well, and it becomes the wine that warms old age.',pt:'A amizade nova é mosto: doce e turva. Dá-lhe anos, guarda-a bem, e torna-se o vinho que aquece a velhice.'},inv:{ro:'Pune azi ceva „la învechit": o legătură tânără îngrijită.',en:'Lay something down to age today: a young bond well tended.',pt:'Põe hoje algo a envelhecer: um laço jovem bem cuidado.'}},
  {el:'friend',kw:{ro:'Cei trei prieteni',en:'The Three Friends',pt:'Os Três Amigos'},t:{ro:'Ajung trei prieteni adevărați ca să treci orice viață: unul care te ascultă, unul care te ridică, unul care îți spune adevărul.',en:'Three true friends suffice for any life: one who listens, one who lifts, one who tells you the truth.',pt:'Bastam três amigos verdadeiros para qualquer vida: um que escuta, um que levanta, um que diz a verdade.'},inv:{ro:'Numește-ți azi cei trei — și spune-i unuia mulțumesc.',en:'Name your three today — and thank one of them.',pt:'Nomeia hoje os teus três — e agradece a um deles.'}},
  {el:'friend',kw:{ro:'Binecuvântarea prieteniei',en:'The Blessing of Friendship',pt:'A Bênção da Amizade'},t:{ro:'Un prieten adevărat e dovada umblătoare că nu ești singur pe lume. Fii și tu, pentru cineva, dovada aceasta.',en:'A true friend is walking proof you are not alone in the world. Be that proof for someone too.',pt:'Um amigo verdadeiro é a prova ambulante de que não estás só no mundo. Sê também essa prova para alguém.'},inv:{ro:'Fii azi dovada cuiva: arată-i că nu e singur.',en:'Be someone’s proof today: show them they are not alone.',pt:'Sê hoje a prova de alguém: mostra-lhe que não está só.'}},

  /* ———————— CERCUL ÎNCEPUTULUI ———————— */
  {el:'begin',kw:{ro:'Prima zi',en:'The First Day',pt:'O Primeiro Dia'},t:{ro:'Orice zi acceptă să fie prima zi. Calendarul nu are nicio putere asupra începuturilor; tu le ai pe toate.',en:'Any day agrees to be the first day. The calendar has no power over beginnings; you hold them all.',pt:'Qualquer dia aceita ser o primeiro dia. O calendário não tem poder sobre os começos; tu tem-los todos.'},inv:{ro:'Declară azi „ziua întâi" a unui lucru bun.',en:'Declare today “day one” of something good.',pt:'Declara hoje o «dia um» de algo bom.'}},
  {el:'begin',kw:{ro:'Semnul de start',en:'The Starting Signal',pt:'O Sinal de Partida'},t:{ro:'Aștepți un semn ca să începi? Acesta este. Semnele arată rar mai clar de atât.',en:'Waiting for a sign to begin? This is it. Signs rarely come clearer.',pt:'Esperas um sinal para começar? É este. Os sinais raramente vêm mais claros.'},inv:{ro:'Consideră cartea aceasta semnul. Începe azi.',en:'Take this card as the sign. Begin today.',pt:'Toma esta carta como o sinal. Começa hoje.'}},
  {el:'begin',kw:{ro:'Stângăcia sfântă',en:'The Holy Clumsiness',pt:'O Desajeito Sagrado'},t:{ro:'Începutul are dreptul sfânt de a fi stângaci. Cine cere eleganță de la ziua întâi n-a început niciodată nimic.',en:'The beginning holds a holy right to clumsiness. Whoever demands elegance of day one has never begun anything.',pt:'O começo tem o direito sagrado de ser desajeitado. Quem exige elegância ao primeiro dia nunca começou nada.'},inv:{ro:'Începe azi prost ceva ce merită început.',en:'Begin something worth beginning badly today.',pt:'Começa hoje mal algo que vale a pena começar.'}},
  {el:'begin',kw:{ro:'Ușa nouă',en:'The New Door',pt:'A Porta Nova'},t:{ro:'Când o ușă se închide, alta se deschide — dar trebuie să ieși din holul în care plângi după prima.',en:'When one door closes another opens — but you must leave the hallway where you mourn the first.',pt:'Quando uma porta se fecha, outra se abre — mas tens de sair do corredor onde choras a primeira.'},inv:{ro:'Ieși azi din hol: fă un pas spre ușa următoare.',en:'Leave the hallway today: step toward the next door.',pt:'Sai hoje do corredor: dá um passo para a próxima porta.'}},
  {el:'begin',kw:{ro:'Zorii lucrului',en:'The Dawn of the Work',pt:'A Aurora da Obra'},t:{ro:'Începutul e jumătatea întregului, spuneau bătrânii lumii. Cine a pornit azi a și făcut jumătate din drum.',en:'The beginning is half of the whole, the world’s elders said. Who starts today has already walked half the road.',pt:'O começo é metade do todo, diziam os anciãos do mundo. Quem parte hoje já andou metade do caminho.'},inv:{ro:'Fă azi jumătatea magică: doar începe.',en:'Do the magic half today: just begin.',pt:'Faz hoje a metade mágica: apenas começa.'}},
  {el:'begin',kw:{ro:'Curățenia de dinainte',en:'The Clearing Before',pt:'A Limpeza de Antes'},t:{ro:'Înainte de a începe ceva nou, fă loc: un obicei vechi dat jos face cât două obiceiuri noi urcate.',en:'Before beginning something new, make room: one old habit taken down equals two new ones raised.',pt:'Antes de começar algo novo, faz espaço: um hábito velho retirado vale dois novos erguidos.'},inv:{ro:'Eliberează azi locul: renunță întâi la ceva.',en:'Clear the spot today: first give something up.',pt:'Liberta hoje o lugar: primeiro larga algo.'}},
  {el:'begin',kw:{ro:'Frica de la start',en:'The Starting-Line Fear',pt:'O Medo da Partida'},t:{ro:'Frica de dinaintea începutului e cea mai mare frică a lui; scade cu fiecare pas. Deci primul pas e și cel mai viteaz.',en:'The fear before the start is its greatest; it shrinks with each step. So the first step is also the bravest.',pt:'O medo antes do começo é o maior; diminui a cada passo. Logo, o primeiro passo é o mais valente.'},inv:{ro:'Fă azi pasul cel mai viteaz: primul.',en:'Take the bravest step today: the first.',pt:'Dá hoje o passo mais valente: o primeiro.'}},
  {el:'begin',kw:{ro:'Începutul mic de tot',en:'The Tiny Beginning',pt:'O Começo Minúsculo'},t:{ro:'Vrei să citești? O pagină. Să alergi? Până la colț. Începutul de neratat e cel prea mic pentru scuze.',en:'Want to read? One page. To run? To the corner. The unmissable beginning is the one too small for excuses.',pt:'Queres ler? Uma página. Correr? Até à esquina. O começo infalível é o pequeno demais para desculpas.'},inv:{ro:'Alege azi versiunea prea-mică-pentru-scuze și f-o.',en:'Choose the too-small-for-excuses version today and do it.',pt:'Escolhe hoje a versão pequena-demais-para-desculpas e fá-la.'}},
  {el:'begin',kw:{ro:'A doua oară prima oară',en:'The First Time Again',pt:'A Primeira Vez de Novo'},t:{ro:'Poți începe din nou aceeași căsnicie, aceeași meserie, aceeași viață — cu ochii de la început. Reînceperea e o artă.',en:'You can begin anew the same marriage, trade, life — with beginning eyes. Re-beginning is an art.',pt:'Podes recomeçar o mesmo casamento, ofício, vida — com olhos de princípio. Recomeçar é uma arte.'},inv:{ro:'Reîncepe azi ceva vechi cu ochi de prima zi.',en:'Restart something old today with first-day eyes.',pt:'Recomeça hoje algo antigo com olhos de primeiro dia.'}},
  {el:'begin',kw:{ro:'Sămânța din buzunar',en:'The Seed in the Pocket',pt:'A Semente no Bolso'},t:{ro:'Ideea neînsemnată pe care o porți de ani în buzunar e o sămânță care așteaptă. Buzunarul nu e pământ.',en:'The small idea carried in your pocket for years is a waiting seed. A pocket is not soil.',pt:'A ideia pequena que trazes há anos no bolso é uma semente à espera. O bolso não é terra.'},inv:{ro:'Scoate azi sămânța din buzunar: primul gest concret.',en:'Take the seed from the pocket today: the first concrete act.',pt:'Tira hoje a semente do bolso: o primeiro gesto concreto.'}},
  {el:'begin',kw:{ro:'Ora începătorilor',en:'The Beginners’ Hour',pt:'A Hora dos Principiantes'},t:{ro:'În fiecare maestru doarme începătorul care a îndrăznit. În fiecare începător, un posibil maestru. Dormi sau îndrăznești?',en:'In every master sleeps the beginner who dared. In every beginner, a possible master. Sleeping or daring?',pt:'Em cada mestre dorme o principiante que ousou. Em cada principiante, um possível mestre. Dormes ou ousas?'},inv:{ro:'Îndrăznește azi ca un începător cu viitor de maestru.',en:'Dare today like a beginner with a master’s future.',pt:'Ousa hoje como principiante com futuro de mestre.'}},
  {el:'begin',kw:{ro:'Piatra de hotar',en:'The Boundary Stone',pt:'O Marco'},t:{ro:'Pune o piatră de hotar: „aici s-a terminat vechiul fel". Omul are nevoie de granițe văzute ca să creadă în cele lăuntrice.',en:'Set a boundary stone: “here the old way ended.” People need visible borders to believe the inner ones.',pt:'Põe um marco: «aqui acabou o modo antigo». A pessoa precisa de fronteiras visíveis para crer nas interiores.'},inv:{ro:'Marchează azi vizibil un început: o dată scrisă, un obiect, un loc.',en:'Mark a beginning visibly today: a written date, an object, a place.',pt:'Marca hoje visivelmente um começo: uma data escrita, um objeto, um lugar.'}},
  {el:'begin',kw:{ro:'Musafirul dimineții',en:'The Morning’s Guest',pt:'O Hóspede da Manhã'},t:{ro:'În fiecare dimineață, un început bate la ușă îmbrăcat în zi obișnuită. De obicei nu-i deschidem, că nu pare a fi el.',en:'Each morning a beginning knocks, dressed as an ordinary day. Usually we do not answer, for it does not look the part.',pt:'Cada manhã um começo bate à porta, vestido de dia comum. Normalmente não abrimos, porque não parece ele.'},inv:{ro:'Deschide-i azi: tratează ziua banală ca pe un început deghizat.',en:'Answer today: treat the plain day as a disguised beginning.',pt:'Abre hoje: trata o dia banal como um começo disfarçado.'}},
  {el:'begin',kw:{ro:'Începutul de după eșec',en:'The Beginning After Failure',pt:'O Começo Depois do Fracasso'},t:{ro:'Eșecul e doar un început căruia i s-a citit greșit numele. Reia-l cu ce știi acum și îl va chema pe cel adevărat.',en:'Failure is only a beginning whose name was misread. Retake it with what you now know, and it will call the true one.',pt:'O fracasso é só um começo cujo nome se leu mal. Retoma-o com o que agora sabes e ele chamará o verdadeiro.'},inv:{ro:'Recitește azi un „eșec": ce început ascunde?',en:'Reread one “failure” today: what beginning does it hide?',pt:'Relê hoje um «fracasso»: que começo esconde?'}},
  {el:'begin',kw:{ro:'Cheful de mai târziu',en:'The Later Mood',pt:'A Vontade de Depois'},t:{ro:'Cheful de a începe vine de obicei după ce ai început — niciodată înainte. Nu-l aștepta la start; te așteaptă pe drum.',en:'The mood to begin usually arrives after beginning — never before. Do not await it at the start; it awaits you on the road.',pt:'A vontade de começar chega normalmente depois de começar — nunca antes. Não a esperes na partida; ela espera-te no caminho.'},inv:{ro:'Începe azi fără chef; el te prinde din urmă în zece minute.',en:'Begin without the mood today; it catches up in ten minutes.',pt:'Começa hoje sem vontade; ela alcança-te em dez minutos.'}},
  {el:'begin',kw:{ro:'Primul client, primul pas',en:'The First of Anything',pt:'O Primeiro de Tudo'},t:{ro:'Primul client, primul rând, primul kilometru: toate „primele" sunt disproporționat de valoroase. Ele sparg vraja lui zero.',en:'The first customer, line, kilometer: all “firsts” are disproportionately precious. They break the spell of zero.',pt:'O primeiro cliente, a primeira linha, o primeiro quilómetro: todos os «primeiros» valem desproporcionadamente. Quebram o feitiço do zero.'},inv:{ro:'Sparge azi un zero: obține primul de orice fel.',en:'Break a zero today: get a first of any kind.',pt:'Quebra hoje um zero: consegue um primeiro de qualquer tipo.'}},
  {el:'begin',kw:{ro:'Caietul nou',en:'The New Notebook',pt:'O Caderno Novo'},t:{ro:'Un caiet nou iartă tot ce ai scris în cele vechi. Viața dă caiete noi în fiecare dimineață; puțini le desfac.',en:'A new notebook forgives everything written in the old ones. Life hands out new notebooks each morning; few open them.',pt:'Um caderno novo perdoa tudo o que escreveste nos velhos. A vida dá cadernos novos cada manhã; poucos os abrem.'},inv:{ro:'Desfă azi caietul nou: iartă-ți paginile vechi.',en:'Open the new notebook today: forgive your old pages.',pt:'Abre hoje o caderno novo: perdoa as tuas páginas velhas.'}},
  {el:'begin',kw:{ro:'Începutul în doi',en:'Beginning Together',pt:'Começar a Dois'},t:{ro:'Începuturile anunțate cuiva drag au de două ori mai multe șanse: unul pornește, doi țin drumul.',en:'Beginnings announced to a dear one have double the odds: one starts, two hold the road.',pt:'Os começos anunciados a alguém querido têm o dobro das hipóteses: um parte, dois seguram o caminho.'},inv:{ro:'Anunță azi începutul tău unui om care ține cu tine.',en:'Announce your beginning today to someone who roots for you.',pt:'Anuncia hoje o teu começo a alguém que torce por ti.'}},
  {el:'begin',kw:{ro:'Vârsta începutului',en:'The Age of Beginning',pt:'A Idade do Começo'},t:{ro:'Nimeni nu întreabă răsăritul câți ani are soarele. Începutul tău e nou, oricâți ani ai tu.',en:'No one asks the sunrise how old the sun is. Your beginning is new, however old you are.',pt:'Ninguém pergunta ao nascer do sol quantos anos tem o sol. O teu começo é novo, tenhas os anos que tiveres.'},inv:{ro:'Șterge azi „e prea târziu pentru mine" dintr-o propoziție.',en:'Delete “too late for me” from one sentence today.',pt:'Apaga hoje o «tarde demais para mim» de uma frase.'}},
  {el:'begin',kw:{ro:'Uceniciile paralele',en:'The Parallel Apprenticeships',pt:'As Aprendizagens Paralelas'},t:{ro:'Începe ceva nou și vei învăța două lucruri: meșteșugul — și cine ești când nu știi încă nimic.',en:'Begin something new and you learn two things: the craft — and who you are when you know nothing yet.',pt:'Começa algo novo e aprendes duas coisas: o ofício — e quem és quando ainda nada sabes.'},inv:{ro:'Observă-te azi ca începător: cine ești fără pricepere?',en:'Watch yourself as a beginner today: who are you without skill?',pt:'Observa-te hoje como principiante: quem és sem perícia?'}},
  {el:'begin',kw:{ro:'Rădăcina înainte de floare',en:'Root Before Flower',pt:'A Raiz Antes da Flor'},t:{ro:'La început crește rădăcina, și nimeni nu aplaudă. Nu-ți măsura începuturile în aplauze; măsoară-le în rădăcină.',en:'At first the root grows, and no one applauds. Do not measure beginnings in applause; measure them in root.',pt:'No princípio cresce a raiz, e ninguém aplaude. Não meças os começos em aplausos; mede-os em raiz.'},inv:{ro:'Lucrează azi la rădăcină, fără public, cu spor.',en:'Work on the root today, no audience, with vigor.',pt:'Trabalha hoje na raiz, sem público, com afinco.'}},
  {el:'begin',kw:{ro:'Prima piatră a podului',en:'The Bridge’s First Stone',pt:'A Primeira Pedra da Ponte'},t:{ro:'Podurile mari încep cu o piatră aruncată în apă de un om care n-a văzut încă malul celălalt. Încrederea vine zidind.',en:'Great bridges begin with a stone cast into water by someone who has not yet seen the far bank. Faith comes by building.',pt:'As grandes pontes começam com uma pedra lançada à água por quem ainda não viu a outra margem. A fé vem construindo.'},inv:{ro:'Aruncă azi prima piatră a unui pod de-al tău.',en:'Cast the first stone of a bridge of yours today.',pt:'Lança hoje a primeira pedra de uma ponte tua.'}},
  {el:'begin',kw:{ro:'Dimineața vieții',en:'The Morning of Life',pt:'A Manhã da Vida'},t:{ro:'Oricât ar fi ceasul vieții tale, ceva din tine e mereu la răsărit. Găsește partea aceea și pune-o la lucru.',en:'Whatever your life’s hour, something in you is always at sunrise. Find that part and set it to work.',pt:'Seja qual for a hora da tua vida, algo em ti está sempre ao amanhecer. Encontra essa parte e põe-na a trabalhar.'},inv:{ro:'Ce e „la răsărit" în tine acum? Dă-i azi întâietate.',en:'What is “at sunrise” in you now? Give it precedence today.',pt:'O que está «ao amanhecer» em ti agora? Dá-lhe hoje prioridade.'}},
  {el:'begin',kw:{ro:'Semnătura pe ziua întâi',en:'Signing Day One',pt:'A Assinatura do Dia Um'},t:{ro:'Ziua întâi nu cere izbândă; cere doar semnătura ta: „am fost aici și am început". Restul zilelor vin la semnătura asta.',en:'Day one asks no victory; only your signature: “I was here and I began.” The other days come to that signature.',pt:'O dia um não pede vitória; só a tua assinatura: «estive aqui e comecei». Os outros dias vêm a essa assinatura.'},inv:{ro:'Semnează azi ziua întâi a ceva. Atât e sarcina.',en:'Sign day one of something today. That is the whole task.',pt:'Assina hoje o dia um de algo. É essa toda a tarefa.'}},
  {el:'begin',kw:{ro:'Golul de dinainte',en:'The Void Before',pt:'O Vazio de Antes'},t:{ro:'Înaintea oricărei creații stă un gol care sperie. Nu e dușman: e locul pregătit pentru ce aduci tu.',en:'Before every creation stands a frightening void. It is no enemy: it is the place prepared for what you bring.',pt:'Antes de toda a criação há um vazio que assusta. Não é inimigo: é o lugar preparado para o que trazes.'},inv:{ro:'Intră azi în golul care sperie cu o singură cărămidă.',en:'Enter the frightening void today with a single brick.',pt:'Entra hoje no vazio que assusta com um único tijolo.'}},
  {el:'begin',kw:{ro:'Ruga începutului',en:'The Beginning’s Prayer',pt:'A Oração do Começo'},t:{ro:'Începe cu o binecuvântare orice lucru și lucrul o va purta în el până la capăt, ca un parfum turnat în temelie.',en:'Begin anything with a blessing and the work will carry it to the end, like perfume poured into the foundation.',pt:'Começa qualquer coisa com uma bênção e a obra levá-la-á até ao fim, como perfume vertido no alicerce.'},inv:{ro:'Binecuvântează azi începutul înainte de primul gest.',en:'Bless the beginning today before the first gesture.',pt:'Abençoa hoje o começo antes do primeiro gesto.'}},
  {el:'begin',kw:{ro:'Harta necompletată',en:'The Unfinished Map',pt:'O Mapa por Completar'},t:{ro:'Pe hărțile vechi, la margini scria „aici sunt lei". Începutul e mersul în ținutul cu lei — și descoperirea că sunt pisici.',en:'On old maps the margins read “here be lions.” Beginning is walking into lion country — and finding cats.',pt:'Nos mapas antigos, nas margens lia-se «aqui há leões». Começar é entrar na terra dos leões — e descobrir que são gatos.'},inv:{ro:'Intră azi în ținutul „cu lei" al tău. Numără pisicile.',en:'Enter your “lion country” today. Count the cats.',pt:'Entra hoje na tua «terra dos leões». Conta os gatos.'}},
  {el:'begin',kw:{ro:'Începutul tăcut',en:'The Quiet Beginning',pt:'O Começo Silencioso'},t:{ro:'Nu orice început se anunță cu trâmbițe; cele mai temeinice pornesc în șoaptă, ca germinația.',en:'Not every beginning is trumpeted; the sturdiest start in a whisper, like germination.',pt:'Nem todo o começo se anuncia com trombetas; os mais sólidos partem em sussurro, como a germinação.'},inv:{ro:'Începe azi în tăcere; lasă rezultatele să anunțe.',en:'Begin in silence today; let results make the announcement.',pt:'Começa hoje em silêncio; deixa os resultados anunciar.'}},
  {el:'begin',kw:{ro:'Puterea zilei de luni',en:'The Power of Monday',pt:'O Poder da Segunda-Feira'},t:{ro:'Nu da vina pe luni; e doar ziua care are curajul să înceapă săptămâna. Fă-ți-o aliată: dă-i un plan frumos.',en:'Do not blame Monday; it is merely the day brave enough to start the week. Ally with it: give it a beautiful plan.',pt:'Não culpes a segunda; é só o dia com coragem de começar a semana. Torna-a aliada: dá-lhe um belo plano.'},inv:{ro:'Pregătește de azi lunea viitoare: un singur lucru frumos în ea.',en:'Prepare next Monday today: one beautiful thing in it.',pt:'Prepara hoje a próxima segunda: uma coisa bela nela.'}},
  {el:'begin',kw:{ro:'Nașterea de fiecare zi',en:'The Daily Birth',pt:'O Nascimento Diário'},t:{ro:'Te-ai născut o dată din mamă și te naști zilnic din somn. A doua naștere e în mâinile tale: fă din ea un obicei frumos.',en:'You were born once of your mother and are born daily from sleep. The second birth is in your hands: make it a beautiful habit.',pt:'Nasceste uma vez da tua mãe e nasces todos os dias do sono. O segundo nascimento está nas tuas mãos: faz dele um belo hábito.'},inv:{ro:'Naște-te mâine frumos: primele cinci minute, ale tale.',en:'Be born beautifully tomorrow: the first five minutes, yours.',pt:'Nasce belamente amanhã: os primeiros cinco minutos, teus.'}},
  {el:'begin',kw:{ro:'Cercul care se deschide',en:'The Circle that Opens',pt:'O Círculo que Se Abre'},t:{ro:'Orice sfârșit, privit mai de aproape, e un cerc care se deschide spre altul. Viața nu se termină; se continuă altfel.',en:'Every ending, seen closely, is a circle opening into another. Life does not end; it continues otherwise.',pt:'Todo o fim, visto de perto, é um círculo a abrir-se para outro. A vida não acaba; continua de outro modo.'},inv:{ro:'Privește azi un sfârșit de aproape: unde se deschide?',en:'Look closely at one ending today: where does it open?',pt:'Olha hoje de perto um fim: onde se abre?'}},
  {el:'begin',kw:{ro:'Binecuvântarea începătorului',en:'The Beginner’s Blessing',pt:'A Bênção do Principiante'},t:{ro:'Ferice de cel care începe: toate drumurile sunt încă ale lui, toate greșelile încă iertate, tot cerul încă deschis.',en:'Blessed is the one who begins: all roads still theirs, all mistakes still forgiven, all sky still open.',pt:'Bem-aventurado o que começa: todos os caminhos ainda são seus, todos os erros ainda perdoados, todo o céu ainda aberto.'},inv:{ro:'Intră azi în starea de binecuvântare: începe.',en:'Enter the blessed state today: begin.',pt:'Entra hoje no estado de bênção: começa.'}},

  {el:'begin',kw:{ro:'Foaia de hârtie și creionul',en:'The Paper and the Pencil',pt:'O Papel e o Lápis'},t:{ro:'Tot ce a schimbat lumea a încăput întâi pe o foaie de hârtie. Începe cu creionul: e cea mai ieftină unealtă de creație și cea mai puternică.',en:'All that changed the world first fit on a sheet of paper. Begin with the pencil: the cheapest tool of creation and the mightiest.',pt:'Tudo o que mudou o mundo coube primeiro numa folha de papel. Começa pelo lápis: a ferramenta de criação mais barata e a mais poderosa.'},inv:{ro:'Scrie azi pe hârtie prima linie a unui lucru nou.',en:'Write the first line of something new on paper today.',pt:'Escreve hoje no papel a primeira linha de algo novo.'}},

  /* ———————— CERCUL SFÂRȘITULUI ———————— */
  {el:'endx',kw:{ro:'Sfârșitul curat',en:'The Clean Ending',pt:'O Fim Limpo'},t:{ro:'Lucrurile încheiate curat nu bântuie. Cele lăsate în coadă de pește se întorc noaptea la ușă.',en:'Things ended cleanly do not haunt. Those left dangling return to the door at night.',pt:'As coisas terminadas com limpeza não assombram. As deixadas a meio voltam à porta de noite.'},inv:{ro:'Încheie azi curat un lucru lăsat în coadă de pește.',en:'Cleanly close one dangling thing today.',pt:'Fecha hoje com limpeza algo deixado a meio.'}},
  {el:'endx',kw:{ro:'Ultima pagină',en:'The Last Page',pt:'A Última Página'},t:{ro:'O carte se judecă și după cum se închide. La fel o slujbă, o vârstă, o iubire: ultima pagină colorează totul.',en:'A book is judged also by how it closes. So a job, an age, a love: the last page colors the whole.',pt:'Um livro julga-se também por como fecha. Assim um emprego, uma idade, um amor: a última página tinge tudo.'},inv:{ro:'Ce se închide acum în viața ta? Scrie-i o ultimă pagină frumoasă.',en:'What is closing in your life now? Write it a beautiful last page.',pt:'O que se fecha agora na tua vida? Escreve-lhe uma bela última página.'}},
  {el:'endx',kw:{ro:'Rămasul-bun',en:'The Farewell',pt:'A Despedida'},t:{ro:'Rămasul-bun spus întreg — cu ochii în ochi, cu mulțumire — preface despărțirea din rană în amintire.',en:'A farewell said whole — eye to eye, with thanks — turns parting from wound into memory.',pt:'Uma despedida dita inteira — olhos nos olhos, com gratidão — transforma a separação de ferida em memória.'},inv:{ro:'Nu fugi azi de un rămas-bun datorat. Spune-l întreg.',en:'Do not flee a farewell owed today. Say it whole.',pt:'Não fujas hoje a uma despedida devida. Di-la inteira.'}},
  {el:'endx',kw:{ro:'Cortina lăsată la timp',en:'The Curtain Dropped in Time',pt:'A Cortina Descida a Tempo'},t:{ro:'Arta rară nu e a ține spectacolul, ci a ști actul din urmă. Ce se lungește peste rost își mănâncă frumusețea.',en:'The rare art is not keeping the show going, but knowing the final act. What outstays its meaning eats its own beauty.',pt:'A arte rara não é prolongar o espetáculo, mas conhecer o último ato. O que passa do sentido come a própria beleza.'},inv:{ro:'Ce ții în viață peste rost? Lasă azi cortina cu grație.',en:'What do you keep past its meaning? Drop the curtain gracefully today.',pt:'O que manténs para lá do sentido? Desce hoje a cortina com graça.'}},
  {el:'endx',kw:{ro:'Moștenirea clipei din urmă',en:'The Last Moment’s Bequest',pt:'O Legado do Último Instante'},t:{ro:'Din orice se sfârșește rămâne un sâmbure care nu piere: lecția. Culege sâmburele, lasă coaja.',en:'From all that ends remains an imperishable kernel: the lesson. Gather the kernel, leave the husk.',pt:'De tudo o que acaba fica um caroço que não perece: a lição. Colhe o caroço, deixa a casca.'},inv:{ro:'Dintr-un sfârșit recent, scrie azi lecția într-o frază.',en:'From a recent ending, write the lesson in one sentence today.',pt:'De um fim recente, escreve hoje a lição numa frase.'}},
  {el:'endx',kw:{ro:'Toamna lucrurilor',en:'The Autumn of Things',pt:'O Outono das Coisas'},t:{ro:'Nimic nu se sfârșește urât dacă i se îngăduie toamna: vremea în care rodul se predă și frunza se lasă.',en:'Nothing ends badly if granted its autumn: the season when fruit is handed over and the leaf lets go.',pt:'Nada acaba mal se lhe for concedido o seu outono: o tempo em que o fruto se entrega e a folha se solta.'},inv:{ro:'Dă azi „toamnă" unui lucru: timp de predare, nu tăiere bruscă.',en:'Grant something its autumn today: handover time, not a sudden cut.',pt:'Dá hoje «outono» a algo: tempo de entrega, não corte brusco.'}},
  {el:'endx',kw:{ro:'Ușa închisă frumos',en:'The Door Closed Well',pt:'A Porta Bem Fechada'},t:{ro:'Trântitul ușii se aude o clipă; închisul ei blând se ține minte o viață. Alege sunetul cu care rămâi.',en:'A slammed door sounds for a moment; a gently closed one is remembered for life. Choose the sound you keep.',pt:'A porta batida ouve-se um instante; a fechada com doçura lembra-se uma vida. Escolhe o som com que ficas.'},inv:{ro:'Dacă închizi ceva azi, închide fără trântit.',en:'If you close something today, close without slamming.',pt:'Se fechares algo hoje, fecha sem bater.'}},
  {el:'endx',kw:{ro:'Doliu și mulțumire',en:'Mourning and Thanks',pt:'Luto e Gratidão'},t:{ro:'Plânge ce se duce și mulțumește-i — în aceeași respirație. Din amestecul acesta se face pacea.',en:'Weep for what departs and thank it — in the same breath. Of this blend, peace is made.',pt:'Chora o que parte e agradece-lhe — na mesma respiração. Desta mistura faz-se a paz.'},inv:{ro:'Pentru ceva pierdut: o lacrimă și un mulțumesc, azi, împreună.',en:'For something lost: one tear and one thanks, together, today.',pt:'Por algo perdido: uma lágrima e um obrigado, juntos, hoje.'}},
  {el:'endx',kw:{ro:'Capătul care măsoară',en:'The End that Measures',pt:'O Fim que Mede'},t:{ro:'Doar de la capăt se vede drumul întreg. Nu judeca ziua la prânz, nici viața la mijloc.',en:'Only from the end is the whole road seen. Judge not the day at noon, nor the life at its middle.',pt:'Só do fim se vê o caminho inteiro. Não julgues o dia ao meio-dia, nem a vida a meio.'},inv:{ro:'Suspendă azi o judecată despre un drum aflat la mijloc.',en:'Suspend one judgment today on a road still mid-way.',pt:'Suspende hoje um julgamento sobre um caminho a meio.'}},
  {el:'endx',kw:{ro:'Predarea ștafetei',en:'Passing the Baton',pt:'A Passagem do Testemunho'},t:{ro:'A ști să predai ștafeta e ultima probă a alergătorului bun. Cursa continuă; mâna care predă binecuvântează.',en:'Knowing how to pass the baton is the good runner’s final test. The race goes on; the passing hand blesses.',pt:'Saber passar o testemunho é a última prova do bom corredor. A corrida continua; a mão que entrega abençoa.'},inv:{ro:'Predă azi ceva mai departe: o sarcină, un rol, un secret de meserie.',en:'Pass something on today: a task, a role, a trade secret.',pt:'Passa hoje algo adiante: uma tarefa, um papel, um segredo do ofício.'}},
  {el:'endx',kw:{ro:'Sfârșitul zilei',en:'The Day’s End',pt:'O Fim do Dia'},t:{ro:'Exersează sfârșiturile mici: ziua încheiată împăcat e repetiția blândă pentru toate celelalte sfârșituri.',en:'Practice small endings: a day closed in peace is the gentle rehearsal for all other endings.',pt:'Pratica os fins pequenos: o dia fechado em paz é o ensaio suave para todos os outros fins.'},inv:{ro:'Repetă diseară: încheie ziua împăcat, orice-a fost.',en:'Rehearse tonight: end the day at peace, whatever it held.',pt:'Ensaia esta noite: fecha o dia em paz, tenha tido o que teve.'}},
  {el:'endx',kw:{ro:'Ce rămâne',en:'What Remains',pt:'O que Fica'},t:{ro:'Se sfârșesc banii, funcțiile, chiar puterile — nu se sfârșesc binele făcut, copiii crescuți, cuvintele bune spuse.',en:'Money ends, titles end, even strength — good done, children raised, kind words spoken do not end.',pt:'Acaba o dinheiro, os cargos, até as forças — não acaba o bem feito, os filhos criados, as boas palavras ditas.'},inv:{ro:'Investește azi o oră în ce nu se sfârșește.',en:'Invest one hour today in what does not end.',pt:'Investe hoje uma hora no que não acaba.'}},
  {el:'endx',kw:{ro:'Iertarea de dinainte de capăt',en:'Forgiveness Before the End',pt:'O Perdão Antes do Fim'},t:{ro:'Nu lăsa iertările pentru ultima zi; nimeni nu-și cunoaște ultima zi. Iartă cu calendarul deschis.',en:'Do not save forgivings for the last day; no one knows their last day. Forgive with the calendar open.',pt:'Não guardes os perdões para o último dia; ninguém conhece o seu último dia. Perdoa com o calendário aberto.'},inv:{ro:'Fă azi o iertare pe care o programaseși „cândva".',en:'Grant today a forgiveness you had scheduled for “someday.”',pt:'Concede hoje um perdão que tinhas marcado para «um dia».'}},
  {el:'endx',kw:{ro:'Golul de după',en:'The After-Void',pt:'O Vazio de Depois'},t:{ro:'După orice sfârșit vine un gol. Nu-l astupa în grabă: golul e pământul proaspăt arat al vieții următoare.',en:'After every ending comes a void. Do not fill it hastily: the void is the freshly plowed soil of the next life.',pt:'Depois de cada fim vem um vazio. Não o enchas à pressa: o vazio é a terra lavrada da vida seguinte.'},inv:{ro:'Stă un gol în viața ta? Lasă-l azi arat, nu astupat.',en:'Is there a void in your life? Leave it plowed today, not plugged.',pt:'Há um vazio na tua vida? Deixa-o hoje lavrado, não tapado.'}},
  {el:'endx',kw:{ro:'Testamentul zilnic',en:'The Daily Testament',pt:'O Testamento Diário'},t:{ro:'Trăiește-ți ziua astfel încât, dacă ar fi ultima, să nu fie penibilă — iar dacă nu e, să fie temelie.',en:'Live your day so that if it were the last it would not be shameful — and if it is not, it becomes foundation.',pt:'Vive o teu dia de modo que, se fosse o último, não fosse vergonhoso — e, se não for, seja alicerce.'},inv:{ro:'Trece-ți azi ziua prin dubla probă: ultimă sau temelie.',en:'Pass today through the double test: last or foundation.',pt:'Passa hoje o dia pelo duplo teste: último ou alicerce.'}},
  {el:'endx',kw:{ro:'Apusul ca artă',en:'Sunset as an Art',pt:'O Poente como Arte'},t:{ro:'Soarele apune vărsând aur, nu scuze. Învață de la el: pleacă dăruind, nu justificându-te.',en:'The sun sets pouring gold, not excuses. Learn from it: leave giving, not justifying.',pt:'O sol põe-se derramando ouro, não desculpas. Aprende com ele: parte dando, não te justificando.'},inv:{ro:'La orice plecare de azi, lasă aur: un mulțumesc, un bine.',en:'At every leaving today, pour gold: a thanks, a kindness.',pt:'Em cada partida de hoje, deixa ouro: um obrigado, um bem.'}},
  {el:'endx',kw:{ro:'Sfârșitul fricii de sfârșit',en:'The End of the Fear of Endings',pt:'O Fim do Medo do Fim'},t:{ro:'Cine s-a împăcat cu sfârșiturile trăiește de două ori mai viu: nu mai cheltuiește nimic pe frică.',en:'Whoever makes peace with endings lives twice as vividly: nothing is spent on fear anymore.',pt:'Quem fez as pazes com os fins vive duas vezes mais vivo: já nada gasta com o medo.'},inv:{ro:'Împrietenește-te azi cu un mic sfârșit: privește-l în față.',en:'Befriend one small ending today: look it in the face.',pt:'Faz hoje amizade com um pequeno fim: olha-o de frente.'}},
  {el:'endx',kw:{ro:'Cununa lucrului împlinit',en:'The Crown of Finished Work',pt:'A Coroa da Obra Cumprida'},t:{ro:'„Am terminat" spus cu mâna pe inimă e una dintre marile bucurii ale omului. Nu ți-o refuza amânând finalurile.',en:'“It is finished,” said hand on heart, is one of a person’s great joys. Do not deny it to yourself by postponing endings.',pt:'«Está terminado», dito com a mão no coração, é uma das grandes alegrias humanas. Não a negues a ti adiando os finais.'},inv:{ro:'Câștigă azi cununa: du un lucru până la „am terminat".',en:'Win the crown today: carry one thing to “it is finished.”',pt:'Ganha hoje a coroa: leva algo até ao «está terminado».'}},
  {el:'endx',kw:{ro:'Rândunica plecată',en:'The Departed Swallow',pt:'A Andorinha Partida'},t:{ro:'Rândunica nu-și ia adio de la cuib; știe că plecarea e parte din locuire. Pleacă și tu fără dramă unde e de plecat.',en:'The swallow takes no farewell of the nest; it knows leaving is part of dwelling. Leave without drama where leaving is due.',pt:'A andorinha não se despede do ninho; sabe que partir faz parte do habitar. Parte também tu sem drama de onde é preciso partir.'},inv:{ro:'De unde e vremea să pleci ușor? Fă azi un gest de plecare.',en:'Where is it time to leave lightly? Make one leaving gesture today.',pt:'De onde é tempo de partir leve? Faz hoje um gesto de partida.'}},
  {el:'endx',kw:{ro:'Focul de tabără stins',en:'The Doused Campfire',pt:'A Fogueira Apagada'},t:{ro:'Drumeții buni sting focul, strâng locul și-l lasă mai curat decât l-au găsit. Așa se pleacă de oriunde.',en:'Good travelers douse the fire, tidy the site and leave it cleaner than found. That is how to leave anywhere.',pt:'Os bons viajantes apagam o fogo, arrumam o lugar e deixam-no mais limpo do que o acharam. Assim se parte de qualquer lugar.'},inv:{ro:'Lasă azi orice loc — proiect, cameră, discuție — mai curat decât l-ai găsit.',en:'Leave every place today — project, room, talk — cleaner than found.',pt:'Deixa hoje cada lugar — projeto, sala, conversa — mais limpo do que o achaste.'}},
  {el:'endx',kw:{ro:'Numărătoarea de la capăt',en:'Counting from the End',pt:'A Contagem a Partir do Fim'},t:{ro:'Numără-ți verile rămase cu părinții, cu copiii mici, cu prietenii dragi. Numărul mic nu întristează; trezește.',en:'Count the summers left with parents, with small children, with dear friends. The small number does not sadden; it awakens.',pt:'Conta os verões que restam com os pais, com os filhos pequenos, com os amigos queridos. O número pequeno não entristece; desperta.'},inv:{ro:'Fă azi socoteala trează — și sună pe cineva din listă.',en:'Do the waking arithmetic today — and call someone on the list.',pt:'Faz hoje a conta desperta — e liga a alguém da lista.'}},
  {el:'endx',kw:{ro:'Ultimul cuvânt bun',en:'The Last Kind Word',pt:'A Última Palavra Boa'},t:{ro:'Desparte-te de fiecare om ca și cum vorbele acelea ar putea rămâne ultimele. Așa nu vei regreta nicio despărțire.',en:'Part from each person as if those words might remain the last. Thus no parting will be regretted.',pt:'Despede-te de cada pessoa como se aquelas palavras pudessem ficar as últimas. Assim nenhuma despedida trará remorso.'},inv:{ro:'Încheie azi fiecare conversație cu un cuvânt care poate rămâne.',en:'End each conversation today with a word fit to remain.',pt:'Termina hoje cada conversa com uma palavra digna de ficar.'}},
  {el:'endx',kw:{ro:'Semințele din fructul copt',en:'The Seeds in the Ripe Fruit',pt:'As Sementes do Fruto Maduro'},t:{ro:'Fructul se sfârșește; semințele lui abia încep. Orice final rodnic poartă în el începuturi cu duiumul.',en:'The fruit ends; its seeds only begin. Every fruitful ending carries beginnings in plenty.',pt:'O fruto acaba; as suas sementes apenas começam. Todo o fim fecundo traz começos em abundância.'},inv:{ro:'Dintr-un final al tău, numără azi semințele: ce începe din el?',en:'From one of your endings, count the seeds today: what begins from it?',pt:'De um fim teu, conta hoje as sementes: o que começa dele?'}},
  {el:'endx',kw:{ro:'Pacea cu ce n-a fost',en:'Peace with What Was Not',pt:'A Paz com o que Não Foi'},t:{ro:'Unele vieți posibile nu s-au întâmplat. Fă pace cu ele: n-au fost drumuri pierdute, ci drumuri nealese de un om întreg.',en:'Some possible lives did not happen. Make peace with them: not lost roads, but roads unchosen by a whole person.',pt:'Algumas vidas possíveis não aconteceram. Faz as pazes com elas: não foram caminhos perdidos, mas caminhos não escolhidos por uma pessoa inteira.'},inv:{ro:'Ia-ți azi rămas-bun de la o viață posibilă — cu respect, fără regret.',en:'Bid farewell today to one possible life — with respect, without regret.',pt:'Despede-te hoje de uma vida possível — com respeito, sem remorso.'}},
  {el:'endx',kw:{ro:'Cartea închisă a zilei',en:'The Day’s Closed Book',pt:'O Livro Fechado do Dia'},t:{ro:'La miezul nopții, ziua devine carte închisă: nu mai poți scrie în ea, poți doar învăța din ea. Nu o mai rescrie în gol.',en:'At midnight the day becomes a closed book: you can write in it no more, only learn from it. Stop rewriting it in vain.',pt:'À meia-noite o dia torna-se livro fechado: já não podes escrever nele, só aprender dele. Pára de o reescrever em vão.'},inv:{ro:'Nu rescrie diseară ziua; extrage lecția și pune cartea pe raft.',en:'Do not rewrite the day tonight; take the lesson and shelve the book.',pt:'Não reescrevas o dia esta noite; tira a lição e arruma o livro.'}},
  {el:'endx',kw:{ro:'Hotarul dintre ani',en:'The Border Between Years',pt:'A Fronteira Entre Anos'},t:{ro:'Nu-ți trebuie Revelion ca să închei un an lăuntric. Poți pune hotar oricând: „până aici — de aici".',en:'You need no New Year’s Eve to close an inner year. You may set the border anytime: “this far — from here on.”',pt:'Não precisas de passagem de ano para fechar um ano interior. Podes pôr a fronteira quando quiseres: «até aqui — daqui em diante».'},inv:{ro:'Pune azi un hotar: încheie un „an lăuntric" și deschide altul.',en:'Set a border today: close one inner year and open another.',pt:'Põe hoje uma fronteira: fecha um ano interior e abre outro.'}},
  {el:'endx',kw:{ro:'Grația deznodământului',en:'The Grace of the Denouement',pt:'A Graça do Desenlace'},t:{ro:'În povești, nodul se desface la sfârșit. Ai răbdare cu intriga vieții tale: unele noduri se desfac doar în ultimul act.',en:'In stories, the knot unties at the end. Be patient with your life’s plot: some knots untie only in the final act.',pt:'Nas histórias, o nó desata-se no fim. Tem paciência com o enredo da tua vida: alguns nós só se desatam no último ato.'},inv:{ro:'Poartă azi cu răbdare un nod nedesfăcut încă.',en:'Carry one still-tied knot patiently today.',pt:'Leva hoje com paciência um nó ainda por desatar.'}},
  {el:'endx',kw:{ro:'Odihna de după săvârșire',en:'The Rest After Completion',pt:'O Descanso Depois da Obra'},t:{ro:'După lucrul săvârșit vine odihna care nu mai trebuie justificată. E cea mai dulce dintre toate odihnele.',en:'After completed work comes the rest that needs no justification. The sweetest of all rests.',pt:'Depois da obra cumprida vem o descanso que já não precisa de justificação. O mais doce de todos os descansos.'},inv:{ro:'Termină azi ceva — apoi odihnește-te fără vină.',en:'Finish something today — then rest without guilt.',pt:'Termina hoje algo — depois descansa sem culpa.'}},
  {el:'endx',kw:{ro:'Steaua căzătoare',en:'The Falling Star',pt:'A Estrela Cadente'},t:{ro:'Steaua care cade nu moare; ne dăruiește o dorință. Fă și tu din căderile tale daruri pentru cei care privesc.',en:'The falling star does not die; it gifts us a wish. Make your own falls into gifts for those who watch.',pt:'A estrela que cai não morre; oferece-nos um desejo. Faz também das tuas quedas dons para quem observa.'},inv:{ro:'Transformă azi o cădere a ta în dar: povestește-i lecția cuiva.',en:'Turn one of your falls into a gift today: tell someone its lesson.',pt:'Transforma hoje uma queda tua em dom: conta a alguém a sua lição.'}},
  {el:'endx',kw:{ro:'Amenul mic',en:'The Small Amen',pt:'O Pequeno Ámen'},t:{ro:'„Așa să fie" spus peste ce nu se mai poate schimba e cheia care descuie restul vieții. Amin nu e resemnare; e eliberare.',en:'“So be it,” said over what cannot change, is the key that unlocks the rest of life. Amen is not resignation; it is release.',pt:'«Assim seja», dito sobre o que já não muda, é a chave que abre o resto da vida. Ámen não é resignação; é libertação.'},inv:{ro:'Spune azi un „așa să fie" peste un lucru neschimbabil.',en:'Say one “so be it” today over an unchangeable thing.',pt:'Diz hoje um «assim seja» sobre algo imutável.'}},
  {el:'endx',kw:{ro:'Ultima carte din cerc',en:'The Circle’s Last Card',pt:'A Última Carta do Círculo'},t:{ro:'Orice sfârșit adevărat se închide ca un cerc: exact acolo unde a început, dar cu un om mai înalt înăuntru.',en:'Every true ending closes like a circle: exactly where it began, but with a taller person inside.',pt:'Todo o fim verdadeiro fecha-se como um círculo: exatamente onde começou, mas com uma pessoa mais alta dentro.'},inv:{ro:'Măsoară azi: cu ce ești mai înalt decât la începutul unui drum încheiat?',en:'Measure today: how are you taller than at a finished road’s start?',pt:'Mede hoje: em que és mais alto do que no início de um caminho terminado?'}},
  {el:'endx',kw:{ro:'Binecuvântarea sfârșitului',en:'The Blessing of the End',pt:'A Bênção do Fim'},t:{ro:'Mulțumește sfârșiturilor: ele fac loc, ele coc, ele predau. Fără ele, nimic nu s-ar termina — deci nimic n-ar rodi.',en:'Thank the endings: they clear room, they ripen, they hand over. Without them nothing would finish — so nothing would bear fruit.',pt:'Agradece aos fins: eles abrem espaço, amadurecem, entregam. Sem eles nada terminaria — logo nada daria fruto.'},inv:{ro:'Binecuvântează azi un sfârșit care ți-a făcut loc.',en:'Bless one ending today that made room for you.',pt:'Abençoa hoje um fim que te abriu espaço.'}},

  {el:'endx',kw:{ro:'Recunoștința de la capăt',en:'Gratitude at the End',pt:'A Gratidão no Fim'},t:{ro:'La capătul oricărui lucru bun, ultima vorbă cea mai potrivită nu e „ce păcat că s-a terminat", ci „ce bine că a fost".',en:'At the end of anything good, the fittest last word is not “what a pity it ended,” but “how good that it was.”',pt:'No fim de qualquer coisa boa, a última palavra mais certa não é «que pena que acabou», mas «que bom que foi».'},inv:{ro:'Pentru un lucru bun încheiat, spune azi: „ce bine că a fost".',en:'For one good thing ended, say today: “how good that it was.”',pt:'Por uma coisa boa terminada, diz hoje: «que bom que foi».'}},

  /* ———————— CERCUL JOCULUI ———————— */
  {el:'play',kw:{ro:'Joaca serioasă',en:'Earnest Play',pt:'O Brincar a Sério'},t:{ro:'Omul e întreg doar acolo unde se joacă. În joc, mintea, inima și mâinile cântă în sfârșit împreună.',en:'A person is whole only where they play. In play, mind, heart and hands at last sing together.',pt:'A pessoa é inteira só onde brinca. No jogo, mente, coração e mãos cantam finalmente juntos.'},inv:{ro:'Joacă-te azi zece minute cu totul, fără scop.',en:'Play wholly for ten minutes today, purposeless.',pt:'Brinca hoje dez minutos por inteiro, sem objetivo.'}},
  {el:'play',kw:{ro:'Regulile jocului',en:'The Rules of the Game',pt:'As Regras do Jogo'},t:{ro:'Jocul fără reguli se destramă; regulile fără joc mor de plictis. Viața bună le ține pe amândouă de mână.',en:'A game without rules unravels; rules without play die of boredom. A good life holds both by the hand.',pt:'O jogo sem regras desfaz-se; as regras sem jogo morrem de tédio. A boa vida segura ambos pela mão.'},inv:{ro:'Adaugă azi joc într-o regulă și o regulă într-un joc.',en:'Add play to a rule today, and a rule to a play.',pt:'Acrescenta hoje jogo a uma regra e uma regra a um jogo.'}},
  {el:'play',kw:{ro:'Pierdutul frumos',en:'Losing Beautifully',pt:'Perder com Beleza'},t:{ro:'Cine știe pierde frumos câștigă ceva mai rar decât victoria: libertatea de a juca mereu.',en:'Whoever loses beautifully wins something rarer than victory: the freedom to always play.',pt:'Quem sabe perder com beleza ganha algo mais raro que a vitória: a liberdade de jogar sempre.'},inv:{ro:'Pierde azi ceva cu zâmbet întreg: un joc, o dispută măruntă.',en:'Lose something with a whole smile today: a game, a petty dispute.',pt:'Perde hoje algo com um sorriso inteiro: um jogo, uma disputa miúda.'}},
  {el:'play',kw:{ro:'Râsul din burtă',en:'The Belly Laugh',pt:'A Gargalhada'},t:{ro:'Râsul adevărat pornește din burtă și face curat prin tot omul. E scuturatul covoarelor sufletului.',en:'True laughter starts in the belly and cleans through the whole person. It is the beating of the soul’s carpets.',pt:'O riso verdadeiro parte da barriga e limpa a pessoa inteira. É o sacudir dos tapetes da alma.'},inv:{ro:'Caută azi un râs din burtă — și nu-l opri.',en:'Seek one belly laugh today — and do not stop it.',pt:'Procura hoje uma gargalhada — e não a pares.'}},
  {el:'play',kw:{ro:'Jocul cu copilul',en:'Playing with the Child',pt:'Brincar com a Criança'},t:{ro:'Când te joci cu un copil pe bune, nu-i faci lui un dar: îți deschide el ție poarta spre țara de unde ai plecat.',en:'When you truly play with a child, the gift is not yours to give: they open for you the gate to the land you left.',pt:'Quando brincas de verdade com uma criança, o presente não és tu que o dás: ela abre-te a porta para a terra de onde partiste.'},inv:{ro:'Joacă-te azi pe bune cu un copil — pe regulile lui.',en:'Play truly with a child today — by their rules.',pt:'Brinca hoje de verdade com uma criança — pelas regras dela.'}},
  {el:'play',kw:{ro:'Gluma bună',en:'The Kind Joke',pt:'A Piada Boa'},t:{ro:'Gluma bună râde împreună cu omul; cea rea râde de el. Prima leagă, a doua taie. Alege-ți uneltele.',en:'A kind joke laughs with a person; a cruel one laughs at them. The first binds, the second cuts. Choose your tools.',pt:'A piada boa ri com a pessoa; a má ri dela. A primeira une, a segunda corta. Escolhe as tuas ferramentas.'},inv:{ro:'Fă azi o glumă care leagă, niciuna care taie.',en:'Make one binding joke today, none that cut.',pt:'Faz hoje uma piada que une, nenhuma que corte.'}},
  {el:'play',kw:{ro:'Terenul de joacă al minții',en:'The Mind’s Playground',pt:'O Recreio da Mente'},t:{ro:'Ideile mari se nasc rar la birou și des la joacă: în duș, pe drum, în glumă. Dă minții recreație și îți va da recolte.',en:'Great ideas are rarely born at the desk and often at play: in the shower, on the road, in jest. Give the mind recess and it gives you harvests.',pt:'As grandes ideias raramente nascem à secretária e muitas vezes no brincar: no duche, no caminho, na graça. Dá recreio à mente e ela dá-te colheitas.'},inv:{ro:'Dă azi minții o recreație adevărată — fără vină.',en:'Give the mind a true recess today — guilt-free.',pt:'Dá hoje à mente um recreio verdadeiro — sem culpa.'}},
  {el:'play',kw:{ro:'Dansul',en:'The Dance',pt:'A Dança'},t:{ro:'Dansul e trupul care își aduce aminte că nu e doar unealtă. Nu trebuie să știi să dansezi; trebuie doar să-l lași.',en:'Dance is the body remembering it is not merely a tool. You need not know how; you need only let it.',pt:'A dança é o corpo a lembrar-se de que não é só ferramenta. Não precisas de saber dançar; só de deixar.'},inv:{ro:'Lasă azi trupul să danseze un cântec întreg, fără martori dacă vrei.',en:'Let the body dance one whole song today, witness-free if you wish.',pt:'Deixa hoje o corpo dançar uma canção inteira, sem testemunhas se quiseres.'}},
  {el:'play',kw:{ro:'Jocul cu greutățile',en:'Playing with Burdens',pt:'Brincar com os Fardos'},t:{ro:'Unele poveri se duc mai ușor jucându-te cu ele: pune-le nume caraghioase, dă-le puncte, fă-le nivel de joc.',en:'Some burdens carry easier when played with: give them silly names, score them, make them game levels.',pt:'Alguns fardos carregam-se melhor a brincar: dá-lhes nomes tolos, pontua-os, faz deles níveis de jogo.'},inv:{ro:'Preface azi o corvoadă în joc: puncte, cronometru, miză mică.',en:'Turn one chore into a game today: points, timer, small stakes.',pt:'Transforma hoje uma tarefa num jogo: pontos, cronómetro, aposta pequena.'}},
  {el:'play',kw:{ro:'Seriozitatea care ucide',en:'The Deadly Seriousness',pt:'A Seriedade que Mata'},t:{ro:'Ferește-te de omul care nu râde niciodată de sine — și mai ales ferește-te să devii el.',en:'Beware the person who never laughs at themselves — and above all beware becoming them.',pt:'Cuidado com quem nunca ri de si mesmo — e sobretudo cuidado para não te tornares essa pessoa.'},inv:{ro:'Râzi azi o dată, cu drag, de propria persoană.',en:'Laugh once today, fondly, at yourself.',pt:'Ri hoje uma vez, com carinho, de ti próprio.'}},
  {el:'play',kw:{ro:'Jocul de unul singur',en:'Solitary Play',pt:'O Jogo Solitário'},t:{ro:'Fluieratul, desenatul pe marginea foii, aruncatul pietrei pe apă: micile jocuri de unul singur țin sufletul uns.',en:'Whistling, doodling in margins, skipping stones: the small solitary games keep the soul oiled.',pt:'Assobiar, rabiscar nas margens, fazer ricochetes na água: os pequenos jogos solitários mantêm a alma lubrificada.'},inv:{ro:'Unge azi sufletul: un mic joc de unul singur.',en:'Oil the soul today: one small solitary game.',pt:'Lubrifica hoje a alma: um pequeno jogo solitário.'}},
  {el:'play',kw:{ro:'Concursul cu tine',en:'The Contest with Yourself',pt:'O Concurso Contigo'},t:{ro:'Singura întrecere fără învinși: tu de azi contra tu de ieri. Premiul se ridică zilnic, la orice oră.',en:'The only contest without losers: today’s you against yesterday’s. The prize is collected daily, at any hour.',pt:'A única competição sem vencidos: o tu de hoje contra o de ontem. O prémio levanta-se todos os dias, a qualquer hora.'},inv:{ro:'Bate-l azi pe cel de ieri la un singur capitol.',en:'Beat yesterday’s you in a single chapter today.',pt:'Vence hoje o teu eu de ontem num único capítulo.'}},
  {el:'play',kw:{ro:'Jucăria stricată',en:'The Broken Toy',pt:'O Brinquedo Partido'},t:{ro:'Copilul plânge jucăria stricată, apoi inventează alt joc. Planul stricat nu e sfârșitul jocului; e invitație la alt joc.',en:'The child weeps for the broken toy, then invents another game. A broken plan is not the end of play; it invites another game.',pt:'A criança chora o brinquedo partido e depois inventa outro jogo. O plano desfeito não é o fim do jogo; convida a outro jogo.'},inv:{ro:'Dintr-un plan stricat, inventează azi alt joc.',en:'From a broken plan, invent another game today.',pt:'De um plano desfeito, inventa hoje outro jogo.'}},
  {el:'play',kw:{ro:'Gratuitatea',en:'Gratuitousness',pt:'A Gratuitidade'},t:{ro:'Jocul nu produce nimic și tocmai de aceea produce omul. Ce faci fără folos te face pe tine.',en:'Play produces nothing, and precisely thus it produces the person. What you do without profit makes you.',pt:'O jogo não produz nada e justamente por isso produz a pessoa. O que fazes sem proveito faz-te a ti.'},inv:{ro:'Fă azi ceva complet nefolositor și complet frumos.',en:'Do something wholly useless and wholly beautiful today.',pt:'Faz hoje algo completamente inútil e completamente belo.'}},
  {el:'play',kw:{ro:'Uitatul de sine',en:'Self-Forgetting',pt:'O Esquecer-se de Si'},t:{ro:'În jocul adevărat te uiți pe tine — și exact atunci ești cel mai tu. Paradoxul acesta e o poartă.',en:'In true play you forget yourself — and exactly then you are most yourself. This paradox is a gate.',pt:'No jogo verdadeiro esqueces-te de ti — e exatamente então és mais tu. Este paradoxo é uma porta.'},inv:{ro:'Caută azi activitatea în care te uiți pe tine. Intră în ea.',en:'Find the activity where you forget yourself today. Enter it.',pt:'Procura hoje a atividade em que te esqueces de ti. Entra nela.'}},
  {el:'play',kw:{ro:'Mingea întoarsă',en:'The Returned Ball',pt:'A Bola Devolvida'},t:{ro:'Conversația bună e un joc cu mingea: o primești, o întorci frumos, o lași și pe ea să zboare. Nu o ține; nu o îngropa.',en:'Good conversation is a ball game: receive it, return it well, let it fly too. Do not hold it; do not bury it.',pt:'A boa conversa é um jogo de bola: recebe-a, devolve-a bem, deixa-a também voar. Não a seguras; não a enterres.'},inv:{ro:'Joacă azi frumos cu mingea vorbirii: întreabă și înapoiază.',en:'Play the talking ball well today: ask and return.',pt:'Joga hoje bem a bola da conversa: pergunta e devolve.'}},
  {el:'play',kw:{ro:'Costumul de sărbătoare',en:'The Festive Costume',pt:'O Traje de Festa'},t:{ro:'Din când în când, viața cere costum de joc: o pălărie caraghioasă, un dans în bucătărie, o cină tematică. Cine se costumează se reînnoiește.',en:'Now and then life calls for play-costume: a silly hat, a kitchen dance, a themed dinner. Who dresses up renews themselves.',pt:'De vez em quando a vida pede traje de jogo: um chapéu tolo, uma dança na cozinha, um jantar temático. Quem se fantasia renova-se.'},inv:{ro:'Pune azi o notă de costum în banal: orice mic „parcă am fi".',en:'Add a costume note to the ordinary today: any small “let’s pretend.”',pt:'Põe hoje uma nota de fantasia no banal: qualquer pequeno «faz de conta».'}},
  {el:'play',kw:{ro:'Norocul începătorului',en:'Beginner’s Luck',pt:'A Sorte do Principiante'},t:{ro:'Norocul începătorului există: e libertatea celui care nu știe încă de ce nu se poate. Păstrează neștiința aceasta.',en:'Beginner’s luck exists: it is the freedom of one who does not yet know why it cannot be done. Keep that unknowing.',pt:'A sorte do principiante existe: é a liberdade de quem ainda não sabe porque não se pode. Guarda esse não-saber.'},inv:{ro:'Joacă azi ceva ca un începător norocos: fără „nu se poate".',en:'Play something today like a lucky beginner: no “it can’t be done.”',pt:'Joga hoje algo como principiante sortudo: sem «não dá».'}},
  {el:'play',kw:{ro:'Pauza de joacă',en:'Recess',pt:'O Recreio'},t:{ro:'Școala a știut ceva ce biroul a uitat: la fiecare cincizeci de minute, sufletul cere curte și clopoțel.',en:'School knew what the office forgot: every fifty minutes, the soul asks for a yard and a bell.',pt:'A escola sabia o que o escritório esqueceu: a cada cinquenta minutos, a alma pede pátio e campainha.'},inv:{ro:'Sună azi clopoțelul: pauze mici de joacă între orele de muncă.',en:'Ring the bell today: small recesses between work hours.',pt:'Toca hoje a campainha: pequenos recreios entre as horas de trabalho.'}},
  {el:'play',kw:{ro:'Jocul vieții lungi',en:'The Long Game',pt:'O Jogo Longo'},t:{ro:'Joacă jocul lung: acolo răbdarea bate viteza, caracterul bate șmecheria și binele făcut se întoarce cu prieteni.',en:'Play the long game: there patience beats speed, character beats cunning, and good done returns with friends.',pt:'Joga o jogo longo: aí a paciência vence a velocidade, o caráter vence a manha e o bem feito volta com amigos.'},inv:{ro:'Alege azi mutarea bună pe termen lung, nu pe azi.',en:'Choose today the move good for the long term, not for today.',pt:'Escolhe hoje a jogada boa a longo prazo, não para hoje.'}},
  {el:'play',kw:{ro:'Zâmbetul de start',en:'The Starting Smile',pt:'O Sorriso de Partida'},t:{ro:'Începe orice treabă cu un zâmbet scurt, ca un start de joc. Trupul crede fața și se pregătește de bucurie.',en:'Begin any task with a brief smile, like a game’s start. The body believes the face and readies for joy.',pt:'Começa qualquer tarefa com um sorriso breve, como início de jogo. O corpo acredita no rosto e prepara-se para a alegria.'},inv:{ro:'Pornește azi trei treburi cu zâmbet de start.',en:'Start three tasks today with the starting smile.',pt:'Começa hoje três tarefas com o sorriso de partida.'}},
  {el:'play',kw:{ro:'Jocul cu vremea rea',en:'Playing with Bad Weather',pt:'Brincar com o Mau Tempo'},t:{ro:'Copiii nu anulează copilăria pe ploaie; mută jocul înăuntru. Mută și tu bucuria înăuntru când afară e furtună.',en:'Children do not cancel childhood in the rain; they move the game indoors. Move your joy indoors when it storms outside.',pt:'As crianças não cancelam a infância à chuva; mudam o jogo para dentro. Muda também a alegria para dentro quando lá fora há tempestade.'},inv:{ro:'E „vreme rea" în viața ta? Mută azi un joc înăuntru.',en:'Is there “bad weather” in your life? Move one game indoors today.',pt:'Há «mau tempo» na tua vida? Muda hoje um jogo para dentro.'}},
  {el:'play',kw:{ro:'Cutia cu jocuri veche',en:'The Old Game Box',pt:'A Caixa de Jogos Antiga'},t:{ro:'Ce joc iubeai la zece ani? El știe încă ceva despre tine ce ai uitat. Deschide cutia din când în când.',en:'What game did you love at ten? It still knows something about you that you forgot. Open the box now and then.',pt:'Que jogo amavas aos dez anos? Ele ainda sabe algo de ti que esqueceste. Abre a caixa de vez em quando.'},inv:{ro:'Redeschide săptămâna asta un joc al copilăriei tale.',en:'Reopen a childhood game of yours this week.',pt:'Reabre esta semana um jogo da tua infância.'}},
  {el:'play',kw:{ro:'Publicul care nu există',en:'The Audience that Is Not There',pt:'O Público que Não Existe'},t:{ro:'Jucăm mult teatru pentru un public care de fapt nu se uită. Ieși din piesă: lumea e mai puțin atentă și mai blândă decât crezi.',en:'We act much for an audience that is not actually watching. Leave the play: the world is less attentive and kinder than you think.',pt:'Representamos muito para um público que na verdade não olha. Sai da peça: o mundo é menos atento e mais bondoso do que pensas.'},inv:{ro:'Fă azi un lucru „penibil" și vezi că nu se uita nimeni.',en:'Do one “embarrassing” thing today and see no one was watching.',pt:'Faz hoje algo «embaraçoso» e vê que ninguém olhava.'}},
  {el:'play',kw:{ro:'Mize mici, inimă mare',en:'Small Stakes, Big Heart',pt:'Apostas Pequenas, Coração Grande'},t:{ro:'Joacă-te cu mize mici și inima toată: așa înveți curajul fără să-l plătești scump.',en:'Play with small stakes and your whole heart: thus courage is learned without paying dearly.',pt:'Joga com apostas pequenas e o coração todo: assim se aprende a coragem sem a pagar caro.'},inv:{ro:'Riscă azi ceva mic cu toată inima.',en:'Risk something small wholeheartedly today.',pt:'Arrisca hoje algo pequeno de todo o coração.'}},
  {el:'play',kw:{ro:'Festivalul mărunt',en:'The Small Festival',pt:'A Festa Miúda'},t:{ro:'Nu aștepta ocaziile mari: fă din vineri seara un festival, din cafeaua de duminică un ritual, din orice masă o mică nuntă.',en:'Do not wait for grand occasions: make Friday night a festival, Sunday coffee a ritual, any meal a small wedding.',pt:'Não esperes as grandes ocasiões: faz da sexta à noite um festival, do café de domingo um ritual, de qualquer refeição um pequeno casamento.'},inv:{ro:'Ridică azi o masă obișnuită la rang de sărbătoare.',en:'Raise one ordinary meal to feast rank today.',pt:'Eleva hoje uma refeição comum a categoria de festa.'}},
  {el:'play',kw:{ro:'Hazul de necaz',en:'Laughing at Trouble',pt:'Rir da Desgraça'},t:{ro:'Hazul de necaz nu neagă necazul; îi taie doar dreptul de a conduce. Cine mai poate râde mai poate lupta.',en:'Laughing at trouble does not deny it; it only strips its right to rule. Who can still laugh can still fight.',pt:'Rir da desgraça não a nega; só lhe tira o direito de mandar. Quem ainda ri ainda luta.'},inv:{ro:'Găsește azi hazul dintr-un necaz mărunt.',en:'Find the humor in one small trouble today.',pt:'Encontra hoje a graça numa pequena contrariedade.'}},
  {el:'play',kw:{ro:'Jocul curat',en:'Fair Play',pt:'O Jogo Limpo'},t:{ro:'Poți câștiga murdar o partidă, dar pierzi jocul cel mare: încrederea celor cu care mai ai de jucat o viață.',en:'You may win one match dirty, but you lose the great game: the trust of those you must play with for a lifetime.',pt:'Podes ganhar sujo uma partida, mas perdes o grande jogo: a confiança de quem ainda jogará contigo uma vida.'},inv:{ro:'Joacă azi curat și unde nu te vede arbitrul.',en:'Play fair today even where no referee watches.',pt:'Joga limpo hoje mesmo onde o árbitro não vê.'}},
  {el:'play',kw:{ro:'Bucuria altora la joc',en:'Others’ Joy in the Game',pt:'A Alegria dos Outros no Jogo'},t:{ro:'Jocul cel mai bun e cel din care toți pleacă mai bucuroși. Aranjează jocurile vieții tale după regula asta.',en:'The best game is the one everyone leaves happier from. Arrange your life’s games by this rule.',pt:'O melhor jogo é aquele de que todos saem mais felizes. Organiza os jogos da tua vida por essa regra.'},inv:{ro:'Fă azi un joc din care toți ies câștigați.',en:'Make one game today where everyone wins.',pt:'Faz hoje um jogo em que todos ganham.'}},
  {el:'play',kw:{ro:'Instrumentul de suflet',en:'The Soul’s Instrument',pt:'O Instrumento da Alma'},t:{ro:'Fiecare om are un joc-instrument la care sufletul lui sună întreg: pescuitul, șahul, grădina, chitara. Al tău care e?',en:'Everyone has one instrument-game where their soul sounds whole: fishing, chess, the garden, the guitar. Which is yours?',pt:'Cada pessoa tem um jogo-instrumento onde a alma soa inteira: a pesca, o xadrez, o jardim, a guitarra. Qual é o teu?'},inv:{ro:'Cântă azi la instrumentul tău de suflet, măcar puțin.',en:'Play your soul’s instrument today, at least a little.',pt:'Toca hoje o teu instrumento da alma, ao menos um pouco.'}},
  {el:'play',kw:{ro:'Jocul de-a v-ați ascunselea cu bucuria',en:'Hide-and-Seek with Joy',pt:'As Escondidas com a Alegria'},t:{ro:'Bucuria se ascunde în locuri banale și așteaptă să fie găsită. Regula ei e una singură: caut-o zilnic.',en:'Joy hides in ordinary places and waits to be found. Its single rule: seek it daily.',pt:'A alegria esconde-se em lugares banais e espera ser achada. A sua única regra: procura-a todos os dias.'},inv:{ro:'Găsește azi bucuria ascunsă în trei locuri banale.',en:'Find joy hidden in three ordinary places today.',pt:'Encontra hoje a alegria escondida em três lugares banais.'}},
  {el:'play',kw:{ro:'Sfârșitul jocului bun',en:'The Good Game’s End',pt:'O Fim do Bom Jogo'},t:{ro:'La sfârșitul unui joc bun nu întrebi cine a câștigat; întrebi când mai jucăm. Așa să-ți fie și zilele.',en:'At a good game’s end you do not ask who won; you ask when we play again. May your days be likewise.',pt:'No fim de um bom jogo não perguntas quem ganhou; perguntas quando jogamos de novo. Assim sejam os teus dias.'},inv:{ro:'Încheie azi ziua ca un joc bun: „când mai jucăm?"',en:'End today like a good game: “when do we play again?”',pt:'Termina hoje o dia como um bom jogo: «quando jogamos de novo?»'}},
  {el:'play',kw:{ro:'Binecuvântarea jocului',en:'The Blessing of Play',pt:'A Bênção do Jogo'},t:{ro:'Ferice de cel care nu și-a pierdut jocul: el are în buzunar cheia de rezervă de la toate zilele grele.',en:'Blessed is the one who has not lost their play: they carry the spare key to every hard day.',pt:'Bem-aventurado quem não perdeu o seu brincar: traz no bolso a chave suplente de todos os dias difíceis.'},inv:{ro:'Pune azi cheia în buzunar: apără-ți un sfert de oră de joacă.',en:'Pocket the key today: defend one quarter hour of play.',pt:'Guarda hoje a chave no bolso: defende um quarto de hora de brincadeira.'}},

  /* ———————— CERCUL RECOLTEI ———————— */
  {el:'harvest',kw:{ro:'Secerișul cinstit',en:'The Honest Harvest',pt:'A Colheita Honesta'},t:{ro:'Culegi ce ai semănat, înmulțit. Legea aceasta nu se lasă păcălită de scuze — dar nici nu uită vreun bob semănat.',en:'You reap what you sowed, multiplied. This law is not fooled by excuses — nor does it forget one sown grain.',pt:'Colhes o que semeaste, multiplicado. Esta lei não se engana com desculpas — nem esquece um grão semeado.'},inv:{ro:'Seamănă azi conștient: fiecare gest e un bob.',en:'Sow consciously today: every gesture is a grain.',pt:'Semeia hoje com consciência: cada gesto é um grão.'}},
  {el:'harvest',kw:{ro:'Rodul târziu',en:'The Late Fruit',pt:'O Fruto Tardio'},t:{ro:'Unele semințe răsar la zece ani după semănat: o vorbă spusă unui copil, un bine uitat de tine. Nimic bun nu se pierde.',en:'Some seeds sprout ten years after sowing: a word said to a child, a kindness you forgot. Nothing good is lost.',pt:'Algumas sementes brotam dez anos depois: uma palavra dita a uma criança, um bem que esqueceste. Nada de bom se perde.'},inv:{ro:'Seamănă azi ceva ce nu vei vedea răsărind curând.',en:'Sow today something you will not soon see sprout.',pt:'Semeia hoje algo que não verás brotar tão cedo.'}},
  {el:'harvest',kw:{ro:'Hambarul recunoștinței',en:'The Barn of Gratitude',pt:'O Celeiro da Gratidão'},t:{ro:'Recolta nedusă în hambar putrezește pe câmp. Bucuriile nemulțumite se pierd la fel: strânge-le seara în hambar.',en:'Harvest not brought to the barn rots in the field. Unthanked joys are lost the same: gather them into the barn each evening.',pt:'A colheita não levada ao celeiro apodrece no campo. As alegrias não agradecidas perdem-se igual: recolhe-as ao celeiro cada noite.'},inv:{ro:'Umple diseară hambarul: trei mulțumiri pentru azi.',en:'Fill the barn tonight: three thanks for today.',pt:'Enche esta noite o celeiro: três agradecimentos por hoje.'}},
  {el:'harvest',kw:{ro:'Pârga',en:'The First Fruits',pt:'As Primícias'},t:{ro:'Din orice câștig, pune deoparte întâi partea binelui: pentru un om, o cauză, un mulțumesc. Pârga sfințește restul.',en:'From any gain, first set aside the good’s share: for a person, a cause, a thanks. The first fruits hallow the rest.',pt:'De qualquer ganho, separa primeiro a parte do bem: para uma pessoa, uma causa, um obrigado. As primícias santificam o resto.'},inv:{ro:'Din următorul câștig, dă întâi pârga. Hotărăște azi cui.',en:'From your next gain, give the first fruits first. Decide today to whom.',pt:'Do próximo ganho, dá primeiro as primícias. Decide hoje a quem.'}},
  {el:'harvest',kw:{ro:'Roadele altora în tine',en:'Others’ Fruits in You',pt:'Os Frutos dos Outros em Ti'},t:{ro:'Tot ce știi a fost semănat de cineva: părinți, dascăli, străini de-o clipă. Ești recolta multor grădinari. Fii una bună.',en:'All you know was sown by someone: parents, teachers, strangers of a moment. You are the harvest of many gardeners. Be a good one.',pt:'Tudo o que sabes foi semeado por alguém: pais, mestres, estranhos de um instante. És a colheita de muitos jardineiros. Sê uma boa.'},inv:{ro:'Mulțumește azi unui „grădinar" al tău, cu numele lui.',en:'Thank one of your “gardeners” today, by name.',pt:'Agradece hoje a um dos teus «jardineiros», pelo nome.'}},
  {el:'harvest',kw:{ro:'Câmpul vecinului',en:'The Neighbor’s Field',pt:'O Campo do Vizinho'},t:{ro:'Nu-ți irosi vara cântărind recolta vecinului. Fiecare câmp are pământul, ploaia și povestea lui.',en:'Do not waste your summer weighing the neighbor’s harvest. Each field has its own soil, rain and story.',pt:'Não gastes o verão a pesar a colheita do vizinho. Cada campo tem a sua terra, a sua chuva e a sua história.'},inv:{ro:'Azi: ochii pe brazda ta, nu pe cântarul altuia.',en:'Today: eyes on your furrow, not on another’s scale.',pt:'Hoje: olhos no teu rego, não na balança alheia.'}},
  {el:'harvest',kw:{ro:'Anul slab',en:'The Lean Year',pt:'O Ano Magro'},t:{ro:'Vin și ani slabi la orice gospodărie. Nu ești blestemat; ești agricultor. Pregătește pământul pentru anul care vine.',en:'Lean years come to every farm. You are not cursed; you are a farmer. Prepare the soil for the coming year.',pt:'Anos magros chegam a toda a lavoura. Não estás amaldiçoado; és lavrador. Prepara a terra para o ano que vem.'},inv:{ro:'Într-o zonă slabă a vieții, lucrează azi pământul, nu doliul.',en:'In a lean area of life, work the soil today, not the mourning.',pt:'Numa área magra da vida, trabalha hoje a terra, não o luto.'}},
  {el:'harvest',kw:{ro:'Grâul și neghina',en:'Wheat and Tares',pt:'O Trigo e o Joio'},t:{ro:'În orice recoltă a vieții se amestecă grâu și neghină. Nu arunca recolta pentru neghină; învață cernutul.',en:'In every life harvest, wheat and tares mix. Do not discard the harvest for the tares; learn to sift.',pt:'Em toda a colheita da vida misturam-se trigo e joio. Não deites fora a colheita por causa do joio; aprende a peneirar.'},inv:{ro:'Cerne azi o experiență amestecată: păstrează grâul.',en:'Sift one mixed experience today: keep the wheat.',pt:'Peneira hoje uma experiência misturada: guarda o trigo.'}},
  {el:'harvest',kw:{ro:'Roada răbdării',en:'The Fruit of Patience',pt:'O Fruto da Paciência'},t:{ro:'Nimeni n-a grăbit vreodată un măr să se coacă trăgând de el. Unele recolte cer un singur lucru: să nu strici așteptând.',en:'No one ever ripened an apple by pulling on it. Some harvests ask one thing only: do not spoil while waiting.',pt:'Ninguém apressou uma maçã puxando por ela. Algumas colheitas pedem só uma coisa: não estragar enquanto esperas.'},inv:{ro:'Unde tragi de măr? Lasă-l azi în pace să se coacă.',en:'Where are you pulling the apple? Leave it to ripen today.',pt:'Onde puxas a maçã? Deixa-a hoje amadurecer em paz.'}},
  {el:'harvest',kw:{ro:'Împărțitul recoltei',en:'Sharing the Harvest',pt:'A Partilha da Colheita'},t:{ro:'Recolta împărțită se face sămânță în alte grădini; cea zăvorâtă se face doar teamă de hoți.',en:'A shared harvest becomes seed in other gardens; a locked one becomes only fear of thieves.',pt:'A colheita partilhada torna-se semente noutros jardins; a trancada torna-se apenas medo de ladrões.'},inv:{ro:'Împarte azi din recolta ta: cunoștințe, roade, timp.',en:'Share from your harvest today: knowledge, fruits, time.',pt:'Partilha hoje da tua colheita: saber, frutos, tempo.'}},
  {el:'harvest',kw:{ro:'Spicele rămase',en:'The Gleanings',pt:'As Espigas Deixadas'},t:{ro:'Gospodarii vechi lăsau spice pe câmp pentru trecători. Lasă și tu, în urma izbânzilor tale, ceva de cules pentru alții.',en:'Old householders left ears in the field for passersby. Leave behind your successes something for others to glean.',pt:'Os antigos lavradores deixavam espigas no campo para os que passavam. Deixa também, atrás das tuas vitórias, algo para outros respigarem.'},inv:{ro:'Lasă azi „spice": o ocazie, un pont, o ușă deschisă cuiva.',en:'Leave “gleanings” today: an opportunity, a tip, an open door.',pt:'Deixa hoje «espigas»: uma oportunidade, uma dica, uma porta aberta.'}},
  {el:'harvest',kw:{ro:'Roadele nevăzute',en:'The Unseen Fruits',pt:'Os Frutos Invisíveis'},t:{ro:'Cele mai bune roade ale tale nu sunt în cămară: sunt oameni care s-au făcut mai buni pentru că ai trecut pe lângă ei.',en:'Your best fruits are not in the pantry: they are people made better because you passed by them.',pt:'Os teus melhores frutos não estão na despensa: são pessoas que se tornaram melhores porque passaste por elas.'},inv:{ro:'Coace azi un rod nevăzut: ridică un om cu o vorbă.',en:'Ripen an unseen fruit today: lift someone with a word.',pt:'Amadurece hoje um fruto invisível: eleva alguém com uma palavra.'}},
  {el:'harvest',kw:{ro:'Toamna mulțumirii',en:'The Autumn of Thanks',pt:'O Outono da Gratidão'},t:{ro:'La capătul fiecărei perioade, fă-i secerișul: ce am primit? ce am învățat? cui mulțumesc? Abia apoi ară din nou.',en:'At each season’s close, hold its harvest: what did I receive? what did I learn? whom do I thank? Only then plow again.',pt:'No fecho de cada época, faz a sua colheita: o que recebi? o que aprendi? a quem agradeço? Só depois lavra de novo.'},inv:{ro:'Fă azi secerișul lunii trecute: primit, învățat, mulțumit.',en:'Harvest last month today: received, learned, thanked.',pt:'Colhe hoje o mês passado: recebido, aprendido, agradecido.'}},
  {el:'harvest',kw:{ro:'Vinul din struguri călcați',en:'Wine from Trodden Grapes',pt:'O Vinho das Uvas Pisadas'},t:{ro:'Strugurele devine vin abia călcat în picioare. Unele deveniri ale tale au același preț; nu-l plăti degeaba — fă vin.',en:'The grape becomes wine only once trodden. Some of your becomings cost the same; do not pay in vain — make wine.',pt:'A uva só se faz vinho depois de pisada. Alguns dos teus devires custam o mesmo; não pagues em vão — faz vinho.'},inv:{ro:'Dintr-o călcare în picioare a vieții, începe azi vinul: lecția, opera, schimbarea.',en:'From one of life’s treadings, start the wine today: the lesson, the work, the change.',pt:'De uma pisadela da vida, começa hoje o vinho: a lição, a obra, a mudança.'}},
  {el:'harvest',kw:{ro:'Cămara pentru iarnă',en:'The Winter Pantry',pt:'A Despensa para o Inverno'},t:{ro:'Vara pui în borcane pentru iarnă. Pune și în suflet: amintiri bune, prietenii întărite, rugăciuni făcute. Vine și iarnă.',en:'In summer you jar for winter. Stock the soul too: good memories, strengthened friendships, prayers made. Winter also comes.',pt:'No verão enfrascas para o inverno. Abastece também a alma: boas memórias, amizades firmadas, orações feitas. O inverno também vem.'},inv:{ro:'Pune azi un „borcan" în cămara sufletului.',en:'Put one “jar” in the soul’s pantry today.',pt:'Põe hoje um «frasco» na despensa da alma.'}},
  {el:'harvest',kw:{ro:'Măsura seceratului',en:'The Reaper’s Measure',pt:'A Medida do Ceifeiro'},t:{ro:'Nu semăna mai mult decât poți secera și nu promite mai mult decât poți duce. Câmpul nerecoltat acuză mai tare decât cel mic.',en:'Sow no more than you can reap, promise no more than you can carry. An unharvested field accuses louder than a small one.',pt:'Não semeies mais do que podes ceifar nem prometas mais do que podes levar. O campo por colher acusa mais alto que o pequeno.'},inv:{ro:'Taie azi din listă ce nu vei secera niciodată.',en:'Cut from the list today what you will never reap.',pt:'Corta hoje da lista o que nunca ceifarás.'}},
  {el:'harvest',kw:{ro:'Sămânța păstrată',en:'The Kept Seed',pt:'A Semente Guardada'},t:{ro:'Țăranul înțelept nu mănâncă niciodată sămânța de anul viitor, oricât de grea e iarna. Păzește-ți semințele: sănătatea, numele bun, nădejdea.',en:'The wise farmer never eats next year’s seed, however hard the winter. Guard your seeds: health, good name, hope.',pt:'O lavrador sábio nunca come a semente do ano seguinte, por duro que seja o inverno. Guarda as tuas sementes: saúde, bom nome, esperança.'},inv:{ro:'Ce „sămânță" ești ispitit să mănânci azi? Păstreaz-o.',en:'What “seed” are you tempted to eat today? Keep it.',pt:'Que «semente» és tentado a comer hoje? Guarda-a.'}},
  {el:'harvest',kw:{ro:'Roua muncii de dimineață',en:'The Dew of Morning Work',pt:'O Orvalho do Trabalho Matinal'},t:{ro:'Ce semeni dimineața prinde roua; ce semeni seara prinde doar oboseala. Pune lucrul de preț la ceasul de preț.',en:'What you sow at morning catches dew; what you sow at evening catches only fatigue. Put precious work in the precious hour.',pt:'O que semeias de manhã apanha orvalho; o que semeias à noite apanha só cansaço. Põe a obra preciosa na hora preciosa.'},inv:{ro:'Mută de mâine semănatul cel mare la ceasul cu rouă.',en:'From tomorrow, move the main sowing to the dew hour.',pt:'A partir de amanhã, muda a sementeira principal para a hora do orvalho.'}},
  {el:'harvest',kw:{ro:'Roadele de peste gard',en:'The Fruits Over the Fence',pt:'Os Frutos Sobre a Cerca'},t:{ro:'Pomul bun rodește și peste gardul vecinului — și nu-și cere ramurile înapoi. Lasă-ți binele să cadă și în curți străine.',en:'A good tree bears fruit over the neighbor’s fence too — and does not recall its branches. Let your good fall into foreign yards as well.',pt:'A boa árvore dá fruto também sobre a cerca do vizinho — e não chama os ramos de volta. Deixa o teu bem cair também em quintais alheios.'},inv:{ro:'Lasă azi un rod să cadă „peste gard", fără să-l revendici.',en:'Let one fruit fall “over the fence” today, unclaimed.',pt:'Deixa hoje um fruto cair «sobre a cerca», sem o reclamar.'}},
  {el:'harvest',kw:{ro:'Bobul putrezit',en:'The Grain that Dies',pt:'O Grão que Morre'},t:{ro:'Bobul care nu acceptă să intre în pământ rămâne singur; cel care se dă pe sine aduce spic. Unele dăruiri de sine sunt semănat.',en:'The grain that will not enter the ground remains alone; the one that gives itself brings forth the ear. Some self-givings are sowing.',pt:'O grão que não aceita entrar na terra fica só; o que se entrega traz espiga. Algumas entregas de si são sementeira.'},inv:{ro:'Unde te ții „bob întreg" de frică? Dă-te azi pământului.',en:'Where do you stay a “whole grain” from fear? Give yourself to the soil today.',pt:'Onde ficas «grão inteiro» por medo? Entrega-te hoje à terra.'}},
  {el:'harvest',kw:{ro:'Ograda plină seara',en:'The Full Yard at Evening',pt:'O Quintal Cheio à Noite'},t:{ro:'Seara gospodarului bun: unelte la loc, animale hrănite, poarta închisă, inima liniștită. Rânduiala de seară e recolta zilei.',en:'The good householder’s evening: tools stored, animals fed, gate shut, heart at rest. The evening order is the day’s harvest.',pt:'A noite do bom lavrador: ferramentas no lugar, animais alimentados, portão fechado, coração em paz. A ordem da noite é a colheita do dia.'},inv:{ro:'Fă diseară „ograda plină": toate la locul lor, inima liniștită.',en:'Make the “full yard” tonight: all in place, heart at rest.',pt:'Faz esta noite o «quintal cheio»: tudo no lugar, o coração em paz.'}},
  {el:'harvest',kw:{ro:'Mulțumirea care înmulțește',en:'The Thanks that Multiplies',pt:'A Gratidão que Multiplica'},t:{ro:'Peste ce mulțumești, crește; peste ce te plângi, seacă. Recunoștința e sistem de irigație pentru viață.',en:'What you thank over, grows; what you complain over, dries. Gratitude is life’s irrigation system.',pt:'Sobre o que agradeces, cresce; sobre o que te queixas, seca. A gratidão é o sistema de rega da vida.'},inv:{ro:'Irigă azi cu mulțumire trei zone ale vieții tale.',en:'Irrigate three areas of your life with thanks today.',pt:'Rega hoje com gratidão três áreas da tua vida.'}},
  {el:'harvest',kw:{ro:'Târgul cinstit',en:'The Honest Market',pt:'A Feira Honesta'},t:{ro:'Du-ți roadele la târg fără să le vopsești: marfa cinstită își face clientelă pe viață. La fel omul.',en:'Bring your fruits to market unpainted: honest goods make lifelong customers. So does an honest person.',pt:'Leva os teus frutos à feira sem os pintar: a mercadoria honesta faz clientes para a vida. Assim a pessoa honesta.'},inv:{ro:'Prezintă azi ceva exact cum e — și câștigă pe termen lung.',en:'Present something exactly as it is today — and win long-term.',pt:'Apresenta hoje algo tal como é — e ganha a longo prazo.'}},
  {el:'harvest',kw:{ro:'Recolta de oameni',en:'The Harvest of People',pt:'A Colheita de Pessoas'},t:{ro:'La sfârșitul vieții, hambarul tău adevărat va fi plin de oameni: crescuți, ajutați, iubiți, iertați. Acesta e singurul grânar care contează.',en:'At life’s end, your true barn will be full of people: raised, helped, loved, forgiven. The only granary that counts.',pt:'No fim da vida, o teu verdadeiro celeiro estará cheio de pessoas: criadas, ajudadas, amadas, perdoadas. O único celeiro que conta.'},inv:{ro:'Adaugă azi un om în grânarul tău: ajută, iubește sau iartă.',en:'Add one person to your granary today: help, love or forgive.',pt:'Acrescenta hoje uma pessoa ao teu celeiro: ajuda, ama ou perdoa.'}},
  {el:'harvest',kw:{ro:'Ploaia la vreme',en:'The Timely Rain',pt:'A Chuva a Tempo'},t:{ro:'Tu sameni și uzi; creșterea o dă altcineva. Fă-ți partea întreagă și încrede-te pentru rest: ploaia știe când.',en:'You sow and water; the growth is given by Another. Do your whole part and trust for the rest: the rain knows when.',pt:'Tu semeias e regas; o crescimento é dado por Outro. Faz a tua parte inteira e confia o resto: a chuva sabe quando.'},inv:{ro:'Fă azi partea ta întreagă — și predă restul cerului.',en:'Do your whole part today — and hand the rest to heaven.',pt:'Faz hoje a tua parte inteira — e entrega o resto ao céu.'}},
  {el:'harvest',kw:{ro:'Snopul legat',en:'The Bound Sheaf',pt:'O Feixe Atado'},t:{ro:'Spicele risipite se pierd în vânt; legate snop, hrănesc o casă. Adună-ți realizările mărunte în snopi: proiecte duse, povești spuse.',en:'Scattered ears are lost to the wind; bound in a sheaf, they feed a house. Bind your small achievements into sheaves: projects finished, stories told.',pt:'As espigas soltas perdem-se ao vento; atadas em feixe, alimentam uma casa. Ata as tuas pequenas conquistas em feixes: projetos concluídos, histórias contadas.'},inv:{ro:'Leagă azi un snop: încheie și adună într-un tot câteva lucruri mărunte.',en:'Bind one sheaf today: finish and gather a few small things into a whole.',pt:'Ata hoje um feixe: termina e junta num todo algumas coisas pequenas.'}},
  {el:'harvest',kw:{ro:'Gustul primului rod',en:'The Taste of the First Fruit',pt:'O Sabor do Primeiro Fruto'},t:{ro:'Primul rod al muncii tale are un gust pe care nu-l va mai avea niciun alt rod. Oprește-te și savurează-l; nu-l înghiți din mers.',en:'The first fruit of your work has a taste no later fruit will have. Stop and savor it; do not swallow it on the run.',pt:'O primeiro fruto do teu trabalho tem um sabor que nenhum outro terá. Pára e saboreia-o; não o engulas a correr.'},inv:{ro:'Savurează azi, pe îndelete, un rod recent al muncii tale.',en:'Savor a recent fruit of your work today, unhurried.',pt:'Saboreia hoje, sem pressa, um fruto recente do teu trabalho.'}},
  {el:'harvest',kw:{ro:'Câmpul lăsat să se odihnească',en:'The Fallow Field',pt:'O Campo em Pousio'},t:{ro:'Din când în când, câmpul se lasă nesemănat ca să-și refacă puterea. Îngăduie-ți și ție sezoane de pârloagă fără vină.',en:'Now and then a field is left unsown to restore its strength. Allow yourself guilt-free fallow seasons too.',pt:'De vez em quando o campo fica por semear para refazer a força. Permite-te também pousios sem culpa.'},inv:{ro:'Declară o zonă a vieții „în pârloagă" pentru un sezon.',en:'Declare one life area “fallow” for a season.',pt:'Declara uma área da vida «em pousio» por uma estação.'}},
  {el:'harvest',kw:{ro:'Numărătoarea boabelor',en:'Counting the Grains',pt:'A Contagem dos Grãos'},t:{ro:'Nu număra boabele altora și nu-ți disprețui puținul: dintr-un pumn de boabe bune iese un an întreg de pâine.',en:'Do not count others’ grains nor despise your little: from one handful of good grain comes a whole year of bread.',pt:'Não contes os grãos dos outros nem desprezes o teu pouco: de uma mão-cheia de bom grão sai um ano inteiro de pão.'},inv:{ro:'Numără-ți azi pumnul de boabe bune — și seamănă-l.',en:'Count your handful of good grain today — and sow it.',pt:'Conta hoje a tua mão-cheia de bom grão — e semeia-a.'}},
  {el:'harvest',kw:{ro:'Ospățul recoltei',en:'The Harvest Feast',pt:'A Festa da Colheita'},t:{ro:'După seceriș, satele făceau ospăț: munca cere sărbătoarea ei, altfel devine robie. Sărbătorește-ți recoltele, oricât de mici.',en:'After reaping, villages held a feast: work demands its celebration, or it becomes bondage. Celebrate your harvests, however small.',pt:'Depois da ceifa, as aldeias faziam festa: o trabalho pede a sua celebração, senão vira servidão. Celebra as tuas colheitas, por pequenas que sejam.'},inv:{ro:'Sărbătorește azi o recoltă recentă: o masă bună, un pahar ridicat.',en:'Celebrate a recent harvest today: a good meal, a raised glass.',pt:'Celebra hoje uma colheita recente: uma boa refeição, um copo erguido.'}},
  {el:'harvest',kw:{ro:'Moștenirea câmpului',en:'The Field’s Legacy',pt:'O Legado do Campo'},t:{ro:'Lasă câmpul mai roditor decât l-ai primit: pământul, meseria, familia, țara. Aceasta e toată datoria omului, și toată gloria lui.',en:'Leave the field more fruitful than you received it: the land, the trade, the family, the country. That is a person’s whole duty, and their whole glory.',pt:'Deixa o campo mais fértil do que o recebeste: a terra, o ofício, a família, o país. Esse é todo o dever da pessoa, e toda a sua glória.'},inv:{ro:'Fă azi un gest care lasă un „câmp" mai roditor în urma ta.',en:'Make one gesture today that leaves a “field” more fruitful behind you.',pt:'Faz hoje um gesto que deixe um «campo» mais fértil atrás de ti.'}},
  {el:'harvest',kw:{ro:'Binecuvântarea recoltei',en:'The Blessing of the Harvest',pt:'A Bênção da Colheita'},t:{ro:'Toată roada bună coboară din același cer. Mulțumește Celui care dă creșterea — și recolta ta se va ține de pământ cu amândouă mâinile.',en:'All good fruit descends from the same heaven. Thank the One who gives the growth — and your harvest will hold the earth with both hands.',pt:'Todo o bom fruto desce do mesmo céu. Agradece Àquele que dá o crescimento — e a tua colheita segurará a terra com as duas mãos.'},inv:{ro:'Încheie azi cu mulțumire către Cel care dă creșterea.',en:'Close today with thanks to the One who gives the growth.',pt:'Fecha hoje com gratidão Àquele que dá o crescimento.'}},
  {el:'harvest',kw:{ro:'Pâinea de pe masă',en:'The Bread on the Table',pt:'O Pão na Mesa'},t:{ro:'Între bobul semănat și pâinea de pe masă stau o sută de mâini și un an de răbdare. Nu mânca niciodată nerecunoscător.',en:'Between the sown grain and the bread on the table lie a hundred hands and a year of patience. Never eat ungratefully.',pt:'Entre o grão semeado e o pão na mesa estão cem mãos e um ano de paciência. Nunca comas sem gratidão.'},inv:{ro:'La masa de azi, gândește-te o clipă la toate mâinile din spatele ei.',en:'At today’s meal, think a moment of all the hands behind it.',pt:'Na refeição de hoje, pensa um momento em todas as mãos por trás dela.'}}
];
